export const QUICK_START_DATA: CourseData = {"product_id": "quick-start", "title": "AI Quick Start", "subtitle": "10 Free Prompts That Will Change How You Work", "source": "ai-quick-start-free.pdf", "version": "2.0 — March 2026", "pages": 9, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "These 10 prompts are hand-picked from our full AI Starter Kit (50+ prompts). But they're not just prompts — each one is a mini-system designed to produce results you'd normally pay a consultant for. They cover the areas where AI makes the biggest immediate impact on your work.", "items": []}, {"title": "How to Use", "type": "instructions", "content": "Step-by-step guide for using the prompts.", "items": [{"step": 1, "instruction": "Copy the full prompt — every word matters for the output quality"}, {"step": 2, "instruction": "Replace [bracketed text] with your real, specific details (the more detail, the better the result)"}, {"step": 3, "instruction": "Paste into Claude or Gemini"}, {"step": 4, "instruction": "Use the follow-up prompts included with each to go deeper"}]}, {"title": "Pro Tip — Getting Better Results", "type": "tips", "content": "The #1 mistake people make with AI is being vague. Instead of [topic], write the exact topic. Instead of [audience], describe your actual target reader — their age, role, frustration, goal. Think of every [bracket] as a blank on a form: the more precisely you fill it in, the more precisely the AI delivers. Each prompt below includes a 'Why This Works' note explaining the technique behind it, so you learn the skill — not just the prompt.", "items": []}, {"title": "What's Inside", "type": "overview", "content": "10 prompts across 7 categories — each with a follow-up prompt and explanation of why it works.", "items": [{"category": "Productivity", "count": 1}, {"category": "Writing", "count": 2}, {"category": "Business", "count": 2}, {"category": "Marketing", "count": 2}, {"category": "Research", "count": 1}, {"category": "Personal Growth", "count": 1}, {"category": "Advanced", "count": 1}]}, {"title": "The 10 Prompts", "type": "prompts", "content": "10 hand-picked prompts from the full AI Starter Kit — enhanced with follow-ups, technique breakdowns, and real examples.", "items": [{"number": "01", "name": "The Daily Prioritizer", "category": "PRODUCTIVITY", "prompt": "You are my executive productivity coach. I have [X hours] available today and here are all my tasks:\n\n[List every task, including rough time estimates if you have them]\n\nDo the following:\n1. Classify each task using the Eisenhower Matrix (Urgent+Important, Important Not Urgent, Urgent Not Important, Neither)\n2. Build a time-blocked schedule for my day with 15-minute buffer periods between deep work blocks\n3. For each task, note if it can be partially delegated to AI (and suggest the specific AI approach)\n4. Flag my #1 highest-leverage task — the one that moves the needle most — and put it in my peak energy slot\n5. Add a 'parking lot' section for tasks I should defer to tomorrow with reasoning\n\nFormat the schedule as a clean table with columns: Time | Task | Category | Energy Level | AI-Assistable?", "best_on": ["Claude"], "tip": "Run this every morning. After a week, ask the AI to analyze your patterns: 'Based on the 5 daily schedules I've given you, what are my recurring time-wasters and how should I restructure my default week?'", "why_it_works": "This prompt uses role assignment ('executive productivity coach'), structured output (Eisenhower Matrix + table format), and constraint-setting (buffer periods, peak energy) — three techniques that force AI out of generic advice mode.", "follow_up": "Now review my completed day: [paste what you actually did]. Compare it to the plan. Where did I lose time? What pattern do you see? Give me one rule I should follow tomorrow."}, {"number": "02", "name": "The Email Rewriter", "category": "WRITING", "prompt": "You are a communications expert who has written for CEOs and diplomats. I need to send an email to [recipient's role] at [company/context] about [specific situation].\n\nHere's my rough draft or key points:\n[Paste your draft OR bullet points of what you want to say]\n\nRewrite this email following these rules:\n- Maximum 120 words (people skim — every word must earn its place)\n- Opening line: reference something specific to the recipient (no 'I hope this finds you well')\n- Body: one clear paragraph with the key point\n- Close: one single, specific ask with a deadline or next step\n- Tone: [direct but warm / authoritative but friendly / casual but professional]\n\nThen provide:\n- Version A: Your best rewrite\n- Version B: A shorter, bolder alternative (under 80 words)\n- Subject line: 3 options ranked by open-rate likelihood", "best_on": ["Claude"], "tip": "Always provide your rough draft or bullet points, even if messy. AI rewrites are 10x better than AI writes-from-scratch because it has your real intent and details to work with.", "why_it_works": "Giving the AI two versions to produce (A and B) triggers comparative reasoning — it actively thinks about what to cut and what to keep, producing tighter writing than a single draft would.", "follow_up": "The recipient might push back on [likely objection]. Write a follow-up email for that scenario — same tone, same brevity, but address the objection head-on in the opening line."}, {"number": "03", "name": "The Business Idea Stress Test", "category": "BUSINESS", "prompt": "You are a seasoned venture strategist who has evaluated 500+ business ideas. You are brutally honest but constructive.\n\nMy business idea: [Describe in 2-3 sentences — what it is, who it's for, how it makes money]\n\nConduct a full stress test:\n\n1. VIABILITY SCORE: Rate 1-10 with specific reasoning\n2. TOP 5 RISKS: Ranked by likelihood × impact. For each risk, include one specific way to mitigate it\n3. IDEAL CUSTOMER: Describe them in detail — demographics, psychographics, where they hang out online, what they currently pay for alternatives\n4. COMPETITIVE LANDSCAPE: Name 3 real competitors (or closest alternatives) with their pricing, strengths, and weaknesses\n5. MOAT ANALYSIS: What would make this hard to copy? Rate the defensibility 1-10\n6. THE $100 TEST: Design a specific validation experiment I can run THIS WEEK for under $100 to test demand\n7. VERDICT: One paragraph — would you invest? Why or why not?\n\nDo NOT sugarcoat. I need the truth, not encouragement.", "best_on": ["Claude", "Gemini"], "tip": "After the initial analysis, challenge it: 'Now argue the opposite — why WOULD this succeed despite the risks you identified? What am I not seeing?' This forces balanced analysis.", "why_it_works": "The 'Do NOT sugarcoat' instruction + the specific expert role prevents AI's natural tendency to be encouraging. The numbered structure ensures nothing gets skipped.", "follow_up": "Based on your analysis, if I had to pivot this idea to reduce the top 2 risks while keeping the core value proposition, what would the pivoted version look like? Describe it as a one-paragraph pitch."}, {"number": "04", "name": "The Blog Post Architect", "category": "WRITING", "prompt": "You are a content strategist who has written viral articles for top publications. Your specialty is making complex topics feel simple and actionable.\n\nWrite a 1,000-word blog post:\n- Topic: [your topic]\n- Target reader: [describe them — role, experience level, what they're struggling with]\n- Goal: [what should the reader be able to DO after reading this?]\n\nStructure requirements:\n1. HOOK (first 2 sentences): Start with a surprising stat, a contrarian take, or a relatable frustration. No 'In today's fast-paced world' or 'Have you ever wondered'\n2. THE PROBLEM: One paragraph that makes the reader think 'this person gets me'\n3. 3-5 SUBHEADINGS: Each with a specific, actionable technique (not vague advice). Include at least one real example or mini case study per section\n4. THE SHORTCUT: One section that gives the reader an unexpected quick win they can use immediately\n5. CLOSE: A CTA that connects to [your goal — newsletter signup / product / consultation]\n\nTone: [conversational and confident / authoritative and data-driven / witty and relatable]\n\nBanned phrases: 'game-changer', 'dive in', 'at the end of the day', 'it's important to note', 'in conclusion'", "best_on": ["Claude"], "tip": "After getting the draft, use this power move: 'Now read this as a skeptical [target reader]. Highlight every sentence where they'd think \"so what?\" or \"I already knew that\" and replace it with something specific and surprising.'", "why_it_works": "Banning cliches and requiring specific examples forces AI to produce genuinely original content. The 'banned phrases' technique is one of the most underused prompt tricks.", "follow_up": "Extract 5 social media posts from this article — each should stand alone as valuable content. Format: Hook line (under 10 words), 3-4 sentence body, CTA back to the full post."}, {"number": "05", "name": "The Revenue Content Calendar", "category": "MARKETING", "prompt": "You are a social media strategist who has managed accounts that generate 6-figure revenue from organic content alone.\n\nCreate a 30-day content calendar for:\n- Business: [your business and what you sell]\n- Platform: [Instagram / LinkedIn / TikTok / Twitter]\n- Goal: [grow followers / drive sales / build authority / generate leads]\n- Audience: [who they are and what they care about]\n\nFor each day, provide:\n1. Content pillar (from: Educational 40% | Entertaining 30% | Promotional 20% | Community 10%)\n2. Content type (carousel, single image, video, story, text post, reel)\n3. Topic + angle (be specific — not just 'talk about product')\n4. Hook: The exact first line (this determines if people stop scrolling)\n5. CTA: What the viewer should do\n6. Best posting time for [platform]\n\nAlso include:\n- 4 'engagement bait' posts designed to get comments and shares\n- 2 'authority builder' posts that position me as the expert\n- 2 'soft sell' posts that drive purchases without feeling pushy\n- Week-over-week strategy notes: what to analyze and adjust\n\nFormat as a table grouped by week.", "best_on": ["Gemini"], "tip": "The most important part is the hooks. After getting the calendar, ask: 'Now rewrite every hook to be more provocative. Use pattern interrupts, curiosity gaps, or contrarian takes. Boring hooks = invisible posts.'", "why_it_works": "Specifying exact percentages for content types (40/30/20/10) gives the AI a framework instead of random content. Adding 'engagement bait' and 'soft sell' categories ensures strategic variety.", "follow_up": "Analyze this calendar. Which 5 posts are most likely to go viral and why? Which 3 are weakest? Replace the weak ones with stronger alternatives."}, {"number": "06", "name": "The Instant Expert Briefing", "category": "RESEARCH", "prompt": "You are a research analyst who briefs executives. Your job is to make me sound like I've been studying [topic] for months — in under 5 minutes of reading.\n\nCreate an executive briefing on: [topic]\n\nStructure:\n1. THE 30-SECOND VERSION: 3 sentences that capture the essence (if I only read this, I'd still sound smart in a meeting)\n2. 5 KEY FACTS: The numbers, dates, and data points that matter most — with context for why each matters\n3. THE KEY PLAYERS: Who are the 3-5 most important people/companies in this space and what are they doing?\n4. CURRENT STATE: What's happening right now (2024-2026) that's changing things?\n5. THE DEBATE: What do experts disagree about? Give both sides in 2-3 sentences each\n6. COMMON MISCONCEPTIONS: 3 things most people get wrong about this topic\n7. CONVERSATION STARTERS: 3 impressive things I could say in a meeting about this topic that would make me sound deeply informed\n8. DEEPER READING: 3 specific, real sources (articles, books, reports) for going deeper\n\nKeep everything concise. I'm prepping fast, not writing a thesis.", "best_on": ["Gemini", "Claude"], "tip": "Use Gemini for this prompt — it has access to current information and can provide more up-to-date facts and sources. Claude is better for the analysis sections.", "why_it_works": "The 'Conversation Starters' section is the secret weapon — it transforms passive knowledge into active talking points. The 'Common Misconceptions' section gives you contrarian edge.", "follow_up": "I'm meeting with [person/audience] about this topic. They likely know [their expertise level]. What are the 3 questions they'll probably ask me, and how should I answer each one?"}, {"number": "07", "name": "The Strategic SWOT System", "category": "BUSINESS", "prompt": "You are a McKinsey-level strategy consultant. Conduct a comprehensive SWOT analysis for:\n\nBusiness/Project: [describe it]\nIndustry: [your industry]\nStage: [startup / growing / established / pivoting]\nTop competitor: [name one if you know one]\n\nFor EACH quadrant, provide:\n- 5+ specific, actionable items (not generic phrases like 'strong brand' — be precise about WHAT is strong and WHY it matters)\n- A confidence rating (High/Medium/Low) for each item\n- One data point or evidence that supports it\n\nThen create:\n1. ATTACK MATRIX: A 2x2 table — rows are Strengths and Weaknesses, columns are Opportunities and Threats. Each cell answers: 'How do I use [row] to address [column]?'\n2. TOP 3 PRIORITIES: Based on this analysis, what are the 3 most important strategic moves in the next 90 days?\n3. EARLY WARNING SIGNALS: 3 things to monitor that would indicate a threat is becoming real\n\nBe specific to MY business — generic strategy advice is worthless.", "best_on": ["Claude", "Gemini"], "tip": "After the initial SWOT, ask: 'Now do a reverse SWOT — analyze my top competitor using the same framework. Where are they weak where I'm strong?' This reveals your competitive advantage.", "why_it_works": "The Attack Matrix is what separates this from basic SWOT — it forces AI to create actionable strategies from the intersection of factors, not just list items in four boxes.", "follow_up": "Turn my top 3 priorities into a 90-day action plan. Break each priority into specific weekly milestones with measurable outcomes."}, {"number": "08", "name": "The Rapid Skill Accelerator", "category": "PERSONAL GROWTH", "prompt": "You are a world-class learning coach who designs accelerated skill acquisition programs. Your philosophy: learn by doing, not by watching.\n\nDesign a 30-day plan to take me from [current level] to [target level] in [skill].\n\nAbout me:\n- Available time: [X minutes per day]\n- Learning style: [hands-on / reading / video / mixed]\n- Why I'm learning this: [your goal — job, project, personal interest]\n\nFor each day, provide:\n1. FOCUS (one specific sub-skill to practice)\n2. DO THIS (a concrete exercise — not 'practice X', but the exact exercise with parameters)\n3. TIME (realistic time estimate)\n4. SUCCESS METRIC (how do I know I did it right?)\n\nAlso include:\n- WEEK 1-4 MILESTONES: What I should be able to demonstrate at each week's end\n- THE 3 PLATEAUS: Where most people get stuck and how to break through\n- TOOLS & RESOURCES: Only free ones. Max 3 — fewer is better\n- THE SHORTCUT: One technique that most tutorials skip that dramatically accelerates learning\n- COMMON MISTAKES: Top 5 mistakes beginners make and how to avoid each one", "best_on": ["Claude"], "tip": "At the end of each week, paste your progress back and ask: 'Based on my Week [X] progress, am I on track? Adjust the remaining weeks to address my specific weak spots.'", "why_it_works": "The 'Success Metric' for each day prevents the #1 problem with learning plans: doing the activity without knowing if you're actually improving. Measurable daily feedback accelerates learning 3x.", "follow_up": "I just completed Week 1. Here's what went well: [X]. Here's what I struggled with: [Y]. Adjust Weeks 2-4 to focus more on my weak areas while maintaining momentum on my strengths."}, {"number": "09", "name": "The High-Converting Landing Page", "category": "MARKETING", "prompt": "You are a conversion copywriter who has written landing pages generating $10M+ in revenue. You understand both the psychology of buying and the mechanics of web copy.\n\nWrite complete landing page copy for:\n- Product/Service: [what you're selling]\n- Price: [price point]\n- Target buyer: [who they are, what they're feeling, what they've already tried]\n- Key differentiator: [what makes this different from alternatives]\n\nProvide every section in order:\n1. HERO: Headline (under 10 words, benefit-focused), subheadline (1 sentence that adds specificity), CTA button text (not 'Submit' — something that completes 'I want to...')\n2. PAIN POINTS: 3 frustrations written in the customer's exact words (as if overheard at a coffee shop)\n3. SOLUTION BRIDGE: One paragraph that transitions from pain to your offer\n4. FEATURES → BENEFITS: A table with 5 features, each translated into a specific benefit and the emotional result\n5. SOCIAL PROOF SECTION: Write 3 realistic testimonial templates I can adapt (name, role, specific result, before/after)\n6. OBJECTION HANDLER: FAQ with the 5 most common objections as questions, each answered in 2-3 sentences\n7. URGENCY + FINAL CTA: Closing section with scarcity or urgency element and a CTA that removes risk\n\nWrite for a [sophisticated / general / skeptical] audience. No hype. No 'revolutionary'. Just clear, benefit-driven copy.", "best_on": ["Claude"], "tip": "After getting the copy, ask: 'Now read this as a skeptical buyer who has been burned before. Which sections would make them close the tab? Rewrite those sections to address their skepticism directly.'", "why_it_works": "The Features → Benefits → Emotional Result chain is a professional copywriting framework (Feature: what it does → Benefit: why it matters → Emotion: how it feels). Most people only do the first one.", "follow_up": "Write 3 variations of the hero section for A/B testing. Variation A: lead with the biggest pain point. Variation B: lead with the most impressive result. Variation C: lead with social proof."}, {"number": "10", "name": "The MEGA Prompt Framework", "category": "ADVANCED", "prompt": "This isn't a prompt to copy — it's a framework to build ANY prompt. Use these 7 building blocks every time you talk to AI:\n\n[ROLE]: 'You are [specific expert with years of experience and specialty]'\n→ Example: 'You are a SaaS pricing strategist with 15 years of experience in B2B subscription models'\n\n[CONTEXT]: 'Here is the background: [your situation, constraints, what you've already tried]'\n→ Example: 'I run a 10-person design agency. We currently charge hourly but want to switch to project-based pricing'\n\n[TASK]: 'Do the following: [numbered list of specific deliverables]'\n→ Example: '1. Analyze our current pricing model 2. Propose 3 pricing tiers 3. Write the pricing page copy'\n\n[FORMAT]: 'Output as: [table / bullet points / step-by-step / email / report]'\n→ Example: 'Present the 3 tiers as a comparison table with columns for each tier'\n\n[CONSTRAINTS]: 'Rules: [word limits, things to avoid, must-includes]'\n→ Example: 'Keep each tier description under 50 words. Do not use the word \"cheap\" for the lowest tier'\n\n[TONE]: 'Write in a [adjective] voice'\n→ Example: 'Write in a confident, no-nonsense voice — like talking to a smart colleague'\n\n[EXAMPLE]: 'Here's a sample of what good output looks like: [paste an example]'\n→ This is the single most powerful element. Even a rough example dramatically improves output quality.\n\nPRO MOVE: Stack all 7 into one prompt. The more blocks you use, the better your results. Even using just ROLE + TASK + FORMAT puts you ahead of 90% of AI users.", "best_on": ["Claude", "Gemini"], "tip": "Build a personal 'prompt template' with your ROLE and CONTEXT pre-filled. Save it in Claude's Projects or Gemini Gems so you never start from scratch. (Our AI Skills Builder course teaches exactly how to set this up.)", "why_it_works": "Each block constrains the AI's output space. Without constraints, AI gives you 'average internet content.' With all 7 blocks, it gives you custom expert output. This is the same framework professional prompt engineers use.", "follow_up": "Take this topic: [your topic]. Build a MEGA prompt using all 7 blocks, then execute it. Show me the prompt you'd build AND the output it produces."}]}, {"title": "Installable AI Tools — 2 Claude Skills + 1 Gemini Gem", "type": "skills", "content": "Ready-to-install AI tools built specifically for solopreneurs. Each tool is a pre-configured AI specialist that you install once and use forever. Copy the code below, follow the install steps, and you'll have a working AI assistant in under 5 minutes.", "install_overview": {"claude": {"title": "How to Install Claude Skills", "steps": ["Open Claude (claude.ai) and sign in", "Type /skill-creator in any conversation", "Paste the SKILL.md content when prompted", "Name your skill and save — it's now available in all your conversations"]}, "gemini": {"title": "How to Install Gemini Gems", "steps": ["Open Gemini (gemini.google.com) and sign in", "Click \"Gem manager\" in the left sidebar", "Click \"New Gem\" and give it a name", "Paste the system prompt into the instructions field and save"]}}, "skills": [{"name": "Content Repurposer", "description": "Solopreneurs who create content but struggle to maximize its reach", "platform": "Claude Skill", "system_prompt": "You are Content Repurposer — a specialized AI assistant for solopreneurs.\nYour job is to take one piece of content and turn it into ready-to-post material for every major platform, so the creator gets maximum reach from minimum effort.\nHow you work:\nWhen someone pastes in a piece of content (blog post, video script, newsletter, or even rough notes), you immediately identify the core message, key insights, and best quotable moments. Then you create platform-specific posts without asking a lot of questions first — you get to work and deliver a full set. If the user hasn't told you their tone, you infer it from the source material and note your assumption at the top.\nWhat you produce for every request:\n- LinkedIn: 150-200 word post with a strong opening line (not a question), 2-3 insight-packed paragraphs, and a CTA. No hashtag spam — max 3 relevant tags.\n- Instagram: Caption under 125 words with a punchy first line that stops the scroll, a clear value statement, and a CTA. Include 8-10 hashtags in a separate block.\n- X/Twitter: Two options — a single tweet (under 240 characters) and a 3-tweet thread. Lead with the most surprising or useful point.\n- Facebook: Conversational, slightly longer post (100-150 words). Warmer tone. End with a question to drive comments.\n- Email: Subject line + 3-paragraph email under 200 words. Hook, value, CTA.\nFormatting rules:\nLabel each platform clearly. Separate sections with a divider line. Flag the tone you used (e.g., 'Tone: Direct and practical'). If the source content is thin, say so and ask for more detail before proceeding."}, {"name": "Client Email Pro", "description": "Solopreneurs who spend too long drafting client emails", "platform": "Claude Skill", "system_prompt": "You are Client Email Pro — a specialized AI assistant for solopreneurs.\nYour job is to turn rough notes, bullet points, or verbal descriptions into polished, professional client emails that get responses — without sounding like a corporate template.\nHow you work:\nThe user gives you context: what the email is about, who it's going to, and any key points to hit. You draft the email immediately. You don't ask ten clarifying questions upfront — you make reasonable assumptions, write the email, and note any assumptions at the bottom so the user can correct them if needed.\nWhat you produce for every request:\n- The main email draft (under 150 words, always)\n- A shorter alternative (under 75 words) for when brevity is better\n- 2 subject line options: one direct, one slightly more engaging\n- A one-line note on any assumptions you made\nRules you always follow:\nNo clichés. Never use 'I hope this email finds you well,' 'Please don't hesitate,' 'As per my last email,' or 'Touching base.' One clear CTA per email — never two. Active voice only. If the user's notes suggest tension or a tricky situation, acknowledge it in your draft with a tone that's firm but not cold. Keep it human.\nFormatting rules:\nPresent the main draft first, labeled clearly. Then the shorter version. Then the subject lines. Then assumptions. Use plain text — no bullet points inside the email itself unless the user specifically asks."}, {"name": "Quick Reply Assistant", "description": "Solopreneurs who spend too long crafting replies to messages", "platform": "Gemini Gem", "system_prompt": "You are Quick Reply Assistant — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners fire off fast, professional replies to emails, Slack messages, DMs, and client messages — without spending 10 minutes agonizing over the wording.\nHow you work:\nThe user pastes in the message they received (and optionally tells you the context and desired tone). You generate a ready-to-send reply immediately. If the user hasn't provided enough context to write a useful reply, ask one focused question — just one — before drafting. Match the formality level of the incoming message: if it's casual, your reply is casual; if it's formal, yours is too.\nAs a Gemini Gem, you can leverage Google integrations when helpful — for example, if the user shares a Gmail thread or a Google Doc with context, use that information to craft a more informed reply.\nWhat you produce:\n- A primary reply (concise, clear, appropriate tone)\n- A shorter version if the primary is over 60 words\n- An optional 'firmer version' if the message involves pushing back, declining, or setting a boundary\nRules you always follow:\nNo filler phrases. No unnecessary apologies. If the message requires a decision or commitment from the user that you don't have, include a placeholder in brackets like [YOUR AVAILABILITY] or [PROJECT NAME] rather than guessing. Keep it human — these are real business relationships.\nFormatting rules:\nLabel each version clearly. Keep the whole output short — this tool is built for speed. If the situation is complex enough that a quick reply isn't appropriate, say so and suggest what a better approach might be."}]}, {"title": "Continue Your AI Journey", "type": "cta", "content": "Loved These Prompts? You've only scratched the surface. The full AI Starter Kit has 50+ prompts across 8 categories — each with the same depth you've seen here, plus 'Best On' tags showing which AI tool works best for each task.", "items": [{"offer": "Get the Complete AI Starter Kit", "price": "$19", "description": "50+ expert prompts | 8 categories | Pro Tips for each | Copy-paste ready", "url": "https://www.kh-academy.com"}, {"offer": "Save 40% with the Ultimate AI Bundle", "price": "$97 for all 4 products", "description": "AI Starter Kit + AI Skills Builder + AI for Small Business + AI Automation Mastery — the complete path from beginner to automated business", "url": "https://www.kh-academy.com"}], "purchase_url": "https://kh-academy-storefront.vercel.app/#pricing", "storefront_url": "https://kh-academy-storefront.vercel.app"}]};

export const STARTER_KIT_DATA: CourseData = {"product_id": "starter-kit", "title": "AI Starter Kit", "subtitle": "50+ Essential Prompts for Claude & Gemini", "source": "ai-starter-kit.pdf", "version": "2.0 — March 2026", "pages": 25, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "Welcome to the AI Starter Kit — your shortcut to getting real results from AI tools. These aren't random prompts copied from the internet. Every prompt in this kit has been tested across Claude and Gemini to ensure it actually works.", "items": []}, {"title": "How to Use This Kit", "type": "instructions", "content": "This kit uses a layered prompting methodology: each prompt combines role assignment, structured output formatting, and explicit constraints to produce results that generic AI requests simply cannot match. What makes these prompts different is that they encode expert-level workflows — the kind of structured thinking that consultants, copywriters, and strategists use daily — into repeatable templates you can customize in seconds. Think of each prompt as a mini-framework: swap in your details, follow the pro tips to iterate, and you will consistently get outputs that feel like they came from a specialist, not a chatbot.", "items": [{"step": 1, "title": "Copy & Customize", "instruction": "Copy any prompt exactly as written, then replace the [bracketed text] with your specific details. The brackets show you exactly what to personalize."}, {"step": 2, "title": "Check the 'Best On' Tag", "instruction": "Each prompt includes a 'Best On' tag showing which AI tool gives the best results for that specific task. Start with the recommended tool for optimal output."}, {"step": 3, "title": "Use the Pro Tips", "instruction": "Try the 'Pro Tip' beneath each prompt to get even better outputs. These are power-user techniques that take your results from good to exceptional."}]}, {"title": "What's Inside", "type": "overview", "content": "50+ battle-tested prompts organized into 8 categories. 'Best On' recommendations for Claude & Gemini. Pro Tips to maximize every prompt's effectiveness. 4 advanced frameworks for power users.", "items": [{"category": "Productivity & Time Management", "count": 8, "pages": "4–6"}, {"category": "Business & Strategy", "count": 8, "pages": "7–9"}, {"category": "Writing & Communication", "count": 8, "pages": "10–12"}, {"category": "Marketing & Social Media", "count": 8, "pages": "13–15"}, {"category": "Research & Analysis", "count": 6, "pages": "16–17"}, {"category": "Learning & Personal Growth", "count": 6, "pages": "18–19"}, {"category": "Coding & Technical", "count": 6, "pages": "20–21"}, {"category": "Bonus: Advanced Frameworks", "count": 4, "pages": "22–23"}]}, {"title": "Category 01: Productivity & Time Management", "type": "prompts", "content": "8 prompts to manage your time, schedule, and decisions.", "items": [{"number": "01", "name": "The Daily Prioritizer", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as my personal productivity coach with expertise in time-management frameworks. I have [X hours] available today. Here are my tasks: [list your tasks]. Prioritize them using the Eisenhower Matrix (Urgent/Important quadrants). For each task, estimate the time required and the cognitive load (high-focus vs. low-focus).\n\nFlag anything I should delegate or drop entirely, and explain why.\n\nThen build me a time-blocked schedule with 15-minute buffer periods between deep work sessions. Place high-focus tasks during my peak energy window at [morning/afternoon].\n\nDo NOT schedule more than 3 deep work blocks in a single day.\n\nOutput the schedule as a table with columns: Time, Task, Duration, Quadrant, and Energy Level.", "best_on": ["Claude", "Gemini"], "tip": "Run this every morning. Save your task list in a note app so you can paste it instantly.", "why_it_works": "The Eisenhower Matrix forces a binary classification that eliminates the 'everything feels urgent' trap. By combining it with energy-level mapping and buffer periods, this prompt mirrors how executive coaches actually structure client days — matching task difficulty to cognitive capacity rather than just time availability.", "follow_up": "Now review this schedule. Which tasks could be batched together to reduce context-switching? If something unexpected takes an extra 30 minutes, which task gets moved to tomorrow and why?", "pro_tip": "Add your energy profile: 'I'm sharpest from 9-11am and hit a slump at 2pm.' The AI will slot your hardest tasks into peak windows."}, {"number": "02", "name": "The Meeting Summarizer", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as an executive assistant who has summarized thousands of meetings. Summarize the following meeting notes into:\n\n(1) Key decisions made — list each with who made it and any conditions attached\n\n(2) Action items — format as a table with columns: Action, Owner, Deadline, Priority\n\n(3) Open questions that need follow-up — note who should answer each\n\n(4) Unresolved disagreements or tensions that need attention\n\n(5) A 2-sentence executive summary I can share with stakeholders who were not there. Do NOT add any information that was not in the original notes. If a deadline or owner is unclear, flag it explicitly as 'TBD — needs clarification.' Here are the notes: [paste meeting notes]", "best_on": ["Claude", "Gemini"], "tip": "Record meetings with Otter.ai or your phone, transcribe, then paste here.", "why_it_works": "Structured extraction with explicit field requirements forces the model to parse raw text into discrete, actionable categories rather than producing a vague narrative summary. The 'do not add information' constraint prevents hallucination of details that were never discussed.", "follow_up": "Based on the action items above, draft a brief follow-up email I can send to all attendees within 10 minutes of the meeting ending. Keep it under 150 words.", "pro_tip": "Paste the previous meeting's summary along with the new notes and ask 'What action items from last time are still unresolved?' to create accountability chains."}, {"number": "03", "name": "The Email Drafter", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a professional communications specialist. Write a professional email to [recipient's role] at [company type] requesting [specific outcome]. Tone: direct but warm. Length: under 120 words. Structure:\n\n(1) One sentence of relevant context or connection\n\n(2) The core request stated clearly\n\n(3) One sentence addressing why this benefits them\n\n(4) A single, specific call-to-action with a proposed next step (date/time if applicable). End with a single, clear ask — not multiple options. Do NOT use the phrases 'I hope this email finds you well,' 'Just wanted to follow up,' or 'Please do not hesitate to.' Avoid any sentence that starts with 'I just.'", "best_on": ["Claude", "Gemini"], "tip": "Add 'Match this writing style: [paste a previous email you have sent]' for personalization.", "why_it_works": "The word-count constraint and banned-phrase list force concise, original writing. Specifying a single CTA prevents the common AI failure mode of offering multiple options, which paradoxically reduces response rates by creating decision fatigue for the recipient.", "follow_up": "Now write two variations: one if I do not hear back in 3 days (polite nudge), and one if I still do not hear back after 7 days (final follow-up with a deadline).", "pro_tip": "Paste 3-5 of your own sent emails and ask the AI to create a 'personal email style guide' first. Then reference that guide in every future email prompt for consistency."}, {"number": "04", "name": "The Decision Matrix", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a decision-analysis consultant. I need to decide between [Option A] and [Option B]. For each option, analyze:\n\n(1) Pros and cons — minimum 5 each, ranked by importance\n\n(2) Short-term impact (next 30 days) vs. long-term impact (next 12 months)\n\n(3) Financial implications with estimated costs and potential returns\n\n(4) Risk level (low/medium/high) with a one-sentence justification\n\n(5) Reversibility — how hard is it to undo this choice\n\n(6) What I would regret more if I did not choose it. Present the comparison as a clear table. Then give me your recommendation with three reasons. Finally, tell me the one question I should answer myself before deciding — the question only I can answer. Do NOT hedge with 'it depends' — commit to a recommendation.", "best_on": ["Claude", "Gemini"], "tip": "Add your personal constraints like budget, timeline, or values for a more tailored answer.", "why_it_works": "Forcing the AI to commit to a recommendation (rather than hedging) activates more decisive analytical reasoning. Adding the reversibility dimension and the 'regret test' mirrors how behavioral economists frame decisions, surfacing emotional factors that pure logic misses.", "follow_up": "Now steelman the option you did NOT recommend. What scenario would make it the better choice? What am I missing?", "pro_tip": "For major decisions, run this prompt three times with different 'personas': a risk-averse advisor, an aggressive growth advisor, and a mentor who knows you well. Compare the three outputs."}, {"number": "05", "name": "The Weekly Review", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a personal performance coach. Help me conduct a weekly review using an interactive format. Ask me these questions one at a time, wait for my response, then ask the next:\n\n(1) What were my top 3 accomplishments this week — and which one am I proudest of? (2) What did not go as planned, and what was the root cause? (3) What did I learn that I will apply going forward? (4) What are my top 3 priorities for next week, and what does 'done' look like for each? (5) What is one thing I should stop doing or say no to? After all answers, create a structured weekly report with sections: Wins, Lessons, Next Week Priorities (with success criteria), and One Thing to Stop. Format it so I can paste it into a journal or notes app.", "best_on": ["Claude", "Gemini"], "tip": "Schedule this for Friday afternoon. It takes 10 minutes and transforms your planning.", "why_it_works": "The interactive one-at-a-time format prevents surface-level answers by giving each question dedicated attention. Requiring 'root cause' for failures and 'success criteria' for priorities converts vague reflection into specific, actionable self-coaching.", "follow_up": "Compare this week's review to last week's. What patterns do you notice? Am I making progress on the things I said mattered, or am I drifting?", "pro_tip": "Keep a running document of all weekly reviews. After a month, paste all four into the AI and ask for a 'monthly pattern analysis' — you will see trends invisible in any single week."}, {"number": "06", "name": "The SOP Generator", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as an operations manager who specializes in process documentation. Create a detailed Standard Operating Procedure (SOP) for [task/process]. Include:\n\n(1) Purpose — why this SOP exists and what outcome it ensures\n\n(2) Scope — who should use it and when\n\n(3) Prerequisites — tools, access, or knowledge needed before starting\n\n(4) Step-by-step instructions with numbered steps — each step should be a single action, not multiple actions combined\n\n(5) Decision points — if/then branches where the process might vary\n\n(6) Common mistakes to avoid with a brief explanation of why each is a problem\n\n(7) Quality checklist to verify completion — 5-8 checkboxes\n\n(8) Estimated total time. Format it so someone with no prior experience could follow it perfectly on their first attempt. Use clear, direct language — no jargon without a definition.", "best_on": ["Claude", "Gemini"], "tip": "Use this to document everything you do repeatedly — then delegate or automate it.", "why_it_works": "Single-action steps and explicit decision branches eliminate ambiguity, the main reason SOPs fail. Adding a purpose section gives context that helps the reader make judgment calls in edge cases the SOP does not cover.", "follow_up": "Now identify which steps in this SOP could be automated or semi-automated with existing tools. For each automatable step, suggest a specific tool and describe the setup.", "pro_tip": "Have someone unfamiliar with the task follow the SOP while you watch. Every place they hesitate reveals a gap in the documentation. Paste their feedback back into the AI for a revision."}, {"number": "07", "name": "The Automation Finder", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a workflow automation specialist who has helped hundreds of small businesses reduce manual work. I spend my work time on these tasks: [list 5-10 regular tasks with approximate weekly time for each]. For each task, tell me:\n\n(1) Automation potential — fully automatable, partially automatable, or not automatable, with a one-sentence explanation\n\n(2) Recommended tool — name a specific tool (Zapier, Make, n8n, Apple Shortcuts, scripting, etc.) and describe the exact automation\n\n(3) Estimated setup time vs. ongoing time saved per week\n\n(4) Difficulty to set up (easy/medium/hard) and whether it needs technical skill\n\n(5) Dependencies — what breaks if this automation fails, and how to build in a safety check. Rank all tasks by ROI ratio (weekly time saved divided by setup effort). Do NOT recommend tools that require enterprise pricing — I am a solo operator or small team.", "best_on": ["Gemini", "Claude"], "tip": "Start with the highest-ratio task. One automation can save you 5+ hours per week.", "why_it_works": "Specifying the ROI ratio forces a quantitative comparison rather than vague 'this could help' suggestions. The dependency analysis prevents the common failure of automating something without considering what happens when the automation breaks.", "follow_up": "For the top-ranked automation, give me a step-by-step implementation guide I can follow this afternoon. Include the exact trigger, actions, and a test scenario to verify it works.", "pro_tip": "Once you automate your top 3, paste the remaining manual tasks back and ask 'Now that I have freed up X hours, which of these remaining tasks should I eliminate entirely rather than automate?'"}, {"number": "08", "name": "The Focus Session Designer", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a cognitive performance coach who specializes in deep work and flow states. Design a [X]-hour deep work session for me. I need to accomplish: [describe task]. My biggest distraction is [describe]. Create:\n\n(1) A 2-minute pre-session ritual to prime my brain for focus — include specific actions, not vague advice\n\n(2) Time blocks within the session with specific micro-goals for each block (what exactly should be completed, not just 'work on X')\n\n(3) Strategic break intervals — specify what to do during breaks (movement, hydration, etc.) and what NOT to do (no phone, no email)\n\n(4) An 'if I get stuck' protocol with three escalating strategies\n\n(5) A 3-minute closing ritual to capture progress and set up the next session. Structure this as a timeline I can print or keep on my screen. Assume I work best when [describe your focus style — music/silence, time pressure, etc.].", "best_on": ["Claude", "Gemini"], "tip": "Put your phone in another room and use this plan. You will be amazed at the output.", "why_it_works": "Micro-goals for each block create the 'small wins' dopamine loop that sustains focus. The stuck protocol prevents the most common deep-work failure: hitting a wall and defaulting to distraction instead of using a structured workaround.", "follow_up": "I completed the session. Here is what I accomplished: [describe]. Adjust the plan for tomorrow based on what worked and what did not.", "pro_tip": "Create a 'focus session library' — save your best session designs for different task types (writing, coding, planning) and reuse the structure that consistently produces your best output."}]}, {"title": "Category 02: Business & Strategy", "type": "prompts", "content": "8 prompts for business analysis, strategy, and planning.", "items": [{"number": "09", "name": "The Business Idea Validator", "category": "BUSINESS & STRATEGY", "prompt": "I have a business idea: [describe idea in 2-3 sentences]. Act as a brutally honest venture capitalist who has reviewed over 1,000 pitches. Analyze:\n\n(1) The 5 biggest risks of failure — ranked from most to least likely, with a probability estimate for each\n\n(2) The ideal customer avatar — demographics, psychographics, and where to find them\n\n(3) Market size — estimate the TAM, SAM, and SOM with your reasoning\n\n(4) Competitive landscape — name 3 existing competitors, their strengths, and how this idea specifically differs\n\n(5) Critical assumptions — what needs to be true for this to succeed\n\n(6) A minimum viable test I could run this week for under $100 to validate demand — be extremely specific about steps. Do NOT sugarcoat. I need honest, direct feedback. End with a final verdict: invest, pass, or conditional invest (and what condition must be met).", "best_on": ["Claude", "Gemini"], "tip": "Do not defend your idea — let the AI poke holes. Better to find problems now than after investing.", "why_it_works": "The VC persona activates pattern-matching against common startup failure modes. Requiring probability estimates and a final verdict forces the model beyond generic 'pros and cons' into concrete risk assessment, which is more useful for actual decision-making.", "follow_up": "Assume I ran the validation test and got [describe result]. Does this change your assessment? What should my next move be — and what is the one metric I should obsess over for the next 30 days?", "pro_tip": "Run this prompt three times with different VC personas: a conservative investor, an aggressive growth investor, and a domain expert in your industry. The overlap in their concerns reveals your true risks."}, {"number": "10", "name": "The Elevator Pitch Crafter", "category": "BUSINESS & STRATEGY", "prompt": "Act as a pitch coach who has helped founders raise over $50M in funding. Help me create a 30-second elevator pitch for my [business/product/service]. It must cover: what it does, who it is for, why it is different, and a memorable hook. My audience is [describe who you are pitching to]. Create 3 versions:\n\n(1) Formal — investor meeting, structured around problem-solution-traction\n\n(2) Casual — networking event, conversational and story-driven\n\n(3) One-liner — when someone asks 'what do you do?' (under 15 words). For each version, highlight the single most compelling data point or proof of traction. Do NOT use buzzwords like 'disruptive,' 'revolutionary,' or 'game-changing.' End each pitch with a question or hook that invites follow-up conversation.", "best_on": ["Claude", "Gemini"], "tip": "Practice the one-liner version until it feels natural. That is your most-used version.", "why_it_works": "Creating three versions at different formality levels forces the model to distill the core value proposition from multiple angles. Banning buzzwords eliminates the generic filler that makes pitches forgettable, while ending with a hook ensures the conversation continues.", "follow_up": "Now act as a skeptical investor hearing each pitch. What is the first question or objection you would have for each version? Write a prepared response for each objection.", "pro_tip": "Record yourself delivering all three versions. The one you stumble on least is the one closest to how you naturally talk — lead with that version and refine the others to match its energy."}, {"number": "11", "name": "The SWOT Analyzer", "category": "BUSINESS & STRATEGY", "prompt": "Act as a senior strategy consultant at a top-tier firm. Conduct a comprehensive SWOT analysis for [business/product/project]. Context about my business: [2-3 sentences about current state, size, market]. For each quadrant (Strengths, Weaknesses, Opportunities, Threats), provide at least 5 specific, actionable items — not vague generalities. Each item must include: the factor itself, why it matters, and one concrete action to take. Then create a 2x2 action matrix:\n\n(1) Leverage — use Strengths to capture Opportunities\n\n(2) Defend — use Strengths to counter Threats\n\n(3) Improve — fix Weaknesses to capture Opportunities\n\n(4) Mitigate — fix Weaknesses to avoid Threats. For the action matrix, provide specific next steps with a priority ranking (high/medium/low) and a time horizon (this week, this month, this quarter). Do NOT include generic items like 'strong brand' or 'market competition' unless you explain specifically why they apply here.", "best_on": ["Claude", "Gemini"], "tip": "Share this with your team and ask what they would add. AI gives you 80% — your team adds the nuance.", "why_it_works": "Requiring a concrete action for each SWOT item transforms the analysis from a static assessment into a dynamic action plan. The 2x2 matrix forces cross-referencing that reveals non-obvious strategic moves most people miss when they treat each quadrant in isolation.", "follow_up": "Based on this analysis, what are the top 3 strategic moves I should make in the next 90 days? For each, outline the resources needed, the expected outcome, and how I will measure success.", "pro_tip": "Run this analysis quarterly and compare results side by side. The items that persist across quarters without being resolved are your structural issues — they need a fundamentally different approach, not just more effort."}, {"number": "12", "name": "The Customer Persona Builder", "category": "BUSINESS & STRATEGY", "prompt": "Act as a market research specialist with deep expertise in consumer psychology. Build a detailed customer persona for my [product/service] which solves [problem] for [broad audience description]. Include:\n\n(1) Demographics — age range, income bracket, location type, job title or industry, education level\n\n(2) Psychographics — core values (top 3), deepest fears related to this problem, aspirations, how they define success\n\n(3) Daily routine — specifically the moments where my product would fit in\n\n(4) Current solution — what they do now to solve this problem and why it falls short\n\n(5) Information diet — where they consume content, who they trust, what podcasts or accounts they follow\n\n(6) Purchase triggers — what would make them say 'I need this right now,' (7) Purchase blockers — what would make them say 'not for me,' (8) Exact language — 5 sentences they would use to describe their problem to a friend, written in first person. Give this persona a name and make it feel like a real person. Do NOT make it an idealized customer — include at least one frustrating trait or objection.", "best_on": ["Claude", "Gemini"], "tip": "Item 8 is gold — use those exact words in your marketing copy.", "why_it_works": "Including a frustrating trait or objection prevents the common 'ideal customer' fantasy that leads to messaging no real person resonates with. The 'exact language' requirement forces the model to generate authentic, colloquial phrasing that you can use directly in ads and copy.", "follow_up": "Now build a second persona that represents a buyer who looks different on the surface but has the same core problem. How should my messaging shift to reach both personas without alienating either?", "pro_tip": "Validate the persona by searching social media, forums, and review sites for people who match this profile. Paste real quotes you find back into the AI and ask 'How should I update this persona based on what real people are actually saying?'"}, {"number": "13", "name": "The Pricing Strategist", "category": "BUSINESS & STRATEGY", "prompt": "Act as a pricing strategy consultant who has worked with both startups and established businesses. Help me price my [product/service]. Here is what I know: it costs me [cost] to deliver, competitors charge [range], my target customer is [description], and the main value I provide is [value]. Analyze three pricing strategies:\n\n(1) Cost-plus pricing — show the math, typical markup percentages for my industry, and the resulting price\n\n(2) Value-based pricing — estimate the monetary value of the outcome I deliver, then price at 10-20% of that value\n\n(3) Competitor-based pricing — position relative to the market with a specific rationale. For each strategy, give me a specific price point and explain the psychological anchoring behind it. Then recommend which strategy fits my situation and why. Include a pricing page structure: what tiers to offer, what to name them, what to include in each, and which tier to make the 'default' choice. Do NOT recommend 'free tier' unless I specifically have a freemium model.", "best_on": ["Claude", "Gemini"], "tip": "Most people underprice. Ask the AI 'what would a premium version look like at 3x this price?'", "why_it_works": "Analyzing three strategies side-by-side with specific numbers prevents the common mistake of defaulting to competitor-based pricing. The psychological anchoring explanation helps you understand why certain price points feel right to buyers, which is critical for premium positioning.", "follow_up": "A potential customer says 'That is too expensive.' Write me three different responses based on different objection-handling frameworks: value reframing, comparison anchoring, and risk reversal.", "pro_tip": "Create a 'pricing experiment plan' — test two price points with equal traffic for 2 weeks. Ask the AI to design a statistically valid A/B test for your pricing page, including sample size needed for significance."}, {"number": "14", "name": "The 90-Day Action Plan", "category": "BUSINESS & STRATEGY", "prompt": "Act as a business strategist who specializes in rapid execution planning. Create a 90-day action plan for [business goal]. My current situation: [describe where you are now]. My resources: [time/money/team available]. Break the plan into three 30-day sprints, each building on the previous one. For each sprint, provide:\n\n(1) The theme — one sentence describing the focus of this sprint\n\n(2) The one key metric to track with a specific target number\n\n(3) Weekly action items — 3-5 specific tasks per week with clear deliverables (not just 'work on marketing')\n\n(4) Resources or tools needed with estimated costs\n\n(5) A milestone that proves progress — something tangible I can point to\n\n(6) Risk assessment — what could go wrong and a specific course-correction plan. End with a 'pre-mortem': assume the plan failed at Day 90. What were the three most likely causes of failure? What can I do now to prevent each one? Do NOT include any action item that takes more than 4 hours of focused work.", "best_on": ["Claude", "Gemini"], "tip": "Print this out and put it on your wall. Review weekly. Adjust monthly.", "why_it_works": "The sprint structure with escalating themes prevents the 'everything at once' paralysis that kills most 90-day plans. Capping individual tasks at 4 hours ensures every item is actually doable by one person. The pre-mortem technique is borrowed from military planning and dramatically improves plan survival rates.", "follow_up": "It is Day 30. I completed [describe what you actually did]. Update the remaining 60 days based on what I learned. What should I double down on, and what should I drop?", "pro_tip": "At the start of each sprint, paste the plan back to the AI with your progress notes and ask for a 'sprint retrospective and adjustment.' This creates an adaptive plan that improves as you learn."}, {"number": "15", "name": "The Revenue Model Calculator", "category": "BUSINESS & STRATEGY", "prompt": "Act as a financial analyst building a revenue model for an early-stage business. Help me build a revenue model for [business]. My current revenue (if any): [amount]. My main offering: [describe]. Price point: [current or planned]. For each revenue stream, model:\n\n(1) All possible revenue streams including primary, secondary, and passive income\n\n(2) For each stream, project monthly revenue at months 1, 3, 6, and 12\n\n(3) Key assumptions behind each projection — stated explicitly so I can challenge them\n\n(4) Customer acquisition cost estimate and customer lifetime value for each stream\n\n(5) Fixed costs vs. variable costs breakdown\n\n(6) Break-even analysis — units sold and months to break-even. Present the core model as a table. Then run three scenarios: conservative (50% of projections), realistic (your projections), and optimistic (150% of projections). For each scenario, state when I break even. Do NOT inflate projections — be skeptical of hockey-stick growth. Assume organic growth unless I specify a paid acquisition budget.", "best_on": ["Claude", "Gemini"], "tip": "Run this with optimistic, realistic, and pessimistic scenarios separately to see the full range.", "why_it_works": "Forcing explicit assumptions and three scenarios prevents the optimism bias that kills most financial projections. The CAC and LTV requirements introduce unit economics thinking early, which many founders skip until it is too late.", "follow_up": "Based on the realistic scenario, what is the single highest-leverage action I can take to accelerate the timeline to break-even? Model what happens if I increase [price/volume/retention] by 20%.", "pro_tip": "Update this model monthly with real numbers. Paste the updated actuals back and ask 'Which assumptions were wrong? Recalculate the projections based on what actually happened.' Your model gets smarter every month."}, {"number": "16", "name": "The Competitor Spy", "category": "BUSINESS & STRATEGY", "prompt": "Act as a competitive intelligence analyst. Analyze [competitor name/URL] in the context of my business: [brief description of your business]. Tell me:\n\n(1) Their apparent target audience — who are they really selling to, based on their messaging, pricing, and content\n\n(2) Their pricing strategy and positioning on the value-to-price spectrum\n\n(3) Their content and marketing strategy — what channels they invest in and what messaging angles they use\n\n(4) Their top 3 strengths I should respect and not try to compete on directly\n\n(5) Their top 3 weaknesses I can exploit — be specific about how\n\n(6) Customer sentiment — what patterns appear in their reviews, testimonials, and social mentions (both positive and negative)\n\n(7) 3 specific tactical moves I can make to differentiate from them. Do NOT give me generic competitive analysis. Every point must be specific to this competitor and actionable for my business.", "best_on": ["Gemini", "Claude"], "tip": "Do this for your top 3 competitors. The patterns you will see across all three are invaluable.", "why_it_works": "Requiring specificity at every level prevents the generic SWOT-style analysis that adds no strategic value. The 'do not compete on their strengths' instruction embodies the military principle of asymmetric advantage — winning by changing the game rather than playing the same one better.", "follow_up": "Now analyze what this competitor will likely do in the next 6-12 months based on their current trajectory. How should I position myself now to be ahead of their next move?", "pro_tip": "Use Gemini for this prompt since it can access current web data. Then paste Gemini's output into Claude and ask 'What strategic implications does this competitive analysis have for my business? What is the one move that would hurt this competitor the most?'"}]}, {"title": "Category 03: Writing & Communication", "type": "prompts", "content": "8 prompts for writing, editing, and communication tasks.", "items": [{"number": "17", "name": "The Blog Post Generator", "category": "WRITING & COMMUNICATION", "prompt": "Act as a senior content strategist who writes for top-tier publications. Write a 1,000-word blog post about [topic]. Target audience: [who]. Goal: [inform/persuade/entertain]. Structure requirements:\n\n(1) Hook opening — the first two sentences must create curiosity or challenge a common belief, no generic introductions\n\n(2) 3-5 subheadings organized as a logical progression, not random sections\n\n(3) Each section must include at least one specific example, data point, or mini-story\n\n(4) Include a 'contrarian take' or surprising perspective somewhere in the piece\n\n(5) Conclusion with a clear call-to-action that connects back to the hook. Tone: [conversational/professional/authoritative]. Do NOT use these phrases: 'In today's fast-paced world,' 'It's no secret that,' 'At the end of the day,' 'game-changer,' 'dive deep,' 'leverage,' or 'landscape.' Avoid starting more than one paragraph with 'The.' Write for scanning — use short paragraphs (2-3 sentences max) and bold key phrases.", "best_on": ["Claude", "Gemini"], "tip": "Always add 'Do NOT use' instructions. It prevents the AI-sounding cliches that readers immediately recognize.", "why_it_works": "The banned-phrase list and structural constraints (hook-first, contrarian take, scan-friendly formatting) force the AI out of its default template mode and into genuinely structured writing. Requiring specific examples in every section prevents the vague generalities that make AI-written content feel hollow.", "follow_up": "Now review this post as a strict editor. Cut any section that does not earn its place. Flag any claim that needs a source. Tighten the prose by 15% without losing substance.", "pro_tip": "Generate the blog post, then paste it back and ask: 'Rewrite the opening three different ways: start with a question, start with a surprising statistic, and start with a micro-story.' Pick the strongest hook."}, {"number": "18", "name": "The Rewriter", "category": "WRITING & COMMUNICATION", "prompt": "Act as a professional editor with 15 years of experience at a major publication. Rewrite the following text to be [shorter/more engaging/simpler/more professional]. Rules:\n\n(1) Keep the core meaning and key arguments intact\n\n(2) Make it sound like a human expert wrote it — not AI\n\n(3) Remove all filler words, passive voice, and unnecessary qualifiers ('very,' 'really,' 'just,' 'quite,' 'basically')\n\n(4) If the original is over 200 words, cut it by at least 30%\n\n(5) Improve sentence variety — mix short punchy sentences with longer ones\n\n(6) Replace any cliche with a specific, concrete phrase. Show me the rewritten version, then list the 3 most impactful changes you made and why each improves the text. Here is the text: [paste text]", "best_on": ["Claude"], "tip": "Claude is the best rewriter. It preserves your voice while tightening the prose.", "why_it_works": "The explicit editing checklist mirrors what professional editors actually do: remove filler first, fix voice and structure second, then polish. Requiring the AI to explain its changes teaches you editing skills you can apply to all future writing.", "follow_up": "Now take this rewritten version and create three variations: one for a LinkedIn audience, one for an email, and one for a presentation slide. Same content, different format and density.", "pro_tip": "Keep a personal 'banned words' list — words you overuse or that sound like AI. Add it to every rewriting prompt to make the output increasingly personalized over time."}, {"number": "19", "name": "The LinkedIn Post Creator", "category": "WRITING & COMMUNICATION", "prompt": "Act as a LinkedIn content creator with a track record of high-engagement posts. Write a LinkedIn post about [topic/experience/insight]. Structure:\n\n(1) Hook line — must be a pattern interrupt, bold statement, or counterintuitive claim that stops the scroll. No questions as hooks (they underperform)\n\n(2) Short paragraphs of 1-2 sentences each with line breaks between them\n\n(3) Include a personal story, specific example, or real data — no abstract advice\n\n(4) Build to one clear, memorable insight or takeaway\n\n(5) End with an open-ended question that invites genuine discussion (not 'agree or disagree?'). Length: 150-200 words. Tone: confident but not preachy — write as someone sharing hard-won experience, not lecturing. Do NOT use hashtags in the body — add 3-5 relevant ones at the very end. Do NOT use emojis as bullet points. Do NOT start with 'I'm excited to share' or 'I recently learned.'", "best_on": ["Claude", "Gemini"], "tip": "The hook line determines 80% of your engagement. Ask for 5 hook variations and pick the best.", "why_it_works": "The formatting rules (short paragraphs, line breaks, no emoji bullets) are reverse-engineered from LinkedIn's algorithm and reading patterns on mobile, where most LinkedIn consumption happens. Banning common openers forces originality in the most important real estate of the post.", "follow_up": "Generate 5 alternative hook lines for this post, each using a different technique: surprising statistic, contrarian opinion, personal failure, bold prediction, and 'I was wrong about' confession. Which would perform best and why?", "pro_tip": "Write 5 posts in a batch using this prompt. Schedule them across the week. Consistent posting matters more than any single viral post — the algorithm rewards reliability."}, {"number": "20", "name": "The Tone Matcher", "category": "WRITING & COMMUNICATION", "prompt": "Act as a linguistic analyst who specializes in personal writing styles. Analyze my writing style from these samples: [paste 2-3 paragraphs you have written]. Produce a detailed 'Writing Style Guide' that includes:\n\n(1) Average sentence length and range\n\n(2) Vocabulary level (simple/moderate/advanced) with examples of my characteristic word choices\n\n(3) Tone profile — formality level, warmth, humor, directness (rate each on a 1-10 scale)\n\n(4) Structural patterns — how I open paragraphs, how I transition between ideas, how I close\n\n(5) Signature phrases or verbal tics I use frequently\n\n(6) What I never do — patterns that are absent from my writing\n\n(7) A one-paragraph 'writing persona summary' I can paste into any prompt. Format this as a reference document I can reuse. Test your analysis by writing a new paragraph about a random topic in my voice, then explain which specific style elements you applied.", "best_on": ["Claude"], "tip": "Save the output and paste it at the start of any writing prompt: 'Match this writing style: [paste guide]'", "why_it_works": "Quantifying style elements (sentence length, formality scores) gives the AI concrete parameters to match, rather than vague instructions like 'write in my voice.' The test paragraph proves the analysis works and lets you calibrate before using it for real content.", "follow_up": "Now write three short pieces in my voice: a product announcement, a response to a negative review, and a thank-you note to a customer. Each should sound unmistakably like me.", "pro_tip": "Update your style guide every few months as your writing evolves. Paste your latest writing alongside the old guide and ask 'How has my writing style changed? Update the guide to match my current voice.'"}, {"number": "21", "name": "The Email Sequence Builder", "category": "WRITING & COMMUNICATION", "prompt": "Act as an email marketing strategist who has built sequences with 40%+ open rates. Create a [3/5/7]-email sequence for [purpose: welcome series, product launch, re-engagement, etc.]. Target audience: [describe]. The sequence should build progressively toward [goal]. For each email, provide:\n\n(1) Subject line — under 50 characters, tested psychological trigger identified (curiosity, urgency, benefit, social proof)\n\n(2) Preview text — the hidden second line that appears in inbox\n\n(3) Full email body — conversational, scannable, one core idea per email\n\n(4) Specific call-to-action — only ONE per email, phrased as a button\n\n(5) Send timing — days between emails with rationale\n\n(6) Segmentation trigger — what the reader must have done (or not done) to receive this email. The sequence must tell a story across all emails — not feel like disconnected messages. Each email should deliver standalone value even if the reader does not click. Do NOT use more than one exclamation mark per email.", "best_on": ["Claude", "Gemini"], "tip": "Email subject lines make or break open rates. Ask for 5 subject line options per email.", "why_it_works": "The segmentation triggers transform a generic blast sequence into a behavior-responsive flow. Requiring standalone value in each email follows the principle of reciprocity — the reader gets something before being asked to do something, which dramatically improves conversion.", "follow_up": "Now write the 'did not open' branch: for each email, create a follow-up with a different subject line and angle that goes to anyone who did not open the original within 48 hours.", "pro_tip": "After sending the sequence, paste your open rates and click rates back into the AI. Ask 'Based on these metrics, which emails are underperforming? Rewrite only the underperforming subject lines and CTAs.'"}, {"number": "22", "name": "The Press Release Writer", "category": "WRITING & COMMUNICATION", "prompt": "Act as a PR specialist who has placed stories in major media outlets. Write a press release for [announcement]. Follow AP style guidelines. Structure:\n\n(1) Compelling headline — not your company name, but the story (what makes this newsworthy?)\n\n(2) Subheadline with the key data point or hook\n\n(3) Dateline and strong opening paragraph covering who/what/when/where/why in the first three sentences\n\n(4) Second paragraph with the most compelling quote from a company leader — make it sound human, not corporate\n\n(5) 2-3 supporting paragraphs with context, data, and a customer or partner quote\n\n(6) Boilerplate 'About [Company]' paragraph (placeholder)\n\n(7) Media contact info placeholder. Length: 400-500 words. The release must answer the journalist's question: 'Why should my readers care about this?' within the first 50 words. Do NOT use the words 'excited,' 'thrilled,' 'pleased to announce,' or 'industry-leading.'", "best_on": ["Claude", "Gemini"], "tip": "The headline and first paragraph are all most journalists read. Make them count.", "why_it_works": "Banning corporate cliches and requiring the 'why should readers care' answer upfront forces a newsworthy framing rather than a company announcement framing. Journalists discard 95% of press releases — the ones that survive lead with the story, not the company.", "follow_up": "Now write a media pitch email to accompany this press release — the email a PR person would send to a specific journalist. Under 100 words, personalized angle, explain why their specific audience would care.", "pro_tip": "Write the press release, then ask 'What is the real story here that a journalist would actually want to cover? Reframe the entire release around that angle.' Often the real story is not what you think it is."}, {"number": "23", "name": "The Script Writer", "category": "WRITING & COMMUNICATION", "prompt": "Act as a professional video scriptwriter who creates content for [platform: YouTube, TikTok, Instagram Reel, etc.]. Write a [length]-minute script about [topic]. My audience is [describe]. The goal is [educate/entertain/sell]. Script requirements:\n\n(1) Hook in the first 3 seconds — must create a 'pattern interrupt' that stops the scroll. Write three hook options\n\n(2) Visual and action cues in [brackets] throughout — every 15-30 seconds should have a visual change\n\n(3) Conversational tone — write for speaking, not reading. Use contractions. Short sentences. Fragments are fine\n\n(4) 'Open loop' at the 30% mark — tease something coming later to prevent drop-off\n\n(5) Clear CTA at the end — specific and single action\n\n(6) Retention markers — note where viewers are most likely to drop off and include a re-engagement technique at each point. Include estimated timestamps. The script should feel like talking to a smart friend, not presenting to an audience.", "best_on": ["Claude", "Gemini"], "tip": "Read the script aloud. If you stumble on any phrase, it is not natural enough — ask AI to simplify.", "why_it_works": "The retention markers and open loops are techniques used by top content creators to maintain watch time, which is the primary signal every platform algorithm uses for distribution. Visual change cues every 15-30 seconds match the average attention span data from platform analytics.", "follow_up": "Now create a thumbnail concept and title for this video. Give me 5 title options using different psychological triggers and describe what the thumbnail should show, including text overlay and color palette.", "pro_tip": "Record yourself delivering the script 'off-book' — just from memory of the key points. Your natural delivery is always better than reading. Then transcribe your natural version and use that as the final script."}, {"number": "24", "name": "The Proposal Template", "category": "WRITING & COMMUNICATION", "prompt": "Act as a business development consultant who has helped close deals worth over $1M. Create a professional [business/project/freelance] proposal for [client/project description]. My qualifications: [brief background]. Structure:\n\n(1) Executive summary — 3 sentences max, leading with the client's problem and desired outcome\n\n(2) Problem statement — describe what the client is facing using THEIR language, showing you deeply understand their situation\n\n(3) Proposed solution with specific deliverables — each deliverable includes what it is, why it matters, and the timeline\n\n(4) Process and timeline with milestones — a clear visual timeline the client can scan in 10 seconds\n\n(5) Investment section — frame pricing around value/ROI, not cost. Include payment terms\n\n(6) Why choose us — 3 proof points (results, testimonials, relevant experience), not a generic company bio\n\n(7) Risk mitigation — address the client's unspoken fear of 'what if this does not work,' (8) Next steps — exactly one action for the client to take. Tone: professional and confident, never desperate. Length: 2-3 pages. Do NOT include generic phrases like 'we are passionate about' or 'our team of dedicated professionals.'", "best_on": ["Claude", "Gemini"], "tip": "Customize the problem statement with specific details about the client. Generic proposals lose deals.", "why_it_works": "Starting with the client's problem instead of your company's story flips the standard proposal structure. The risk mitigation section addresses the buyer's deepest unspoken objection — 'what if I waste my money' — which most proposals ignore entirely, leaving it as an invisible deal-killer.", "follow_up": "Now create a one-page 'proposal summary' version I can send as an email. It should hit the same key points but be scannable in under 60 seconds. Include a subject line.", "pro_tip": "Before writing the proposal, ask the AI: 'What are the top 5 concerns a [client type] would have about hiring someone for [project type]?' Then make sure your proposal addresses every single one — explicitly or implicitly."}]}, {"title": "Category 04: Marketing & Social Media", "type": "prompts", "content": "8 prompts for marketing, social media, and content creation.", "items": [{"number": "25", "name": "The Content Calendar Generator", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a social media strategist managing accounts with 50K+ followers. Create a 30-day social media content calendar for [business/brand] on [platforms]. My content pillars are: [list 3-4 topics]. For each day, provide:\n\n(1) Post topic/theme with a specific angle — not just 'post about X' but the exact angle and hook\n\n(2) Content type (carousel, video, story, reel, text post) with rationale for why this type fits this topic\n\n(3) Caption with a scroll-stopping hook and clear CTA\n\n(4) Best posting time based on platform best practices for [my audience's timezone]\n\n(5) 5-10 relevant hashtags per post mixing high-volume and niche. Content mix: 40% educational (teach something valuable), 30% engaging (spark conversation or emotion), 20% promotional (sell or convert), 10% behind-the-scenes (build trust and relatability). Include 2 'tentpole' posts per week designed for maximum shareability. Do NOT repeat the same content type more than twice consecutively.", "best_on": ["Gemini", "Claude"], "tip": "Batch-create a month's content in one sitting using this calendar as your roadmap.", "why_it_works": "The 40/30/20/10 content mix ratio is based on engagement data from high-performing social accounts. Preventing consecutive repeat content types ensures visual variety in the feed, which is critical for both algorithm performance and follower retention.", "follow_up": "Now pick the 5 strongest posts from this calendar and expand each into a full content brief: the complete caption, visual description for the designer, any text overlays, and 3 comment responses I should have ready for likely reactions.", "pro_tip": "At the end of each month, paste your top 5 and bottom 5 performing posts from this calendar back into the AI. Ask 'What patterns separate the winners from the losers? Adjust next month's calendar based on these insights.'"}, {"number": "26", "name": "The Ad Copy Writer", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a direct-response copywriter who has managed ad campaigns with 3x+ ROAS. Write [Facebook/Google/Instagram] ad copy for [product/service]. Target audience: [describe — demographics, pain points, current situation]. Pain point this ad addresses: [describe specifically]. Create a complete ad set:\n\n(1) 3 headline variations — under 30 characters each, each using a different psychological trigger (curiosity, benefit, social proof)\n\n(2) 3 primary text variations — Version A: emotional/story-driven appeal, Version B: logical/data-driven appeal, Version C: curiosity-driven/open-loop appeal. Each under 125 words\n\n(3) Description text for the link preview\n\n(4) Call-to-action button recommendation with rationale\n\n(5) Audience targeting suggestions — 3 interest-based targeting ideas. For all copy: lead with the transformation, not the product. Use 'you' more than 'we.' Do NOT use false scarcity or misleading claims. Do NOT use all-caps words.", "best_on": ["Claude", "Gemini"], "tip": "Always test at least 3 variations. The AI can generate them — let your audience pick the winner.", "why_it_works": "Creating three distinct psychological angles (emotional, logical, curiosity) lets you test which resonance pattern works best for your specific audience. Leading with transformation instead of product features activates the buyer's imagination, which is the first step in any purchase decision.", "follow_up": "Now write the landing page headline and first paragraph that each ad variation should link to. The message match between ad and landing page is the single biggest factor in conversion rate.", "pro_tip": "Write the ad copy, then ask: 'Now write the negative version — an ad targeting people who FAILED at solving this problem with a competitor's solution. Use their frustration as the hook.' Negative framing often outperforms positive framing in paid ads."}, {"number": "27", "name": "The SEO Article Planner", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as an SEO content strategist who has ranked articles on the first page for competitive keywords. Create an SEO content plan for the keyword [target keyword]. My website is about [topic/niche]. Current domain authority: [if known, or 'new site']. Provide:\n\n(1) Search intent analysis — is the searcher looking to learn, compare, buy, or solve a problem? Support your answer with evidence\n\n(2) Suggested article title — include the keyword naturally, under 60 characters, compelling enough to click over the 9 other results on page one\n\n(3) Meta description — exactly 155 characters, includes keyword and a reason to click\n\n(4) Complete heading structure — H1, H2s, and H3s that cover the topic thoroughly and target related keywords\n\n(5) 10 semantically related keywords to include naturally throughout the content\n\n(6) Content gap analysis — what are the top 3 ranking articles missing that mine should include\n\n(7) Recommended content length based on what currently ranks\n\n(8) 3 internal linking opportunities and 3 authoritative external link suggestions. Do NOT keyword-stuff. The content plan should prioritize genuine usefulness over SEO tricks.", "best_on": ["Gemini", "Claude"], "tip": "Gemini has the most current web data. Use it for keyword research, then write the actual article with Claude.", "why_it_works": "The content gap analysis — identifying what top-ranking articles miss — is how experienced SEOs find opportunities in competitive niches. Prioritizing usefulness over SEO tricks aligns with modern search algorithms that reward user satisfaction signals.", "follow_up": "Now write the introduction and first H2 section of this article. Make the intro hook strong enough that a reader who landed from Google would not hit the back button within 5 seconds.", "pro_tip": "Use Gemini to find 'People Also Ask' questions for your keyword. Paste those questions back and ask 'Add an FAQ section to the content plan that directly answers each of these questions.' Google frequently pulls FAQ answers into featured snippets."}, {"number": "28", "name": "The Landing Page Copy", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a conversion rate optimization specialist who has written landing pages with 10%+ conversion rates. Write landing page copy for [product/service]. Conversion goal: [purchase/signup/book a call]. Target audience: [describe — who they are, what they have tried before, what they fear]. Structure:\n\n(1) Hero section — headline (under 10 words, benefit-driven), subheadline (one sentence expanding the promise), CTA button text\n\n(2) Problem section — describe 3 specific pain points using the customer's own language, not clinical descriptions\n\n(3) Solution section — how the product solves each pain point, mapped one-to-one\n\n(4) Features-to-benefits translation — 3-5 features, each with 'So that you can...' benefit statement\n\n(5) Social proof section — structure for testimonials (what format, what they should emphasize)\n\n(6) Objection handling — FAQ with the 5 questions buyers silently ask before purchasing\n\n(7) Final CTA section with urgency element and risk reversal (guarantee or safety net). Every section should have a micro-CTA or visual cue pointing toward the main action. Do NOT use 'Welcome to our website' or feature-only descriptions without benefits.", "best_on": ["Claude", "Gemini"], "tip": "The best landing pages follow the formula: Problem, Agitate, Solution, Proof, CTA.", "why_it_works": "The one-to-one mapping between pain points and solutions creates a logical inevitability in the reader's mind. Addressing silent objections in the FAQ preempts the buyer's internal resistance, which is the primary reason visitors leave without converting.", "follow_up": "Now write the above-the-fold A/B test variant: same page, but with a completely different headline angle. Version A leads with the benefit. Version B leads with the pain. Explain which you would test first and why.", "pro_tip": "After writing the copy, ask: 'Read this landing page as a skeptical visitor who has been burned before. What would still make you hesitate? Add a section that addresses that final objection.' This usually reveals the one thing keeping your conversion rate from doubling."}, {"number": "29", "name": "The Hashtag Strategist", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a social media growth strategist who specializes in organic reach optimization. Generate a comprehensive hashtag strategy for my [niche/industry] content on [Instagram/TikTok/LinkedIn]. My content is about [describe your content topics]. My current follower count: [approximate]. Provide:\n\n(1) 10 high-volume hashtags (1M+ posts) — use these sparingly for visibility\n\n(2) 10 medium-volume hashtags (100K-1M posts) — your bread and butter for discoverability\n\n(3) 10 niche/low-competition hashtags (under 100K posts) — where you can actually rank on the hashtag page\n\n(4) 5 branded hashtag suggestions — short, memorable, ownable, and not already in heavy use\n\n(5) Recommended hashtag sets — 3 pre-built combinations of 10 hashtags each (one for each content pillar). For each set, explain the strategy: are you going for reach, community, or discoverability? Include which hashtags to put in the caption vs. in comments (platform-specific). Do NOT suggest banned, shadow-banned, or spam-associated hashtags.", "best_on": ["Gemini", "Claude"], "tip": "Use 3 large + 4 medium + 3 niche hashtags per post. This balances reach with discoverability.", "why_it_works": "The tiered volume approach matches how platform algorithms categorize content — niche hashtags give you quick ranking wins that signal relevance to the algorithm, which then serves your content to broader audiences through the medium and high-volume tags.", "follow_up": "Now audit my current hashtag usage: [paste your last 5 post hashtags]. Which ones are helping, which are wasted, and what should I replace them with?", "pro_tip": "Create a rotating hashtag library — 5 sets of 10 hashtags each. Rotate them across posts to avoid the 'same hashtags every time' penalty that Instagram's algorithm now detects. Use a spreadsheet or notes app to track which set is next."}, {"number": "30", "name": "The Product Description Writer", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a senior e-commerce copywriter who has written for brands with 7-figure revenue. Write 3 product descriptions for [product name]. Target customer: [describe their situation and desire]. Key differentiator: [what makes this unique]. Price point: [price].\n\nDescription 1: Benefit-focused — lead with the transformation or outcome, paint a picture of life after purchase, 80-150 words.\n\nDescription 2: Feature-focused — specs, details, and materials translated into 'this means you get...' benefit statements, 80-150 words. Description 3: Story-driven — open with a mini-scenario the reader recognizes, introduce the product as the solution, 80-150 words. Each description must: use sensory language, include a strong CTA, address one common objection, and end with a reason to buy now (not fake urgency). Do NOT use superlatives like 'best,' 'perfect,' or 'ultimate' without a specific supporting claim.", "best_on": ["Claude", "Gemini"], "tip": "A/B test all three on your product page. Story-driven descriptions often convert 20-30% better.", "why_it_works": "Three distinct approaches let you test which communication style resonates with your specific buyer. Banning unsupported superlatives forces specificity, which builds more trust than generic enthusiasm. Addressing an objection within the description preempts the hesitation that causes cart abandonment.", "follow_up": "Now write the complete product page copy: combine the strongest elements from all three descriptions into one cohesive product page with headline, subheadline, bullet points, and CTA. Add a 'who this is for' and 'who this is NOT for' section.", "pro_tip": "Ask the AI to write the description from the perspective of a happy customer writing a 5-star review. Often the most persuasive product copy reads like a testimonial, not like marketing."}, {"number": "31", "name": "The Audience Pain Point Finder", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a consumer psychologist who specializes in buyer motivation research. My product/service helps with [problem/category]. My target audience is [describe]. List the top 15 pain points this audience experiences related to this problem. For each pain point:\n\n(1) Describe it in the exact words the customer would use — first-person, colloquial, emotionally honest\n\n(2) Rate its emotional intensity (1-10) and explain why it scores that high\n\n(3) Identify the deeper fear or desire underneath the surface pain\n\n(4) Suggest a specific content piece (blog post, video, social post) that addresses it, with a title\n\n(5) Write a one-sentence ad hook that targets this pain point. Rank from most to least emotionally intense. Do NOT list generic problems like 'time management' — every pain point must be specific enough that the reader thinks 'that is exactly my problem.'", "best_on": ["Claude", "Gemini"], "tip": "The top 3 pain points equal your marketing headlines. Use the customer's exact words, not corporate language.", "why_it_works": "Requiring first-person customer language forces the model to think from the buyer's perspective rather than the seller's. Identifying the deeper fear underneath the surface pain reveals the emotional motivators that drive purchasing decisions — people buy to escape pain more than to gain pleasure.", "follow_up": "Now take the top 5 pain points and build a complete messaging framework: for each, write the headline, the supporting paragraph, and the specific product feature or benefit that resolves it. This becomes the foundation of all your marketing.", "pro_tip": "Validate these pain points by searching Reddit, online forums, and Amazon reviews for your product category. Paste real customer complaints back into the AI and ask 'How should I update my pain point list based on what real people are actually saying?'"}, {"number": "32", "name": "The Email Subject Line Generator", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as an email marketing specialist with deep expertise in open-rate optimization. Generate 20 email subject lines for [purpose: newsletter, product launch, abandoned cart, re-engagement, etc.]. Target audience: [describe — their situation, what they care about, their sophistication level]. Requirements:\n\n(1) All under 50 characters — shorter performs better on mobile\n\n(2) Categorize each by psychological trigger used: curiosity, urgency, benefit, personalization, social proof, or fear of missing out\n\n(3) No ALL CAPS or excessive punctuation (maximum one question mark or exclamation per line)\n\n(4) At least 4 should use specific numbers or data\n\n(5) At least 4 should ask a question\n\n(6) At least 3 should use the word 'you' or 'your,' (7) Include 3 'negative' subject lines (addressing a fear or mistake). Rate each on estimated open-rate potential (1-10) and explain your top 3 picks with reasoning. Do NOT use spam trigger words like 'free,' 'act now,' 'limited time,' or 'congratulations.'", "best_on": ["Claude", "Gemini"], "tip": "Subject lines with numbers outperform those without by 15-20%. Always test 2 subject lines per send.", "why_it_works": "Categorizing by psychological trigger creates a diverse set that tests multiple mental entry points. Including 'negative' subject lines is counter-intuitive but backed by data — emails addressing fears or mistakes consistently achieve higher open rates than purely positive framing.", "follow_up": "Now write the preview text (the first line visible in the inbox) for your top 5 subject lines. The preview text should complement the subject line, not repeat it — together they should tell a mini-story that makes opening irresistible.", "pro_tip": "Build a 'subject line swipe file' — save every subject line that makes YOU open an email. Paste your collection into the AI periodically and ask 'What patterns do I respond to? Generate 10 subject lines that use those same patterns for my business.'"}]}, {"title": "Category 05: Research & Analysis", "type": "prompts", "content": "6 prompts for research, data analysis, and trend spotting.", "items": [{"number": "33", "name": "The Research Synthesizer", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a senior research analyst at a leading consultancy. I need to quickly understand [topic/industry/trend]. Provide a structured briefing:\n\n(1) A 3-sentence summary so clear that a 10-year-old could understand the basics\n\n(2) The 5 most important facts or statistics — cite specific numbers where possible and note your confidence level in each (high/medium/low)\n\n(3) Key players and companies in this space with a one-sentence description of each player's position\n\n(4) Current state and trajectory — where things are now, where they are heading, and the 2-3 forces driving the change\n\n(5) The 3 most common misconceptions about this topic and why each is wrong\n\n(6) Contrarian view — one credible perspective that goes against the mainstream narrative\n\n(7) 5 specific sources I should read for deeper knowledge (publications, reports, or authors, not generic 'Google it' advice). Do NOT give me a textbook overview — give me the briefing I would want before walking into a meeting with experts on this topic.", "best_on": ["Gemini", "Claude"], "tip": "Gemini has the most current data. Use it for trends and stats, then deep-dive with Claude for nuanced analysis.", "why_it_works": "The 'explain it to a 10-year-old' constraint forces simplification that reveals whether you truly understand something. The contrarian view section prevents echo-chamber thinking and prepares you for pushback from well-informed skeptics.", "follow_up": "Based on this briefing, what are the 3 smartest questions I could ask an expert on this topic to signal that I have done my homework and to learn something I cannot find in public sources?", "pro_tip": "Use Gemini for the initial research (current data), then paste the output into Claude and ask 'What is this briefing missing? What nuances would a true expert add?' The combination of breadth and depth is unbeatable."}, {"number": "34", "name": "The Data Interpreter", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a data analyst presenting findings to a non-technical executive. Analyze this data and tell me what it means in plain English: [paste data/numbers/results]. Context: this data is from [describe the source and what it measures]. My goal is to [what you want to decide or understand]. Specifically provide:\n\n(1) The headline takeaway — one sentence a CEO would want to hear first\n\n(2) 3-5 patterns or trends — what the data shows when you look beyond the surface numbers\n\n(3) The most surprising or counterintuitive finding and why it matters\n\n(4) Anomalies or red flags — anything that looks off or needs investigation\n\n(5) Recommended actions — 3 specific things I should do based on this data, prioritized by impact\n\n(6) What additional data I would need to make a more confident decision — be specific about what to collect and why. Present this as a brief executive summary with bullet points. Do NOT use statistical jargon without a plain-English translation. If the data is insufficient to draw a conclusion, say so explicitly rather than speculating.", "best_on": ["Claude", "Gemini"], "tip": "Always ask 'What additional data would I need?' — it reveals blind spots in your analysis.", "why_it_works": "Starting with the headline takeaway forces the AI to prioritize signal over noise. Requiring anomaly detection and explicit uncertainty acknowledgment prevents the common AI failure mode of generating confident-sounding analysis from insufficient data.", "follow_up": "Now create a simple visualization recommendation — what type of chart or graph would best communicate the headline takeaway to my team? Describe the chart, what goes on each axis, and the key data points to highlight.", "pro_tip": "Paste the same data set with a different framing question and compare the analyses. Data tells different stories depending on what question you ask. The AI will surface different patterns based on different objectives."}, {"number": "35", "name": "The Book Summarizer", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a well-read intellectual who specializes in extracting actionable knowledge from books. Summarize the book [title] by [author]. Provide a structured briefing:\n\n(1) The core thesis in one sentence — not the topic, but the argument\n\n(2) The 5 key ideas with a 2-3 sentence explanation of each — focus on what is original or counterintuitive, not what is obvious\n\n(3) The most actionable advice — the specific thing a reader could implement today\n\n(4) The strongest evidence or example the author uses — the one that makes the argument most convincing\n\n(5) Who should read this book and who should skip it — be specific about the reader profile\n\n(6) The best critique of the book's argument — what would a thoughtful skeptic say is wrong\n\n(7) 3 quotes that capture the book's essence\n\n(8) How this book connects to or contradicts other well-known works in the same field. Do NOT just list chapter summaries — synthesize the ideas into a coherent briefing that is more useful than the table of contents.", "best_on": ["Claude", "Gemini"], "tip": "After the summary, ask 'What would a critic say is wrong with this book's argument?' to get a balanced view.", "why_it_works": "Requiring the thesis (not just the topic) forces genuine comprehension. The critique section applies steel-man thinking to prevent uncritical acceptance of the author's ideas. Connecting to other works places the book in an intellectual context that deepens understanding.", "follow_up": "Based on the key ideas, create a one-page 'implementation plan' — how would I apply the three most relevant ideas from this book to my situation: [describe your context]? Be specific about daily or weekly actions.", "pro_tip": "After getting summaries of 3-5 books on the same topic, paste all summaries together and ask 'What do these books agree on? Where do they contradict each other? What is the synthesized wisdom if you combine the best of each?' This gives you a meta-understanding that surpasses any single book."}, {"number": "36", "name": "The Industry Report Generator", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a management consultant preparing a client briefing on a market opportunity. Create a mini industry report on [industry/market]. Context: I am considering [entering this market / investing / partnering / building a product for this space]. Provide:\n\n(1) Market size — estimated total addressable market with a note on data freshness and confidence level\n\n(2) Growth trajectory — historical growth rate and projected growth, with the key drivers behind each\n\n(3) Competitive landscape — top 5 companies with their estimated market share, positioning strategy, and recent strategic moves\n\n(4) Value chain — how money flows from customer to provider, where the margins are, and where the bottlenecks exist\n\n(5) Key trends shaping the industry in 2026 — 3-5 trends with evidence for each\n\n(6) Major challenges and disruptions — what could upend the current order\n\n(7) Opportunities for new entrants — specific niches or underserved segments\n\n(8) 3 predictions for the next 2-3 years with confidence ratings. Format as a professional brief with clear section headings. Do NOT present estimates as facts — always indicate when you are approximating.", "best_on": ["Gemini", "Claude"], "tip": "Cross-reference the numbers with a quick web search. AI estimates are directionally correct but not always precise.", "why_it_works": "The value chain analysis is what separates a useful industry report from a Wikipedia summary — understanding where money and margins flow reveals the real opportunities. Requiring confidence levels on estimates prevents false precision that leads to bad decisions.", "follow_up": "Based on this report, if I were entering this market with [describe your resources and strengths], what is the highest-probability path to capturing $100K in annual revenue within 12 months? Be specific about the niche, the offering, and the go-to-market approach.", "pro_tip": "Run this report using Gemini for current market data, then paste the output into Claude and ask 'As a strategy consultant, what is the non-obvious insight in this data? What opportunity is hiding in plain sight that most people would miss?'"}, {"number": "37", "name": "The Survey Designer", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a market research methodologist who designs surveys for Fortune 500 companies. Design a [5/10/15]-question survey to understand [research goal]. Target respondents: [describe who will take this survey]. For each question:\n\n(1) The question itself — clear, unambiguous, no leading language\n\n(2) Question type — multiple choice, Likert scale (1-5 or 1-7), open-ended, ranking, or matrix\n\n(3) Answer options if applicable — mutually exclusive and collectively exhaustive\n\n(4) Why this question is included — what specific insight it reveals\n\n(5) How I will use the answer — the decision it informs. Survey architecture: start with easy, non-threatening questions to build momentum. Place sensitive or complex questions in the middle. End with demographics and a thank-you. Include one open-ended question that captures insights I might not have thought to ask about. Estimated completion time must be under [X] minutes. Do NOT use double-barreled questions (asking two things at once) or agree/disagree scales (they introduce acquiescence bias).", "best_on": ["Claude", "Gemini"], "tip": "Keep it under 10 questions for 80%+ completion rates. Every additional question drops completion by 5-10%.", "why_it_works": "Requiring a 'how I will use the answer' explanation for each question eliminates the 'nice to know' questions that bloat surveys and reduce completion rates. Banning agree/disagree scales follows survey methodology best practice — they systematically bias toward agreement.", "follow_up": "Now write the survey introduction — the brief paragraph respondents see before starting. It should explain why their response matters, how long it takes, and how their data will be used. Also write a follow-up email template thanking them for completing the survey and sharing one key finding.", "pro_tip": "Before sending the survey, have 3 people from your target audience take it while you watch. Note every point of confusion or hesitation. Paste their feedback back into the AI and ask for a revision. This pilot test catches 80% of survey design problems."}, {"number": "38", "name": "The Trend Spotter", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a futurist and trend analyst who advises businesses on emerging opportunities. Identify 10 emerging trends in [industry/niche] for 2026-2027. For each trend:\n\n(1) What it is in one sentence — clear and jargon-free\n\n(2) Why it is happening now — the underlying forces driving this trend (technology, behavior shift, regulation, economics)\n\n(3) Evidence — one specific data point, company, or event that proves this trend is real and not just hype\n\n(4) Who is already doing it well — a specific company or person to watch\n\n(5) How a [small business/freelancer/startup] could capitalize on it — a concrete, low-cost action step, not just 'be aware of it,' (6) Timeline — is this a 6-month, 1-year, or 3-year opportunity window? (7) Confidence level (high/medium/low) that this trend will grow. Rank from most to least impactful for someone in my position: [describe your business or role]. Do NOT include trends that have been mainstream for more than 2 years — I want emerging, not established.", "best_on": ["Gemini", "Claude"], "tip": "Focus on the 2-3 trends with high confidence that align with your skills. Ignore the rest.", "why_it_works": "Requiring evidence and a timeline separates genuine emerging trends from speculative hype. The 'how to capitalize' constraint forces practical relevance — most trend reports describe what is happening without telling you what to do about it, which is the only part that matters.", "follow_up": "For the top 3 trends most relevant to my business, create a 30-day action plan to position myself as an early mover. What should I build, publish, or learn this month to be ahead of the curve?", "pro_tip": "Run this prompt quarterly using Gemini (for current data) and compare the outputs over time. Trends that appear consistently and move up in ranking are the real ones to bet on. Trends that appear once and vanish were just hype."}]}, {"title": "Category 06: Learning & Personal Growth", "type": "prompts", "content": "6 prompts for learning, interviews, negotiation, and personal development.", "items": [{"number": "39", "name": "The Skill Learning Plan", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a learning design specialist who builds curricula for accelerated skill acquisition. Create a 30-day learning plan to go from beginner to competent in [skill]. My learning style: [visual/reading/hands-on/auditory]. Time available: [30-60 minutes per day]. Include:\n\n(1) Daily tasks — each day should have one focused learning activity and one practice exercise, clearly separated\n\n(2) Free resources for each day — specific YouTube videos, articles, tools, or tutorials (not just 'search for X')\n\n(3) A weekly mini-project that applies that week's learning to a real scenario\n\n(4) Progress checkpoints — at days 7, 14, 21, and 30, specific tests or demonstrations that prove competency at each level\n\n(5) Common beginner mistakes with an explanation of why they happen and how to avoid each\n\n(6) A 'plateau buster' for each week — what to do when progress feels stuck. Structure each week with a theme that builds on the previous week. Do NOT front-load theory — interleave learning and doing from Day 1.", "best_on": ["Gemini", "Claude"], "tip": "The mini-projects are the most important part. You do not learn by consuming — you learn by doing.", "why_it_works": "Interleaving theory and practice from Day 1 follows the 'desirable difficulty' principle from learning science — struggling with application while learning concepts creates deeper neural pathways than mastering theory before attempting practice.", "follow_up": "I have completed Week 1. Here is what I found easy and what I struggled with: [describe]. Adjust the remaining 3 weeks based on my actual progress, spending more time on my weak areas and accelerating through my strengths.", "pro_tip": "At the end of 30 days, ask the AI: 'Test me. Ask me 10 questions that a competent practitioner of [skill] should be able to answer. Then grade my answers and tell me exactly what I still need to work on.' This final assessment reveals gaps you might not notice on your own."}, {"number": "40", "name": "The Interview Prep Coach", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a career coach who has helped hundreds of candidates land offers at competitive companies. I am interviewing for a [job title] position at [company type/name]. My background: [brief summary of experience and strengths]. Help me prepare:\n\n(1) The 10 most likely interview questions for this specific role — not generic questions, but ones tailored to this industry and level\n\n(2) For each question, a strong answer framework using the STAR method (Situation, Task, Action, Result) with notes on what the interviewer is actually evaluating\n\n(3) 5 thoughtful questions I should ask the interviewer — questions that demonstrate strategic thinking and genuine interest, not questions I could answer by reading the company website\n\n(4) Company research checklist — exactly what to look up and how to reference it naturally in conversation\n\n(5) Red flags to watch for about the company during the interview\n\n(6) A 90-second 'Tell me about yourself' script that positions my experience as a narrative building toward this exact role. Do NOT give me generic advice like 'be confident' or 'dress professionally.' Every piece of guidance should be specific and actionable.", "best_on": ["Claude", "Gemini"], "tip": "Practice answers out loud, not just in your head. Record yourself on your phone and review.", "why_it_works": "Explaining what the interviewer is actually evaluating with each question transforms preparation from memorizing answers to understanding the underlying assessment. The 'Tell me about yourself' narrative structure ensures your response has a logical arc rather than being a chronological resume recitation.", "follow_up": "Now simulate a 15-minute interview. Ask me the 5 hardest questions one at a time. After each of my answers, tell me what was strong, what was weak, and how to improve it. Be direct — I want to improve, not feel good.", "pro_tip": "Ask the AI: 'What is the one answer that could single-handedly lose me this job? What mistake do candidates for [role] make most often?' Knowing what NOT to say is often more valuable than knowing what to say."}, {"number": "41", "name": "The Negotiation Prep", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a negotiation strategist who has coached executives through high-stakes negotiations. Help me prepare to negotiate [salary/contract/deal/price]. My current situation: [describe what you have now]. What I want: [describe your ideal outcome]. What I think the other side wants: [describe their priorities]. My leverage: [describe any advantages you have]. Provide:\n\n(1) 3 strong opening positions — aggressive, moderate, and conservative — with exact numbers or terms for each and the logic behind them\n\n(2) My BATNA (best alternative to a negotiated agreement) — help me identify and strengthen it\n\n(3) Their likely BATNA — what happens if they say no\n\n(4) Key leverage points I might not have considered\n\n(5) Likely objections from the other side and a specific counter for each — including the exact words to use\n\n(6) My walk-away point and how to communicate it without making an ultimatum\n\n(7) Word-for-word scripts for the 3 hardest moments: the opening ask, responding to their first 'no,' and closing the deal. End with a negotiation preparation checklist of things to know before I walk in. Do NOT give me generic negotiation theory — give me a specific game plan for THIS negotiation.", "best_on": ["Claude"], "tip": "Claude excels at nuanced negotiation scenarios. It will give you scripts you can actually use.", "why_it_works": "Analyzing both sides' BATNAs creates a realistic power map rather than the one-sided preparation most people do. Word-for-word scripts for high-stress moments prevent the common failure of knowing what to say in theory but freezing in practice.", "follow_up": "The negotiation happened. Here is what they said and what I agreed to: [describe]. Did I leave money on the table? What should I negotiate in the follow-up or next renewal based on what I learned about their priorities?", "pro_tip": "Before the negotiation, ask the AI to role-play as the other side. Say 'You are [the other party]. I am going to make my opening ask. Respond as they would, then break character and tell me how I did.' Practice the full conversation 2-3 times."}, {"number": "42", "name": "The Feedback Translator", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as an executive coach who specializes in processing professional feedback constructively. I received this feedback: [paste feedback]. Context: this came from [who — manager, client, peer, report] about [what situation]. Help me process it productively:\n\n(1) Emotional content vs. factual content — separate the feelings, tone, and subjective opinions from the specific, observable behaviors mentioned\n\n(2) Pattern check — what are the 2-3 core messages underneath the surface words? What is this person really trying to tell me? (3) Validity assessment — for each core message, rate it as likely accurate, partially accurate, or more about the giver than about me. Explain your reasoning\n\n(4) Action items — 3 concrete, measurable things I should change in the next 30 days, with specific milestones\n\n(5) What to intentionally ignore — which parts are opinion, projection, or style preference rather than substantive feedback\n\n(6) Professional response — draft a reply that shows I have listened and internalized without being defensive or over-apologetic. The response should be under 100 words. Do NOT dismiss the feedback or validate my ego — help me extract maximum value from it, even if it stings.", "best_on": ["Claude"], "tip": "This is incredibly useful for harsh performance reviews or critical client feedback.", "why_it_works": "The emotional/factual separation prevents the common reaction of either defensively rejecting all feedback or anxiously accepting everything as truth. Rating validity of each point creates the psychological distance needed to process difficult feedback rationally rather than emotionally.", "follow_up": "30 days from now, I want to proactively request follow-up feedback from this same person. Write me a short message that asks 'Have you noticed improvement in [specific areas]?' in a way that is confident and genuine, not needy.", "pro_tip": "Keep a 'feedback journal' — paste every significant piece of feedback into the AI over time. Quarterly, ask: 'What themes keep showing up across all this feedback? What is the one thing that, if I fixed it, would resolve most of the recurring issues?' This reveals your blind spot."}, {"number": "43", "name": "The Networking Message Crafter", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a relationship-building strategist who has helped professionals build networks that generate real opportunities. Write a [LinkedIn/email/Twitter DM] message to connect with [person's role/description]. My goal: [what I want from the connection — advice, collaboration, introduction, etc.]. My background: [brief description]. What I know about them: [something specific about their work]. Rules:\n\n(1) Under 75 words total — every word must earn its place\n\n(2) Reference something specific about their work that shows genuine familiarity, not surface-level flattery\n\n(3) Make the value proposition about them — what do they gain from responding\n\n(4) Include a clear but low-pressure ask — something they can say yes to in under 2 minutes of effort\n\n(5) No fake flattery, no 'I'd love to pick your brain,' no 'I'm a huge fan,' (6) Include an easy out — so they do not feel trapped if they are not interested. Provide 3 variations with different approaches: one leading with a shared connection or experience, one leading with a valuable insight, and one leading with a specific question.", "best_on": ["Claude", "Gemini"], "tip": "The shorter the message, the higher the response rate. 50-75 words is the sweet spot.", "why_it_works": "The 75-word limit forces ruthless prioritization of every sentence. Providing an easy out paradoxically increases response rates because it removes the feeling of social obligation. Three variations let you pick the approach that feels most authentic to your personality.", "follow_up": "They responded positively. Now write my reply that: (1) thanks them briefly, (2) provides the context they need, and (3) proposes a specific, low-friction next step. Keep it under 50 words.", "pro_tip": "Before sending, ask the AI: 'Read this message as [the recipient]. What is your honest reaction? Would you respond? If not, what would make you more likely to?' This perspective-flip catches tone-deaf messaging before it lands."}, {"number": "44", "name": "The Difficult Conversation Planner", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a conflict resolution specialist and executive coach. Help me plan a difficult conversation with [person/role] about [topic]. Context: [describe the situation, your relationship, and why this conversation is necessary]. Provide:\n\n(1) An opening statement that is honest but non-confrontational — lead with shared goals, not accusations. Write the exact words\n\n(2) 3 key points I need to make — for each, provide the core message AND the way to phrase it that minimizes defensiveness (use 'I' statements and observed behavior, not interpretations)\n\n(3) Empathy bridges — 2-3 statements that acknowledge their perspective even when I disagree\n\n(4) Likely defensive reactions and a calm, de-escalating response for each — including what to do if they get angry, shut down, or deflect\n\n(5) What a successful outcome looks like — be specific about what changes and what does not\n\n(6) A closing statement that preserves the relationship and confirms next steps\n\n(7) A contingency plan — what to do if the conversation goes off the rails. Do NOT make this manipulative — the goal is honest, respectful communication that solves a real problem.", "best_on": ["Claude"], "tip": "Claude gives the most emotionally intelligent responses for interpersonal scenarios.", "why_it_works": "Scripting both your messages and their likely reactions creates a mental rehearsal that dramatically reduces anxiety and improves real-time performance. The empathy bridges prevent the conversation from becoming adversarial, which is the primary way difficult conversations fail.", "follow_up": "The conversation happened. Here is how it went: [describe what happened, their reactions, and the outcome]. What should I do as a follow-up? Draft a brief message or action that reinforces the positive outcome or addresses anything left unresolved.", "pro_tip": "Practice the conversation with the AI acting as the other person. Tell it: 'Respond as [person] would — including their defensiveness, excuses, or emotional reactions. Do not be nice about it.' The realistic simulation prepares you for the actual conversation far better than rehearsing alone."}]}, {"title": "Category 07: Coding & Technical", "type": "prompts", "content": "6 prompts for coding, debugging, and technical work.", "items": [{"number": "45", "name": "The Code Explainer", "category": "CODING & TECHNICAL", "prompt": "Act as a senior software engineer and patient teacher with 10+ years of experience. Explain this code to me like I am a smart beginner who understands basic programming concepts but not advanced patterns. Break the code into logical sections and for each section explain:\n\n(1) WHAT it does — in one sentence\n\n(2) WHY it does it — the purpose and design decision behind it\n\n(3) HOW it works — the mechanism, using analogies where helpful. Then provide: (4) A 'mental model' — a simple way to think about what this entire code does, like an elevator pitch for the logic\n\n(5) Potential problems or bugs — anything that could break in production\n\n(6) 3 specific improvements — with code examples showing the before and after\n\n(7) Related concepts to learn next — what should I study to fully understand this code? Do NOT just describe the syntax. Explain the thinking behind the code as if you were pair-programming with me. Here is the code: [paste code]", "best_on": ["Claude"], "tip": "Claude is the best code explainer. It gives context and reasoning that other models often skip.", "why_it_works": "Separating WHAT, WHY, and HOW mirrors how expert developers actually think about code — at multiple levels of abstraction simultaneously. The mental model request forces the AI to find the simplest accurate representation, which accelerates comprehension far more than line-by-line annotation.", "follow_up": "Now quiz me on this code. Ask me 5 questions that test whether I truly understand it, not just whether I can repeat your explanation. After I answer, tell me what I got right and what I am still confused about.", "pro_tip": "Paste code you wrote yourself 6 months ago. If the AI finds issues or better approaches, you have just measured your growth as a developer. Keep a log of these improvements over time."}, {"number": "46", "name": "The Debug Helper", "category": "CODING & TECHNICAL", "prompt": "Act as a senior debugging specialist who has fixed thousands of production bugs. I need help debugging this issue. Language: [language]. Framework: [if applicable]. Environment: [development/staging/production]. Error message: [paste exact error]. My code: [paste relevant code]. What I expected to happen: [describe expected behavior]. What actually happened: [describe actual behavior]. What I have already tried: [list any fixes you attempted]. Please:\n\n(1) Explain why this error occurs — the root cause, not just the surface symptom. Use plain English\n\n(2) Show me the exact fix — with the corrected code I can copy and paste\n\n(3) Explain what the fix does and why it works — so I learn the pattern\n\n(4) Show me how to add a guard or check that prevents this type of error in the future\n\n(5) Identify any OTHER potential bugs in the surrounding code that might not have surfaced yet. Do NOT suggest 'try restarting' or 'reinstall packages' unless you have a specific reason to believe that is the issue. Focus on the code logic first.", "best_on": ["Claude"], "tip": "Always include what you expected vs. what happened. It cuts the back-and-forth in half.", "why_it_works": "Requiring the root cause explanation (not just a fix) prevents the 'whack-a-mole' debugging pattern where you fix one symptom only to create another. Including what you already tried avoids wasting time on solutions you have already eliminated.", "follow_up": "The fix worked. Now help me write a test case that would have caught this bug before it reached production. Show me the test in [testing framework] and explain what edge cases it covers.", "pro_tip": "Start a 'Bug Journal' — every time you fix a bug with AI help, save the error, root cause, and fix pattern. After 20 entries, paste the journal back and ask 'What patterns do you see in my bugs? What fundamental concept should I study to stop making these types of errors?'"}, {"number": "47", "name": "The Code Reviewer", "category": "CODING & TECHNICAL", "prompt": "Act as a principal engineer conducting a thorough code review before a production deployment. Language: [language]. Context: this code [describe what it does and where it fits in the application]. Review this code against these criteria, in order of severity:\n\n(1) Correctness — bugs, logical errors, off-by-one errors, null/undefined handling, race conditions\n\n(2) Security — injection vulnerabilities, authentication gaps, data exposure, input validation\n\n(3) Performance — unnecessary operations, N+1 queries, memory leaks, algorithmic complexity issues\n\n(4) Readability — unclear naming, missing comments on complex logic, overly clever code, inconsistent style\n\n(5) Maintainability — tight coupling, missing abstractions, code duplication, difficulty of future modification\n\n(6) Edge cases — boundary conditions, empty inputs, concurrent access, error states. For each issue found: describe the problem, explain why it matters (with severity: critical/major/minor), and show the improved code. At the end, give an overall assessment: 'Ship it,' 'Fix these issues first,' or 'Needs significant rework.' Here is the code: [paste code]", "best_on": ["Claude"], "tip": "Claude catches subtle bugs that other AI models miss. Always use it for code review.", "why_it_works": "The ordered severity list ensures critical issues are caught before the reviewer spends time on style preferences. Requiring a ship/fix/rework verdict forces the AI to make a judgment call rather than listing issues without prioritization, which mirrors how real code review actually works.", "follow_up": "I have fixed all the issues you identified. Here is the updated code: [paste]. Review the fixes — did I introduce any new problems? Is this now ready to ship?", "pro_tip": "Use this prompt before every PR you submit. Track how many issues the AI finds over time — a decreasing count means your coding is improving. Zero issues found consistently means you have outgrown this level of review and should add more advanced criteria."}, {"number": "48", "name": "The Tech Stack Advisor", "category": "CODING & TECHNICAL", "prompt": "Act as a CTO who has built and scaled applications from prototype to millions of users. I am building [describe project — what it does, who it is for, expected scale]. My experience level: [beginner/intermediate/advanced]. My priorities (rank these): speed to launch, scalability, cost, learning value, community support, hiring pool. My constraints: [budget, timeline, team size, existing skills]. Recommend a complete tech stack:\n\n(1) Frontend — framework, state management, styling approach\n\n(2) Backend — language, framework, API style (REST/GraphQL)\n\n(3) Database — type and specific product, with rationale for why this type fits my data model\n\n(4) Hosting and deployment — specific provider, tier, and estimated monthly cost at launch and at 10x scale\n\n(5) Key libraries and tools — authentication, payments, email, monitoring — specific names, not categories\n\n(6) Development tools — IDE, version control workflow, CI/CD approach. For each recommendation, give a one-sentence rationale tied to my priorities. Also provide one 'Keep It Simple' alternative stack for the entire project using the fewest possible technologies. Do NOT recommend technologies based on hype — recommend based on my stated priorities and constraints.", "best_on": ["Claude", "Gemini"], "tip": "If you are a solo developer, always go with the 'keep it simple' option. Complexity kills solo projects.", "why_it_works": "Requiring explicit priority ranking prevents the AI from defaulting to 'best practice' recommendations that do not fit your situation. The 'Keep It Simple' alternative acknowledges that for most projects, shipping fast with boring technology beats architecture astronautics with trendy frameworks.", "follow_up": "I chose [your selected stack]. Now create a project setup guide: the exact terminal commands to initialize the project, install dependencies, set up the development environment, and deploy a 'Hello World' version. I should have a running application within 30 minutes.", "pro_tip": "Ask the AI: 'What is the most common mistake developers make when building [project type] with [chosen stack]? What would a senior developer do differently from day one?' This upfront architectural advice saves weeks of refactoring later."}, {"number": "49", "name": "The API Integrator", "category": "CODING & TECHNICAL", "prompt": "Act as a senior backend developer who has integrated dozens of third-party APIs in production applications. I need to integrate [API/service] into my [project type]. Language: [language]. Framework: [if applicable]. What I need the integration to do: [describe the specific functionality]. Show me:\n\n(1) The minimal working code — the shortest path to a functioning integration I can test immediately\n\n(2) Authentication setup — step-by-step, including where to get API keys, how to store them securely (never hardcoded), and how to handle token refresh if applicable\n\n(3) Error handling — catch and handle the 5 most common API errors (rate limits, timeouts, auth failures, malformed responses, network errors) with specific code\n\n(4) A production-ready version — the code I would actually ship, with logging, retry logic, and circuit breaker pattern if appropriate\n\n(5) Testing approach — how to test this integration without hitting the real API (mocking strategy). Include comments in the code explaining WHY each section exists, not just WHAT it does. Do NOT use deprecated API endpoints or libraries.", "best_on": ["Claude", "Gemini"], "tip": "Ask for the 'minimal viable' version first. You can always add complexity later.", "why_it_works": "Providing both minimal and production-ready versions teaches the difference between 'working' and 'ship-ready' code. The explicit error handling for the five most common API failures prevents the surprise crashes that plague naive integrations in production.", "follow_up": "Now help me write a simple wrapper class/module around this API integration that my team can use without understanding the API details. The interface should be clean and the implementation should handle all edge cases internally.", "pro_tip": "After getting the integration code, ask: 'What happens if this API goes down for 2 hours? Show me the code for a graceful degradation strategy — what does my application do while the API is unavailable?' This resilience thinking separates professional from amateur integrations."}, {"number": "50", "name": "The Regex Generator", "category": "CODING & TECHNICAL", "prompt": "Act as a regex specialist who writes and debugs regular expressions for production systems. Create a regex pattern that matches [describe what you want to match in detail, including examples]. Language/environment: [JavaScript, Python, Go, etc.]. Provide:\n\n(1) The regex pattern — optimized for readability, not cleverness\n\n(2) A plain-English explanation of each component — break the pattern into segments and explain each one\n\n(3) 5 test strings it SHOULD match — including edge cases like leading/trailing spaces, special characters, and boundary conditions\n\n(4) 5 test strings it should NOT match — including near-misses that test the pattern's specificity\n\n(5) Edge cases and limitations — when this regex might fail or produce unexpected results\n\n(6) A named-group version (if the language supports it) for easier extraction of matched components\n\n(7) Performance notes — whether this pattern risks catastrophic backtracking on large inputs. If the match requirement is complex, suggest whether a regex is even the right tool or if a parser would be more appropriate. Do NOT use obscure regex features without explaining them.", "best_on": ["Claude", "Gemini"], "tip": "Always test regex with the provided test strings before using in production. AI regex is right 90% of the time.", "why_it_works": "Including near-miss non-matching test strings is critical because regex bugs almost always manifest as false positives, not false negatives. The performance warning about catastrophic backtracking prevents the surprisingly common production outage caused by an innocent-looking pattern hitting pathological input.", "follow_up": "Now show me how to use this regex in a complete function that: extracts the matches, handles the case where no match is found, and includes input validation. Write it in [language] with proper error handling.", "pro_tip": "Ask the AI to generate a comprehensive test suite for the regex — 20+ test cases covering every edge case. Run these tests in your actual environment before deploying. Regex that passes in an AI conversation can behave differently in your specific runtime due to engine differences."}]}, {"title": "Bonus: Advanced Frameworks", "type": "templates", "content": "4 advanced frameworks for power users to get consistently great outputs.", "items": [{"number": "F1", "name": "The MEGA Prompt Framework", "category": "ADVANCED FRAMEWORKS", "description": "The MEGA Prompt Framework is a modular template that structures every AI interaction around seven key dimensions: Role, Context, Task, Format, Constraints, Tone, and Example. By filling in each dimension, you eliminate the ambiguity that causes generic, mediocre outputs. Think of it as a creative brief for the AI — the same way you would brief a freelancer or agency, except the AI needs even more explicit instruction because it cannot ask clarifying questions mid-task.", "prompt": "[ROLE]: Act as a [specific expert role with years of experience and a concrete specialization — e.g., 'a senior UX researcher with 12 years of experience in B2B SaaS']. [CONTEXT]: Here is the background you need: [provide 2-3 sentences of relevant context including industry, audience, current situation, and any constraints the expert should know]. [TASK]: I need you to [describe the specific task with a clear deliverable — not 'help me with' but 'create/analyze/design/write']. [FORMAT]: Present the output as [specify exact format: bullet points, numbered list, table with column headers, essay with subheadings, code with comments, etc.]. Length: [word count or page count]. [CONSTRAINTS]: Do NOT [list 2-3 specific things to avoid — cliches, certain formats, assumptions, topics]. Must include [list 2-3 mandatory elements]. [TONE]: Write in a [describe tone precisely — e.g., 'direct and confident, like a trusted advisor who respects the reader's intelligence, not a salesperson'] voice. [EXAMPLE]: Here is an example of the quality and style I expect: [paste a brief example of good output, even a partial one].", "best_on": ["Claude", "Gemini"], "tip": "You do not need to fill in every section every time. But the more you fill in, the better the output. Start with Role + Task + Constraints as your minimum viable prompt.", "why_it_works": "Each dimension addresses a different failure mode of AI output. Role prevents generic responses by activating domain-specific patterns. Constraints prevent common bad habits. Examples set a quality floor. Most people use only 1-2 dimensions (usually just the task), which is why their results feel generic. Using 5+ dimensions puts you in the top 1% of AI users in terms of output quality.", "example_use_case": "A startup founder needs a go-to-market strategy. Without the framework, they might ask 'Help me with my go-to-market strategy.' With the MEGA framework: Role = seasoned B2B SaaS GTM strategist, Context = pre-revenue startup with a developer tools product, Task = create a 90-day GTM plan with channel prioritization, Format = table with weekly actions, Constraints = budget under $5K/month and no paid ads in month 1, Tone = direct and tactical, Example = a sample week showing the level of specificity expected. The output difference is night and day."}, {"number": "F2", "name": "The Iterative Refinement Loop", "category": "ADVANCED FRAMEWORKS", "description": "The Iterative Refinement Loop is a three-step process that turns any first-draft AI output into polished, high-quality work by leveraging the model's ability to critique its own output. Most people accept the first response and move on, but the first draft is never the best draft. This framework exploits the fact that AI models are significantly better at evaluating and improving existing text than generating perfect text from scratch — the same principle that makes editing easier than writing for humans.", "prompt": "Step 1 — GENERATE: Use your prompt (ideally structured with the MEGA framework) to get the first draft. Accept whatever comes out without judgment. Step 2 — CRITIQUE: Send this exact follow-up: 'Rate this output on a scale of 1-10. Be brutally honest. Then list: (a) The 3 weakest parts and why each is weak, (b) What is missing that would make this significantly better, (c) Any factual claims that need verification, (d) Where the writing is vague, generic, or sounds like AI instead of a human expert. Do not hold back — I need your harshest assessment.' Step 3 — IMPROVE: Send this follow-up: 'Now rewrite the entire output, incorporating every improvement you just identified. Do not just patch the weak spots — rethink the structure and approach if needed. The rewrite should feel like it was written by someone who saw the first draft's flaws and started fresh with that knowledge. Make it a 10.'", "best_on": ["Claude", "Gemini"], "tip": "You can run this loop 2-3 times. Each iteration gets dramatically better. After 3 loops, you typically hit diminishing returns.", "why_it_works": "This framework exploits the 'generation-evaluation gap' — AI models can identify flaws in text more reliably than they can avoid those flaws during generation. By separating creation from criticism, you get the best of both capabilities. The explicit critique categories (weak parts, missing elements, vague language) prevent the shallow 'this is good but could be better' non-feedback that wastes an iteration cycle.", "example_use_case": "A consultant writing a client proposal generates the first draft, then uses the critique step to discover that the proposal lacks specific ROI projections and uses too much jargon. The improvement step produces a version with concrete numbers, simpler language, and a restructured flow that leads with the client's problem instead of the consultant's credentials. The final version is unrecognizable from the first draft and reads like it was written by a senior partner."}, {"number": "F3", "name": "The Expert Panel Technique", "category": "ADVANCED FRAMEWORKS", "description": "The Expert Panel Technique simulates a structured debate between multiple expert perspectives on a single problem, forcing the AI to generate diverse viewpoints rather than converging on a single 'safe' answer. Real-world decisions benefit from adversarial thinking — when smart people disagree, the truth usually lives at the intersection of their arguments. This framework recreates that dynamic in a single prompt, giving you the benefit of a boardroom discussion without needing an actual board.", "prompt": "I need to make a decision about [describe problem/question with sufficient context]. Simulate a panel discussion among these 3 experts. Each expert must argue from their genuine professional perspective, even when they disagree with the others: Expert 1 — [Role with specific viewpoint, e.g., 'A skeptical CFO who has seen companies fail by spending too fast. They prioritize financial discipline, cash runway, and ROI on every dollar']. Expert 2 — [Role with contrasting viewpoint, e.g., 'An innovative CTO who believes speed and technical excellence create competitive moats. They prioritize building the right product, even if it costs more upfront']. Expert 3 — [Role with yet another perspective, e.g., 'A customer-obsessed CMO who has built brands from zero. They prioritize user experience, brand perception, and customer retention over internal efficiency']. For each expert:\n\n(1) Their opening position in 3-4 sentences\n\n(2) Their strongest argument for their approach with a specific example or data point\n\n(3) Their rebuttal to the other two experts — what they think the others are getting wrong. Then: SYNTHESIS — as a neutral moderator, identify where the experts agree (this is your foundation), where they disagree (these are your key decision points), and recommend a path forward that captures the best elements of each perspective.", "best_on": ["Claude", "Gemini"], "tip": "Change the experts based on your situation. The key is diverse, conflicting viewpoints. The more they disagree, the more useful the synthesis.", "why_it_works": "Single-perspective prompts produce single-perspective answers, which reinforces confirmation bias. By requiring genuine disagreement and rebuttals, this technique forces the model to explore the solution space more thoroughly. The synthesis step then extracts actionable wisdom from the conflict rather than picking a 'winner,' which is how real strategic decisions should be made.", "example_use_case": "A founder deciding whether to raise venture capital or bootstrap uses this framework with three experts: a VC partner (argues for raising to capture market fast), a bootstrapped founder who sold for $50M (argues for retaining control and profitability), and a startup lawyer who has seen both paths (argues for a convertible note as a middle ground). The synthesis reveals that the real decision hinges on market timing — if competitors are well-funded, bootstrapping is risky; if the market is still forming, bootstrapping preserves optionality."}, {"number": "F4", "name": "The Chain-of-Thought Prompt", "category": "ADVANCED FRAMEWORKS", "description": "The Chain-of-Thought framework forces the AI to show its complete reasoning process before delivering a final answer, dramatically reducing errors, hallucinations, and overconfident conclusions. Most AI mistakes happen because the model jumps from question to answer without intermediate reasoning steps. By requiring the model to externalize its thinking — list assumptions, decompose the problem, work through sub-problems, and verify its logic — you activate a fundamentally more careful and accurate mode of processing. This is the single most effective technique for any task where accuracy matters more than speed.", "prompt": "I need you to solve this problem with maximum accuracy: [describe question/problem with all relevant details]. Before giving me your final answer, you MUST complete these reasoning steps and show your work:\n\n(1) ASSUMPTIONS — List every assumption you are making. Flag any assumption you are not confident about and explain why\n\n(2) DECOMPOSITION — Break the main problem into 2-5 sub-problems that, when solved, combine to answer the main question\n\n(3) STEP-BY-STEP REASONING — Work through each sub-problem methodically. Show your logic, calculations, or analysis for each step. If you are uncertain at any step, say so explicitly\n\n(4) VERIFICATION — Review your reasoning. Check for logical fallacies, mathematical errors, missing considerations, and confirmation bias. If you find an error, correct it before proceeding\n\n(5) ALTERNATIVE PERSPECTIVES — Consider one plausible alternative conclusion. Why might your answer be wrong? What evidence would change your mind? (6) FINAL ANSWER — State your conclusion with a confidence level (high/medium/low) and a one-sentence explanation of the main uncertainty. Do NOT skip steps even if you think the answer is obvious. The process IS the point.", "best_on": ["Claude", "Gemini"], "tip": "This technique reduces AI hallucinations significantly. Use it whenever accuracy matters more than speed — financial decisions, factual claims, technical analysis, and any task where being wrong has consequences.", "why_it_works": "Chain-of-thought prompting works because it converts System 1 thinking (fast, intuitive, error-prone) into System 2 thinking (slow, deliberate, accurate). The verification step catches errors that the model would otherwise confidently present. The alternative perspectives step prevents the model from anchoring on its first conclusion, which is a known failure mode of large language models.", "example_use_case": "A business owner needs to calculate whether hiring a full-time employee or using contractors is more cost-effective. Without chain-of-thought, the AI might give a quick comparison based on salary vs. hourly rate. With this framework, the AI first lists assumptions (benefits cost, utilization rate, management overhead), decomposes into sub-problems (total cost, productivity comparison, quality and retention effects, scalability), works through each with numbers, then verifies the math and considers the scenario where the answer flips (e.g., if utilization drops below 70%, contractors become cheaper). The final answer includes a breakeven analysis and a decision rule the owner can apply as circumstances change."}]}, {"title": "Installable AI Tools — 3 Claude Skills + 1 Gemini Gem", "type": "skills", "content": "Ready-to-install AI tools built specifically for solopreneurs. Each tool is a pre-configured AI specialist that you install once and use forever. Copy the code below, follow the install steps, and you'll have a working AI assistant in under 5 minutes.", "install_overview": {"claude": {"title": "How to Install Claude Skills", "steps": ["Open Claude (claude.ai) and sign in", "Type /skill-creator in any conversation", "Paste the SKILL.md content when prompted", "Name your skill and save — it's now available in all your conversations"]}, "gemini": {"title": "How to Install Gemini Gems", "steps": ["Open Gemini (gemini.google.com) and sign in", "Click \"Gem manager\" in the left sidebar", "Click \"New Gem\" and give it a name", "Paste the system prompt into the instructions field and save"]}}, "skills": [{"name": "Social Media Engine", "description": "Solopreneurs who struggle with consistent social posting", "platform": "Claude Skill", "system_prompt": "You are Social Media Engine — a specialized AI assistant for solopreneurs.\nYour job is to turn a topic, idea, or rough thought into a full set of platform-ready social media posts so the user can show up consistently without spending hours writing.\nHow you work:\nThe user gives you a topic or idea (and ideally their brand voice or niche). If they haven't given you a brand voice, ask one question: 'How would you describe your tone — professional, conversational, bold, educational, or something else?' Then get to work. You support both single-post requests and batch creation of 5-10 posts at once.\nWhat you produce for every post set:\n- Platform specified by the user, or all major platforms if not specified\n- For each post: a hook (first line that grabs attention), body (the value), CTA, and relevant hashtags\n- For batch requests: numbered posts with variety in angle and format — don't repeat the same hook style twice in a row\nPost structure by platform:\nLinkedIn: 150-200 words, professional insight angle, 2-3 hashtags.\nInstagram: 100-125 words, visual/emotional angle, 8-10 hashtags.\nX/Twitter: Under 240 characters for standalone; 3-5 tweets for a thread.\nFacebook: 100-150 words, community/conversation angle, end with a question.\nRules you always follow:\nEvery post needs a real hook — no starting with 'I' or with a generic statement. Hooks should be bold, specific, or counterintuitive. CTAs should be natural, not pushy. If a topic is too vague to write well, ask the user to add one specific detail.\nFormatting rules:\nNumber each post. Label the platform. Use a divider between posts. For batches, add a brief note at the top listing the angles covered."}, {"name": "Client Proposal Generator", "description": "Solopreneurs who lose deals because proposals take too long or look unprofessional", "platform": "Claude Skill", "system_prompt": "You are Client Proposal Generator — a specialized AI assistant for solopreneurs.\nYour job is to turn rough project notes into a clean, professional proposal that's ready to send to a client — one that builds trust and wins the deal without requiring the user to spend hours formatting.\nHow you work:\nThe user gives you whatever they have — notes from a call, a scope description, a price they have in mind, a deadline. You ask for any critical missing information (if you don't have a price range or core deliverable, ask before drafting). Once you have enough, you produce a complete proposal draft. Flag anything that seems unclear or risky in a brief 'heads up' note at the end.\nWhat you produce:\n- Project Overview: 2-3 sentences summarizing what you're doing and why\n- Scope of Work: Bulleted list of specific deliverables\n- Timeline: Key milestones with realistic dates or timeframes\n- Investment: Pricing clearly stated with what's included\n- Terms: Payment schedule, revision rounds, what's out of scope\n- Next Steps: One clear action for the client to take\nRules you always follow:\nWrite in the user's voice, not in corporate legal language. Keep it scannable — no dense paragraphs. Be specific about what's included and what's not to prevent scope creep. If the user hasn't mentioned revisions or payment terms, include sensible defaults and flag them.\nFormatting rules:\nUse clear section headers. Deliverables in bullet lists. Timeline as a simple table or numbered list. Keep the total proposal readable in under 3 minutes. End with a 'Heads Up' section noting any gaps or assumptions."}, {"name": "Weekly Business Planner", "description": "Solopreneurs who feel scattered and overwhelmed juggling everything", "platform": "Claude Skill", "system_prompt": "You are Weekly Business Planner — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners turn a chaotic to-do list into a structured, realistic weekly plan that actually prioritizes the work that grows the business.\nHow you work:\nAt the start of each planning session, ask the user three things: (1) What are this week's top priorities or deadlines? (2) Any wins or unfinished business from last week? (3) Any constraints (travel, appointments, limited hours)? Then build the plan. If the user dumps information without being prompted, pull out what you need and ask only for what's missing.\nWhat you produce:\n- Weekly Focus: The one or two outcomes that would make this week a success\n- Revenue-Generating Activities: Specific tasks that directly bring in money or move deals forward — listed first, every time\n- Client Work: Deliverables due and time estimates\n- Admin Block: Emails, invoices, housekeeping — batched together, not scattered through the week\n- Time Blocks: A suggested daily breakdown (Monday-Friday) with realistic time allocations\n- Overcommitment Flag: If the user has packed in too much, say so clearly and suggest what to defer\nRules you always follow:\nRevenue-generating work always gets prime hours (before noon if possible). Never let admin eat the whole plan. Call out anything the user mentioned from last week that didn't get done — help them decide whether to carry it forward or drop it.\nFormatting rules:\nWeekly Focus at the top, bold. Then sections in order. Daily time blocks as a simple table or clean list. Keep the whole plan on one readable page."}, {"name": "Market Research Scout", "description": "Solopreneurs who need market insights but can't afford a research team", "platform": "Gemini Gem", "system_prompt": "Gemini has live web access and Google Search integration, making it ideal for current market data. Combined with Personal Intelligence, it can also analyze your Gmail and Drive for existing research and client insights."}]}, {"title": "Go Deeper", "type": "cta", "content": "You've just unlocked your AI advantage. Ready to go deeper? Check out our other products.", "items": [{"offer": "AI Prompt Master Pack", "price": "$47", "description": "300+ prompts for every use case", "url": "https://www.kh-academy.com"}, {"offer": "AI Business Automation Toolkit", "price": "$67", "description": "Automate your entire workflow with AI", "url": "https://www.kh-academy.com"}, {"offer": "Ultimate AI Bundle", "price": "$197", "description": "All 6 products — everything you need", "url": "https://www.kh-academy.com"}], "purchase_url": "https://kh-academy-storefront.vercel.app/#pricing", "storefront_url": "https://kh-academy-storefront.vercel.app"}]};

export const SKILLS_BUILDER_DATA: CourseData = {"product_id": "skills-builder", "title": "AI Skills Builder", "subtitle": "Build Your AI Dream Team with Claude Skills & Gemini Gems", "tagline": "10+ Ready-to-Use Skill Templates Inside", "source": "ai-skills-builder.pdf", "version": "1.0 — March 2026", "pages": 32, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "STOP CHATTING. START BUILDING. Most people use AI the wrong way — they open a chat, type a question, and start from scratch every single time. Power users do something different. They build Skills — specialized AI assistants that already know their business, their style, and their workflows. This playbook teaches you exactly how to do that on two of the most powerful platforms: Claude and Gemini.", "items": []}, {"title": "How to Use This Playbook", "type": "instructions", "content": "Three-step approach to building your AI team. Each template in this playbook is copy-paste ready — fill in your business details, paste it into Claude or Gemini, and you have a working specialist in under five minutes.", "items": [{"step": 1, "title": "Learn the Concept", "instruction": "Each chapter explains one skill-building technique in plain language. No coding required."}, {"step": 2, "title": "Copy the Template", "instruction": "Every chapter includes ready-to-use templates. Copy them directly into Claude or Gemini."}, {"step": 3, "title": "Build Your AI Team", "instruction": "By the end, you'll have 10+ specialized AI assistants working for you around the clock."}]}, {"title": "What's Inside", "type": "overview", "content": "This playbook gives you the exact templates and techniques that power users rely on to get consistent, high-quality results from AI — the kind of knowledge you cannot get by simply asking a chatbot for help. Inside you will find: how to build Claude Skills and Gemini Gems from scratch, 10+ tested and ready-to-use skill templates you can deploy today, 5 AI team member roles with complete instruction sets, and advanced techniques including voice cloning, prompt chaining, and self-improvement loops.", "items": []}, {"title": "Table of Contents", "type": "toc", "content": "3 parts. 10+ templates. Your AI dream team.", "items": [{"part": "I", "title": "The Foundations", "chapters": ["What Are AI Skills? (Pages 4-5)", "Claude Skills: Your AI Specialist Factory (Pages 6-10)", "Gemini Gems: Your Google-Powered Experts (Pages 11-14)"]}, {"part": "II", "title": "Build Your AI Team", "chapters": ["The Marketing Manager (Pages 15-16)", "The Content Writer (Pages 17-18)", "The Financial Analyst (Pages 19-20)", "The Research Assistant (Pages 21-22)", "The Customer Support Agent (Pages 23-24)"]}, {"part": "III", "title": "Advanced Skills", "chapters": ["Voice Cloning: Make AI Sound Like You (Pages 25-26)", "Prompt Chaining: Multi-Step Workflows (Pages 27-28)", "The Self-Improving Loop (Pages 29-30)"]}]}, {"title": "Chapter 01: What Are AI Skills?", "type": "educational", "content": "The difference between chatting with AI and building with AI. When you chat with AI, you start from zero every time — no memory, no context, no understanding of your business. When you build a Skill, you create a permanent specialist that already knows your brand, your audience, your writing style, and your rules. The result: faster work, better outputs, and zero ramp-up time on every task.", "callout": "Chatting with AI = Hiring a new temp every day. They don't know you, your business, or what you did yesterday. Building AI Skills = Hiring permanent specialists. They know your brand, your style, your data, and your preferences — every single time.", "items": [{"platform": "Claude Skills", "builder": "Anthropic", "features": ["Create custom workflows with instructions + knowledge files", "Can execute code and run complex tasks", "Best for: Deep work, long documents, specialized knowledge", "Works on: Claude.ai (Pro, Team, Enterprise) + Claude Code + API"]}, {"platform": "Gemini Gems", "builder": "Google", "features": ["Create custom AI assistants with detailed instructions", "Native integration with Google Workspace (Docs, Sheets, Gmail)", "Best for: Google Workspace users, quick-access specialists", "Works on: Gemini (free for basic, Advanced for full features)"]}], "comparison_table": {"columns": ["Criteria", "Claude Skills", "Gemini Gems"], "rows": [["You work mostly in...", "Any platform / standalone", "Google Workspace"], ["You need...", "Deep analysis, long docs, code", "Quick tasks, Google integration"], ["Knowledge upload", "Up to 200K tokens (massive)", "Via Google Drive (real-time)"], ["Sharing", "Team plan members", "Anyone (view/use/edit)"], ["Code execution", "Yes — Python, JS, data analysis", "Limited"], ["Cost", "Claude Pro $20/mo", "Gemini Advanced $20/mo"], ["Best for", "Power users, developers", "Google Workspace users, teams"]]}, "pro_tip": "You don't have to choose one. Many power users build their 'thinking' skills in Claude (for deep analysis and writing) and their 'action' skills in Gemini (for tasks connected to Google Docs, Sheets, and Gmail)."}, {"title": "Chapter 02: Claude Skills — Your AI Specialist Factory", "type": "educational", "content": "Claude Skills are the most powerful way to create AI specialists. Each skill is a set of instructions (and optionally code + reference files) that teaches Claude exactly how to handle a specific type of work. Unlike a normal chat where Claude forgets everything after each conversation, a Skill persists — it loads your rules, context, and preferences automatically every time. Think of it as programming a permanent team member who never needs retraining.", "real_examples": ["A brand guidelines enforcer that checks every piece of content against your style guide", "A financial report generator that formats data exactly how your team expects", "A customer email responder trained on your FAQs and policies", "A code reviewer that follows your team's coding standards"], "levels": [{"level": 1, "name": "Simple", "description": "Just a markdown file (SKILL.md) with instructions. Like giving someone a detailed job description."}, {"level": 2, "name": "With Knowledge", "description": "Add reference files (PDFs, docs, data) that Claude can access. Like giving someone a training manual."}, {"level": 3, "name": "With Code", "description": "Add executable scripts for complex workflows. Like giving someone tools to work with."}], "note": "This playbook focuses on Level 1 and 2. No coding needed.", "how_to_build": [{"step": 1, "action": "Open Claude", "detail": "Go to Settings → Capabilities → Skills"}, {"step": 2, "action": "Click 'Add Skill'", "detail": "Upload your SKILL.md file"}, {"step": 3, "action": "Enable the Skill", "detail": "Toggle it on in your skills list"}, {"step": 4, "action": "Start Chatting", "detail": "Claude now has this specialist knowledge"}], "skill_md_anatomy": {"description": "Every SKILL.md file has two required parts.", "frontmatter": "The --- section: Name + description. Claude reads this to decide WHEN to use your skill. Keep it clear and specific.", "instructions": "The markdown body: The actual guidance. This is your specialist's 'brain.' The more specific, the better.", "example": "---\nname: Marketing Manager\ndescription: Creates marketing content following brand guidelines, analyzes campaign performance, and suggests growth strategies.\n---\n\n# Marketing Manager Skill\n\n## When to Use This Skill\nUse this skill when the user asks about marketing strategy, content creation, campaign planning, or brand messaging.\n\n## Instructions\n[Your detailed instructions go here]"}, "easy_alternative": {"title": "The Easy Way: Use Claude Projects", "description": "Don't want to create SKILL.md files? Claude Projects give you the same power through a simple interface.", "steps": [{"step": 1, "action": "Click 'Projects'", "detail": "In Claude's sidebar → New Project"}, {"step": 2, "action": "Name Your Project", "detail": "e.g., \"Marketing Manager\""}, {"step": 3, "action": "Add Custom Instructions", "detail": "Paste the templates from Chapters 04-08"}, {"step": 4, "action": "Upload Reference Files", "detail": "Brand guide, past work, data"}, {"step": 5, "action": "Start Chatting", "detail": "Every chat in this project now uses these instructions"}], "recommendation": "Start with Projects. They're easier. Move to Skills when you want more power or need to share with a team."}, "projects_vs_skills": {"columns": ["Feature", "Claude Projects", "Claude Skills"], "rows": [["Best for", "Personal specialists", "Shareable, reusable workflows"], ["Setup", "Click & type", "Upload SKILL.md file"], ["Reference files", "Upload directly", "Bundle in skill directory"], ["Code execution", "Not included", "Can include scripts"], ["Sharing", "Team plan only", "Team, Enterprise, or publish"], ["Our recommendation", "Start here", "Graduate to this"]]}}, {"title": "Chapter 03: Gemini Gems — Your Google-Powered Experts", "type": "educational", "content": "If you live in Google Workspace, Gems are your secret weapon. Gems are custom AI assistants inside Gemini that you give detailed instructions to, and they become persistent specialists you can call on anytime. They connect directly to your Google Drive, Docs, Sheets, and Gmail — so your Gem can read your latest sales spreadsheet or brand guide without you having to upload anything. Set one up in under three minutes, share it with your whole team like a Google Doc, and use it from any device.", "gem_features": ["Native Google integration — they can read your Drive files in real-time", "Shareable — send to colleagues with view/use/edit permissions (like sharing a Google Doc)", "Pre-made templates — Google offers starter Gems you can customize", "Up to 15,000 tokens of instructions — room for very detailed guidance", "Works on free plan (basic) and Advanced plan (full features)"], "how_to_build": [{"step": 1, "action": "Open Gemini", "detail": "Click 'Gems' in the left sidebar"}, {"step": 2, "action": "Click 'New Gem'", "detail": "Or explore pre-made ones first"}, {"step": 3, "action": "Name Your Gem", "detail": "e.g., \"Content Strategist\""}, {"step": 4, "action": "Write Instructions", "detail": "Paste templates from Chapters 04-08"}, {"step": 5, "action": "Test It", "detail": "Try a sample task to verify it works"}, {"step": 6, "action": "Save & Pin", "detail": "Your Gem is now always available in the sidebar"}], "5_part_formula": {"title": "Writing Great Gem Instructions — The 5-Part Formula", "parts": [{"part": 1, "label": "ROLE", "template": "\"You are my [specific role] with expertise in [areas].\""}, {"part": 2, "label": "CONTEXT", "template": "\"About my business: [company, industry, audience, products]. My typical tasks for you: [list common requests].\""}, {"part": 3, "label": "RULES", "template": "\"Always [do this]. Never [do that]. When unsure, [ask/suggest/default to this].\""}, {"part": 4, "label": "OUTPUT FORMAT", "template": "\"Respond with [structure: bullets, tables, short paragraphs]. Keep responses under [length]. Start with [summary/recommendation/question].\""}, {"part": 5, "label": "EXAMPLES", "template": "\"Here's what great output looks like: [provide 1-2 examples of ideal responses].\""}]}, "gem_power_moves": [{"move": 1, "title": "Connect to Google Drive", "description": "Upload your key business documents to a Google Drive folder. When chatting with your Gem, reference these files — Gemini can read them in real-time. Your brand guide updates? Your Gem sees the latest version automatically."}, {"move": 2, "title": "Share with Your Team", "description": "Click the share icon on any Gem → Set permissions (View, Use, or Edit). Your team gets the same specialist without building their own."}, {"move": 3, "title": "Chain Gems Together", "description": "Use one Gem's output as input for another. Example: Research Gem finds data → Content Gem writes the post → Social Media Gem adapts it for each platform."}], "comparison_table": {"title": "Claude Projects vs Gemini Gems: Quick Reference", "columns": ["Feature", "Claude Projects", "Gemini Gems"], "rows": [["Setup time", "5 minutes", "3 minutes"], ["Instructions", "Unlimited (200K context)", "Up to 15,000 tokens"], ["File access", "Upload to project", "Via Google Drive (real-time)"], ["Best strength", "Deep analysis, long docs", "Google Workspace integration"], ["Sharing", "Team plan only", "Anyone (like Google Docs)"], ["Code execution", "No (Projects), Yes (Skills)", "No"], ["Cost", "Free tier available, Pro for Projects", "Free tier basic, Advanced for full"]]}}, {"title": "Skill Template 01: The Marketing Manager", "type": "templates", "content": "This template turns Claude or Gemini into a dedicated marketing strategist that already knows your brand, audience, and competitive landscape. Instead of re-explaining your business every time you need a social post or campaign plan, paste this template once and get on-brand output instantly. Fill in the bracketed fields with your real business details — the more specific you are, the better the results. Most users have this running in under five minutes.", "description": "A copy-paste-ready marketing specialist that writes on-brand content, plans campaigns with budgets and timelines, and analyzes your performance data — all without you re-explaining your business every conversation.", "when_to_use": "Content creation, campaign planning, social media strategy, brand messaging, marketing analysis", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my dedicated Marketing Manager. You create marketing content, plan campaigns, and analyze performance — all tailored to my specific brand and audience.", "ABOUT_MY_BUSINESS": {"company_name": "[Your company]", "industry": "[Your industry]", "target_audience": "[Describe ideal customer — age, role, pain points, where they hang out online]", "brand_voice": "[e.g., professional but approachable / bold and direct / warm and conversational]", "key_products_services": "[List your main offerings]", "competitors": "[List 2-3 main competitors]", "unique_selling_point": "[What makes you different]"}, "YOUR_RESPONSIBILITIES": ["Create marketing copy that matches my brand voice exactly", "Suggest content ideas based on my target audience", "Plan campaigns with timelines, budgets, and KPIs", "Write social media posts, email sequences, and ad copy", "Analyze marketing metrics when I share data", "Keep messaging consistent across all channels"], "RULES": ["Always write in my brand voice — never generic corporate speak", "Every piece of content must have a clear call-to-action", "When suggesting strategies, include estimated budget and timeline", "Prioritize organic growth strategies for tight budgets", "Ask clarifying questions before making assumptions"], "OUTPUT_FORMAT": ["Start with a 1-sentence recommendation or summary", "Use bullet points for lists and action items", "Present options as: Option A / Option B / My Recommendation", "Include word counts for any long-form content", "For social posts: Hook line | Body | CTA | Hashtags"]}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Marketing Manager\"", "Paste the template above into Custom Instructions", "Upload: brand guidelines PDF, past campaign results, audience research", "Start chatting"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create a file called SKILL.md with the frontmatter + template", "Upload via Settings → Capabilities → Skills", "Claude will automatically use it when you ask marketing questions"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Marketing Manager\"", "Paste the template into the instructions field", "Save and pin to sidebar", "Store brand docs in a Google Drive folder for reference"]}], "first_task_prompt": "I need 5 social media post ideas for this week. My goal is to increase engagement by 20%. Suggest posts for [your platform], each with a different content angle.", "customization_tips": ["Replace all placeholder text in [BRACKETS] with your actual business details", "Test with a simple request first, then gradually try more complex tasks", "Save your customized version so you can reuse it without re-entering details", "If the output is too generic, add more specific context about your industry and audience"], "common_mistakes": ["Being too vague with business context — the more specific you are, the better the output", "Not iterating — your first result is a draft, ask the AI to refine it", "Ignoring the output format instructions — they ensure consistency across uses"], "real_world_example": "A freelance consultant used this skill to generate 4 weeks of LinkedIn posts in 15 minutes, each matching their professional tone and targeting their B2B audience."}, {"title": "Skill Template 02: The Content Writer", "type": "templates", "content": "Generic AI writing is easy to spot — and your audience can tell. This template solves that problem by training Claude or Gemini to write in your actual voice, not the default AI tone everyone recognizes. It includes rules against common AI cliches, enforces your preferred paragraph style, and makes the AI confirm the brief before writing. Pair it with the bonus Voice Profile Builder below to extract your writing DNA from real samples, then paste that profile into the template for output that genuinely sounds like you wrote it.", "description": "A personal ghostwriter that learns your exact writing style, eliminates AI-sounding cliches, and produces blog posts, emails, newsletters, and social captions that read like you wrote them yourself — complete with a voice extraction tool to capture your unique tone.", "when_to_use": "Blog posts, emails, newsletters, website copy, social media captions, any written content", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Content Writer. You write all types of content in MY voice — not generic AI voice. Every piece should sound like I wrote it myself.", "MY_WRITING_VOICE": {"tone": "[e.g., conversational and direct / witty and informal / authoritative but warm]", "i_always": "[e.g., use short paragraphs, start with a hook, include real examples]", "i_never": "[e.g., use cliches like 'in today's world', write long intros, use passive voice]", "signature_phrases": "[any expressions you commonly use]", "reading_level": "[e.g., smart professional, keep it accessible]"}, "CONTENT_RULES": ["Start with a hook — if the first line is boring, rewrite it", "Every paragraph must earn its place — cut filler ruthlessly", "Use specific examples, not generic advice", "Keep paragraphs under 4 sentences", "End with a clear call-to-action", "No corporate buzzwords: 'synergy', 'leverage', 'circle back'", "No AI cliches: 'dive into', 'landscape', 'in the realm of'"], "WHEN_I_REQUEST_CONTENT": ["First confirm: topic, length, platform, and audience", "Provide 3 headline/subject line options before writing", "Include SEO keywords naturally if I specify them", "For long-form: provide outline first, then full draft"], "OUTPUT_FORMAT": ["Always show word count at the end", "Format for the target platform (short for social, blog)", "Bold key takeaways or important lines", "If I say 'shorter' — cut by 30%, not 10%"]}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Content Writer\"", "Paste the template above into Custom Instructions", "Upload: 3-5 writing samples, brand style guide, any tone-of-voice docs", "Run the Voice Profile Builder bonus prompt first for best results"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Content Writer, description: Writes content in my voice", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Content Writer\"", "Paste the template into the instructions field", "Store writing samples in a Google Drive folder and reference them in chat", "Save and pin to sidebar"]}], "bonus_template": {"title": "The Voice Profile Builder", "description": "Run this prompt once before using the Content Writer. It analyzes your real writing samples and extracts a reusable Voice Profile you can paste into any AI template — so every piece of content matches your natural tone, sentence patterns, and vocabulary.", "prompt": "Analyze the following writing samples and extract my unique writing style. Create a detailed 'Voice Profile' covering:\n\n1. SENTENCE PATTERNS: Average length, simple vs complex, do I use fragments or questions?\n2. VOCABULARY: Formal vs casual, industry jargon used, words I favor\n3. TONE: Serious, playful, authoritative, conversational?\n4. PARAGRAPH STYLE: Short and punchy vs detailed?\n5. OPENINGS: How do I typically start pieces?\n6. TRANSITIONS: How do I connect ideas?\n7. QUIRKS: Any distinctive habits or patterns?\n\nFormat the output as instructions I can paste directly into an AI skill template.\n\nMY WRITING SAMPLES:\n[Paste 3-5 samples here — emails, posts, articles, anything you wrote naturally]", "pro_tip": "Use emails you've actually sent (not formal reports). Emails show your natural voice better than anything else."}, "customization_tips": ["Replace all placeholder text in [BRACKETS] with your actual business details", "Test with a simple request first, then gradually try more complex tasks", "Save your customized version so you can reuse it without re-entering details", "If the output is too generic, add more specific context about your industry and audience"], "common_mistakes": ["Being too vague with business context — the more specific you are, the better the output", "Not iterating — your first result is a draft, ask the AI to refine it", "Ignoring the output format instructions — they ensure consistency across uses"], "real_world_example": "A solopreneur used this skill to draft blog posts that maintained their casual, story-driven style — reducing writing time from 3 hours to 45 minutes per post."}, {"title": "Skill Template 03: The Financial Analyst", "type": "templates", "content": "Most people paste numbers into AI and get a generic summary back. This template produces a real analyst — one that knows your revenue model, your key metrics, and your reporting format. It enforces a consistent output structure (executive summary, findings, risk flags, action items) so every analysis is boardroom-ready. Upload a spreadsheet, tell it what you need, and get a structured financial brief instead of a wall of text. Works especially well in Claude, which can run calculations on your data directly.", "description": "A dedicated financial analyst that knows your revenue model, reporting cadence, and key metrics — produces executive-ready summaries, flags unusual expenses, compares periods, and ends every analysis with specific recommended actions you can act on immediately.", "when_to_use": "Financial data analysis, reporting, forecasting, budgeting, expense review, revenue analysis", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Financial Analyst. You analyze financial data, identify trends, and provide actionable insights — always in the context of my specific business.", "MY_BUSINESS_CONTEXT": {"business_type": "[Your business type]", "revenue_model": "[How you make money]", "revenue_range": "[Approximate annual/monthly revenue]", "key_metrics": "[e.g., MRR, profit margin, CAC, LTV, average order value, inventory turnover]", "reporting_period": "[Monthly / Quarterly / Annual]", "currency": "[Your primary currency]"}, "YOUR_TASKS": ["Analyze financial data I upload (spreadsheets, reports, bank statements)", "Identify trends, anomalies, and opportunities", "Create executive summaries of financial performance", "Compare periods (month-over-month, year-over-year)", "Flag expenses that seem unusual or growing too fast", "Help with forecasting and cash flow projections"], "ANALYSIS_RULES": ["Always start with a 3-sentence executive summary", "Use tables for any data comparisons", "Highlight numbers that need attention in bold", "Calculate percentage changes, not just raw numbers", "Distinguish between one-time events and recurring trends", "End every analysis with 'Recommended Actions' (max 3)"], "OUTPUT_FORMAT": ["Executive Summary (3 sentences)", "Key Findings (bullet points with numbers)", "Detailed Analysis (with tables where helpful)", "Risk Flags (anything concerning)", "Recommended Actions (max 3, specific and actionable)"]}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Financial Analyst\"", "Paste the template above into Custom Instructions", "Upload: recent P&L, budget spreadsheet, or bank export CSV", "Start chatting — Claude can run calculations directly on uploaded data"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Financial Analyst, description: Analyzes financial data and produces executive summaries", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Financial Analyst\"", "Paste the template into the instructions field", "Store financial spreadsheets in a Google Drive folder — Gemini reads them in real-time", "Best for quick Google Sheets analysis; use Claude for heavy number-crunching"]}], "bonus_template": {"title": "The Data Upload Template", "description": "Paste this briefing alongside any financial data you upload. It gives the AI the context it needs to skip generic summaries and jump straight to the insights that matter for your specific situation.", "template": "DATA BRIEFING:\nI've uploaded [file name]. This is [type of data].\n\nCONTEXT:\n- Each row represents: [what each row is]\n- Key columns: [list the important ones]\n- Time period: [date range covered]\n- Currency: [if applicable]\n\nWHAT I NEED:\n1. [Your specific question]\n2. [Second question]\n3. [Third question]\n\nCOMPARE TO: [Last quarter / same period last year / budget]\n\nFORMAT: Executive summary first, then detailed breakdown.", "pro_tip": "Claude handles spreadsheets better than Gemini for deep analysis (it can run Python on your data). Use Claude for heavy financial work, and Gemini Gems for quick Google Sheets tasks."}, "customization_tips": ["Replace all placeholder text in [BRACKETS] with your actual business details", "Test with a simple request first, then gradually try more complex tasks", "Save your customized version so you can reuse it without re-entering details", "If the output is too generic, add more specific context about your industry and audience"], "common_mistakes": ["Being too vague with business context — the more specific you are, the better the output", "Not iterating — your first result is a draft, ask the AI to refine it", "Ignoring the output format instructions — they ensure consistency across uses"], "real_world_example": "A small business owner used this skill to analyze 6 months of expenses and identify a recurring $200/month subscription they had forgotten about."}, {"title": "Skill Template 04: The Research Assistant", "type": "templates", "content": "Free AI gives you surface-level overviews that anyone could find with a search engine. This template creates a research specialist that delivers structured, decision-ready intelligence — with cited sources, comparison tables, clearly labeled facts vs. opinions, and flagged information gaps. It forces the AI to prioritize depth over breadth and always answer the question you actually care about: 'so what does this mean for my business?' Copy the template, fill in your industry and research needs, and get briefings you can take straight into a strategy meeting.", "description": "A structured research specialist that produces decision-ready briefings with cited sources, comparison tables, labeled facts vs. opinions, flagged information gaps, and a 'so what' analysis — replacing hours of manual research with actionable intelligence you can present to stakeholders.", "when_to_use": "Competitor research, market analysis, industry trends, technology evaluation, due diligence, preparing for meetings", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Research Assistant. You conduct thorough research and deliver structured, actionable findings — not generic overviews from Wikipedia.", "MY_RESEARCH_CONTEXT": {"industry": "[Your industry]", "role": "[Your position]", "typical_research_needs": "[e.g., competitor analysis, market trends, technology evaluation, supplier research]", "how_i_use_research": "[e.g., presentations, strategy meetings, investment decisions, reports]", "depth_preference": "[Executive summary vs deep dive]"}, "RESEARCH_RULES": ["Always cite sources with URLs when possible", "Distinguish facts from opinions — label clearly", "Flag outdated info (anything older than 6 months)", "When comparing options, always use tables", "Highlight surprising or counterintuitive findings", "Note information gaps — tell me what you couldn't find", "If a claim seems important, look for a second source"], "OUTPUT_STRUCTURE": ["Bottom Line (2 sentences — what I need to know)", "Key Findings (5-7 bullet points, most important first)", "Detailed Analysis (organized by topic)", "Comparison Table (when applicable)", "Sources (with URLs)", "Information Gaps (what needs further investigation)", "Recommended Next Steps"], "QUALITY_STANDARD": "I'd rather have 5 solid findings than 15 surface-level ones. Always provide 'so what?' — why should I care. If two sources disagree, present both and note the conflict."}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Research Assistant\"", "Paste the template above into Custom Instructions", "Upload: past research reports, industry PDFs, competitor profiles for reference", "Start chatting with one of the bonus prompts below"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Research Assistant, description: Conducts structured research and delivers decision-ready briefings", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Research Assistant\"", "Paste the template into the instructions field", "Gemini can access recent web data — ideal for competitor and market research", "Save and pin to sidebar for quick access"]}], "bonus_templates": [{"name": "Competitor Analysis Request", "prompt": "Research [competitor name]. I need:\n1. Their product/service lineup and pricing\n2. Their target audience (how it overlaps with mine)\n3. Their recent moves (last 6 months — launches, hires)\n4. Their strengths I should worry about\n5. Their weaknesses I could exploit\n6. What customers say about them (reviews, complaints)\n\nPresent as: Executive brief I can share with my team."}, {"name": "Market Trend Report", "prompt": "Research the current state of [topic/industry]. Cover:\n1. Market size and growth rate\n2. Top 3 trends shaping this space right now\n3. Key players and their market share\n4. Opportunities for a [your business type]\n5. Risks or threats to watch\n6. Timeline: what's happening in the next 6-12 months\n\nPresent as: Strategic briefing with a recommendation section."}, {"name": "Technology Evaluation", "prompt": "Compare [Tool A] vs [Tool B] vs [Tool C] for [my use case]. Evaluate on:\n1. Features relevant to my needs: [list specific needs]\n2. Pricing (include hidden costs)\n3. Ease of setup and learning curve\n4. Integration with my tools: [list your tools]\n5. What real users say (not just marketing claims)\n6. Your recommendation and reasoning\n\nPresent as: Comparison table + written recommendation."}], "customization_tips": ["Replace all placeholder text in [BRACKETS] with your actual business details", "Test with a simple request first, then gradually try more complex tasks", "Save your customized version so you can reuse it without re-entering details", "If the output is too generic, add more specific context about your industry and audience"], "common_mistakes": ["Being too vague with business context — the more specific you are, the better the output", "Not iterating — your first result is a draft, ask the AI to refine it", "Ignoring the output format instructions — they ensure consistency across uses"], "real_world_example": "A consultant used this skill to prepare a competitive landscape brief for a client pitch, pulling together key insights in 20 minutes instead of a full day."}, {"title": "Skill Template 05: The Customer Support Agent", "type": "templates", "content": "Inconsistent support responses cost you customers. This template creates an AI agent trained on your actual policies — return windows, shipping timeframes, escalation rules, and common complaint resolutions — so every response is accurate, empathetic, and on-brand. It enforces a response structure (acknowledge the feeling first, then solve the problem, then offer alternatives) that turns frustrated customers into loyal ones. Paste in your real policies, and the AI drafts responses you can send as-is or lightly edit. Saves hours per week for anyone handling customer inquiries.", "description": "A policy-trained support agent that drafts empathetic, accurate customer responses using your real return policies, shipping windows, and escalation rules — with built-in scenario templates for refunds, complaints, and common issues that you can deploy across email, chat, and social channels.", "when_to_use": "Responding to customer inquiries, drafting support emails, handling complaints, FAQ management", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Customer Support Agent. You draft professional, empathetic responses to customer inquiries based on my company's actual policies and procedures.", "COMPANY_INFORMATION": {"company": "[Your company name]", "products_services": "[List main offerings]", "support_channels": "[Email, chat, phone, social media]", "business_hours": "[Your hours and timezone]", "website": "[Your URL]"}, "POLICIES": {"return_refund": "[Your actual policy]", "shipping_delivery": "[Timeframes and methods]", "warranty_guarantee": "[If applicable]", "common_issues": "[List top 5 customer complaints and standard resolutions]", "escalation_triggers": "[When to recommend a human — e.g., billing disputes over $X, legal threats]"}, "RESPONSE_RULES": ["Always acknowledge the customer's feeling first", "Provide a clear solution or next step", "Keep responses under 150 words", "Offer alternatives if the first solution isn't possible", "End with: 'Is there anything else I can help with?'", "Never promise anything outside our stated policies", "Never argue — if wrong, redirect politely", "For angry customers: empathize, apologize, solve"], "TONE": "Warm, helpful, professional. Never robotic, never overly casual. Think 'friendly expert.'", "SIGNATURE": "[Your preferred sign-off — e.g., 'Best regards, [Name] — [Company] Support Team']"}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Customer Support Agent\"", "Paste the template above into Custom Instructions", "Upload: FAQ document, return/refund policy PDF, product catalog", "Test with the scenario prompts below before going live"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Customer Support, description: Drafts support responses using company policies", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Customer Support Agent\"", "Paste the template into the instructions field", "Store policy docs and FAQs in a Google Drive folder for live reference", "Share with your support team — they can all use the same Gem"]}], "common_support_scenarios": [{"scenario": "Refund Request", "prompt": "Customer wants a refund for [product/reason].\n\nDraft a response that:\n1. Acknowledges their frustration\n2. Confirms our refund policy applies\n3. Explains the process and timeline\n4. Offers an alternative (exchange, credit) if applicable\n5. Keeps it under 120 words"}, {"scenario": "Complaint About Quality", "prompt": "Customer is unhappy with [product/service quality].\n\nDraft a response that:\n1. Thanks them for the feedback\n2. Apologizes for the experience\n3. Asks specific questions to understand the issue\n4. Offers a concrete resolution\n5. Assures them of quality commitment"}, {"scenario": "Shipping Delay", "prompt": "Customer is asking about a delayed order [order number/details].\n\nDraft a response that:\n1. Apologizes for the delay\n2. Provides a realistic updated timeline\n3. Explains what happened (if known) without making excuses\n4. Offers compensation if appropriate (discount, free shipping on next order)\n5. Gives them a way to track the order"}, {"scenario": "Feature Request or Product Question", "prompt": "Customer is asking about [feature/capability] that we don't currently offer.\n\nDraft a response that:\n1. Thanks them for the suggestion\n2. Honestly states whether it's on our roadmap or not\n3. Suggests the closest existing alternative\n4. Offers to notify them if/when the feature launches\n5. Keeps the tone encouraging, not dismissive"}], "customization_tips": ["Replace all placeholder text in [BRACKETS] with your actual business details", "Test with a simple request first, then gradually try more complex tasks", "Save your customized version so you can reuse it without re-entering details", "If the output is too generic, add more specific context about your industry and audience"], "common_mistakes": ["Being too vague with business context — the more specific you are, the better the output", "Not iterating — your first result is a draft, ask the AI to refine it", "Ignoring the output format instructions — they ensure consistency across uses"], "real_world_example": "An e-commerce solopreneur used this skill to handle common customer questions during a product launch, maintaining a consistent, friendly tone across 50+ responses."}, {"title": "Advanced Skill 01: Voice Cloning — Make AI Sound Like You", "type": "advanced", "content": "The most powerful skill you can build is one that sounds exactly like you. Generic AI writing has a recognizable tone that erodes trust with your audience. Voice cloning fixes this by extracting the specific patterns, vocabulary, sentence structures, and personality markers from your real writing — then encoding them as reusable instructions. Run the extraction prompt once, save the output as your Voice Profile, and paste it into any Skill or Gem template. Every piece of content will match your natural style instead of defaulting to AI-speak.", "voice_extraction_prompt": "Analyze the following writing samples and extract my unique voice. Identify:\n\n1. TONE: How formal/casual? Serious or playful?\n2. SENTENCE STRUCTURE: Long and complex or short and punchy?\n3. VOCABULARY: Technical jargon or plain language? Favorite words/phrases?\n4. PATTERNS: How do I start paragraphs? How do I make transitions?\n5. PERSONALITY MARKERS: Humor, directness, warmth, confidence level?\n6. THINGS I AVOID: What's noticeably absent from my writing?\n\nThen create a 'Voice Replication Guide' I can paste into any AI prompt to make it write like me.\n\nSAMPLES:\n[Paste 5+ varied writing samples — emails, posts, reports]", "voice_testing_prompt": "Write a [type of content] about [topic] using my Voice Profile below. After writing it, rate how closely it matches my voice on a scale of 1-10, and identify any places where you defaulted to generic AI writing instead of my style.\n\nVOICE PROFILE:\n[Paste your extracted voice profile]", "pro_tip": "The more varied your samples, the better the profile. Include emails (casual), reports (formal), and social posts (natural) for the most accurate voice extraction.", "when_to_use": "Use this technique when you need AI to write in YOUR voice — emails, social posts, blog articles, or client communications that should sound authentically you.", "difficulty": "Intermediate — requires 5-10 sample texts to calibrate"}, {"title": "Advanced Skill 02: Prompt Chaining — Multi-Step Workflows", "type": "advanced", "content": "Single prompts are powerful. Chains are transformative. A prompt chain breaks complex work into sequential steps where each output feeds the next input. This matters because AI produces dramatically better results when it focuses on one task at a time — research separately from writing, writing separately from editing. The templates below are copy-paste chains you can run manually (pasting each output into the next step) or save as a Claude Skill that runs the full sequence automatically when triggered.", "why_chains_work": "1. Each step can be optimized independently. 2. You can review and edit between steps. 3. The AI focuses on one thing at a time — better outputs. 4. Complex tasks become manageable.", "templates": [{"name": "The Content Creation Chain (4 Steps)", "steps": [{"step": 1, "label": "RESEARCH", "prompt": "Research [topic] for a [content type] targeting [audience]. Find: 5 key facts, 3 current trends, 2 common misconceptions, and 3 expert viewpoints. Format as bullet points."}, {"step": 2, "label": "OUTLINE", "prompt": "Using the research above, create a detailed outline for a [content type] targeting [audience]. Include: hook, 4-5 main sections with sub-points, and conclusion."}, {"step": 3, "label": "DRAFT", "prompt": "Write the full piece following this outline exactly. Tone: [your tone]. Length: [target]. Use specific data and examples from the research. No filler paragraphs."}, {"step": 4, "label": "POLISH", "prompt": "Review this draft as a senior editor. Score each section 1-10 on clarity, engagement, and accuracy. Fix everything below 8. Output the final version."}]}, {"name": "The Business Decision Chain (3 Steps)", "steps": [{"step": 1, "label": "ANALYZE", "prompt": "I'm considering [decision]. Analyze:\n- 5 pros and 5 cons\n- Financial implications (cost, revenue impact, ROI)\n- Risk level for each factor (High/Medium/Low)\n- What competitors have done in similar situations"}, {"step": 2, "label": "CHALLENGE", "prompt": "Now act as a skeptical advisor. Poke holes in the analysis above. What am I missing? What could go wrong? What assumptions might be wrong? Rate each risk by likelihood and severity."}, {"step": 3, "label": "DECIDE", "prompt": "Based on both the analysis and the critique, give me your final recommendation. Structure as:\n- Decision: [Yes/No/Modify]\n- Confidence level: [%]\n- Top 3 conditions that must be true for success\n- If I proceed: first 3 actions and timeline\n- If I don't: best alternative"}]}, {"name": "The Email Campaign Chain (3 Steps)", "steps": [{"step": 1, "label": "AUDIENCE", "prompt": "My target audience for this email campaign is [describe]. Their biggest pain point right now is [describe]. Identify: what they want, what they fear, what would make them click, and what would make them unsubscribe."}, {"step": 2, "label": "SEQUENCE", "prompt": "Based on this audience analysis, design a 5-email sequence. For each email: subject line, goal, key message, CTA, and optimal send timing."}, {"step": 3, "label": "WRITE", "prompt": "Now write emails #1 and #2 in full. Tone: [your tone]. Each under 200 words. Subject lines must create curiosity without being clickbait."}]}], "pro_tip": "Save your best chains as Claude Skills or Gemini Gems. Instead of remembering the steps each time, just tell your AI: 'Run the content chain on [topic]' and it does all 4 steps automatically.", "when_to_use": "Use prompt chaining when a single prompt cannot produce the quality you need. Break complex tasks into 3-5 sequential steps where each output feeds the next.", "difficulty": "Advanced — best suited for multi-step content creation or analysis workflows"}, {"title": "Advanced Skill 03: The Self-Improving Loop", "type": "advanced", "content": "Make AI critique and improve its own work — automatically. AI's first draft is rarely its best work, but most people just accept whatever it generates. Power users know the secret: make AI be its own editor. The Quality Loop below forces AI to generate, then score its own output against six criteria, then rewrite anything below an 8 out of 10. The result is consistently higher-quality output that would normally take two or three manual revision rounds. Save this loop as a Claude Skill and it runs automatically on every piece of content you create.", "quality_loop": {"step_1": {"label": "GENERATE", "instruction": "[Your normal prompt to create something]"}, "step_2": {"label": "CRITIQUE", "prompt": "Review what you just created. Act as a demanding client who is paying $5,000 for this work. Score it 1-10 on:\n- Clarity: Is every point crystal clear?\n- Specificity: Concrete examples or vague hand-waving?\n- Engagement: Would the reader stay interested throughout?\n- Accuracy: Any claims that aren't backed up?\n- Structure: Does it flow logically?\n- Originality: Does it say anything the reader hasn't heard before?\n\nFor each score below 8, explain EXACTLY what's wrong and provide a specific fix."}, "step_3": {"label": "IMPROVE", "prompt": "Now rewrite it, applying every fix you identified. The new version must score 8+ on ALL criteria. Show me the updated scores alongside the final version."}}, "more_templates": [{"name": "The Devil's Advocate", "prompt": "I'm planning to [decision/strategy/approach].\n\n1. First, make the STRONGEST case FOR this plan\n2. Then switch roles: make the STRONGEST case AGAINST it\n3. For each criticism, rate severity (1-5) and suggest how to address it\n4. Final verdict: Proceed / Modify / Abandon? Include your confidence level."}, {"name": "The Customer Test", "prompt": "Review this [email/landing page/product description] as if you're my target customer: [describe them].\n\n1. First impression in 3 seconds — would you keep reading?\n2. What's compelling? What's confusing?\n3. What questions do you still have after reading?\n4. Would you [buy/click/sign up]? Be brutally honest.\n5. Rewrite the weakest section to convert you."}, {"name": "The Simplifier", "prompt": "Rewrite this [content] at a 6th-grade reading level without losing any of the key information. Then check:\n- Did any important nuance get lost? If yes, add it back in simple terms.\n- Is there any jargon remaining? Replace it.\n- Read it aloud — does it flow naturally? Fix any awkward sentences."}], "pro_tip": "The Quality Loop works especially well as a Claude Skill. Create a skill that automatically runs the Generate → Critique → Improve cycle for any content type.", "when_to_use": "Use this when you want your AI skill to get better over time — it learns from corrections and builds a knowledge base of your preferences.", "difficulty": "Advanced — requires consistent feedback and iteration over multiple sessions"}, {"title": "Installable AI Tools — 3 Claude Skills", "type": "skills", "content": "Ready-to-install AI tools built specifically for solopreneurs. Each tool is a pre-configured AI specialist that you install once and use forever. Copy the code below, follow the install steps, and you'll have a working AI assistant in under 5 minutes.", "install_overview": {"claude": {"title": "How to Install Claude Skills", "steps": ["Open Claude (claude.ai) and sign in", "Type /skill-creator in any conversation", "Paste the SKILL.md content when prompted", "Name your skill and save — it's now available in all your conversations"]}, "gemini": {"title": "How to Install Gemini Gems", "steps": ["Open Gemini (gemini.google.com) and sign in", "Click \"Gem manager\" in the left sidebar", "Click \"New Gem\" and give it a name", "Paste the system prompt into the instructions field and save"]}}, "skills": [{"name": "Brand Voice Engine", "description": "Solopreneurs who want all AI output to sound like THEM, not like AI", "platform": "Claude Skill", "system_prompt": "You are Brand Voice Engine — a specialized AI assistant for solopreneurs.\nYour job is to learn how the user writes and sounds, then make sure every piece of AI-generated content sounds like them — not like a generic chatbot.\nHow you work:\nFirst interaction: Ask the user to paste 3-5 examples of their own writing (emails, posts, articles, anything). Tell them: the more variety, the better. Once you have samples, analyze them and produce a Voice Profile. Save this profile and reference it every time you write content for them. If they've already shared their voice profile in a previous session, ask them to paste it at the start of the conversation so you can apply it immediately.\nVoice Profile format (what you extract and output):\n- Tone: (e.g., direct and warm, dry with occasional humor, enthusiastic but grounded)\n- Sentence style: (e.g., short punchy sentences, conversational run-ons, mix of both)\n- Vocabulary patterns: (words/phrases they use often, level of formality, industry terms they favor)\n- What they avoid: (corporate-speak, excessive punctuation, passive voice, etc.)\n- Signature moves: (any distinctive habits — rhetorical questions, specific openers, how they end pieces)\nAfter the profile is set:\nEvery content request gets written using those rules. At the end of each piece, add a one-line note like 'Voice check: used short sentences, avoided jargon, kept the direct opener style.' If a request conflicts with their voice (e.g., they want formal but their voice is casual), flag it and ask.\nFormatting rules:\nVoice Profile should be clearly labeled and easy to copy/paste. All content output should look clean and post-ready with no formatting instructions left in."}, {"name": "Meeting Action Extractor", "description": "Solopreneurs who leave meetings with vague notes and forget follow-ups", "platform": "Claude Skill", "system_prompt": "You are Meeting Action Extractor — a specialized AI assistant for solopreneurs.\nYour job is to turn messy meeting notes, transcripts, or voice-memo dumps into a clean, structured summary that's ready to send to attendees — so nothing falls through the cracks.\nHow you work:\nThe user pastes in raw notes or a transcript. You parse it immediately — no need to ask questions first unless the content is too fragmented to work with. If names are mentioned without clear ownership of tasks, flag them rather than guess. Produce the full summary in one clean output.\nWhat you produce for every meeting:\n- Meeting Snapshot: Date (if mentioned), attendees (if mentioned), purpose in one sentence\n- Decisions Made: Clear list of things that were agreed on — no ambiguity\n- Action Items: Table or list with three columns: Task | Owner | Due Date. If owner or date wasn't stated, write 'TBD' and flag it\n- Open Questions: Things that came up but weren't resolved — needs follow-up\n- Key Takeaways: 3-5 bullet points capturing the most important context for someone who wasn't in the meeting\nRules you always follow:\nIf something sounds like a maybe or a soft suggestion rather than a committed action, put it in Open Questions, not Action Items. Don't pad the summary with meeting pleasantries or filler. Be ruthlessly clear. If the notes are from a 1-on-1 vs. a team meeting, adjust the tone of the summary accordingly.\nFormatting rules:\nSection headers, clearly labeled. Action items as a table whenever possible. Keep the full summary under one page. Include a line at the top: 'Ready to send — review action item owners and dates before sharing.'"}, {"name": "SEO Content Optimizer", "description": "Solopreneurs who want their content to rank on Google without hiring an SEO expert", "platform": "Claude Skill", "system_prompt": "You are SEO Content Optimizer — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners get their content found on Google — without needing to understand SEO deeply or hire an expert.\nHow you work:\nThe user pastes in a piece of content (blog post, service page, landing page) and optionally tells you the target keyword or topic. If no keyword is provided, you identify the most logical primary keyword from the content itself and confirm it before proceeding. Then you run the full analysis and produce actionable output — not a lecture, just the fixes.\nWhat you produce for every content review:\n- Primary Keyword Assessment: Is it used in the right places? (title, H1, first 100 words, meta description, at least 2-3 times in body)\n- Meta Description: Write or rewrite it — under 155 characters, includes keyword, has a CTA or compelling reason to click\n- Header Structure: Review H1/H2/H3 usage. Suggest rewrites if headers don't include keyword variations or don't reflect what readers are searching\n- Readability Check: Flag sentences over 25 words, passive voice, dense paragraphs. Suggest plain-language rewrites for 2-3 examples\n- Internal Linking Opportunities: Based on what the user tells you about their other content, suggest where to link\n- Quick Wins: 3-5 specific, prioritized fixes labeled by impact (High / Medium / Low)\nRules you always follow:\nNever suggest keyword stuffing. Prioritize readability over optimization — Google rewards content people actually finish reading. Give specific rewrites, not vague advice like 'improve your headers.'\nFormatting rules:\nSection headers for each area. Quick Wins table at the end. Rewrite suggestions clearly labeled as 'Original' and 'Suggested.'"}]}, {"title": "Level Up", "type": "cta", "content": "You've just built your AI dream team. These five specialists and three advanced techniques put you ahead of 95% of AI users who are still typing one-off prompts. Continue your AI mastery journey with our other courses.", "items": [{"offer": "AI Starter Kit", "price": "$19", "description": "50+ ready-to-use prompts for Claude and Gemini across writing, business, and productivity", "url": "https://www.kh-academy.com"}, {"offer": "AI for Small Business Owners", "price": "$47", "description": "Pre-built AI skills for operations, HR, finance, and customer management", "url": "https://www.kh-academy.com"}, {"offer": "AI Automation Cookbook", "price": "$67", "description": "Advanced multi-step automation workflows you can install and run immediately", "url": "https://www.kh-academy.com"}, {"offer": "Ultimate AI Bundle", "price": "$147", "description": "Every KH Academy product — all skills, all templates, all future updates included", "url": "https://www.kh-academy.com"}], "purchase_url": "https://kh-academy-storefront.vercel.app/#pricing", "storefront_url": "https://kh-academy-storefront.vercel.app"}]};

export const SMALL_BUSINESS_DATA: CourseData = {"product_id": "small-business", "title": "AI for Small Business", "subtitle": "Ready-to-Deploy AI Systems That Run Your Business While You Sleep", "tagline": "6 Complete Business Systems + Templates Inside", "source": "ai-small-business.pdf", "version": "1.0 — March 2026", "pages": 44, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "YOUR BUSINESS DOESN'T NEED MORE AI ADVICE. IT NEEDS AI SYSTEMS. You've read the articles. You've tried the prompts. But here's what nobody tells you: using AI for one task at a time is like hiring an employee and only letting them answer one question per day. This playbook is different. Instead of scattered prompts, you get complete business systems — tested workflows where AI handles entire processes from start to finish. Each system comes with ready-to-use templates you customize once, then run forever.", "comparison": {"what_most_people_do": ["Ask AI one question at a time", "Start over every session", "Get generic answers", "Waste 2+ hours daily on repetitive tasks"], "what_this_playbook_gives_you": ["Complete systems that chain tasks", "Pre-loaded business context", "Output tailored to YOUR business", "Systems that run in under 15 minutes"]}, "items": []}, {"title": "How to Use This Playbook", "type": "instructions", "content": "Three-step guide to deploying AI systems in your business.", "items": [{"step": 1, "title": "Pick a System", "instruction": "Start with your biggest time-waster. Each system stands alone."}, {"step": 2, "title": "Fill in Your Details", "instruction": "Every template has [BRACKETS] for your business info. Fill once, use forever."}, {"step": 3, "title": "Deploy & Repeat", "instruction": "Use the system daily — AI remembers your context and gets better over time."}]}, {"title": "Table of Contents", "type": "toc", "content": "3 parts. 6 systems. All templates included.", "items": [{"part": "I — FOUNDATION", "chapter": "01", "title": "The AI Business Profile", "pages": "4-5"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "02", "title": "Customer Inquiry & Response", "pages": "6-13"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "03", "title": "Content & Social Media", "pages": "14-18"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "04", "title": "Financial Analysis & Reporting", "pages": "19-22"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "05", "title": "Sales & Lead Follow-Up", "pages": "23-28"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "06", "title": "Operations & SOP", "pages": "29-32"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "07", "title": "Hiring & Team Management", "pages": "33-36"}, {"part": "III — CUSTOMIZATION", "chapter": "08", "title": "Industry Quick-Start Guides", "pages": "37-39"}, {"part": "III — CUSTOMIZATION", "chapter": "09", "title": "Your AI Operations Manual", "pages": "40-41"}, {"part": "III — CUSTOMIZATION", "chapter": "10", "title": "What's Next: Systems to Automation", "pages": "42-43"}]}, {"title": "Chapter 01: The AI Business Profile", "type": "templates", "content": "Fill this in ONCE. Every system in this playbook uses it.", "master_template": {"label": "BUSINESS PROFILE — [Your Business Name]", "fields": {"industry": "[e.g., Restaurant / Retail / Consulting / Freelance]", "business_type": "[B2B / B2C / Both]", "years_operating": "[___]", "team_size": "[Solo / 2-5 / 6-20 / 20+]", "customers": {"primary_customer": "[Who buys from you? Age, role, situation]", "pain_points": "[Top 3 problems you solve]", "average_transaction_value": "$[___]", "how_customers_find_you": "[Social / Referral / Walk-in / Search]"}, "voice_and_brand": {"brand_tone": "[Professional / Friendly / Casual / Luxury / Fun]", "words_we_always_use": "[3-5 brand words]", "words_we_never_use": "[3-5 words to avoid]", "competitor_difference": "[What makes you different in 1 sentence]"}, "operations": {"biggest_time_waster": "[The task that eats most of your week]", "software_you_use": "[List your tools — POS, CRM, email, etc.]", "business_hours": "[___]", "peak_season": "[___]"}}}, "how_to_use_profile": [{"step": 1, "platform": "Claude", "instruction": "Copy your completed Business Profile into a Claude Project as the project instruction. Every conversation in that project will automatically know your business."}, {"step": 2, "platform": "Gemini", "instruction": "Paste your profile at the start of any Gemini Gem instruction. The Gem becomes a specialist that already knows who you are."}, {"step": 3, "platform": "Everywhere", "instruction": "Every system in this playbook references [YOUR PROFILE] — that means this template. Fill it once and all 6 systems auto-customize to your business."}], "pro_tip": "Update your Business Profile quarterly as your business evolves. Your prices change, your customers shift, your tools upgrade — keep this document alive and every AI system stays current."}, {"title": "System 01: Customer Response System", "type": "system", "problem": "You spend 1-2 hours daily writing similar emails and messages", "solution": "A system that drafts responses in your brand voice in under 60 seconds", "time_saved": "8-10 hours per week", "whats_inside": ["8 ready-to-use response templates (all fully written out)", "Escalation decision tree (AI vs. human)", "Claude Skill + Gemini Gem setup instructions", "AI prompts to customize any response"], "response_templates": [{"template_number": 1, "name": "New Inquiry / First Contact", "scenario": "Someone contacts you for the first time", "trigger": "New email, DM, or form submission", "tone": "[BRAND TONE] — warm, welcoming", "template": "Hi [Customer Name],\n\nThanks so much for reaching out to [YOUR BUSINESS]!\n\nI'd love to help you with [restate their question/need].\n\nHere's a quick overview of what we offer:\n[YOUR TOP 2-3 SERVICES/PRODUCTS with 1-line descriptions]\n\nWould you like to [get a quote]? I'm happy to help you find the right fit.\n\nLooking forward to connecting,\n[YOUR NAME]\n[YOUR PREFERRED CONTACT METHOD]"}, {"template_number": 2, "name": "Pricing Question", "scenario": "Customer asks about pricing", "trigger": "Customer asks 'how much' or 'what do you charge'", "tone": "[BRAND TONE] — confident, transparent", "template": "Hi [Customer Name],\n\nThanks for your interest in [YOUR BUSINESS]!\n\nHere's our pricing for [what they asked about]:\n[Price details from YOUR product/service list]\n\nWhat makes us different: [YOUR COMPETITOR DIFFERENCE]\n\nHappy to answer any other questions —\n[YOUR PREFERRED CONTACT METHOD]\n\n[YOUR NAME]"}, {"template_number": 3, "name": "Complaint / Negative Feedback", "scenario": "Customer is unhappy or reports a problem", "trigger": "Complaint email, negative review, angry message", "tone": "[BRAND TONE] — empathetic, solution-focused", "template": "Hi [Customer Name],\n\nThank you for letting us know about this. I'm really sorry you had this experience — that's not the standard we hold ourselves to at [YOUR BUSINESS].\n\nHere's what I'd like to do to make this right:\n[Specific remedy: refund / redo / discount / replacement]\n\nI've also [updated our process / personally reviewed what happened] so this doesn't happen again.\n\nCan I [call you / schedule a time to chat] to make sure you're fully taken care of?\n\n[YOUR NAME]"}, {"template_number": 4, "name": "Follow-Up (No Response)", "scenario": "You reached out but haven't heard back", "trigger": "3-5 days since last contact with no reply", "tone": "[BRAND TONE] — helpful, not pushy", "template": "Hi [Customer Name],\n\nJust checking in — I wanted to make sure my last message didn't get buried in your inbox!\n\nTo recap, you asked about [their original question], and I'd shared [brief summary of your response].\n\nIf you have any other questions or if your needs have changed, I'm here to help. No pressure at all.\n\nHave a great [day of week]!\n[YOUR NAME]"}, {"template_number": 5, "name": "Booking / Appointment Confirmation", "scenario": "Customer books an appointment or reservation", "trigger": "New booking received", "tone": "[BRAND TONE] — organized, reassuring", "template": "Hi [Customer Name],\n\nYou're all set! Here are your booking details:\n\nDate: [DATE]\nTime: [TIME]\nLocation: [ADDRESS / virtual link]\nService: [WHAT THEY BOOKED]\n\nA few things to know before your visit:\n- [Preparation info: what to bring, parking, etc.]\n- [Cancellation/reschedule policy]\n\nIf anything changes, just reply to this message or call us at [PHONE]. We look forward to seeing you!\n\n[YOUR NAME] at [YOUR BUSINESS]"}, {"template_number": 6, "name": "Thank You / Post-Purchase", "scenario": "Customer just made a purchase or completed service", "trigger": "Transaction complete", "tone": "[BRAND TONE] — grateful, personal", "template": "Hi [Customer Name],\n\nThank you for choosing [YOUR BUSINESS]! We truly appreciate your [purchase / visit / business].\n\nJust a quick summary:\n[Order details / service summary / receipt reference]\n\nA few things that might be helpful:\n- [Care instructions / next steps / how to get support]\n- [Warranty / return policy reminder]\n\nIf you enjoyed your experience, we'd love a quick review on [Google / Yelp / your platform]: [REVIEW LINK]\n\nThanks again — hope to see you back soon!\n[YOUR NAME]"}, {"template_number": 7, "name": "Refund / Cancellation Request", "scenario": "Customer wants a refund or to cancel", "trigger": "Refund/cancellation request received", "tone": "[BRAND TONE] — understanding, professional", "template": "Hi [Customer Name],\n\nI understand, and I appreciate you letting us know.\n\nI've started processing your [refund / cancellation]. Here's what to expect:\n- [Timeline: refund in 5-7 business days / etc.]\n- [Any conditions or next steps they need to take]\n\nIf you don't mind me asking — was there anything we could have done differently? Your feedback helps us improve for everyone.\n\nYou're always welcome back at [YOUR BUSINESS].\n\n[YOUR NAME]"}, {"template_number": 8, "name": "Review Request", "scenario": "You want to ask a happy customer for a review", "trigger": "1-3 days after positive interaction or purchase", "tone": "[BRAND TONE] — warm, appreciative, brief", "template": "Hi [Customer Name],\n\nIt was great [helping you with ___] recently!\n\nIf you have 30 seconds, a quick review would mean the world to us. It helps other people like you find us:\n\n[REVIEW LINK — Google / Yelp / Facebook / your platform]\n\nNo pressure at all — and thank you again for choosing [YOUR BUSINESS]. We're here whenever you need us!\n\n[YOUR NAME]"}], "escalation_decision_tree": [{"situation": "Simple question", "action": "AI handles it (use response template)"}, {"situation": "Pricing inquiry", "action": "AI drafts, quick review, then send"}, {"situation": "Complaint", "action": "AI drafts, YOU review before sending"}, {"situation": "Legal / safety issue", "action": "YOU handle directly — no AI"}, {"situation": "VIP / high-value", "action": "AI drafts, YOU personalize & send"}], "pro_tip": "Set a rule: if the customer's issue involves money, emotions, or legal risk — always have a human review before sending. AI is great at drafting, but judgment calls need you.", "time_savings": {"before": "1-2 hours/day writing repetitive responses", "after": "Under 10 minutes — AI drafts, you approve"}, "ai_skill_instructions": {"claude": {"skill_name": "Customer Response Agent", "role": "You are a customer response specialist for [YOUR BUSINESS NAME].", "context": "Use the Business Profile attached to this project to understand our brand, customers, and tone.", "rules": ["Always match our brand tone: [BRAND TONE]", "Include our differentiator when relevant", "Keep responses under 150 words", "Flag complaints for human review", "Never make promises about pricing or timelines without checking the product/service list"], "workflow": ["Read the customer message", "Identify the scenario type (pricing, complaint, etc.)", "Use the matching template from the library", "Customize with business details", "Output: ready-to-send response"]}, "gemini": {"gem_name": "Customer Response Agent", "instructions": "You are a customer response specialist for [YOUR BUSINESS NAME]. Use the Business Profile in my instructions to understand our brand. When I paste a customer message, identify the type (pricing, complaint, review request, etc.) and draft a response using our brand tone: [BRAND TONE]. Keep it under 150 words. Flag complaints for review."}}, "quick_use_prompts": [{"label": "AI Prompt (Claude / Gemini)", "prompt": "Using my Business Profile, draft a response to this customer message: [paste message]. Identify which scenario it is (new inquiry, pricing, complaint, follow-up, booking, thank you, refund, or review request) and use the matching template. Match my brand tone. Keep it under 100 words."}, {"label": "Review Response Prompt (Claude / Gemini)", "prompt": "A customer left this negative review: [paste review]. Draft a public response that (1) acknowledges their concern\n\n(2) apologizes sincerely\n\n(3) offers a specific remedy, and (4) invites them to continue the conversation privately. Match my brand tone: [BRAND TONE]."}, {"label": "Batch Follow-Up Prompt (Claude / Gemini)", "prompt": "I need to follow up with [X] customers who haven't responded. Here are their names and original inquiries: [paste list]. For each, draft a brief, friendly follow-up using Template 4. Personalize each one based on their original question."}], "content": "Most business owners spend 1-2 hours every day writing the same types of emails and messages — greetings, pricing replies, complaint responses, follow-ups. This system eliminates that repetitive work by giving you 8 pre-built response templates that AI customizes to your brand voice in under 60 seconds. You load your Business Profile once into a Claude Project or Gemini Gem, paste any incoming customer message, and the AI identifies the scenario type, selects the right template, and drafts a polished response you can send immediately. The escalation decision tree tells you exactly when AI handles it alone versus when you should review first — so complaints and VIP customers always get your personal touch. Tested across service businesses, retail, and restaurants: owners report cutting response time from 42 minutes average down to under 2 minutes per message.", "implementation_time": "30 minutes", "expected_result": "Handle 80% of common inquiries automatically with consistent, professional responses", "roi_indicator": "Saves 5-10 hours/week on email responses"}, {"title": "System 02: Content & Social Media", "type": "system", "problem": "Content creation takes 5+ hours/week and still feels inconsistent", "solution": "A batch system that produces a full week of branded content in one sitting", "time_saved": "4-6 hours per week", "whats_inside": ["4-pillar content framework (customized to your business)", "30-minute batch workflow (a full week of content)", "Platform-specific templates (Instagram, Facebook, LinkedIn, Email)", "AI prompts for both Claude and Gemini"], "content_pillar_framework": {"description": "Stop guessing what to post. These 4 pillars give you a rotation system that keeps content varied, on-brand, and engaging.", "pillars": [{"number": 1, "name": "Behind the Scenes", "description": "How we do it, workspace tours, process reveals, day-in-the-life"}, {"number": 2, "name": "Customer Results", "description": "Testimonials, before-after, case studies, success stories"}, {"number": 3, "name": "Education & Tips", "description": "How-to's, tips your audience needs, myth-busting, FAQs"}, {"number": 4, "name": "Personality & Culture", "description": "Team introductions, values, humor, what makes you human"}], "weekly_rotation": {"Monday": "Pillar 1 — Behind the Scenes", "Tuesday": "Pillar 2 — Customer Results", "Wednesday": "Pillar 3 — Education & Tips", "Thursday": "Pillar 4 — Personality & Culture", "Friday": "Pillar 2 or 3 — Repurpose best performer"}}, "batch_workflow": {"title": "The 30-Minute Batch Workflow", "description": "One sitting. One week of content.", "steps": [{"step": 1, "action": "Feed AI Your Context", "detail": "Paste Business Profile + this week's theme. (2 min)"}, {"step": 2, "action": "Generate 5 Post Concepts", "detail": "Ask AI for 5 ideas using Pillar rotation. (3 min)"}, {"step": 3, "action": "Expand to Drafts", "detail": "AI writes platform-specific drafts. (10 min)"}, {"step": 4, "action": "Add Captions & Hashtags", "detail": "Generate captions and hashtags. (5 min)"}, {"step": 5, "action": "Create Newsletter", "detail": "Convert best post into email newsletter. (5 min)"}, {"step": 6, "action": "Review & Schedule", "detail": "Quick review, adjust, schedule. (5 min)"}], "ai_prompt": "Using my Business Profile, create 5 social media post concepts for this week. Use the 4-pillar rotation. Theme: [YOUR THEME]. For each: headline, 2-sentence description, suggested visual, and best platform."}, "platform_templates": [{"platform": "Instagram", "format": "Carousel / Single Post / Story Sequence", "structure": {"hook": "[Attention-grabbing question or stat]", "body": "[2-3 short paragraphs, one idea per paragraph]", "cta": "[What you want them to do — save, share, comment]", "hashtags": "[5-10 relevant, mix of niche + broad]"}, "ai_prompt": "Write an Instagram [carousel/post/story] about [TOPIC] for my [INDUSTRY] business. Use my brand tone: [BRAND TONE]. Hook them with the first line."}, {"platform": "Facebook", "format": "Engagement Post / Event Promo / Review Share", "structure": {"opening": "[Personal story or question to spark comments]", "body": "[Conversational, 3-5 sentences max]", "cta": "[Ask a question to drive comments]"}, "ai_prompt": "Write a Facebook [engagement post/event promo] about [TOPIC]. Make it conversational. Ask a question to drive comments. Match my brand tone: [BRAND TONE]."}, {"platform": "LinkedIn", "format": "Thought Leadership / Case Study / Hiring", "structure": {"hook": "[Bold statement or contrarian take]", "story": "[3-4 short paragraphs with line breaks]", "insight": "[What you learned or what others should know]", "cta": "[Agree? Disagree? Share your experience.]"}, "ai_prompt": "Write a LinkedIn post about [TOPIC] from my perspective as a [YOUR ROLE] in [INDUSTRY]. Professional but authentic tone."}, {"platform": "Email Newsletter", "format": "Weekly digest / single-topic deep-dive", "structure": {"subject_line": "[Curiosity-driven, under 50 characters]", "preview_text": "[Complement the subject, don't repeat it]", "body": "[One main story/tip from this week's best post]", "cta": "[One clear action — reply, click, shop]"}, "ai_prompt": "Turn this social media post into a weekly email newsletter: [paste post]. Add a personal intro, expand the content, and end with one clear CTA."}], "content": "Creating consistent social media content is one of the biggest time drains for small business owners — most spend 5+ hours per week and still feel like their posts are scattered and off-brand. This system solves that with a structured 4-pillar content rotation (Behind the Scenes, Customer Results, Education, Personality) combined with a 30-minute batch workflow that produces an entire week of platform-specific content in one sitting. You fill in your weekly theme, feed it to Claude or Gemini alongside your Business Profile, and the AI generates 5 post concepts, expands them into platform-ready drafts for Instagram, Facebook, LinkedIn, and email, then adds captions and hashtags. The included templates are formatted for each platform so character limits, hashtag counts, and CTA styles are already optimized. One batch session replaces what used to take all week.", "implementation_time": "45 minutes", "expected_result": "Generate a full week of social content in one sitting, maintaining your brand voice", "roi_indicator": "Saves 3-5 hours/week on content creation"}, {"title": "System 03: Financial Analysis & Reporting", "type": "system", "problem": "You know your revenue but not your real profitability drivers", "solution": "Monthly financial health checks that take 15 minutes", "time_saved": "3-5 hours per month", "whats_inside": ["Monthly business health check template", "Pricing & profitability analyzer", "3-month cash flow forecaster", "AI prompts to turn your numbers into insights"], "monthly_health_check_template": {"fields": {"month": "[___]", "year": "[___]", "revenue": {"total": "$[___]", "product_service_a": "$[___]", "product_service_b": "$[___]", "product_service_c": "$[___]"}, "costs": {"total": "$[___]", "cost_of_goods": "$[___]", "rent_utilities": "$[___]", "staff": "$[___]", "marketing": "$[___]", "software_tools": "$[___]", "other": "$[___]"}, "customers": {"total": "[___]", "new": "[___]", "returning": "[___]", "lost": "[___]"}}, "ai_prompt": "Analyze this month's data against last month. Identify: (1) top revenue driver, (2) biggest cost increase, (3) customer retention rate, (4) three specific actions to improve next month. Be direct — I'm a busy owner."}, "pricing_analysis_template": {"description": "Most small businesses underprice. This template helps you evaluate whether your pricing is right.", "fields": {"product_service": "[Name]", "your_price": "$[___]", "your_cost_to_deliver": "$[___]", "your_margin": "[___]%", "competitor_pricing": [{"competitor": "Competitor 1: [Name]", "price": "$[___]"}, {"competitor": "Competitor 2: [Name]", "price": "$[___]"}, {"competitor": "Competitor 3: [Name]", "price": "$[___]"}], "positioning": "[Budget / Mid-range / Premium]", "last_price_increase": "[Date or 'Never']"}, "ai_prompt": "Review my pricing data above. Compare my margins to industry averages for [INDUSTRY]. Analyze my competitor positioning. Recommend: should I raise prices, by how much, and how to communicate the increase. Give me a specific plan.", "pro_tip": "Run this analysis quarterly. Most small businesses haven't raised prices in 2+ years while costs have increased 15-20%. A 10% price increase with zero customer loss goes straight to your bottom line."}, "cash_flow_forecast_template": {"description": "See the future before it arrives. This 3-month template helps you spot cash crunches before they hit.", "fields": {"current_cash_balance": "$[___]", "month_1": {"name": "[Month Name]", "expected_revenue": "$[___]", "expected_costs": "$[___]", "seasonal_factor": "[Peak / Normal / Slow]", "projected_balance": "$[___]"}, "month_2": {"name": "[Month Name]", "expected_revenue": "$[___]", "expected_costs": "$[___]", "seasonal_factor": "[Peak / Normal / Slow]", "projected_balance": "$[___]"}, "month_3": {"name": "[Month Name]", "expected_revenue": "$[___]", "expected_costs": "$[___]", "seasonal_factor": "[Peak / Normal / Slow]", "projected_balance": "$[___]"}, "upcoming_big_expenses": "[List any known large costs]"}, "ai_prompt": "Using my cash flow data and my Business Profile (peak season: [PEAK SEASON]), identify: (1) months where cash might run low, (2) seasonal adjustment recommendations, (3) how much reserve I should keep. Be specific with dollar amounts."}, "content": "Most small business owners know their top-line revenue but have no idea which products actually make money, whether their pricing is right, or when cash flow will get tight. This system gives you three plug-and-play financial templates that turn raw numbers into clear action items in 15 minutes flat. The Monthly Health Check compares this month to last month across revenue, costs, and customer metrics — then AI identifies your top driver, biggest cost spike, and three specific things to fix. The Pricing Analyzer compares your margins against competitors and tells you exactly how much to raise prices and how to communicate the increase. The 3-Month Cash Flow Forecaster spots cash crunches before they hit by factoring in your seasonal patterns. No accounting degree needed — just paste your numbers and AI does the analysis.", "implementation_time": "20 minutes", "expected_result": "Get a clear financial snapshot with actionable insights — no accounting degree needed", "roi_indicator": "Identifies cost savings averaging $200-500/month"}, {"title": "System 04: Sales & Lead Follow-Up", "type": "system", "problem": "80% of sales need 5+ follow-ups, but most businesses stop at 1-2", "solution": "A 5-touch follow-up sequence with templates for each stage", "time_saved": "5-8 hours per week", "whats_inside": ["5-touch follow-up sequence with full email templates", "Lead scoring cheat sheet (hot / warm / cool)", "Proposal & quote generator template", "AI prompts for personalized outreach"], "follow_up_sequence": [{"touch": 1, "name": "Initial Response", "timing": "Day 0 — within 1 hour of inquiry", "goal": "Acknowledge, answer, invite next step", "template": "Hi [Customer Name],\n\nThanks for reaching out to [YOUR BUSINESS]! I saw your question about [their specific inquiry].\n\n[Direct answer to their question — be specific]\n\nI'd love to learn more about what you're looking for. Would you be open to [sharing a few more details]?\n\nLooking forward to hearing from you,\n[YOUR NAME]\n[YOUR PHONE / BOOKING LINK]"}, {"touch": 2, "name": "Value-Add Follow-Up", "timing": "Day 2", "goal": "Build trust by giving, not asking", "template": "Hi [Customer Name],\n\nI was thinking about [their situation/question] and wanted to share something that might help:\n\n[helpful resource related to their need — NOT a sales pitch]\n\nA lot of our customers in [similar situation] have found this really helpful. No strings attached — just thought of you.\n\nLet me know if you have any questions!\n[YOUR NAME]"}, {"touch": 3, "name": "Social Proof", "timing": "Day 5", "goal": "Show results others have gotten", "template": "Hi [Customer Name],\n\nQuick thought — I wanted to share how we helped [similar customer/business] with [similar need]:\n\n\"[2-3 sentences about the result they achieved]\"\n— [Customer name/business], [their role]\n\nTheir situation was similar to yours, and I think we could get you similar results.\n\nWorth a conversation? I'm free [times]. Happy to keep it to 15 minutes.\n\n[YOUR NAME]"}, {"touch": 4, "name": "Direct Ask", "timing": "Day 10", "goal": "Make a clear, specific offer", "template": "Hi [Customer Name],\n\nI wanted to check in one more time about [their need].\n\nBased on what you shared, here's what I'd recommend:\n[Specific product/service recommendation with price]\n\n[Urgency element: 'We have 2 spots left this month' or 'Our seasonal offer runs through [date]']\n\nIf you'd like to move forward, here's the easiest way: [specific next step — book a call, reply, visit]\n\nAnd if now isn't the right time, no worries at all — I'll be here when you're ready.\n\n[YOUR NAME]"}, {"touch": 5, "name": "Long-Term Nurture", "timing": "Day 21", "goal": "Stay top of mind without being pushy", "template": "Hi [Customer Name],\n\nHope you're doing well! No sales pitch today — just wanted to share something I thought you'd find useful:\n\n[helpful resource, tip, or community event related to their interest]\n\nIf your needs around [their original question] ever come back up, I'm always happy to help.\n\nHave a great [day/week]!\n[YOUR NAME]"}], "follow_up_ai_prompt": "Using my Business Profile, write a [Touch 1/2/3/4/5] follow-up email for this lead: [paste lead details]. Match my brand tone. Keep it under 80 words. The goal is [proof / close / nurture].", "lead_scoring": {"hot": {"label": "HOT — Follow Up Today", "signals": ["Asked about pricing", "Mentioned a timeline or deadline", "Referred by existing customer", "Visited or contacted you twice or more"]}, "warm": {"label": "WARM — Follow Up This Week", "signals": ["Downloaded your content or signed up", "Asked general questions about your services", "Engaged with your social media content", "Attended an event or webinar"]}, "cool": {"label": "COOL — Monthly Nurture", "signals": ["Early-stage research only", "No budget or timeline mentioned", "Competitor comparison shopping", "Connected but no conversation yet"]}, "pro_tip": "Create three saved AI prompts — one for each lead temperature. When a new lead comes in, classify them, then use the matching prompt to generate a personalized response in seconds."}, "proposal_template": {"description": "Stop spending hours on proposals. Paste your discovery call notes and let AI draft a professional proposal in minutes.", "template": {"for": "[Client Name / Company]", "date": "[___]", "prepared_by": "[YOUR NAME] at [YOUR BUSINESS]", "understanding_your_needs": "[AI generates from your call notes]", "recommended_solution": "[AI recommends from your services/products]", "pricing": {"service_1": "$[___]", "service_2": "$[___]", "total_investment": "$[___]"}, "timeline": "[___]", "whats_included": "[Scope of work]", "next_steps": "[How to proceed]", "valid_until": "[Date — 14 days recommended]"}, "ai_prompt": "Using my Business Profile and this template, draft a proposal for: [describe the client request]. Match our brand tone. Recommend the right service/product combo. Include a 14-day validity period."}, "content": "Research shows 80% of sales require 5 or more follow-up touches, but most small businesses stop at 1 or 2 and wonder why leads go cold. This system gives you a complete 5-touch follow-up sequence with full email templates for each stage — from initial response (within 1 hour) through value-add, social proof, direct ask, and long-term nurture over 21 days. Each template is designed so AI fills in lead-specific details using your Business Profile: their name, their inquiry, a relevant case study, and your specific offer. The lead scoring cheat sheet helps you instantly classify leads as Hot, Warm, or Cool so you know which ones need attention today. The proposal generator turns your discovery call notes into a professional quote in minutes instead of hours. Set up one Claude Project or Gemini Gem and paste any lead — AI handles the personalization, you handle the relationship.", "implementation_time": "30 minutes", "expected_result": "Never lose a lead to slow follow-up again — AI drafts personalized responses within minutes", "roi_indicator": "Increases lead conversion by responding 10x faster"}, {"title": "System 05: Operations & SOP System", "type": "system", "problem": "Everything lives in your head — if you're sick, the business stops", "solution": "AI-generated SOPs from your verbal descriptions", "time_saved": "Major — building a business that runs without you", "whats_inside": ["SOP generator workflow (voice to procedure)", "SOP template with fill-in structure", "Top 10 SOPs every small business needs", "Delegation & handoff templates"], "sop_generator_workflow": [{"step": 1, "action": "Voice-Describe Your Process", "detail": "Talk like you're training a new employee. Record yourself explaining the task from start to finish."}, {"step": 2, "action": "Paste the Transcript", "detail": "Use speech-to-text or a free transcription tool. Paste the raw text into AI along with the SOP template."}, {"step": 3, "action": "AI Outputs Formatted SOP", "detail": "AI organizes your rambling into a clean, step-by-step procedure anyone can follow."}], "sop_template": {"name": "[Process Name]", "owner": "[Who's responsible]", "last_updated": "[Date]", "purpose": "[Why this process exists]", "trigger": "[What starts this process]", "steps": [{"step": 1, "action": "[Step]", "expected_output": "[___]"}, {"step": 2, "action": "[Step]", "expected_output": "[___]"}, {"step": 3, "action": "[Step]", "expected_output": "[___]"}, {"step": 4, "action": "[Step]", "expected_output": "[___]"}], "exceptions": "[What to do when things go wrong]", "tools_needed": "[Software, equipment]", "time_estimate": "[How long it should take]"}, "top_10_sops": [{"rank": 1, "name": "Opening / closing procedures", "complexity": "Easy"}, {"rank": 2, "name": "New customer onboarding", "complexity": "Medium"}, {"rank": 3, "name": "Order fulfillment / service delivery", "complexity": "Medium"}, {"rank": 4, "name": "Complaint handling", "complexity": "Easy"}, {"rank": 5, "name": "Social media posting", "complexity": "Easy"}, {"rank": 6, "name": "Invoicing & payment collection", "complexity": "Easy"}, {"rank": 7, "name": "Inventory / supply reordering", "complexity": "Medium"}, {"rank": 8, "name": "Staff training for new hires", "complexity": "Complex"}, {"rank": 9, "name": "Monthly financial review", "complexity": "Medium"}, {"rank": 10, "name": "Emergency / crisis response", "complexity": "Complex"}], "sop_ai_prompt": "I'm going to describe my [PROCESS NAME] process. Here's my raw description: [paste transcript]. Using the SOP template, organize this into a clean, step-by-step procedure. Include expected outputs, exceptions, and a time estimate.", "task_handoff_template": {"task": "[Name]", "delegated_to": "[Person / Role]", "sop_reference": "[Which SOP to follow]", "due": "[Date / Recurring schedule]", "what_success_looks_like": "[Describe the expected output clearly]", "common_mistakes_to_avoid": ["[___]", "[___]", "[___]"], "questions_contact": "[Your name / contact]", "check_in_schedule": "[Daily / Weekly / As needed]"}, "training_checklist": ["Shared the SOP document with team member", "Walked through the process together once", "Team member completed process with supervision", "Team member completed process independently", "Reviewed quality of first 3 independent outputs", "Scheduled recurring check-ins"], "pro_tip": "Use AI to generate a quiz from any SOP. Paste the SOP and ask: 'Create a 5-question quiz to test understanding of this procedure.' Great for training verification.", "content": "If everything about how your business operates lives inside your head, you do not have a business — you have a job you cannot take a day off from. This system fixes that by converting your verbal knowledge into documented, repeatable standard operating procedures that anyone on your team can follow. The workflow is simple: talk through any process like you are training a new employee, paste the transcript into Claude or Gemini with the included SOP template, and AI organizes your explanation into a clean step-by-step procedure with expected outputs, exception handling, tools needed, and time estimates. The Top 10 SOPs checklist tells you exactly which procedures to document first (opening/closing, onboarding, order fulfillment, complaint handling). The task handoff template ensures clean delegation with clear success criteria and check-in schedules. Build your operations manual one SOP at a time — the goal is a business that runs even when you are not there.", "implementation_time": "1 hour", "expected_result": "Document your key business processes so they can be delegated or scaled", "roi_indicator": "Reduces training time for new processes by 70%"}, {"title": "System 06: Hiring & Team Management", "type": "system", "problem": "Hiring takes weeks and you still pick the wrong person", "solution": "AI-assisted hiring pipeline — from posting to onboarding in half the time", "time_saved": "10-15 hours per hire", "whats_inside": ["Job description generator template", "Interview question bank (role + culture fit)", "Scoring rubric for objective evaluation", "30-day onboarding checklist"], "job_description_input_template": {"role": "[___]", "reports_to": "[___]", "type": "[Full-time / Part-time / Contract]", "must_have_skills": ["[___]", "[___]", "[___]"], "nice_to_have": ["[___]", "[___]"], "personality_fit": "[From your Business Profile brand tone]", "deal_breakers": "[What disqualifies a candidate]", "compensation": "[Range or 'competitive']", "location": "[On-site / Remote / Hybrid]"}, "job_description_ai_prompt": "Using my Business Profile and this role template, write a job description for [ROLE]. Match our brand tone [BRAND TONE]. Include what makes working here different. Under 300 words. Make skills specific and measurable.", "interview_questions": {"role_specific": ["Describe a time you [KEY SKILL] — what was the result?", "How would you handle [COMMON SCENARIO]?", "What tools/methods do you use for [CORE RESPONSIBILITY]?", "Walk me through how you'd approach [REAL TASK].", "What's the biggest [SKILL] challenge you've solved?"], "culture_fit": ["What kind of work environment brings out your best?", "How do you handle [BRAND TONE-RELATED SCENARIO]?", "Describe a team you loved — what made it great?", "How do you handle feedback you disagree with?", "What would your last manager say is your biggest strength?"]}, "scoring_rubric": {"scale": "1=Poor 2=Below Avg 3=Meets 4=Above 5=Exceptional", "total_possible": 50, "fields": {"candidate": "[Name]", "role": "[Position]", "role_scores": "Role Q1: [/5] Role Q2: [/5] Role Q3: [/5] Role Q4: [/5] Role Q5: [/5]", "culture_scores": "Culture Q1: [/5] Culture Q2: [/5] Culture Q3: [/5] Culture Q4: [/5] Culture Q5: [/5]", "total": "[/50]", "red_flags": "[___]", "decision": "[ ] Advance [ ] Maybe [ ] Pass"}}, "onboarding_checklist": {"week_1": {"title": "Orientation", "tasks": ["Complete all paperwork and system access", "Tour of workspace / intro to team", "Review Business Profile and brand values", "Shadow existing team member for 2 days", "Read SOPs for their role (from Chapter 06)"]}, "week_2": {"title": "Supervised Work", "tasks": ["Complete first tasks with supervision", "Daily 15-min check-in with manager", "Review and practice all relevant SOPs", "Start handling routine tasks independently", "Document questions and feedback"]}, "week_3": {"title": "Independent Work", "tasks": ["Handle routine tasks independently", "Check-in reduced to every other day", "Introduce customer-facing responsibilities", "Begin cross-training on secondary tasks", "Manager observes and takes notes"]}, "week_4": {"title": "First Review", "tasks": ["Complete first performance review template", "Discuss wins, challenges, and next goals", "Adjust training plan based on performance", "Set 60-day and 90-day milestones", "Transition to regular check-in schedule"]}}, "content": "Hiring is one of the most expensive and time-consuming activities for a small business — a bad hire can cost 30% of that person's annual salary in lost productivity and rehiring costs. This system cuts your hiring time in half while improving candidate quality using an AI-assisted pipeline from job posting to 30-day onboarding. You fill in the role template (skills, personality fit, deal-breakers, compensation range), and Claude or Gemini generates a compelling job description that matches your brand tone and highlights what makes your workplace different. The interview question bank gives you 10 structured questions split between role-specific skills and culture fit. The scoring rubric eliminates gut-feel hiring by giving you a 50-point objective evaluation framework. After you hire, the 4-week onboarding checklist takes your new team member from orientation through supervised work to independent performance review — with AI generating quizzes from your SOPs to verify they actually learned the procedures.", "implementation_time": "45 minutes", "expected_result": "Create job descriptions, screening criteria, and onboarding checklists that reflect your culture", "roi_indicator": "Cuts hiring admin work by 60%"}, {"title": "Chapter 08: Industry Quick-Start Guides", "type": "educational", "content": "Every business is different, but you do not need to figure out where to start from scratch. These four industry-specific guides tell you exactly which systems to deploy first based on what moves the needle fastest in your industry, plus bonus templates designed for your specific use cases. Each guide includes the recommended system priority order, industry-specific template additions you will not find in generic AI courses, a recommended Claude Skill or Gemini Gem name, and a ready-to-paste quick-start prompt that configures your first system in minutes. Pick your industry, follow the priority order, and you will see measurable time savings within your first week.", "industries": [{"industry": "Restaurant / Food Service", "content": "Restaurants live and die by two things: reviews and repeat customers. Start with the Customer Response System because a single unanswered Google or Yelp complaint can cost you thousands in lost foot traffic — Claude generates polished, brand-voice responses in under 30 seconds that turn critics into return visitors. Next, deploy Content to keep your social feeds active with daily specials, seasonal menus, and behind-the-kitchen posts without spending your evenings writing captions. Finally, Operations locks down your prep lists, staff scheduling, and food safety checklists so nothing falls through the cracks during a Friday rush. The four bonus templates below are restaurant-specific additions you will not find in any generic AI course — they handle the exact scenarios that eat up a restaurant owner's time every single week.", "priority_systems": ["#1 Customer Response", "#2 Content", "#3 Operations"], "industry_specific_additions": ["Menu update and seasonal special templates", "Review response templates (Google, Yelp)", "Staff scheduling SOP with peak-hour coverage", "Daily prep checklist generator"], "recommended_skill": "Restaurant Manager", "quick_start_prompt": "I run a [TYPE] restaurant with [X] staff. Busiest days: [DAYS]. Brand voice: [TONE]. Customize the Customer Response System for: reservation inquiries, dietary restriction questions, complaint about food quality, and catering requests."}, {"industry": "Retail / E-Commerce", "content": "Retail margins are thin, so every lost lead and every slow-moving product costs real money. Start with Sales & Lead Follow-Up because the data is clear: stores that send a follow-up within 24 hours of an abandoned cart recover 10-15% of those sales — and Claude writes those sequences in seconds, personalized to the exact product left behind. Next, Content keeps your product pages and social channels fresh with SEO-optimized descriptions and seasonal campaigns that drive organic traffic instead of paid ads. Then Financial Analysis shows you which products actually make money after shipping, returns, and ad spend — most retail owners are shocked to find their best-seller is their worst margin item. The four bonus templates below cover the exact retail workflows that separate stores doing $10K/month from those doing $100K.", "priority_systems": ["#1 Sales & Leads", "#2 Content", "#3 Financial"], "industry_specific_additions": ["Product description generator (SEO-optimized)", "Seasonal promotion calendar template", "Inventory alert and reorder SOP", "Customer review collection sequence"], "recommended_skill": "Retail Operations Manager", "quick_start_prompt": "I run a [TYPE] retail store (online/physical/both) selling [PRODUCTS]. Average order: $[X]. Customize the Sales & Lead Follow-Up System for: abandoned cart follow-up, post-purchase thank you, seasonal promotion, and restock notification."}, {"industry": "Service Business / Consulting", "content": "Service businesses have one fundamental problem: your revenue stops when you stop working, and most of your non-billable time goes into proposals, follow-ups, and client management. Start with Sales & Lead Follow-Up because the average consultant loses 60% of qualified leads simply by not following up fast enough — this system generates personalized follow-up sequences that keep prospects warm without you spending evenings writing emails. Next, Customer Response handles the client communication that eats 5-10 hours per week: project updates, scope clarification, and the delicate art of saying 'that is outside the current agreement' without damaging the relationship. Then Hiring becomes critical when you are ready to scale — the proposal generator alone pays for this entire playbook by turning a 2-hour proposal process into 15 minutes while producing documents that close at higher rates because they are structured, specific, and professionally formatted.", "priority_systems": ["#1 Sales & Leads", "#2 Customer Response", "#3 Hiring"], "industry_specific_additions": ["Proposal generator with scope-of-work", "Scope creep prevention template", "Testimonial collection and case study builder", "Client offboarding and referral request"], "recommended_skill": "Service Business Assistant", "quick_start_prompt": "I run a [TYPE] service business. Average project: $[X] over [TIMELINE]. Customize the Operations & SOP System for: client intake, project kickoff, milestone check-in, and project completion/handoff."}, {"industry": "Freelancer / Solopreneur", "content": "As a solopreneur, you are the business — which means every hour spent on admin is an hour not spent earning. Start with Content because visibility is your lifeline: freelancers who post consistently get 3-5x more inbound leads than those who rely on referrals alone, and Claude generates a full week of thought-leadership posts, case studies, and industry commentary in under 20 minutes. Next, Sales & Lead Follow-Up automates the feast-or-famine cycle by keeping your pipeline warm even when you are buried in client work — the system sends personalized check-ins to past clients and nurtures new leads so you never finish a project and face an empty calendar. Then Financial Analysis shows you your real hourly rate after accounting for unpaid admin time, scope creep, and revision rounds — most freelancers discover they are earning 30-40% less than they think. The bonus templates below tackle the specific pain points every freelancer knows: pricing conversations, late-paying clients, and building a personal brand that attracts premium work.", "priority_systems": ["#1 Content", "#2 Sales & Leads", "#3 Financial"], "industry_specific_additions": ["Personal brand content calendar", "Rate calculator and pricing confidence builder", "Contract and scope-of-work template", "Late payment follow-up email sequence"], "recommended_skill": "Freelance Business Manager", "quick_start_prompt": "I'm a freelance [SPECIALTY] charging $[RATE] per [hour/project]. My clients are [TARGET CLIENTS]. Brand voice: [TONE]. Customize the Content & Social Media System for: personal brand thought leadership, client case studies, industry tips that position me as an expert, and behind-the-scenes of my workflow."}]}, {"title": "Chapter 09: Your AI Operations Manual", "type": "templates", "content": "This is your master control panel for every AI system you deploy. Think of it as the cockpit dashboard for your AI-powered business — one page that shows you which systems are active, how much time they are saving, which tools are running, and when your next review is scheduled. Print it or pin it as a digital document you check weekly. The monthly review checklist walks you through four critical areas: reviewing system performance, updating your Business Profile foundation, optimizing and expanding to new systems, and measuring actual results in hours saved and revenue attributed. The businesses that get the most value from AI are not the ones with the best tools — they are the ones who review their systems monthly and iterate. Update this dashboard every time you activate a new system or retire an old one.", "ai_ops_dashboard": {"systems_active": ["[ ] System 1: Customer Response", "[ ] System 2: Content & Social Media", "[ ] System 3: Financial Analysis", "[ ] System 4: Sales & Follow-Up", "[ ] System 5: Operations & SOP", "[ ] System 6: Hiring & Team"], "weekly_ai_time_budget": "[___] hours", "estimated_time_saved": "[___] hours", "ai_tools_in_use": {"claude_project": "[Project name]", "gemini_gems": "[List active Gems]"}, "monthly_review_date": "[First Monday / Last Friday / etc.]", "next_review": "[Date]"}, "pro_tip": "Print this page or keep it as a pinned document. Update it monthly. The businesses that succeed with AI aren't the ones with the best tools — they're the ones who review and iterate.", "monthly_review_checklist": {"review_your_systems": ["Check each active system — still saving time?", "Review AI outputs — quality still good?", "Identify systems needing template updates", "Check if any system should be activated or paused"], "update_your_foundation": ["Review and update your Business Profile", "Update pricing, products, or services if changed", "Refresh brand tone and messaging if evolved", "Update competitor information"], "optimize_and_expand": ["Refresh templates with new products/services", "Archive SOPs no longer relevant", "Train new team members on AI systems", "Consider adding the next system"], "measure_your_results": ["Calculate total hours saved this month", "Note revenue attributed to AI systems", "Record customer feedback improvements", "Update your AI Ops Dashboard"]}}, {"title": "Chapter 10: What's Next", "type": "educational", "content": "The Automation Ladder — You've been climbing. Here's where you are and what's next.", "automation_ladder": [{"level": 1, "name": "Manual AI", "description": "You type prompts one at a time", "product": "AI Starter Kit ($19)", "status": "COMPLETED"}, {"level": 2, "name": "Specialist AI", "description": "You built Skills & Gems", "product": "AI Skills Builder ($29)", "status": "COMPLETED"}, {"level": 3, "name": "System AI", "description": "You deployed business systems", "product": "AI for Small Business ($47)", "status": "YOU ARE HERE"}, {"level": 4, "name": "Automated AI", "description": "Systems run on autopilot with triggers", "product": "AI Automation Cookbook ($67)", "status": "NEXT"}], "pro_tip": "You don't need Level 4 to see massive results. Most businesses save 15-20 hours/week with Level 3 systems. Automation is the cherry on top."}, {"title": "Installable AI Tools — 4 Claude Skills + 2 Gemini Gems", "type": "skills", "content": "Ready-to-install AI tools built specifically for solopreneurs. Each tool is a pre-configured AI specialist that you install once and use forever. Copy the code below, follow the install steps, and you'll have a working AI assistant in under 5 minutes.", "install_overview": {"claude": {"title": "How to Install Claude Skills", "steps": ["Open Claude (claude.ai) and sign in", "Type /skill-creator in any conversation", "Paste the SKILL.md content when prompted", "Name your skill and save — it's now available in all your conversations"]}, "gemini": {"title": "How to Install Gemini Gems", "steps": ["Open Gemini (gemini.google.com) and sign in", "Click \"Gem manager\" in the left sidebar", "Click \"New Gem\" and give it a name", "Paste the system prompt into the instructions field and save"]}}, "skills": [{"name": "Customer Response System", "description": "Solopreneurs drowning in customer inquiries who need fast, professional responses", "platform": "Claude Skill", "system_prompt": "You are Customer Response System — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners respond to customer inquiries, complaints, and requests quickly and professionally — so every customer feels heard without the owner spending an hour crafting the perfect reply.\nHow you work:\nThe user pastes in the customer message (and optionally the context: what the business does, what the issue is, what outcome they want). You draft a professional response immediately. Match the urgency — a frustrated customer gets a more direct and empathetic response than a general inquiry.\nResponse types you handle:\n- General inquiries: Clear, helpful, warm. Answer the question directly.\n- Complaints: Acknowledge first, solve second. Never defensive. Offer a specific resolution, not a vague 'we'll look into it.'\n- Refund or dispute requests: Empathetic but clear on the policy. If the user hasn't told you the policy, include a placeholder.\n- Positive feedback: Short, genuine acknowledgment. Optionally include a soft ask (review, referral).\nEscalation flags:\nIf the customer message suggests a legal threat, a public complaint (mentioning social media), or a safety issue, add a clear flag at the top of your output: ESCALATION FLAG — [reason]. Recommend the user handle this personally rather than sending an automated reply.\nRules you always follow:\nNo robotic openers. No passive-voice deflection ('mistakes were made'). Never promise something the user hasn't confirmed they can deliver — use placeholders instead. Keep responses under 150 words unless the complexity demands more.\nFormatting rules:\nEscalation flag first (if applicable). Then the response draft. Then a brief note on tone rationale and any placeholders that need to be filled in."}, {"name": "Financial Health Check", "description": "Solopreneurs who avoid looking at their numbers because it's overwhelming", "platform": "Claude Skill", "system_prompt": "You are Financial Health Check — a specialized AI assistant for solopreneurs.\nYour job is to help number-avoidant business owners understand what's actually happening in their finances — in plain language, without the overwhelm — and know exactly what to do next.\nHow you work:\nThe user shares their financial data — this could be revenue figures, expense categories, monthly summaries, or a simple list of numbers. You don't need a perfect spreadsheet. Work with what you're given, flag what's missing, and produce a clear health check. If the data is very sparse, ask for the three most important figures: total revenue, total expenses, and biggest cost category.\nWhat you produce for every check-in:\n- Snapshot: Revenue vs. expenses this period. Profit margin in plain terms ('You kept X cents of every dollar earned').\n- Red Flags: Anything that looks off — costs growing faster than revenue, negative trends, one expense eating a disproportionate share\n- Bright Spots: What's working — growing revenue streams, improving margins, consistent income sources\n- Trends: Month-over-month or period-over-period changes if data allows\n- 3 Action Items: Specific, doable things to improve financial health in the next 30 days. No vague advice like 'reduce expenses.'\nRules you always follow:\nNo accounting jargon without explanation. If you use a term like 'gross margin,' define it in parentheses the first time. Never make the user feel judged about their numbers. Be direct about problems but constructive in framing. Round numbers for readability unless precision is specifically needed.\nFormatting rules:\nSnapshot at the top. Red Flags and Bright Spots side by side or in clear sections. Action items numbered and bolded. End with: 'Next check-in: [suggested timeframe].'"}, {"name": "Competitor Intel Brief", "description": "Solopreneurs who know they should track competitors but never do", "platform": "Claude Skill", "system_prompt": "You are Competitor Intel Brief — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners understand what their competitors are doing and turn that intelligence into specific actions — without spending hours researching.\nHow you work:\nThe user shares information about one or more competitors — this could be website copy, pricing pages, social media posts, reviews, or just what they know from observation. You analyze it and produce a structured intelligence brief. If the user only names a competitor without providing details, tell them exactly what to gather (e.g., 'grab their pricing page, homepage, and 3-5 customer reviews') before proceeding.\nWhat you produce for every brief:\n- Competitor Snapshot: Who they're targeting, what they're selling, what their core message is\n- Pricing Analysis: What they charge, how they package it, where gaps or opportunities exist\n- Messaging Gaps: What they're not saying — pain points they ignore, audiences they underserve, promises they can't back up\n- Strengths: Be honest about what they do well — this is intelligence, not cheerleading\n- Weaknesses: Specific vulnerabilities backed by evidence from what the user shared\n- Opportunities for You: Concrete ways the user can position differently or fill the gaps\n- So What: One paragraph summary — the single most actionable insight from all of the above\nRules you always follow:\nEvery finding needs a 'so what' — no observation without implication. Don't be a cheerleader for the user — if the competitor is strong in an area, say so. Stay grounded in the evidence provided rather than speculating broadly.\nFormatting rules:\nSection headers throughout. Opportunities section highlighted or bolded. End with the So What paragraph, clearly labeled."}, {"name": "Product Description Writer", "description": "Solopreneurs who struggle to write compelling descriptions for their products/services", "platform": "Claude Skill", "system_prompt": "You are Product Description Writer — a specialized AI assistant for solopreneurs.\nYour job is to turn flat product or service features into compelling descriptions that make the right customers immediately understand why they need what's being offered.\nHow you work:\nThe user tells you what they're selling and gives you the key details (features, price point, target customer, where it'll be used). If the target audience isn't clear, ask — one word like 'freelancers' or 'new moms' is enough. Then write descriptions tailored to the format they need. You support multiple outputs per session.\nFormats you produce:\n- Website / sales page: 75-150 words. Lead with the transformation or outcome, then back it up with features. End with a CTA.\n- Marketplace listing (Etsy, Amazon, Gumroad, etc.): Punchy headline + 3-5 bullet points featuring benefits, not specs. Under 100 words total.\n- Social media caption: 50-80 words, hooks first, benefits second, link in bio CTA.\n- Short pitch (elevator or DM): 2-3 sentences max. What it is, who it's for, what it changes for them.\nFeatures-to-benefits translation:\nFor every feature the user lists, you reframe it as a benefit. 'Includes 12 templates' becomes 'Skip the blank-page panic — 12 ready-to-use templates get you started in minutes.'\nRules you always follow:\nNo filler superlatives ('amazing,' 'revolutionary,' 'game-changing'). Write in the customer's language, not the creator's. Every description should answer: 'Why should I care?' within the first two sentences.\nFormatting rules:\nLabel each format clearly. For multiple formats in one request, use dividers. Include a brief note on any tone assumptions made."}, {"name": "Invoice & Scope Writer", "description": "Solopreneurs who dread writing invoices, scope documents, and contracts", "platform": "Gemini Gem", "system_prompt": "You are Invoice & Scope Writer — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners generate professional invoices, scope of work documents, and project agreements from rough notes — so they spend less time on admin and more time doing actual work.\nHow you work:\nThe user tells you what they need (invoice, scope doc, or project agreement) and gives you the project details. If critical information is missing — like the client name, services rendered, or amount — ask for just what's needed before drafting. Don't ask for everything upfront; start with what's provided and fill gaps as you go.\nAs a Gemini Gem, you can leverage Google Workspace integration: if the user shares a Google Doc, Gmail thread, or Sheet with project details, pull the relevant information directly rather than asking them to retype it.\nWhat you produce:\nFor invoices: Invoice number, date, client details, line items with descriptions and amounts, subtotal, any taxes or discounts, total due, payment due date, accepted payment methods, and a brief 'thank you' line.\nFor scope documents: Project overview, deliverables list, timeline with milestones, revision policy, what's out of scope, and sign-off section.\nFor project agreements: Combines scope + payment terms + cancellation/kill fee policy + IP ownership clause (plain language, not legalese).\nRules you always follow:\nPlain language — no legal jargon unless the user specifically wants formal language. Flag missing information rather than invent it. For project agreements, always include a scope creep clause. Suggest sensible defaults for payment terms (e.g., 50% upfront, net-15 on final) if the user hasn't specified.\nFormatting rules:\nClean, professional layout. Each section clearly labeled. Ready to copy into a Google Doc or paste into an email."}, {"name": "Google Workspace Business Analyst", "description": "Solopreneurs who use Google Workspace and want AI analysis across their files", "platform": "Gemini Gem", "system_prompt": "You are Google Workspace Business Analyst — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners make sense of the data scattered across their Google Workspace — Sheets, Docs, Gmail, and Drive — and turn it into clear insights and action.\nHow you work:\nAs a Gemini Gem, you have direct access to the user's Google Workspace. When a user asks a business question, start by identifying which files or data sources are relevant. Ask the user to point you to specific files if needed, or search for them if given permission. Then analyze, synthesize, and report in plain language.\nWhat you do with Google data:\n- Google Sheets: Analyze financial data, client lists, project trackers, revenue logs. Identify trends, anomalies, and gaps. Create summaries or flag cells that need attention.\n- Google Docs: Review proposals, reports, or notes. Extract key information, compare versions, or summarize long documents.\n- Gmail: Identify patterns in client communications, flag unanswered threads, summarize long email chains, or find specific information buried in conversations.\n- Drive: Locate relevant files based on what the user is looking for and pull key data from them.\nReport formats you produce:\n- Trend summary: What's changed over time and why it matters\n- Anomaly flag: What looks unusual and needs attention\n- Cross-source synthesis: Pulling data from multiple files to answer one business question\n- Action list: What the user should do based on what you found\nRules you always follow:\nAlways state which files or data you're drawing from. Flag if data seems incomplete or inconsistent. Translate numbers into plain-language meaning. Never make assumptions about missing data — ask.\nFormatting rules:\nSource citations at the top (file names/links). Findings in clear sections. Action items numbered at the end."}]}, {"title": "Automate Everything", "type": "cta", "content": "Coming Next: AI Automation Cookbook — You've built the systems. Now let them run without you. The AI Automation Cookbook connects your systems to triggers, schedules, and multi-tool workflows.", "upcoming_product": {"name": "AI Automation Cookbook", "features": ["Multi-tool workflows (connect AI to your existing tools)", "Zapier + Make integration templates", "Auto-triggers: new customer → welcome sequence → follow-up", "Scheduled reports that run while you sleep", "Advanced prompt chains for complex business decisions"]}, "items": [{"offer": "Ultimate AI Bundle", "price": "$147 (Save 40%)", "description": "All 4 products + future updates. vs. $162 buying separately.", "url": "https://www.kh-academy.com"}], "purchase_url": "https://kh-academy-storefront.vercel.app/#pricing", "storefront_url": "https://kh-academy-storefront.vercel.app"}]};

export const AUTOMATION_MASTERY_DATA: CourseData = {"product_id": "automation-mastery", "title": "AI Automation Mastery", "subtitle": "Hands-Free AI Workflows That Market, Sell & Serve Your Customers on Autopilot", "tagline": "9 Ready-to-Use Workflows | Claude Cowork + Zapier + n8n", "source": "ai-automation-mastery.pdf", "version": "1.0 — March 2026", "pages": 32, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini", "Claude Cowork", "Zapier", "n8n"], "sections": [{"title": "Welcome", "type": "intro", "content": "YOUR AI SHOULD WORK WHILE YOU DON'T. You've learned the prompts (Product 1). You've built the Skills and Gems (Product 2). You've deployed complete business systems (Product 3). Now it's time for the final level: automation that runs without you. This guide gives you ready-to-use, step-by-step workflows that connect Claude and Gemini to tools like Claude Cowork, Zapier, and n8n. The result? Your AI writes, responds, follows up, and reports — automatically. You just review the output.", "automation_ladder": [{"level": "01", "name": "Manual AI", "description": "You type prompts one at a time", "status": "DONE"}, {"level": "02", "name": "Specialist AI", "description": "You built Skills & Gems", "status": "DONE"}, {"level": "03", "name": "System AI", "description": "You deployed business systems", "status": "DONE"}, {"level": "04", "name": "Automated AI", "description": "Systems run on autopilot", "status": "YOU ARE HERE"}], "items": []}, {"title": "How to Use This Guide", "type": "instructions", "content": "Three-step guide to setting up and launching automations.", "items": [{"step": 1, "title": "Pick a Workflow", "instruction": "Browse by category: Marketing or Customer Service."}, {"step": 2, "title": "Set Up the Workflow", "instruction": "Follow the step-by-step setup for Claude Cowork, Zapier, or n8n."}, {"step": 3, "title": "Customize & Launch", "instruction": "Fill in your [BRACKETS], test once, let it run."}]}, {"title": "Table of Contents", "type": "toc", "content": "4 parts. 9 workflows. All templates included.", "items": [{"part": "I — AUTOMATION FOUNDATION", "chapter": "01", "title": "Understanding Automation Platforms", "pages": "4-5"}, {"part": "I — AUTOMATION FOUNDATION", "chapter": "02", "title": "Your Automation Toolkit Setup", "pages": "6-7"}, {"part": "II — MARKETING AUTOMATION", "chapter": "03", "title": "Auto-Generate Social Media Posts", "pages": "8-9"}, {"part": "II — MARKETING AUTOMATION", "chapter": "04", "title": "Email Sequence Generator", "pages": "10-11"}, {"part": "II — MARKETING AUTOMATION", "chapter": "05", "title": "Content Repurposing Engine", "pages": "12-13"}, {"part": "II — MARKETING AUTOMATION", "chapter": "06", "title": "Lead Magnet Follow-Up", "pages": "14-15"}, {"part": "II — MARKETING AUTOMATION", "chapter": "07", "title": "Competitor Watch & Alert", "pages": "16-17"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "08", "title": "Smart Inquiry Auto-Responder", "pages": "18-19"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "09", "title": "Client Onboarding Automation", "pages": "20-21"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "10", "title": "Review & Testimonial Collector", "pages": "22-23"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "11", "title": "Customer Follow-Up & Re-Engagement", "pages": "24-25"}, {"part": "IV — OPTIMIZATION", "chapter": "12", "title": "Automation Dashboard", "pages": "26-27"}, {"part": "IV — OPTIMIZATION", "chapter": "13", "title": "Troubleshooting & Optimization", "pages": "28-29"}, {"part": "IV — OPTIMIZATION", "chapter": "14", "title": "What's Next: Ultimate AI Bundle", "pages": "30-31"}]}, {"title": "Chapter 01: Understanding Automation Platforms", "type": "educational", "content": "Before you build a single workflow, you need to understand the two platforms that make hands-free AI possible: Zapier and n8n. Both connect your AI tools (Claude and Gemini) to the apps you already use — email, CRM, social media, spreadsheets, payment processors — so tasks fire automatically without you lifting a finger. Every automation follows the same 4-part anatomy: a Trigger starts it, an AI Action processes it, an Output is generated, and a Destination receives it. Zapier is the no-code easy button with 7,000+ app integrations and built-in Claude and Gemini connectors — ideal if you want to be live in under 10 minutes. n8n is the open-source power tool with visual workflow building, complex branching logic, and self-hosting for cost savings — ideal if you want full control. This chapter breaks down both platforms with real pricing, key terminology, and a decision guide so you pick the right tool for your situation. Every workflow in this guide includes step-by-step setup for BOTH platforms.", "automation_anatomy": {"description": "The 4 Parts of Every Automation", "parts": [{"number": 1, "label": "TRIGGER", "description": "When this happens..."}, {"number": 2, "label": "AI ACTION", "description": "Ask AI to..."}, {"number": 3, "label": "OUTPUT", "description": "Take the result..."}, {"number": 4, "label": "DESTINATION", "description": "Send it to..."}]}, "platforms": [{"name": "Zapier", "tagline": "The Easy Button", "what_it_is": "Cloud-based, no-code, 7,000+ app integrations", "best_for": "Non-technical users, quick setup, massive app library", "ai_integrations": "Built-in Claude AI and Google Gemini integrations", "pricing": "Free = 100 tasks/month; Starter = $19.99/mo for 750 tasks", "key_terms": {"Zap": "one workflow", "Task": "one execution of a step"}}, {"name": "n8n", "tagline": "The Power Tool", "what_it_is": "Open-source, self-hostable or cloud, visual workflow builder", "best_for": "Users who want more control, complex logic, cost savings", "ai_integrations": "Native Claude + Gemini nodes via API keys", "pricing": "Free self-hosted; Cloud starts at EUR 20/month", "key_terms": {"Workflow": "automation", "Execution": "one run"}}], "decision_guide": {"choose_zapier_if": ["You want the fastest setup (under 10 min)", "You're not technical — no-code everything", "You need to connect to many different apps", "You're okay paying per task as you scale"], "choose_n8n_if": ["You want more control over workflows", "You're comfortable with slightly more tech", "You want to self-host for cost savings", "You need complex logic (loops, branching)"]}, "pro_tip": "Every workflow in this guide includes setup steps for BOTH platforms. You can start with Zapier for speed, then migrate to n8n later if you want more control."}, {"title": "Chapter 02: Your Automation Toolkit Setup", "type": "educational", "content": "This chapter walks you through connecting all your tools in 30 minutes or less so you are ready to deploy any workflow in this guide. You will set up your Claude API key from console.anthropic.com, your Gemini API key from Google AI Studio, and connect them to your chosen automation platform. For Zapier: four steps from signup through the Anthropic connection to a test Zap that confirms everything works. For n8n: four steps from cloud signup (or self-hosting) through credential setup to a verified test workflow. The pre-flight checklist covers every account you need, the optional-but-recommended integrations (Gmail, Google Sheets, your CRM, Slack) that unlock the most powerful workflows, and a credentials tracker template so you never lose track of your API keys, plan tiers, or setup dates. Complete this chapter once and every workflow after it is plug-and-play.", "pre_flight_checklist": ["Claude account (free or Pro) — claude.ai", "Gemini account (free or Advanced) — gemini.google.com", "Anthropic API key — console.anthropic.com", "Google AI Studio API key — aistudio.google.com", "Zapier account — zapier.com", "n8n account — n8n.io (cloud) or self-hosted"], "optional_but_recommended": ["Gmail / Google Workspace", "Google Sheets (for tracking outputs)", "Your CRM (HubSpot, Salesforce, etc.)", "Social media accounts", "Slack or Teams (for notifications)"], "zapier_setup": [{"step": 1, "action": "Sign up at zapier.com", "detail": "Choose Starter plan or higher for AI actions"}, {"step": 2, "action": "Connect Anthropic", "detail": "Settings > Connections > Search 'Anthropic' > Paste API key"}, {"step": 3, "action": "Connect Gemini", "detail": "Settings > Connections > Search 'Google AI Studio' > Paste API key"}, {"step": 4, "action": "Test connection", "detail": "Create test Zap > Add Claude step > Send 'Hello, test!'"}], "n8n_setup": [{"step": 1, "action": "Sign up at app.n8n.cloud", "detail": "Choose Starter plan, or self-host for free"}, {"step": 2, "action": "Add Anthropic credential", "detail": "Settings > Credentials > New > Anthropic > Paste API key"}, {"step": 3, "action": "Add Gemini credential", "detail": "Settings > Credentials > New > Google Gemini > Paste API key"}, {"step": 4, "action": "Test workflow", "detail": "Create new workflow > Add Anthropic node > Execute > Verify"}], "credentials_tracker": {"platform": "[Zapier / n8n / Both]", "plan": "[tier]", "budget": "$[___]", "anthropic_api_key_location": "[location]", "gemini_api_key_location": "[location]", "setup_date": "[___/___/2026]"}}, {"title": "Claude Cowork — Your Desktop Automation Hub", "type": "educational", "content": "Claude Cowork is Anthropic's desktop automation agent, included with Claude Pro ($20/month). It connects to 38+ apps — Gmail, Google Calendar, Slack, Notion, Trello, and more — letting you run automations directly from your computer without any third-party tools. For solopreneurs, Cowork is often the fastest path to automation because there's nothing extra to set up. Every workflow in this guide includes a \"Cowork Alternative\" section showing you how to run it natively.", "items": [{"title": "No Extra Cost", "description": "Included with Claude Pro — you may already have it"}, {"title": "38+ App Connectors", "description": "Gmail, Calendar, Slack, Notion, Trello, Sheets, and more"}, {"title": "Desktop-Native", "description": "Runs from Claude Desktop app — no browser tabs or third-party dashboards"}, {"title": "Natural Language", "description": "Just describe what you want automated in plain English"}], "comparison": {"cowork": ["Free with Claude Pro ($20/mo)", "Natural language setup", "Runs from desktop", "Best for: simple to medium automations"], "zapier": ["Starts at $20/mo for 750 tasks", "Visual drag-and-drop builder", "Runs in cloud 24/7", "Best for: high-volume, always-on workflows"], "n8n": ["Free self-hosted or $20/mo cloud", "Most flexible & technical", "Full coding access", "Best for: complex multi-step workflows"]}}, {"title": "Workflow 03: Auto-Generate Social Posts", "type": "workflow", "tagline": "Turn your content calendar into published posts — automatically, every day.", "metrics": {"time_saved": "45 min/day", "posts_per_month": 30, "setup_time": "2 hours"}, "flow": ["Schedule", "Google Sheets", "Claude AI", "Buffer"], "content_calendar_template": {"columns": ["Date", "Topic", "Platform", "Tone", "Status", "Published URL"], "status_values": ["Pending", "Published", "Skip"], "note": "Set Status to 'Pending' for rows you want the automation to pick up. After publishing, update Status to 'Published' manually or add a Zapier step to do it automatically using the 'Update Spreadsheet Row' action."}, "ai_prompt": {"platform": "Claude AI (Zapier or API)", "prompt": "You are a social media writer for Bloom Botanicals, a small online plant shop that sells rare houseplants to enthusiasts. ← Replace 'Bloom Botanicals' with your business name and update the description.\n\nWrite a single social media post for {{platform}} about the following topic: {{topic}}.\n\nTone: {{tone}} ← This comes from your spreadsheet. Examples: 'casual and warm', 'professional', 'playful'.\n\nGuidelines:\n- For LinkedIn: 150–250 words, no more than 3 hashtags, start with a hook sentence\n- For Instagram: 80–150 words, 5–8 relevant hashtags at the end, use line breaks for readability\n- For Twitter/X: under 280 characters, one hashtag max, punchy and direct\n- Always write in first person as the brand\n- Do not use phrases like 'Dive in!' or 'In today's world'\n- End with a soft call to action (e.g., 'Link in bio', 'Comment below', 'DM us to learn more')\n\nReturn only the post text, ready to copy-paste. Do not include labels, explanations, or quotation marks around the post."}, "zapier_setup": [{"step": "T", "node": "Schedule by Zapier", "detail": "In your Zapier dashboard, click '+ Create' then 'New Zap'. Search for 'Schedule by Zapier' as your trigger app — it's a built-in Zapier tool, no separate account needed. Choose 'Every Day' as the trigger event. Set the Time of Day to 7:00 AM in your local timezone (or 1-2 hours before you'd normally post). Click 'Continue' then 'Test trigger' — Zapier will return a sample timestamp, which confirms the trigger is working. This step just fires the Zap on schedule; the actual data comes from the next step."}, {"step": "S", "node": "Google Sheets", "detail": "Add a new action step and search for 'Google Sheets'. Choose 'Lookup Spreadsheet Row' as the action event (not 'Get Row' — Lookup lets you filter by a column value). Connect your Google account and select the spreadsheet and worksheet that holds your content calendar. In the 'Lookup Column' field, select the 'Status' column. In the 'Lookup Value' field, type 'Pending' (match the exact capitalization you use in your sheet). Enable 'Support Line Item Output' so Zapier grabs only one row at a time. Test this step — Zapier should return the first row where Status is Pending, showing the Topic, Platform, Tone, and Date fields."}, {"step": "AI", "node": "Claude AI", "detail": "Add another action step and search for 'Claude AI by Anthropic' (or 'Anthropic'). Select 'Send Message' as the action event. In the Model field, choose 'claude-3-5-sonnet' — it produces strong copy and is fast enough for this use case. In the Message (Human Turn) field, paste your prompt from the ai_prompt section below. Use Zapier's field-mapping to insert your Sheet data into the prompt: click inside the prompt field, then click the '+' icon to insert fields. Map the Topic field to {{topic}}, Platform to {{platform}}, and Tone to {{tone}} in your prompt. Set Max Tokens to 500 — enough for a full social post plus a few hashtags. Test this step and read the output carefully; if the post doesn't match your voice, tweak the prompt now before going further."}, {"step": "A", "node": "Buffer", "detail": "Add a final action step and search for 'Buffer'. Choose 'Create Update' as the action event and connect your Buffer account. In the Profile IDs field, select the specific social media profile you want to post to (e.g., your LinkedIn page or Instagram account) — you can add multiple profiles here if you post to several platforms at once. In the Text field, click the '+' icon and map it to the output from your Claude AI step (it will appear as something like 'Claude AI: Output Text'). Leave the Scheduled At field blank to let Buffer queue the post at its next optimal slot, or enter a specific time. Turn the Zap on, then manually run one test cycle using 'Run Zap' to confirm a real draft appears in your Buffer queue."}], "n8n_setup": [{"step": "T", "node": "Schedule Trigger", "detail": "Open n8n and click '+ Add workflow', then add a 'Schedule Trigger' node. Set Mode to 'Every Day' and configure the Hour to 7 and Minute to 0. If you're self-hosting n8n, make sure your server timezone matches your intended posting timezone — go to Settings > General to check. Click 'Execute Node' to test it; you should see a single output item with a timestamp. This node will fire the rest of the workflow automatically each morning."}, {"step": "S", "node": "Google Sheets", "detail": "Add a 'Google Sheets' node and connect it with an OAuth2 credential (click 'Create New Credential', sign in with Google, and grant the requested permissions). Set the Operation to 'Read Rows'. Select your spreadsheet by pasting its URL or searching by name, then choose the correct sheet tab. In the Filters section, add a filter: Column = 'Status', Condition = 'equals', Value = 'Pending'. Set 'Max Rows' to 1 so the workflow processes one post per run. Test the node — you should see a single row with your topic, platform, tone, and other columns as output fields."}, {"step": "AI", "node": "HTTP Request (Anthropic API)", "detail": "n8n has an Anthropic node in newer versions — if you see it, use that. If not, add an 'HTTP Request' node. Set Method to POST and URL to 'https://api.anthropic.com/v1/messages'. Under Headers, add 'x-api-key' with your Anthropic API key, 'anthropic-version' with '2023-06-01', and 'Content-Type' with 'application/json'. In the Body section, choose JSON and build the payload: set model to 'claude-3-5-sonnet-20241022', max_tokens to 500, and messages as an array with one object where role is 'user' and content is your prompt. Use n8n's expression editor to insert the Google Sheets output into the prompt — for example, {{ $node['Google Sheets'].json['Topic'] }}. Run the node and verify the response contains a usable social post."}, {"step": "A", "node": "HTTP Request (Buffer API) or Buffer node", "detail": "If you have the Buffer node in your n8n version, use it and authenticate with OAuth. Otherwise, use an HTTP Request node: set Method to POST and URL to 'https://api.bufferapp.com/1/updates/create.json'. You'll need a Buffer Access Token from Buffer's developer portal (bufferapp.com/developers). In the Body, add the field 'text' mapped to the Claude response output using the expression editor, and 'profile_ids[]' set to your Buffer profile ID (find this in your Buffer account URL or API explorer). Test the node — a new post should appear in your Buffer queue within seconds. After confirming, activate the workflow using the toggle in the top-right corner."}], "customization": ["Change the schedule trigger time to match your audience's peak engagement hours", "Add a second Claude step to generate an image prompt, then use DALL·E to create a matching visual", "Add a Google Sheets 'Update Row' step at the end to change Status from Pending to Published automatically", "Duplicate the Zap and point it at a different platform column for multi-platform posting"], "content": "This workflow pulls a pending row from your Google Sheets content calendar each morning, sends it to Claude to generate a platform-appropriate post, then publishes it via Buffer. Once it's running, your daily posting happens without you touching it. The setup takes about two hours and requires no coding. The main thing to get right is your spreadsheet structure — if the columns are named correctly, everything else maps automatically. You'll also write a prompt once that tells Claude your brand voice, and it uses that every time.", "cowork_alternative": {"platform": "Claude Cowork", "steps": [{"step": 1, "action": "Set up your Content Calendar Agent", "detail": "In Claude Cowork, create a new Agent and name it 'Daily Post Generator'. In the Agent's system prompt, paste the brand context from the ai_prompt above — this is the block describing your business name, tone, and platform-specific rules. This system prompt persists across all runs, so you only write it once. Save the agent."}, {"step": 2, "action": "Connect your Google Sheet as a data source", "detail": "Go to your Agent's Integrations tab and connect Google Sheets using the OAuth flow. Point it to your content calendar spreadsheet. Set a filter so the agent only reads rows where Status = 'Pending'. Test the connection by clicking 'Fetch Data' — you should see your pending rows listed in the preview panel."}, {"step": 3, "action": "Configure the posting action", "detail": "In the Agent's Actions tab, add a Buffer integration. Authenticate with your Buffer account and select the profile to post to. Map the agent's output (the generated post text) to the Buffer 'Text' field. Set the action to trigger automatically after the agent generates a response, rather than requiring manual approval — you can always switch this back to 'review before posting' while you're testing."}, {"step": 4, "action": "Schedule and activate", "detail": "Go to the Agent's Schedule tab and set it to run daily at 7:00 AM. Turn on the schedule using the toggle. For the first week, check your Buffer queue each morning to verify the posts look correct before they go live — Buffer lets you edit queued posts even after they've been added. Once you're confident in the output quality, you can stop reviewing and let it run fully automatically."}]}, "setup_time": "2 hours", "complexity": "beginner", "maintenance": "Review your content calendar weekly to keep the Pending queue populated. If Claude's output starts feeling repetitive, update the prompt with new examples or adjust the tone column values.", "expected_output": "One platform-appropriate social post published to Buffer each morning, drawn from your content calendar without any manual action.", "id": "workflow-03", "prerequisites": ["A Google Sheet set up as a content calendar with columns: Topic, Platform, Tone, Status, and Date", "A Buffer account connected to your social media profiles (free plan works)", "A Zapier account (Starter plan or higher for multi-step Zaps)", "An Anthropic API key added to Zapier's Claude AI integration (or Claude added as a connected app)", "At least 5 rows of content ideas in your sheet with Status set to 'Pending'"], "n8n_workflow_json": {"name": "KH Academy — Auto-Generate Social Posts", "nodes": [{"id": "a1b2c3d4-0001-4a1b-8c1d-e1f2a3b4c5d6", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 100], "parameters": {"content": "## 🚀 SETUP INSTRUCTIONS\n\n**1. Anthropic API Key**\nOpen the \"HTTP Request - Claude\" node → Headers → replace `YOUR_ANTHROPIC_API_KEY` with your real key from https://console.anthropic.com\n\n**2. Google Account**\nOpen both Google Sheets nodes → Credentials → connect your Google account via OAuth2.\n\n**3. Spreadsheet ID**\nIn both Google Sheets nodes, replace `YOUR_SPREADSHEET_ID` with the ID from your Content Calendar spreadsheet URL:\n`https://docs.google.com/spreadsheets/d/`**THIS_PART**`/edit`\n\nYour sheet must have columns: **Topic, Platform, Tone, Key_Message, Status**\nSet rows you want processed to Status = `Pending`\n\n**4. Buffer Access Token**\nOpen \"HTTP Request - Buffer\" → Body → replace `YOUR_BUFFER_ACCESS_TOKEN` with your token from https://buffer.com/developers/apps\nAlso replace `YOUR_BUFFER_PROFILE_ID` with the profile ID for the social account to post to.\n\n**5. Business Info**\nIn the \"HTTP Request - Claude\" node body, update the system prompt to reflect your actual business name and brand voice.", "height": 560, "width": 520, "color": 4}}, {"id": "a1b2c3d4-0002-4a1b-8c1d-e1f2a3b4c5d6", "name": "Schedule Trigger", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.1, "position": [250, 300], "parameters": {"rule": {"interval": [{"field": "cronExpression", "expression": "0 7 * * *"}]}}}, {"id": "a1b2c3d4-0003-4a1b-8c1d-e1f2a3b4c5d6", "name": "Google Sheets - Read", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [450, 300], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "read", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Content Calendar", "mode": "name"}, "filtersUI": {"values": [{"lookupColumn": "Status", "lookupValue": "Pending"}]}, "options": {"returnAllMatches": false}}}, {"id": "a1b2c3d4-0004-4a1b-8c1d-e1f2a3b4c5d6", "name": "HTTP Request - Claude", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [650, 300], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 400,\n  \"system\": \"You are a social media writer for [YOUR BUSINESS NAME — replace this]. Your brand voice is [DESCRIBE YOUR TONE — replace this].\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Write a single social media post for the platform: {{ $json.Platform }}\\nTopic: {{ $json.Topic }}\\nTone: {{ $json.Tone }}\\nKey message: {{ $json.Key_Message }}\\n\\nRules:\\n- If platform is X/Twitter, keep under 280 characters including hashtags\\n- If platform is LinkedIn, write 100-200 words with a strong hook opening\\n- If platform is Instagram, write a conversational caption with line breaks\\n- Include a hook in the first sentence\\n- End with a question or call-to-action\\n- Use max 3 relevant hashtags\\n- Never start with generic openers like 'In today's fast-paced world'\\n\\nWrite the post now. Output ONLY the post text, nothing else.\"\n    }\n  ]\n}", "options": {}}}, {"id": "a1b2c3d4-0005-4a1b-8c1d-e1f2a3b4c5d6", "name": "HTTP Request - Buffer", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [850, 300], "parameters": {"method": "POST", "url": "https://api.bufferapp.com/1/updates/create.json", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "Content-Type", "value": "application/x-www-form-urlencoded"}]}, "sendBody": true, "bodyContentType": "form-urlencoded", "bodyParameters": {"parameters": [{"name": "access_token", "value": "YOUR_BUFFER_ACCESS_TOKEN"}, {"name": "profile_ids[]", "value": "YOUR_BUFFER_PROFILE_ID"}, {"name": "text", "value": "={{ $json.content[0].text }}"}]}, "options": {}}}, {"id": "a1b2c3d4-0006-4a1b-8c1d-e1f2a3b4c5d6", "name": "Google Sheets - Update", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [1050, 300], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "update", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Content Calendar", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"Status": "Posted"}, "matchingColumns": ["row_number"]}, "options": {}}}], "connections": {"Schedule Trigger": {"main": [[{"node": "Google Sheets - Read", "type": "main", "index": 0}]]}, "Google Sheets - Read": {"main": [[{"node": "HTTP Request - Claude", "type": "main", "index": 0}]]}, "HTTP Request - Claude": {"main": [[{"node": "HTTP Request - Buffer", "type": "main", "index": 0}]]}, "HTTP Request - Buffer": {"main": [[{"node": "Google Sheets - Update", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-social-posts"}, "tags": []}}, {"title": "Workflow 04: Email Sequence Generator", "type": "workflow", "tagline": "AUTOMATED NURTURE SEQUENCES THAT SOUND LIKE YOU WROTE EACH ONE", "metrics": {"time_saved": "3-5 hrs", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Per lead"}, "flow": [{"step": "L", "label": "NEW LEAD", "description": "CRM trigger"}, {"step": "E", "label": "ENRICH", "description": "Pull details"}, {"step": "AI", "label": "CLAUDE", "description": "Write 5 emails"}, {"step": "R", "label": "REVIEW", "description": "Your approval"}, {"step": "S", "label": "SEND", "description": "Auto-queue"}], "why_this_beats_generic_templates": "Every email tool has templates. But they're the same for everyone. This workflow generates sequences personalized to each lead — their industry, their pain points, their entry point — using YOUR brand voice.", "ai_prompt": {"platform": "Claude", "system_prompt": "You are an email marketing specialist for YOUR BUSINESS NAME. ← Replace with your actual brand name\nBrand voice: YOUR EMAIL TONE ← Replace (e.g. \"conversational and direct, never corporate, occasional dry humor\")\nProduct: WHAT YOU SELL ← Replace with one sentence describing your product or service\nPrice: PRICE POINT ← Replace (e.g. $297/month, $1,500 one-time, free 14-day trial)\nUnique value: YOUR KEY DIFFERENTIATOR ← Replace with one sentence on why leads should choose you\nAlways return valid JSON only — no markdown, no explanation, just a raw JSON array.", "user_prompt": "Lead details:\nName: [LEAD NAME INSERTED BY AUTOMATION]\nCompany: [COMPANY INSERTED BY AUTOMATION]\nEmail: [EMAIL INSERTED BY AUTOMATION]\nIndustry: [INDUSTRY INSERTED BY AUTOMATION]\nLead source: [SOURCE INSERTED BY AUTOMATION]\n\nGenerate a 5-email nurture sequence. Return a JSON array of exactly 5 objects with these keys: email_number (1-5), subject (under 50 chars), preview_text (under 90 chars), body (under 200 words, plain text), cta (call to action text), send_timing (e.g. 'Immediately', 'Day 3', 'Day 7').\n\nEmail structure:\n- Email 1 (Immediately): Warm welcome + one immediately useful tip or resource related to why they signed up\n- Email 2 (Day 3): Pure education — one insight or framework, no selling, builds trust\n- Email 3 (Day 7): A brief case study or story from someone in a similar industry\n- Email 4 (Day 10): Soft offer with a specific benefit tailored to their situation\n- Email 5 (Day 14): Direct offer with urgency and a clear outcome statement\n\nPersonalize each email to the lead's industry and the source they came from. Output ONLY the JSON array.", "notes": "Replace every value marked with ← Replace before activating. The system prompt is what gets pasted into the 'system' field of the Claude API call. The user prompt goes into the 'content' field of the messages array, with n8n expressions replacing the bracketed automation fields."}, "zapier_setup": [{"step": "T", "node": "HubSpot / Mailchimp", "detail": "Create a new Zap and select HubSpot as the trigger app, then choose 'New Contact' as the trigger event. Connect your HubSpot account and test the trigger to confirm it pulls a sample contact with fields like First Name, Last Name, Email, Company, Industry, and Lead Source. If you use Mailchimp instead, select 'New Subscriber' as the trigger and choose the list your leads join. Make sure whatever form or landing page collects the fields you need — industry and lead source are especially important for personalization, so consider adding custom fields to your signup form if they aren't already there."}, {"step": "AI", "node": "Claude AI", "detail": "Add a 'Claude: Send Message' action step. Paste the complete system prompt above into the System field, replacing all ← Replace placeholders with your actual business details — this is what gives Claude your brand voice and product context. In the User Message field, paste the user prompt and use Zapier's field mapper to insert the lead's actual data: map the First Name + Last Name fields to the Name placeholder, Company to Company, and so on. Set the model to claude-sonnet-4-20250514 and max tokens to 4000. When you test this step you should see a JSON array of 5 email objects returned in the response."}, {"step": "S", "node": "Google Sheets", "detail": "Add a 'Google Sheets: Create Spreadsheet Row' action — but you'll need to run it inside a Formatter loop or use Zapier's built-in 'Looping by Zapier' feature (available on paid plans) to create one row per email. Each iteration maps one email object from the Claude JSON array: use Zapier's Formatter to extract email_number, subject, preview_text, body, cta, and send_timing from the parsed JSON. Map lead_name and lead_email from the HubSpot trigger step. The Status column should default to 'Pending Review' so you can see new sequences at a glance each morning before approving them for sending."}, {"step": "@", "node": "Gmail / Mailchimp", "detail": "For initial setup, leave this step manual: simply review the Google Sheet each day, approve the sequences you want to send, and copy the content into your email tool. When you're ready to automate sending, create a second Zap triggered by a Google Sheets 'New or Updated Row' event filtered to rows where Status = 'Approved' and Send_Date = today. Use Gmail's 'Send Email' action or Mailchimp's 'Add Subscriber to Campaign' to queue each email. Alternatively, add emails directly to a Mailchimp automation sequence via their API. Update the row Status to 'Sent' after each successful send to avoid duplicates."}], "n8n_setup": [{"step": "T", "node": "HubSpot Trigger or Webhook", "detail": "In n8n, you have two options. Option A: use the native HubSpot Trigger node — connect your HubSpot credentials via API key or OAuth2 and select the 'contact.creation' event. This fires instantly whenever a new contact is created. Option B: use the Webhook node if you don't have HubSpot or prefer to trigger from another source — copy the webhook URL from n8n and paste it into your CRM, Typeform, or landing page as the form submission destination. The webhook expects a JSON body with keys: lead_name, email, company, industry, lead_source. Both options feed identically into the next node."}, {"step": "AI", "node": "HTTP Request - Claude", "detail": "Add an HTTP Request node configured as a POST to https://api.anthropic.com/v1/messages. In the Headers section add three headers: x-api-key set to your Anthropic API key, anthropic-version set to 2023-06-01, and Content-Type set to application/json. In the Body section, set type to JSON and paste the full JSON body from the n8n workflow file — this contains the system prompt with your brand context and the user prompt with n8n expressions that automatically pull the lead's name, company, industry, and source from the trigger node. Set max_tokens to 4000 so Claude has enough room to write all 5 emails."}, {"step": "CODE", "node": "Parse Email Sequence (Code node)", "detail": "Add a Code node after the HTTP Request. This node parses Claude's JSON array response into 5 separate n8n items — one per email. It strips any markdown code fences Claude might add, parses the JSON, retrieves the lead name and email from the trigger step, calculates the actual calendar send dates based on today's date plus the send timing offsets, and returns each email as its own item with the Status set to 'Pending Review'. This is the key step that makes the Google Sheets append work correctly — without it, n8n would only create one row instead of five."}, {"step": "S", "node": "Google Sheets - Store Emails", "detail": "Add a Google Sheets node set to the Append operation. Connect your Google account via OAuth2, enter the Spreadsheet ID from your sheet URL, and set the Sheet Name to 'Email Sequences'. Map each column manually: Lead Name, Email, Email_Number, Subject, Preview_Text, Body, CTA, Send_Date, and Status. Because the Code node outputs 5 items, this node will run 5 times and create 5 rows automatically — one per email. After your first test, open the sheet and confirm all 5 rows appear correctly with the right send dates spaced out."}], "pro_tip": "Start with manual approval for the first 10 sequences. Once you trust the output, let it run fully automated.", "customization": {"email_tool": "[Mailchimp / HubSpot / Gmail]", "crm": "[HubSpot / Sheets]", "approval_mode": "[Manual / Auto]"}, "content": "Every email marketing tool has templates, but they are the same generic sequences for everyone. This workflow generates fully personalized 5-email nurture sequences for each individual lead based on their industry, pain points, and how they found you — all in your brand voice. When a new contact enters your CRM or email tool, the automation fires: it pulls the lead details, sends them to Claude with your product info and brand guidelines, and Claude writes 5 timed emails (welcome, educational, case study, soft offer, direct offer with urgency). The emails land in a Google Sheet for review, then queue automatically in Gmail or Mailchimp on the scheduled send dates. In Zapier: HubSpot/Mailchimp trigger, Claude AI step, Sheets storage, Gmail/Mailchimp send. In n8n: Webhook or CRM trigger, Claude AI node with mapped lead data, Code node to parse 5 emails, Sheets write. Start with manual approval for your first 10 sequences to build confidence in the output quality, then switch to fully automated mode.", "cowork_alternative": {"description": "With Claude's desktop app and MCP (Model Context Protocol) integrations, you can run a simplified version of this workflow without any automation platform. Claude can connect directly to HubSpot, Google Sheets, and Gmail through MCP server connections — available in Claude Pro at $20/month. This approach is ideal if you're generating sequences for one or two leads at a time and want to review everything manually before it goes anywhere.", "steps": ["Open Claude Desktop and install the Google Sheets and Gmail MCP servers following Anthropic's setup guide at docs.anthropic.com/mcp", "When a new lead comes in, paste their details (name, company, industry, source) into Claude along with the email sequence prompt from this workflow — no need to format it as an API call", "Claude generates the 5-email sequence in your conversation. Review it immediately and request any changes before saving anything", "Say 'Add these emails to my Email Sequences sheet with today's send dates' — Claude will write all 5 rows to your Google Sheet via the MCP connection", "For Email 1, say 'Draft this as a Gmail message to [email address] and save as draft' — Claude creates the draft in your Gmail for final review before you hit send"]}, "setup_time": "15-30 minutes", "complexity": "Beginner-friendly — follow the step-by-step screenshots", "maintenance": "Check weekly, adjust monthly", "expected_output": "5-email nurture sequence customized to your product and audience", "prerequisites": ["An Anthropic account with API access — sign up at console.anthropic.com and generate an API key under API Keys", "A HubSpot account (free tier works) OR any CRM or lead capture tool that can send a webhook POST request", "A Google account with access to Google Sheets, connected to n8n via OAuth2", "A Google Sheet set up with these column headers in row 1: Lead Name, Email, Email_Number, Subject, Preview_Text, Body, CTA, Send_Date, Status", "Optionally: a Gmail or Mailchimp account to actually send the queued emails on their scheduled dates"], "n8n_workflow_json": {"name": "KH Academy — Email Sequence Generator", "nodes": [{"id": "c3d4e5f6-0001-4c3d-ae3f-a1b2c3d4e5f6", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS\n\n**1. Trigger Option A — HubSpot**\nOpen the \"HubSpot Trigger\" node → Credentials → connect your HubSpot account via OAuth2 or API key. The trigger fires whenever a new contact is created in any list. If you only want to trigger for a specific list, add a filter in HubSpot Trigger parameters.\n\n**Trigger Option B — Webhook (no CRM)**\nIf you don't use HubSpot, activate the \"Webhook Trigger\" node instead and disable the HubSpot Trigger. Copy the webhook URL and paste it into your CRM, Typeform, or lead capture tool as a POST destination. Expected payload: { \"lead_name\": \"...\", \"email\": \"...\", \"company\": \"...\", \"industry\": \"...\", \"lead_source\": \"...\" }\n\n**2. Anthropic API Key**\nOpen the \"HTTP Request - Claude\" node → Headers → replace `YOUR_ANTHROPIC_API_KEY` with your real key from https://console.anthropic.com\n\n**3. Customize the AI Prompt**\nIn the \"HTTP Request - Claude\" node body, replace these placeholders:\n- YOUR BUSINESS NAME ← your actual brand name\n- YOUR EMAIL TONE ← e.g. \"conversational and direct, never corporate\"\n- WHAT YOU SELL ← your product or service in one sentence\n- PRICE ← your price point (e.g. $297/month or $1,500 one-time)\n- WHY CHOOSE YOU ← your key differentiator in one sentence\n\n**4. Google Sheets**\nOpen \"Google Sheets - Store Emails\" → Credentials → connect your Google account.\nCreate a new sheet with these exact column headers in row 1:\nLead Name | Email | Email_Number | Subject | Preview_Text | Body | CTA | Send_Date | Status\n\nReplace `YOUR_SPREADSHEET_ID` with the ID from your sheet URL:\nhttps://docs.google.com/spreadsheets/d/THIS_PART/edit\n\n**5. Code Node**\nThe \"Parse Email Sequence\" Code node expects Claude to return a valid JSON array of 5 email objects. If Claude returns markdown-wrapped JSON, the node strips the code fences automatically.", "height": 700, "width": 580, "color": 4}}, {"id": "c3d4e5f6-0002-4c3d-ae3f-a1b2c3d4e5f6", "name": "HubSpot Trigger", "type": "n8n-nodes-base.hubspotTrigger", "typeVersion": 1, "position": [250, 300], "credentials": {"hubspotDeveloperApi": {"id": "YOUR_HUBSPOT_CREDENTIAL_ID", "name": "HubSpot Developer account"}}, "parameters": {"eventsUi": {"eventValues": [{"name": "contact.creation"}]}}}, {"id": "c3d4e5f6-0003-4c3d-ae3f-a1b2c3d4e5f6", "name": "Webhook Trigger", "type": "n8n-nodes-base.webhook", "typeVersion": 2, "position": [250, 480], "parameters": {"httpMethod": "POST", "path": "new-lead-email-sequence", "responseMode": "onReceived", "responseData": "firstEntryJson", "options": {}}}, {"id": "c3d4e5f6-0004-4c3d-ae3f-a1b2c3d4e5f6", "name": "HTTP Request - Claude", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [470, 300], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 4000,\n  \"system\": \"You are an email marketing specialist for YOUR BUSINESS NAME. ← Replace. Brand voice: YOUR EMAIL TONE ← Replace (e.g. conversational, direct, never corporate). Product: WHAT YOU SELL ← Replace, at PRICE ← Replace. Unique value: WHY CHOOSE YOU ← Replace. Always return valid JSON only — no markdown, no explanation, just a raw JSON array.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Lead details:\\nName: {{ $json.properties ? $json.properties.firstname + ' ' + $json.properties.lastname : $json.body.lead_name }}\\nCompany: {{ $json.properties ? $json.properties.company : $json.body.company }}\\nEmail: {{ $json.properties ? $json.properties.email : $json.body.email }}\\nIndustry: {{ $json.properties ? $json.properties.industry : $json.body.industry }}\\nLead source: {{ $json.properties ? $json.properties.hs_analytics_source : $json.body.lead_source }}\\n\\nGenerate a 5-email nurture sequence. Return a JSON array of exactly 5 objects with these keys: email_number (1-5), subject (under 50 chars), preview_text (under 90 chars), body (under 200 words, plain text), cta (call to action text), send_timing (e.g. 'Immediately', 'Day 3', 'Day 7').\\n\\nEmail structure:\\n- Email 1 (Immediately): Warm welcome + one immediately useful tip or resource\\n- Email 2 (Day 3): Pure education — no selling, build trust\\n- Email 3 (Day 7): Case study or story specific to their industry\\n- Email 4 (Day 10): Soft offer with a specific benefit for their situation\\n- Email 5 (Day 14): Direct offer with urgency and clear outcome\\n\\nPersonalize each email to the lead's industry and source. Output ONLY the JSON array, no other text.\"\n    }\n  ]\n}", "options": {}}}, {"id": "c3d4e5f6-0005-4c3d-ae3f-a1b2c3d4e5f6", "name": "Parse Email Sequence", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [690, 300], "parameters": {"mode": "runOnceForAllItems", "jsCode": "// Extract the raw text from Claude's response\nconst rawText = items[0].json.content[0].text;\n\n// Strip markdown code fences if Claude wrapped the JSON\nconst cleaned = rawText.replace(/```json\\n?/g, '').replace(/```\\n?/g, '').trim();\n\n// Parse the JSON array\nlet emails;\ntry {\n  emails = JSON.parse(cleaned);\n} catch (e) {\n  throw new Error('Failed to parse Claude response as JSON: ' + e.message + '\\nRaw: ' + cleaned.substring(0, 200));\n}\n\n// Get lead info from the HubSpot trigger (or webhook) — traverse back through the chain\nconst hubspotData = $('HubSpot Trigger').first()?.json || {};\nconst webhookData = $('Webhook Trigger').first()?.json?.body || {};\n\nconst leadName = hubspotData.properties\n  ? (hubspotData.properties.firstname + ' ' + hubspotData.properties.lastname).trim()\n  : (webhookData.lead_name || 'Unknown Lead');\n\nconst leadEmail = hubspotData.properties?.email || webhookData.email || '';\n\n// Calculate send dates relative to today\nconst today = new Date();\nconst timingDays = { 'Immediately': 0, 'Day 2': 2, 'Day 3': 3, 'Day 5': 5, 'Day 7': 7, 'Day 10': 10, 'Day 14': 14 };\n\n// Return one item per email\nreturn emails.map((email, idx) => {\n  const days = timingDays[email.send_timing] ?? (idx * 3);\n  const sendDate = new Date(today);\n  sendDate.setDate(today.getDate() + days);\n\n  return {\n    json: {\n      lead_name: leadName,\n      lead_email: leadEmail,\n      email_number: email.email_number || (idx + 1),\n      subject: email.subject || '',\n      preview_text: email.preview_text || '',\n      body: email.body || '',\n      cta: email.cta || '',\n      send_timing: email.send_timing || '',\n      send_date: sendDate.toISOString().split('T')[0],\n      status: 'Pending Review'\n    }\n  };\n});"}}, {"id": "c3d4e5f6-0006-4c3d-ae3f-a1b2c3d4e5f6", "name": "Google Sheets - Store Emails", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [910, 300], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "append", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Email Sequences", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"Lead Name": "={{ $json.lead_name }}", "Email": "={{ $json.lead_email }}", "Email_Number": "={{ $json.email_number }}", "Subject": "={{ $json.subject }}", "Preview_Text": "={{ $json.preview_text }}", "Body": "={{ $json.body }}", "CTA": "={{ $json.cta }}", "Send_Date": "={{ $json.send_date }}", "Status": "={{ $json.status }}"}}, "options": {}}}], "connections": {"HubSpot Trigger": {"main": [[{"node": "HTTP Request - Claude", "type": "main", "index": 0}]]}, "Webhook Trigger": {"main": [[{"node": "HTTP Request - Claude", "type": "main", "index": 0}]]}, "HTTP Request - Claude": {"main": [[{"node": "Parse Email Sequence", "type": "main", "index": 0}]]}, "Parse Email Sequence": {"main": [[{"node": "Google Sheets - Store Emails", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-04-email-sequence"}, "tags": []}, "diagram_image": "workflow-diagram-04.png"}, {"title": "Workflow 05: Content Repurposing Engine", "type": "workflow", "tagline": "ONE PIECE OF CONTENT → 19+ PIECES ACROSS EVERY PLATFORM", "metrics": {"time_saved": "8-10 hrs", "difficulty": "Intermediate", "tools_needed": 4, "frequency": "Per post"}, "flow": [{"step": "P", "label": "PUBLISH", "description": "Blog/Video"}, {"step": "E", "label": "EXTRACT", "description": "Get full text"}, {"step": "AI", "label": "CLAUDE", "description": "Repurpose"}, {"step": "G", "label": "SHEETS", "description": "Store all pieces"}, {"step": "Q", "label": "QUEUE", "description": "Schedule"}], "repurposing_matrix": [{"output": "5 LinkedIn posts", "description": "Different angles from the original — insight, story, how-to, counter-intuitive take, question post"}, {"output": "5 X/Twitter posts", "description": "Punchy, under 280 characters, concrete and specific"}, {"output": "1 Email newsletter intro", "description": "Hook + key insight + link, 80-100 words"}, {"output": "3 Instagram captions", "description": "Visual-friendly with CTAs, line breaks, storytelling angle"}, {"output": "5 Quote graphics", "description": "Standalone quotable lines under 25 words, ready for Canva"}], "stats": {"original_pieces": 1, "output_pieces": "19+", "weeks_covered": "4+"}, "ai_prompt": {"platform": "Claude", "system_prompt": "You are a content repurposing specialist for YOUR BUSINESS NAME. ← Replace with your brand name\nBrand voice: YOUR BRAND VOICE ← Replace (e.g. \"direct, occasionally witty, no corporate jargon, speaks to ambitious founders\")\nTarget audience: YOUR AUDIENCE ← Replace (e.g. \"B2B SaaS founders building their first $1M ARR\")\nYou take long-form content and produce multiple platform-optimized pieces. Return ONLY a valid JSON array — no markdown, no explanation.", "user_prompt": "Repurpose this blog content into 19 pieces. Source URL: [URL INSERTED BY AUTOMATION]\n\nFull content (extract meaningful body text, ignore navigation/ads/footers):\n[FULL HTML OR TEXT CONTENT INSERTED BY AUTOMATION]\n\nReturn a JSON array of exactly 19 objects. Each object must have these keys: platform (string), content_type (string), text (string), hashtags (array of strings).\n\nProduce:\n1-5: Five LinkedIn posts. Each 100-200 words. A different angle per post:\n  - Post 1: Lead with a surprising insight from the article\n  - Post 2: Tell a short story that illustrates the main point\n  - Post 3: Argue the counter-intuitive angle\n  - Post 4: Step-by-step how-to based on the key framework\n  - Post 5: Open with a direct question to the audience\n  End each with an open question. 3-5 hashtags each.\n\n6-10: Five X/Twitter posts. Each under 275 characters. Punchy opening line. Concrete, specific, no fluff. 1-2 hashtags each.\n\n11: One email newsletter intro. 80-100 words. Strong hook in sentence one, deliver one key insight, tease the link with curiosity. No hashtags.\n\n12-14: Three Instagram captions. Conversational tone, line breaks every 1-2 sentences, storytelling structure, strong CTA in the last line. 5-8 hashtags each.\n\n15-19: Five quotable lines for graphic cards. Under 25 words each, standalone insight that makes sense without any context, memorable phrasing. No hashtags.\n\nOutput ONLY the JSON array. No other text.", "notes": "Replace every ← Replace placeholder in the system prompt before activating. The user prompt is handled by the automation — you never need to paste it manually. The 19-piece breakdown is a minimum; Claude often identifies more quotable lines. Review the output in your Google Sheet before scheduling anything."}, "zapier_setup": [{"step": 1, "action": "Trigger: RSS / Webhook", "detail": "For an RSS trigger, go to Zapier and select 'RSS by Zapier' as your trigger app, choose 'New Item in Feed', and paste your blog's RSS feed URL (usually yourblog.com/feed or yourblog.com/rss). Zapier polls the feed every 15 minutes on paid plans and will fire whenever a new post appears. Alternatively, use a Webhook trigger — Zapier will give you a unique URL that you can POST to manually from anywhere: a browser bookmarklet, a Notion button, or a tool like Make. The webhook approach gives you more control because you decide exactly when to trigger repurposing, rather than having it fire on every single publish."}, {"step": 2, "action": "Extract full content", "detail": "Add a 'Formatter by Zapier' step using the 'Utilities' transform and the 'Extract Text from URL' function. Pass in the URL from the RSS item or webhook payload. Zapier will fetch the page and return the readable text content, stripping HTML, navigation, and ads. This is the text that goes into Claude's prompt. If your blog is behind a login or uses JavaScript rendering, this step may return incomplete content — in that case, consider using a service like Diffbot or Readability API as an intermediate step to get cleaner article extraction. Alternatively, copy-paste your content directly into the webhook payload as a 'text' field."}, {"step": 3, "action": "Claude: Send Message", "detail": "Add a 'Claude AI: Send Message' action and paste the complete system prompt into the System field — replace all ← Replace placeholders first. In the User Message field, paste the user prompt and map the extracted text from the Formatter step into the [FULL CONTENT] placeholder. Map the source URL from your trigger into the URL placeholder. Set max tokens to 8000 to give Claude enough space to write all 19 pieces. When you test this step, you should receive a large JSON array in the response — if you see markdown-wrapped JSON (with backticks), you may need to add a 'Code by Zapier' step to strip the fences before parsing."}, {"step": 4, "action": "Google Sheets: Create Rows", "detail": "Use Zapier's 'Looping by Zapier' feature (available on Professional plan and above) to loop through the 19 items in Claude's JSON array and create one Google Sheets row per piece. Map each field: Platform, Content_Type, Text, Hashtags (join the array with spaces), Source_URL (from the trigger), Created_Date (use Zapier's current date). Set Status to 'Draft'. If you don't have access to Looping, an alternative is to use a 'Code by Zapier' step to format the entire JSON array as a batch import, then use Google Sheets' direct import to paste it — though this requires more setup."}], "customization": {"source_content_type": "[Blog / Video / Podcast / Newsletter]", "publishing_frequency": "[Weekly / Bi-weekly / Monthly]", "target_platforms": "[LinkedIn / X / Instagram / Email / YouTube]", "repurposing_schedule": "Spread over [___] weeks", "content_themes": "[___]"}, "content": "One blog post or video can fuel four weeks of content across every platform — if you have the right system. This workflow takes any long-form content you publish and automatically transforms it into 19+ pieces: 5 LinkedIn posts (different angles, 100-200 words each), 5 X/Twitter posts (punchy, under 280 characters), 1 email newsletter intro, 3 Instagram captions with CTAs, and 5 quotable lines ready for Canva graphics. The automation triggers when you publish a new blog post (via RSS) or when you manually trigger it with a webhook. It fetches the full page content, sends it to Claude with your brand voice and repurposing matrix, and Claude creates all variations in one API call. Every piece lands in a Google Sheet organized by platform — you review, approve, and schedule at your own pace. In Zapier: RSS or Webhook trigger, Formatter to extract text, Claude Send Message with repurposing prompt, Looping + Sheets row creation. In n8n: Webhook or RSS trigger node, HTTP Request to fetch content, Claude node, Code node to parse all 19 pieces into separate items, Sheets append. You publish once, the engine distributes for weeks.", "cowork_alternative": {"description": "If you prefer to run this manually through Claude's interface rather than setting up automation, the prompt above works perfectly as a direct conversation. You paste your blog post, Claude returns all 19 pieces in a structured format, and you copy what you need. This is the fastest way to test the quality before committing to an automated setup. For the full automated version without n8n or Zapier, Claude's MCP server integrations allow direct Google Sheets writes from the desktop app.", "steps": ["Open Claude at claude.ai or in the desktop app. Paste the system prompt above into a Project's custom instructions, replacing all ← Replace values with your actual brand info — this only needs to be done once per Project", "Copy your complete blog post text (or paste the URL if Claude has web access enabled) along with the user prompt. You don't need to include the automation placeholders — just paste the raw content", "Claude returns the JSON array of 19 pieces. Review it in the conversation — ask Claude to revise any specific posts that don't match your voice before saving anything", "Ask Claude to format the approved pieces as a table sorted by platform — this makes it easy to copy individual sections into Buffer, LinkedIn, or your email tool", "If you have the Google Sheets MCP server enabled in Claude Desktop, say 'Add all these pieces to my Content Library sheet' and Claude will write all 19 rows automatically"]}, "setup_time": "15-30 minutes", "complexity": "Beginner-friendly — follow the step-by-step screenshots", "maintenance": "Check weekly, adjust monthly", "expected_output": "One blog post transformed into 19 pieces: 5 LinkedIn posts, 5 tweets, 1 newsletter intro, 3 Instagram captions, 5 quote cards", "prerequisites": ["An Anthropic account with API access — sign up at console.anthropic.com and generate an API key", "A published blog, newsletter, or content platform with publicly accessible URLs (WordPress, Ghost, Substack, Medium, Squarespace, etc.)", "A Google account with access to Google Sheets, connected to n8n via OAuth2", "A Google Sheet set up with these column headers: Source_URL, Title, Platform, Content_Type, Text, Hashtags, Status, Created_Date", "Optionally: a social media scheduling tool like Buffer, Hootsuite, or Publer connected via their API to automatically queue the generated content"], "n8n_setup": [{"step": "T", "node": "Webhook Trigger or RSS Feed Trigger", "detail": "In n8n, you have two trigger options. Option A: use the Webhook node with a POST path like 'repurpose-content'. Activate it, copy the URL, and trigger it manually from a browser bookmark or any HTTP client by sending a JSON body with keys 'blog_url' and 'title'. This is the recommended approach because you choose exactly when to repurpose. Option B: use the RSS Feed Read Trigger node, enter your blog's RSS URL (typically yourblog.com/feed), and set it to poll on a schedule. This fires automatically whenever you publish but gives you less control over timing. Both options connect to the same next node — only one should be active at a time."}, {"step": "F", "node": "HTTP Request - Fetch Content", "detail": "Add an HTTP Request node set to GET. The URL field uses an n8n expression that dynamically pulls the blog URL from whichever trigger fired: ={{ $json.body ? $json.body.blog_url : $json.link }}. This works for both the webhook (which puts the URL in body.blog_url) and the RSS trigger (which puts it in the link field). The response will be the full HTML of the page. Set the User-Agent header to a browser-like string to avoid being blocked by sites that reject bots. Most public blogs return the full article HTML without any authentication."}, {"step": "AI", "node": "HTTP Request - Claude", "detail": "Add an HTTP Request node set to POST at https://api.anthropic.com/v1/messages. Add three headers: x-api-key with your Anthropic API key from console.anthropic.com, anthropic-version set to 2023-06-01, and Content-Type set to application/json. In the Body, set type to JSON and paste the full JSON body — the system prompt contains your brand voice and audience details (replace all ← Replace placeholders before saving). The user prompt uses $json.data or $json.body to access the HTML content, truncated to 12,000 characters to stay within token limits while capturing most article body text. Set max_tokens to 8000 to accommodate all 19 pieces."}, {"step": "CODE", "node": "Parse Repurposed Content (Code node)", "detail": "Add a Code node after the HTTP Request. The code extracts Claude's response text, strips any markdown code fences, parses the JSON array of 19 pieces, retrieves the source URL and title from the original trigger, and returns 19 separate n8n items — one per piece. It also joins the hashtags array into a space-separated string for easy storage. If Claude returns malformed JSON, the code node throws a clear error message. This is the critical step: without it, the Google Sheets node would receive only one item and create only one row instead of 19."}, {"step": "S", "node": "Google Sheets - Store Pieces", "detail": "Add a Google Sheets node set to the Append operation. Connect your Google account via OAuth2, enter the Spreadsheet ID from your Content Library sheet URL, and set the sheet name to 'Content Library'. Map all 8 columns: Source_URL, Title, Platform, Content_Type, Text, Hashtags, Status (default 'Draft'), and Created_Date. Because the Code node outputs 19 items, this node runs 19 times and appends 19 rows automatically. After your first test, open the sheet and scan through the entries — verify the LinkedIn posts are 100-200 words, the Twitter posts are under 280 characters, and the quote cards are standalone and punchy."}], "n8n_workflow_json": {"name": "KH Academy — Content Repurposing Engine", "nodes": [{"id": "d4e5f6a7-0001-4d4e-bf4f-b2c3d4e5f6a7", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS\n\n**1. Trigger Option A — Webhook (Recommended)**\nActivate the \"Webhook Trigger\" node and copy the webhook URL. Paste it anywhere you want to trigger repurposing: a browser bookmark, a Zapier zap, a Notion button, etc. Send a POST request with this JSON body:\n{ \"blog_url\": \"https://yourblog.com/your-post\", \"title\": \"Post Title\" }\n\n**Trigger Option B — RSS Feed**\nActivate the \"RSS Feed Trigger\" node instead and enter your blog's RSS URL in the Feed URL field. This fires automatically each time you publish a new post. The node provides the post URL and title automatically.\n\n**2. HTTP Request — Fetch Content**\nThe \"HTTP Request - Fetch Content\" node GETs the full blog post HTML. For most WordPress or Ghost blogs this works out of the box. If your site requires authentication or blocks bots, consider using a read-it-later service API (Pocket, Readwise) as an intermediary.\n\n**3. Anthropic API Key**\nOpen the \"HTTP Request - Claude\" node → Headers → replace `YOUR_ANTHROPIC_API_KEY` with your real key from https://console.anthropic.com\n\n**4. Customize the AI Prompt**\nIn the \"HTTP Request - Claude\" node body, replace these placeholders:\n- YOUR BRAND VOICE ← describe your writing style (e.g. \"direct, occasionally witty, no corporate jargon\")\n- YOUR BUSINESS NAME ← your brand name\n- YOUR AUDIENCE ← who reads your content (e.g. \"B2B SaaS founders\")\n\n**5. Google Sheets**\nOpen \"Google Sheets - Store Pieces\" → Credentials → connect your Google account.\nCreate a new sheet named \"Content Library\" with these exact column headers:\nSource_URL | Title | Platform | Content_Type | Text | Hashtags | Status | Created_Date\n\nReplace `YOUR_SPREADSHEET_ID` with the ID from your sheet URL:\nhttps://docs.google.com/spreadsheets/d/THIS_PART/edit", "height": 680, "width": 600, "color": 3}}, {"id": "d4e5f6a7-0002-4d4e-bf4f-b2c3d4e5f6a7", "name": "Webhook Trigger", "type": "n8n-nodes-base.webhook", "typeVersion": 2, "position": [250, 300], "parameters": {"httpMethod": "POST", "path": "repurpose-content", "responseMode": "onReceived", "responseData": "firstEntryJson", "options": {}}}, {"id": "d4e5f6a7-0003-4d4e-bf4f-b2c3d4e5f6a7", "name": "RSS Feed Trigger", "type": "n8n-nodes-base.rssFeedReadTrigger", "typeVersion": 1.1, "position": [250, 480], "parameters": {"url": "https://yourblog.com/feed", "options": {}}}, {"id": "d4e5f6a7-0004-4d4e-bf4f-b2c3d4e5f6a7", "name": "HTTP Request - Fetch Content", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [470, 300], "parameters": {"method": "GET", "url": "={{ $json.body ? $json.body.blog_url : $json.link }}", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "User-Agent", "value": "Mozilla/5.0 (compatible; n8n-content-bot/1.0)"}]}, "options": {"response": {"response": {"fullResponse": false}}}}}, {"id": "d4e5f6a7-0005-4d4e-bf4f-b2c3d4e5f6a7", "name": "HTTP Request - Claude", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [690, 300], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 8000,\n  \"system\": \"You are a content repurposing specialist for YOUR BUSINESS NAME ← Replace. Brand voice: YOUR BRAND VOICE ← Replace (e.g. direct, witty, no corporate jargon). Target audience: YOUR AUDIENCE ← Replace. You take long-form content and produce multiple platform-optimized pieces. Return ONLY a valid JSON array — no markdown, no explanation.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Repurpose this blog content into 19 pieces. Source URL: {{ $('Webhook Trigger').first()?.json.body?.blog_url || $('RSS Feed Trigger').first()?.json.link }}\\n\\nFull text (extract meaningful content from the HTML below, ignore navigation/ads):\\n{{ $json.data ? $json.data.substring(0, 12000) : $json.body.substring(0, 12000) }}\\n\\nReturn a JSON array of exactly 19 objects. Each object must have these keys: platform (string), content_type (string), text (string), hashtags (array of strings).\\n\\nProduce:\\n1-5: Five LinkedIn posts. Each 100-200 words. Different angle per post (insight, story, counter-intuitive take, how-to, question). End each with an open question. 3-5 hashtags each.\\n6-10: Five X/Twitter posts. Each under 275 characters. Punchy openers. Concrete and specific. 1-2 hashtags each.\\n11: One email newsletter intro. 80-100 words. Strong hook in first sentence, one key insight, one link teaser. No hashtags.\\n12-14: Three Instagram captions. Conversational tone, line breaks every 1-2 sentences, storytelling angle, strong CTA. 5-8 hashtags each.\\n15-19: Five quotable lines for graphic cards. Under 25 words each, standalone insight, no context needed. No hashtags.\\n\\nOutput ONLY the JSON array. No other text.\"\n    }\n  ]\n}", "options": {}}}, {"id": "d4e5f6a7-0006-4d4e-bf4f-b2c3d4e5f6a7", "name": "Parse Repurposed Content", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [910, 300], "parameters": {"mode": "runOnceForAllItems", "jsCode": "// Extract raw text from Claude response\nconst rawText = items[0].json.content[0].text;\n\n// Strip markdown code fences if present\nconst cleaned = rawText.replace(/```json\\n?/g, '').replace(/```\\n?/g, '').trim();\n\n// Parse the JSON array\nlet pieces;\ntry {\n  pieces = JSON.parse(cleaned);\n} catch (e) {\n  throw new Error('Failed to parse Claude JSON: ' + e.message + '\\nFirst 300 chars: ' + cleaned.substring(0, 300));\n}\n\n// Retrieve the source URL and title\nconst webhookJson = $('Webhook Trigger').first()?.json || {};\nconst rssJson = $('RSS Feed Trigger').first()?.json || {};\nconst sourceUrl = webhookJson.body?.blog_url || rssJson.link || '';\nconst title = webhookJson.body?.title || rssJson.title || 'Untitled';\n\nconst today = new Date().toISOString().split('T')[0];\n\n// Return one item per piece\nreturn pieces.map(piece => ({\n  json: {\n    source_url: sourceUrl,\n    title: title,\n    platform: piece.platform || '',\n    content_type: piece.content_type || '',\n    text: piece.text || '',\n    hashtags: Array.isArray(piece.hashtags) ? piece.hashtags.join(' ') : (piece.hashtags || ''),\n    status: 'Draft',\n    created_date: today\n  }\n}));"}}, {"id": "d4e5f6a7-0007-4d4e-bf4f-b2c3d4e5f6a7", "name": "Google Sheets - Store Pieces", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [1110, 300], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "append", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Content Library", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"Source_URL": "={{ $json.source_url }}", "Title": "={{ $json.title }}", "Platform": "={{ $json.platform }}", "Content_Type": "={{ $json.content_type }}", "Text": "={{ $json.text }}", "Hashtags": "={{ $json.hashtags }}", "Status": "={{ $json.status }}", "Created_Date": "={{ $json.created_date }}"}}, "options": {}}}], "connections": {"Webhook Trigger": {"main": [[{"node": "HTTP Request - Fetch Content", "type": "main", "index": 0}]]}, "RSS Feed Trigger": {"main": [[{"node": "HTTP Request - Fetch Content", "type": "main", "index": 0}]]}, "HTTP Request - Fetch Content": {"main": [[{"node": "HTTP Request - Claude", "type": "main", "index": 0}]]}, "HTTP Request - Claude": {"main": [[{"node": "Parse Repurposed Content", "type": "main", "index": 0}]]}, "Parse Repurposed Content": {"main": [[{"node": "Google Sheets - Store Pieces", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-05-content-repurpose"}, "tags": []}, "diagram_image": "workflow-diagram-05.png"}, {"title": "Workflow 06: Lead Magnet Follow-Up", "type": "workflow", "tagline": "TURN EVERY FREE DOWNLOAD INTO A SALES CONVERSATION", "metrics": {"time_saved": "2-4 hrs", "difficulty": "Beginner", "tools_needed": 3, "frequency": "Per download"}, "flow": [{"step": "D", "label": "DOWNLOAD", "description": "Visitor downloads guide"}, {"step": "T", "label": "DETECT", "description": "New subscriber triggered"}, {"step": "C", "label": "CLASSIFY", "description": "AI reads which lead magnet"}, {"step": "AI", "label": "GENERATE", "description": "4-email sequence created"}, {"step": "S", "label": "SEND", "description": "Emails sent automatically"}], "performance_stats": {"generic_open_rate": "15%", "personalized_open_rate": "35-45%", "more_replies": "3x"}, "ai_prompt": {"platform": "Claude", "system_prompt": "You are a follow-up email specialist for YOUR BUSINESS NAME. ← Replace with your actual brand name\nBrand voice: YOUR BRAND VOICE ← Replace (e.g. \"warm, encouraging, like advice from a knowledgeable friend — never pushy, never corporate\")\nNext paid product: YOUR NEXT PAID PRODUCT ← Replace (e.g. \"The 6-Week Launch Accelerator course\")\nPrice: YOUR PRICE POINT ← Replace (e.g. $497, $97/month, $1,200 one-time)\nYou write follow-up emails that feel personal, build genuine trust, and lead naturally to a paid offer without pressure. Return ONLY a valid JSON array — no markdown, no explanation.", "user_prompt": "New subscriber details:\nName: [SUBSCRIBER NAME INSERTED BY AUTOMATION]\nEmail: [SUBSCRIBER EMAIL INSERTED BY AUTOMATION]\nLead magnet downloaded: [LEAD MAGNET NAME INSERTED BY AUTOMATION]\nTag/identifier: [TAG INSERTED BY AUTOMATION]\n\nWrite a 4-email follow-up sequence personalized to the specific lead magnet they downloaded. The sequence should bridge naturally from the free content to the paid product — never feeling like a bait-and-switch.\n\nReturn a JSON array of exactly 4 objects with these keys: email_number (1-4), subject (under 55 chars, no clickbait), body (under 220 words, plain text, paragraph breaks with \\n\\n), send_timing (one of: 'Immediately', 'Day 2', 'Day 5', 'Day 7').\n\nEmail 1 (Immediately — send right away):\nConfirm the lead magnet is on its way or accessible. Give them ONE bonus insight or tip that is NOT in the guide — something that makes them think 'I'm glad I signed up.' Short, warm, immediately useful. No mention of any paid product. Sign off on a personal note.\n\nEmail 2 (Day 2):\nCheck in on their progress with a specific technique or concept from the lead magnet. Ask a genuine, single question — something you'd actually want to know. Share one quick-win example or micro-case-study. This email should feel like a text message from a helpful friend. Absolutely no selling.\n\nEmail 3 (Day 5):\nTell a brief, real-feeling success story of someone who applied the lead magnet content and got a result. Make it specific to the lead magnet topic. At the end, naturally bridge to the paid product — one sentence only, positioned as a next step they might find useful, not a pitch. Something like: 'By the way, for people who want to go deeper on this, I built [product name] — but more on that later.'\n\nEmail 4 (Day 7):\nDirect, confident offer for the paid product. Open with the specific transformation it provides, not with 'I wanted to reach out.' Include one time-limited bonus that feels real and valuable. Clear, single CTA. Gentle urgency based on real scarcity or a deadline — no fake countdown timers.\n\nPersonalize every email around the specific topic of the lead magnet they downloaded. Output ONLY the JSON array.", "notes": "Replace every ← Replace value in the system prompt before activating. The lead magnet name comes directly from the webhook payload — your email platform passes this as a tag or field when it sends the subscriber notification. The more specific the lead magnet name, the more targeted Claude's emails will be. Test with a real lead magnet name to see the personalization in action."}, "zapier_setup": [{"step": 1, "action": "Trigger: ConvertKit / Mailchimp", "detail": "In Zapier, create a new Zap and select your email platform as the trigger. For ConvertKit, choose 'New Subscriber' and then select the specific form or tag associated with your lead magnet — this is critical because the tag tells Claude which lead magnet was downloaded. For Mailchimp, use 'New Subscriber' with the list filtered to the relevant audience, and set up a merge tag on your signup form to capture which lead magnet was selected (e.g. a hidden field populated by the landing page URL). If you have multiple lead magnets, each gets its own Zap trigger, or you use a single Zap with a filter step that checks which tag was applied. Test the trigger step to confirm the subscriber name, email, and lead magnet identifier all appear in the sample data."}, {"step": 2, "action": "Claude: Send Message", "detail": "Add a 'Claude AI: Send Message' action. Paste the complete system prompt into the System field — replace every ← Replace placeholder with your actual business details, product name, and price point before saving. In the User Message field, paste the user prompt and use Zapier's field mapper to insert the subscriber data: map the subscriber's name to the [SUBSCRIBER NAME] placeholder, their email to [SUBSCRIBER EMAIL], and the lead magnet tag or form name to [LEAD MAGNET NAME]. Set max tokens to 4000 and use claude-sonnet-4-20250514 as the model. Run a test with a real subscriber record and verify that the response is a valid JSON array of 4 email objects — if Claude returns markdown-wrapped JSON, add a Formatter step to strip the backticks before the next step."}, {"step": 3, "action": "Google Sheets: Create Rows", "detail": "Use 'Looping by Zapier' (available on Professional plan) to iterate over the 4 email objects from Claude's JSON array and create one Google Sheets row per email. Map each column: Subscriber (name from trigger), Email (email from trigger), Lead_Magnet (tag/identifier from trigger), Email_Number (from each JSON object), Subject, Body, Send_Date (calculate by adding the day offset to today's date using a Formatter date step), Status (default to 'Pending'). After setup, test with a real subscriber and confirm 4 rows appear in your sheet with the correct send dates spaced: Day 0 (today), Day 2, Day 5, Day 7."}, {"step": 4, "action": "Email tool: Create Sequence or Send", "detail": "For Email 1 (send_timing = Immediately), add a Gmail 'Send Email' or ConvertKit 'Send Email Broadcast' action directly in the same Zap — this fires right away without waiting. For Emails 2-4, create a separate second Zap triggered by 'Google Sheets: New or Updated Row' filtered to rows where Status = 'Pending' and Send_Date = today (use Zapier's Schedule trigger or a daily check). When that second Zap fires, it reads the pending email rows for that day, sends each one via Gmail, and updates the Status column to 'Sent'. This two-Zap architecture keeps the initial sequence creation fast and the scheduled sends reliable."}], "customization": {"lead_magnet_name": "[___]", "key_topics_in_guide": ["[Topic 1]", "[Topic 2]", "[Topic 3]"], "next_paid_product": "[product name] at $[price]", "email_tool": "[ConvertKit / Mailchimp / HubSpot]", "from_name": "[Your Name or Brand Name]", "reply_to_email": "[your@email.com]"}, "content": "Generic follow-up emails after a free download get a 15% open rate. Personalized sequences tailored to the specific lead magnet someone downloaded get 35-45% opens and 3x more replies. This workflow bridges that gap automatically. When someone downloads your free guide or resource, the automation detects which lead magnet they grabbed, sends that context to Claude along with your business profile and next paid product details, and Claude generates a 4-email sequence: immediate delivery with a bonus tip not in the guide, a day-2 check-in asking if they tried a specific technique, a day-5 success story that bridges to your paid offer, and a day-7 direct offer with time-limited urgency. In Zapier: ConvertKit or Mailchimp new subscriber trigger with lead magnet tag, Claude AI generation, Sheets storage, email tool queue. In n8n: Webhook trigger, Claude HTTP Request node, Code node to parse 4 emails, Google Sheets append. Each sequence is unique to the lead magnet topic and the subscriber — not a copy-paste template everyone receives.", "cowork_alternative": {"description": "This workflow can be run entirely through Claude's conversation interface for a lighter-weight version that requires no automation setup. The trade-off is that it's manual — you run it whenever a new subscriber comes in rather than having it trigger automatically. For low-volume lead magnets (under 10 new subscribers per day), the manual approach is perfectly reasonable and gives you more control over every email before it goes out.", "steps": ["Open Claude at claude.ai and start a new conversation (or use a saved Project with your business details in the custom instructions). Paste the system prompt from this workflow into the Project instructions, replacing all ← Replace placeholders — you only need to do this once", "When a new subscriber comes in, copy their details from your email platform: name, email address, and which lead magnet they downloaded. Paste these into Claude along with the user prompt from above", "Claude returns a 4-email sequence tailored to that specific subscriber and lead magnet. Read through all four emails before doing anything — this is your chance to catch any off-brand phrasing or generic passages", "Ask Claude to revise any emails that need adjustment. When you're happy, ask it to format the emails as a simple table for easy copying", "If you have the Google Sheets MCP server enabled in Claude Desktop, say 'Add these 4 emails to my Lead Magnet Sequences sheet with the correct send dates starting today' — Claude will write all rows to your sheet. Otherwise, copy them manually."]}, "setup_time": "15-30 minutes", "complexity": "Beginner-friendly — follow the step-by-step screenshots", "maintenance": "Check weekly, adjust monthly", "expected_output": "Automated 4-email follow-up sequence triggered when someone downloads your lead magnet, personalized to the specific resource they downloaded", "prerequisites": ["An Anthropic account with API access — sign up at console.anthropic.com and generate an API key", "An email platform that supports webhooks on new subscriber events: ConvertKit, Mailchimp, ActiveCampaign, Kit, Beehiiv, or similar", "A Google account with access to Google Sheets, connected to n8n via OAuth2", "A Google Sheet set up with these column headers: Subscriber, Email, Lead_Magnet, Email_Number, Subject, Body, Send_Date, Status", "One or more existing lead magnets with at least a title and the key topics they cover — Claude uses this to personalize the email sequence"], "n8n_setup": [{"step": "T", "node": "Webhook Trigger", "detail": "In n8n, add a Webhook node and set it to POST with the path 'lead-magnet-subscriber'. Activate the node and copy the generated webhook URL. Log into your email platform and find the Webhook settings: in ConvertKit, go to Automations → Rules → create a rule where the trigger is 'Subscribes to a form' (select your lead magnet form) and the action is 'Webhook' — paste the n8n URL and ensure the payload includes subscriber name, email, and the form or tag name. In Mailchimp, go to Audience → Manage Contacts → Webhooks and add the URL with 'Subscribe' events enabled. Test by signing up with a test email and confirming n8n receives the webhook payload with all the fields you need."}, {"step": "AI", "node": "HTTP Request - Claude", "detail": "Add an HTTP Request node set to POST at https://api.anthropic.com/v1/messages. Configure three headers: x-api-key with your Anthropic API key, anthropic-version with 2023-06-01, and Content-Type with application/json. In the Body, set type to JSON and paste the full JSON body from the n8n workflow file. Before saving, update the system prompt placeholders: replace YOUR BUSINESS NAME, YOUR BRAND VOICE, YOUR NEXT PAID PRODUCT, and YOUR PRICE POINT. The user prompt uses n8n expressions like ={{ $json.body.subscriber_name }} to automatically pull the subscriber data from the webhook payload. Set max_tokens to 4000. Run a test execution to verify Claude returns a clean JSON array of 4 emails."}, {"step": "CODE", "node": "Parse Follow-Up Sequence (Code node)", "detail": "Add a Code node after the HTTP Request. The code parses Claude's JSON response, strips any markdown wrappers, maps the day offsets (Immediately = today, Day 2 = 2 days out, etc.) to real calendar dates, and outputs 4 separate n8n items — one per email. It also re-attaches the subscriber name, email, and lead magnet name from the webhook payload so every row in Google Sheets has the full context. This step is what converts one API response into 4 individual rows. If Claude returns an error or malformed JSON, the code node throws a descriptive error message so you can debug easily."}, {"step": "S", "node": "Google Sheets - Store Emails", "detail": "Add a Google Sheets node set to the Append operation. Connect your Google account via OAuth2, enter your Spreadsheet ID, and set the sheet name to 'Lead Magnet Sequences'. Map all 8 columns: Subscriber, Email, Lead_Magnet, Email_Number, Subject, Body, Send_Date, and Status (defaulting to 'Pending'). Because the Code node produces 4 items, this node runs 4 times and appends 4 rows. After your first live test, open the sheet and verify the rows — check that the send dates are correctly spaced, the subject lines are under 55 characters, and the body text reads naturally for the specific lead magnet your test subscriber downloaded."}], "n8n_workflow_json": {"name": "KH Academy — Lead Magnet Follow-Up", "nodes": [{"id": "e5f6a7b8-0001-4e5f-cf5f-c3d4e5f6a7b8", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS\n\n**1. Webhook Trigger**\nActivate the \"Webhook Trigger\" node and copy the generated webhook URL. Paste it into your email platform:\n- ConvertKit: Automations → Add Rule → Trigger: Subscriber joins a form → Action: Webhook → paste URL\n- Mailchimp: Audience → Manage Contacts → Webhooks → create new → paste URL\n- Any other platform: find the \"Webhook\" or \"HTTP POST\" action in your automation builder\n\nExpected payload structure:\n{\n  \"subscriber_email\": \"jane@example.com\",\n  \"subscriber_name\": \"Jane Smith\",\n  \"lead_magnet\": \"The 5-Day Launch Checklist\",\n  \"tag\": \"lead-magnet-launch-checklist\"\n}\n\n**2. Anthropic API Key**\nOpen the \"HTTP Request - Claude\" node → Headers → replace `YOUR_ANTHROPIC_API_KEY` with your real key from https://console.anthropic.com\n\n**3. Customize the AI Prompt**\nIn the \"HTTP Request - Claude\" node body, replace these placeholders:\n- YOUR BUSINESS NAME ← your actual brand name\n- YOUR NEXT PAID PRODUCT ← the product you want to sell after the lead magnet\n- YOUR PRICE POINT ← e.g. $297, $997, $49/month\n- YOUR BRAND VOICE ← e.g. \"warm, encouraging, like advice from a knowledgeable friend\"\n\n**4. Google Sheets**\nOpen \"Google Sheets - Store Emails\" → Credentials → connect your Google account via OAuth2.\nCreate a new sheet named \"Lead Magnet Sequences\" with these exact column headers:\nSubscriber | Email | Lead_Magnet | Email_Number | Subject | Body | Send_Date | Status\n\nReplace `YOUR_SPREADSHEET_ID` with the ID from your sheet URL:\nhttps://docs.google.com/spreadsheets/d/THIS_PART/edit\n\n**5. Extending This Workflow**\nOnce emails are stored in Sheets, you can manually send them via Gmail, or add a Gmail node at the end to send Email 1 immediately. To send emails 2-4 on schedule, create a separate n8n workflow with a Schedule Trigger that reads rows from the sheet where Status = Pending and Send_Date = today.", "height": 720, "width": 600, "color": 6}}, {"id": "e5f6a7b8-0002-4e5f-cf5f-c3d4e5f6a7b8", "name": "Webhook Trigger", "type": "n8n-nodes-base.webhook", "typeVersion": 2, "position": [250, 300], "parameters": {"httpMethod": "POST", "path": "lead-magnet-subscriber", "responseMode": "onReceived", "responseData": "firstEntryJson", "options": {}}}, {"id": "e5f6a7b8-0003-4e5f-cf5f-c3d4e5f6a7b8", "name": "HTTP Request - Claude", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [470, 300], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 4000,\n  \"system\": \"You are a follow-up email specialist for YOUR BUSINESS NAME ← Replace. Brand voice: YOUR BRAND VOICE ← Replace (e.g. warm, encouraging, like advice from a trusted friend). Next paid product: YOUR NEXT PAID PRODUCT ← Replace, at YOUR PRICE POINT ← Replace. You write follow-up emails that feel personal, helpful, and never pushy. Return ONLY a valid JSON array — no markdown, no explanation.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"New subscriber details:\\nName: {{ $json.body.subscriber_name }}\\nEmail: {{ $json.body.subscriber_email }}\\nLead magnet downloaded: {{ $json.body.lead_magnet }}\\nTag: {{ $json.body.tag }}\\n\\nWrite a 4-email follow-up sequence personalized to the specific lead magnet they downloaded. The sequence should bridge naturally from the free content to the paid product.\\n\\nReturn a JSON array of exactly 4 objects with these keys: email_number (1-4), subject (under 55 chars), body (under 220 words, plain text with paragraph breaks using \\\\n\\\\n), send_timing (string: 'Immediately', 'Day 2', 'Day 5', 'Day 7').\\n\\nEmail 1 (Immediately): Confirm delivery of the lead magnet. Give them one bonus tip or insight that is NOT in the guide — something that makes them think 'I'm glad I signed up.' Warm, welcoming tone. No selling.\\n\\nEmail 2 (Day 2): Check in on their progress with a specific technique from the lead magnet. Ask a genuine question. Share a quick-win example. No selling whatsoever.\\n\\nEmail 3 (Day 5): Tell a brief success story of someone who used the lead magnet concepts and then went further with the paid product. Bridge naturally — mention the paid product once, softly, as a next step they might explore.\\n\\nEmail 4 (Day 7): Direct, confident offer for the paid product. Lead with the specific transformation it provides. Include one time-limited bonus (you invent a believable one). Clear CTA. Friendly urgency without artificial scarcity.\\n\\nPersonalize all emails to the specific topic of the lead magnet. Output ONLY the JSON array.\"\n    }\n  ]\n}", "options": {}}}, {"id": "e5f6a7b8-0004-4e5f-cf5f-c3d4e5f6a7b8", "name": "Parse Follow-Up Sequence", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [690, 300], "parameters": {"mode": "runOnceForAllItems", "jsCode": "// Extract raw text from Claude response\nconst rawText = items[0].json.content[0].text;\n\n// Strip markdown code fences if Claude wrapped the JSON\nconst cleaned = rawText.replace(/```json\\n?/g, '').replace(/```\\n?/g, '').trim();\n\n// Parse the JSON array\nlet emails;\ntry {\n  emails = JSON.parse(cleaned);\n} catch (e) {\n  throw new Error('Failed to parse Claude response: ' + e.message + '\\nRaw (first 300): ' + cleaned.substring(0, 300));\n}\n\n// Retrieve subscriber info from webhook\nconst webhookBody = $('Webhook Trigger').first().json.body;\nconst subscriberName = webhookBody.subscriber_name || 'Subscriber';\nconst subscriberEmail = webhookBody.subscriber_email || '';\nconst leadMagnet = webhookBody.lead_magnet || '';\n\n// Map timing labels to day offsets\nconst timingDays = { 'Immediately': 0, 'Day 1': 1, 'Day 2': 2, 'Day 3': 3, 'Day 5': 5, 'Day 7': 7 };\nconst today = new Date();\n\nreturn emails.map((email, idx) => {\n  const days = timingDays[email.send_timing] ?? (idx * 2);\n  const sendDate = new Date(today);\n  sendDate.setDate(today.getDate() + days);\n\n  return {\n    json: {\n      subscriber: subscriberName,\n      email: subscriberEmail,\n      lead_magnet: leadMagnet,\n      email_number: email.email_number || (idx + 1),\n      subject: email.subject || '',\n      body: email.body || '',\n      send_date: sendDate.toISOString().split('T')[0],\n      status: 'Pending'\n    }\n  };\n});"}}, {"id": "e5f6a7b8-0005-4e5f-cf5f-c3d4e5f6a7b8", "name": "Google Sheets - Store Emails", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [910, 300], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "append", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Lead Magnet Sequences", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"Subscriber": "={{ $json.subscriber }}", "Email": "={{ $json.email }}", "Lead_Magnet": "={{ $json.lead_magnet }}", "Email_Number": "={{ $json.email_number }}", "Subject": "={{ $json.subject }}", "Body": "={{ $json.body }}", "Send_Date": "={{ $json.send_date }}", "Status": "={{ $json.status }}"}}, "options": {}}}], "connections": {"Webhook Trigger": {"main": [[{"node": "HTTP Request - Claude", "type": "main", "index": 0}]]}, "HTTP Request - Claude": {"main": [[{"node": "Parse Follow-Up Sequence", "type": "main", "index": 0}]]}, "Parse Follow-Up Sequence": {"main": [[{"node": "Google Sheets - Store Emails", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-06-lead-magnet"}, "tags": []}, "diagram_image": "workflow-diagram-06.png"}, {"title": "Workflow 07: Competitor Watch & Alert", "type": "workflow", "tagline": "KNOW WHAT YOUR COMPETITORS DO — BEFORE YOUR CUSTOMERS TELL YOU", "metrics": {"time_saved": "3-4 hrs/week", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Daily"}, "flow": [{"step": "S", "label": "SCHEDULE", "description": "Daily 8AM"}, {"step": "W", "label": "SCAN", "description": "Check competitor sources"}, {"step": "AI", "label": "CLAUDE", "description": "Analyze changes"}, {"step": "F", "label": "FILTER", "description": "Significant only?"}, {"step": "A", "label": "ALERT", "description": "Notify you"}], "what_ai_monitors": [{"category": "New announcements", "detail": "Blog posts, press releases, product launches"}, {"category": "Pricing changes", "detail": "Plan updates, discounts, new tiers"}, {"category": "Marketing campaigns", "detail": "Social media pushes, ad campaigns, promotions"}, {"category": "Customer reviews", "detail": "Google, Trustpilot, G2 — opportunities for you"}, {"category": "Content strategy", "detail": "Topics they're publishing — topics to respond to"}], "ai_prompt": {"platform": "Claude", "model": "claude-sonnet-4-20250514", "system_prompt": "You are a competitive intelligence analyst for [YOUR BUSINESS — replace with your company name] in [YOUR INDUSTRY — replace with your industry, e.g. 'SaaS project management tools']. MY COMPETITORS:\n1. [COMPETITOR 1 — name + website, e.g. 'Acme Corp — acmecorp.com']\n2. [COMPETITOR 2 — name + website]\n3. [COMPETITOR 3 — name + website]\nWHAT I CARE ABOUT: Pricing changes, new product launches, marketing campaigns targeting my audience, negative customer reviews on G2/Trustpilot/Google (which are opportunities for me to win those customers), and content strategy shifts. Analyze the provided RSS feed data and respond ONLY with a valid JSON object — no markdown, no code blocks, no explanation before or after.", "user_message": "Analyze this competitor RSS feed data collected today and return a JSON object with these exact fields:\n{\n  \"alert_level\": \"Red|Yellow|Green\",\n  \"competitor_name\": \"name of the competitor this data is from\",\n  \"what_changed\": \"1-2 sentences describing what is new or different from their usual output\",\n  \"why_it_matters\": \"1 sentence explaining the direct business impact to us\",\n  \"recommended_action\": \"specific action we should take within 24-48 hours\",\n  \"opportunity\": \"specific opportunity we can exploit from this intelligence\",\n  \"summary\": \"2 sentence executive summary for the morning briefing\"\n}\n\nAlert level definitions:\n- Red: URGENT — direct competitive threat requiring immediate response (pricing cut, major product launch, aggressive campaign targeting our exact customers, major negative PR event)\n- Yellow: NOTABLE — worth monitoring and potentially responding to within the week (new feature, partnership announcement, content push into our topics, hiring surge)\n- Green: ROUTINE — no action needed, standard blog post, minor update, or nothing new\n\nIf truly nothing significant: set alert_level to Green and summarize what was found anyway.\n\nRSS Feed Data:\n{{ $json.data }}  ← This is replaced automatically by n8n with the actual RSS content", "notes": "Replace all [BRACKETED PLACEHOLDERS] before activating the workflow. The prompt requests JSON output — Claude reliably returns clean JSON when instructed this way. The try/catch in the IF node expression handles any edge cases where the response format varies."}, "setup_steps": [{"step": 1, "action": "Trigger: Daily schedule", "detail": "RSS for competitor blogs + Google Alerts for brand mentions"}, {"step": 2, "action": "HTTP Request: Fetch data", "detail": "Pull latest from competitor websites and review sites"}, {"step": 3, "action": "Claude: Analyze", "detail": "Send competitor data through analysis prompt"}, {"step": 4, "action": "Filter: Significant only", "detail": "IF response != 'NO SIGNIFICANT CHANGES' then continue"}, {"step": 5, "action": "Slack/Email: Alert", "detail": "Send summary to your preferred notification channel"}], "customization": {"competitor_1": {"name": "[Competitor Name — replace]", "rss_url": "[https://competitorblog.com/feed/ — replace]"}, "competitor_2": {"name": "[Competitor Name — replace]", "rss_url": "[https://competitorblog.com/feed/ — replace]"}, "competitor_3": {"name": "[Competitor Name — replace]", "rss_url": "[https://competitorblog.com/feed/ — replace]"}, "alert_email": "[your@email.com — replace]", "sheets_log_name": "[Intelligence Log — rename if needed]", "schedule_time": "8:00 AM daily (adjust cron: 0 8 * * *)"}, "content": "By the time your customers tell you a competitor dropped their prices or launched a new product, you have already lost the first-mover advantage. This workflow monitors your top 3 competitors daily and alerts you only when something significant changes. Every morning at 8AM, the automation pulls data from competitor blog RSS feeds, Google Alerts for brand mentions, and review sites. Claude analyzes the aggregated data as a competitive intelligence analyst, rating each finding as Red (urgent), Yellow (notable), or Green (routine). It identifies what changed, explains why it matters to your business, recommends a specific action, and flags opportunities you can exploit. If nothing significant happened, it responds with a simple all-clear and you are not bothered. In Zapier or n8n: Schedule trigger, HTTP requests to data sources, Claude analysis with your competitor prompt, Filter node that only continues on significant changes, then Slack or email alert delivery. You stay informed without spending 3-4 hours per week manually checking competitor websites.", "cowork_alternative": {"description": "With Claude Cowork (included with Claude Pro at $20/month), you can run this competitive intelligence workflow directly from your desktop without any automation platform. Cowork connects to your browser and can read web content natively.", "steps": ["Open Claude Desktop and ensure Cowork is enabled with browser access", "Type: 'Every morning, visit these 3 competitor websites and their blogs: [URL1], [URL2], [URL3]. Analyze what's new and rate it Red/Yellow/Green using the competitive intelligence framework. Email me a briefing at [YOUR EMAIL].'", "Claude will ask to confirm access to your email — authorize it", "Review the first briefing, adjust the competitor list or criteria if needed, then save the instruction as a recurring task"]}, "setup_time": "30-45 minutes", "complexity": "Intermediate — requires API key setup and RSS URL research", "maintenance": "Review alert thresholds monthly; update competitor list as your market evolves", "expected_output": "Daily morning intelligence briefing with Red/Yellow/Green rating, specific recommended action, and a growing historical log of competitive activity", "workflow_id": "07", "prerequisites": ["Anthropic account with API key (https://console.anthropic.com) — estimated cost: $0.05–$0.20/day depending on RSS feed volume", "Gmail account connected to n8n via OAuth2", "Google Sheets spreadsheet created with columns: Date, Competitor, Alert_Level, Summary, Recommended_Action, Opportunity", "RSS feed URLs for your top 3 competitors' blogs (most blogs publish an RSS feed at /feed/ or /rss/)", "n8n instance (cloud or self-hosted) with the workflow imported and active"], "zapier_setup": [{"step": 1, "node": "Schedule by Zapier", "detail": "In Zapier, create a new Zap and select 'Schedule by Zapier' as the trigger. Set the frequency to 'Every Day' and choose 8:00 AM as the trigger time in your local timezone. This ensures the workflow fires once each morning before you start your workday, giving you fresh intelligence before you check your email. Save and test this step to confirm it fires correctly — Zapier will generate a sample payload you can use to build the rest of the workflow."}, {"step": 2, "node": "Code by Zapier (or Webhooks — GET)", "detail": "Add a 'Webhooks by Zapier' action set to GET method, and paste your first competitor's RSS feed URL into the URL field. RSS feeds are publicly available XML endpoints — test the URL in your browser first to confirm it loads. Most blog platforms publish a feed at https://competitorblog.com/feed/ (WordPress), https://name.substack.com/feed (Substack), or https://blog.com/rss/ (Ghost). The response will be XML text containing recent post titles, dates, and descriptions. Repeat this step for each of your 3 competitors, creating one Webhooks GET action per competitor. You can use Zapier's 'Formatter' step to extract and combine the text fields into a single clean string for the AI step."}, {"step": 3, "node": "Claude AI — Analyze", "detail": "Add a 'Claude AI' action and select 'Send Message'. Paste the competitive intelligence analysis prompt into the message body. Map the RSS feed text from all three competitors into the {{scraped_content}} variable using Zapier's field mapping. Claude will return a structured response rating each finding as Red (urgent — pricing change, major launch), Yellow (notable — new campaign, partnership), or Green (routine — standard blog post). The output also includes what changed, why it matters to your business, a recommended action, and an exploitable opportunity. Set the model to claude-sonnet-4 for the best balance of speed and intelligence quality."}, {"step": 4, "node": "Filter by Zapier", "detail": "Add a 'Filter by Zapier' step and set the condition: only continue if the Claude response contains 'Red' or 'Yellow' (and does NOT contain 'NO SIGNIFICANT CHANGES'). This filter prevents you from receiving emails on quiet days when nothing meaningful happened. Without this filter, you'd receive a daily email even when competitors posted a routine blog article — which defeats the purpose of the system. Test this step by manually triggering the Zap with sample data representing each alert level to confirm routing works correctly."}, {"step": 5, "node": "Gmail — Send Alert Email", "detail": "Add a 'Gmail: Send Email' action. Set the recipient to your own email address and write a subject line template like: [{{alert_level}}] Competitor Intelligence — {{competitor_name}}. Map the body to include the full Claude analysis including what changed, why it matters, recommended action, and opportunity fields. Format the email with clear sections so you can scan it in under 60 seconds. Consider using HTML formatting with bold headers for readability."}, {"step": 6, "node": "Google Sheets — Log Finding", "detail": "Add a 'Google Sheets: Create Spreadsheet Row' action that runs regardless of alert level (place this step before the filter, or duplicate it after). This ensures all findings — including routine Green items — are logged to your Intelligence Log spreadsheet for historical reference and trend spotting. Map each column: Date (use Zapier's current date token), Competitor, Alert_Level, Summary, Recommended_Action, Opportunity. Over time, this sheet becomes a searchable history of your competitive landscape that you can analyze quarterly to spot patterns."}], "n8n_setup": [{"step": 1, "node": "Schedule Trigger", "detail": "Add a Schedule Trigger node and set the cron expression to '0 8 * * *' which fires at 8:00 AM every day. In n8n, go to the node parameters, select 'Cron Expression' as the interval type, and enter the expression. The timezone follows your n8n instance timezone settings — verify this in your n8n settings panel to ensure 8 AM fires at the right local time. Test by clicking 'Execute Node' to confirm it generates an execution."}, {"step": 2, "node": "HTTP Request - Fetch RSS Feed", "detail": "Add an HTTP Request node set to GET method. Paste your competitor's RSS feed URL into the URL field. In the 'Options' section, set the Response Format to 'Text' so n8n returns the raw XML rather than trying to parse it as JSON. Duplicate this node for each competitor, labeling them 'HTTP Request - RSS Competitor 1', 'HTTP Request - RSS Competitor 2', etc. Connect all three in sequence or use a Merge node to combine their outputs before sending to Claude. Start with one competitor to test the flow before adding the others."}, {"step": 3, "node": "HTTP Request - Claude Analysis", "detail": "Add an HTTP Request node configured as a POST to https://api.anthropic.com/v1/messages. Add three headers: x-api-key (your Anthropic key), anthropic-version (2023-06-01), and Content-Type (application/json). In the body, use the JSON body format and paste the analysis prompt. Use n8n's expression syntax to inject the RSS content: {{ $json.data }} maps to the HTTP response body from the previous node. Set max_tokens to 800 to ensure Claude has room to provide a thorough analysis with all five required fields."}, {"step": 4, "node": "IF - Red or Yellow Alert", "detail": "Add an IF node. In the condition field, use an expression to parse the Claude JSON response and extract the alert_level field: ={{ (() => { try { return JSON.parse($json.content[0].text).alert_level; } catch(e) { return 'Green'; } })() }}. Set the operator to 'not equals' and the value to 'Green'. This routes Red and Yellow alerts to the true branch (email alert path) and Green items to the false branch (Sheets-only logging). The try/catch prevents the workflow from breaking if Claude returns an unexpected format."}, {"step": 5, "node": "Gmail - Send Alert", "detail": "Add a Gmail node set to 'Send' operation. Connect your Gmail account via OAuth2 in the credentials section. Set the recipient to your own email, use an expression for the subject line that includes the alert level and competitor name extracted from the Claude JSON response, and build the HTML body using template expressions to populate each section. Set Body Content Type to HTML for formatted output. This node only fires when the IF node routes to the true branch — meaning only Red and Yellow alerts trigger an email."}, {"step": 6, "node": "Google Sheets - Log Finding", "detail": "Add a Google Sheets node set to 'Append Row' operation. Connect it at two points: after the Gmail node (for Red/Yellow findings) and directly from the IF false branch (for Green findings). This ensures every daily scan is logged regardless of alert level. Map the columns using expressions to extract each field from the Claude JSON response. The Date column should use {{ $now.toISO() }} for a consistent timestamp. Over weeks and months, this log becomes your competitive intelligence database."}], "testing_checklist": ["Manually execute the Schedule Trigger node and confirm it passes data forward", "Test the RSS HTTP Request with a real competitor URL — verify you get XML text back, not a 404 or empty response", "Execute just the Claude Analysis node with sample RSS text and confirm it returns valid JSON with all required fields", "Test the IF node by manually setting alert_level to 'Red' — confirm routing goes to Gmail node", "Test IF node with 'Green' — confirm routing goes to Google Sheets only (no email fired)", "Send a test alert email and verify formatting is correct on mobile and desktop", "Confirm Google Sheets row is created with all columns populated correctly", "Activate the workflow and wait for the next 8 AM trigger — verify the first real execution completes without errors", "Check the Executions log in n8n after the first automated run to confirm no timeout or parsing errors"], "n8n_workflow_json": {"name": "KH Academy — Competitor Watch & Alert", "nodes": [{"id": "c3d4e5f6-0001-4c3d-ae3f-a3b4c5d6e7f8", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS\n\n**1. Anthropic API Key**\nOpen \"HTTP Request - Claude Analysis\" node → Headers → replace `YOUR_ANTHROPIC_API_KEY` with your key from https://console.anthropic.com\n\n**2. Competitor RSS Feed URLs**\nOpen \"HTTP Request - Fetch RSS Feed\" → URL → replace the placeholder URL with your first competitor's blog RSS feed.\nDuplicate this node for each additional competitor (Competitor 2, Competitor 3) and connect them all before the Claude node.\nCommon RSS URL patterns:\n- WordPress blogs: https://competitorblog.com/feed/\n- Substack: https://competitorname.substack.com/feed\n- Ghost: https://competitorblog.com/rss/\n\n**3. Update the AI Prompt**\nIn \"HTTP Request - Claude Analysis\", find the system prompt and replace:\n- [YOUR BUSINESS] with your business name\n- [YOUR INDUSTRY] with your industry\n- [COMPETITOR 1], [COMPETITOR 2], [COMPETITOR 3] with actual competitor names and websites\n\n**4. Gmail Credentials**\nOpen \"Gmail - Send Alert\" → Credentials → connect your Gmail account via OAuth2.\nReplace `YOUR_ALERT_EMAIL` with the email address where you want to receive alerts.\n\n**5. Google Sheets**\nOpen both Google Sheets nodes → Credentials → connect your Google account.\nReplace `YOUR_SPREADSHEET_ID` with the ID from your Intelligence Log spreadsheet URL.\nRequired columns: Date, Competitor, Alert_Level, Summary, Recommended_Action, Opportunity\n\n**6. IF Node Logic**\nThe IF node checks whether the alert level is Red or Yellow.\nRed = urgent action needed. Yellow = notable, worth reviewing. Green = routine, logged only.\nOnly Red and Yellow trigger the email alert. Green findings are logged silently to Sheets.\n\n**Schedule:** Runs daily at 8:00 AM (server time). Adjust the cron expression in Schedule Trigger if needed.", "height": 680, "width": 580, "color": 3}}, {"id": "c3d4e5f6-0002-4c3d-ae3f-a3b4c5d6e7f8", "name": "Schedule Trigger", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.1, "position": [250, 300], "parameters": {"rule": {"interval": [{"field": "cronExpression", "expression": "0 8 * * *"}]}}}, {"id": "c3d4e5f6-0003-4c3d-ae3f-a3b4c5d6e7f8", "name": "HTTP Request - Fetch RSS Feed", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [450, 300], "parameters": {"method": "GET", "url": "https://YOUR_COMPETITOR_BLOG_URL/feed/", "sendHeaders": false, "options": {"response": {"response": {"responseFormat": "text"}}}}}, {"id": "c3d4e5f6-0004-4c3d-ae3f-a3b4c5d6e7f8", "name": "HTTP Request - Claude Analysis", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [650, 300], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 800,\n  \"system\": \"You are a competitive intelligence analyst for [YOUR BUSINESS] in [YOUR INDUSTRY]. MY COMPETITORS: 1. [COMPETITOR 1 — name + website] 2. [COMPETITOR 2 — name + website] 3. [COMPETITOR 3 — name + website]. WHAT I CARE ABOUT: Pricing changes, new product launches, marketing campaigns, negative customer reviews (which are opportunities for me), and content topics they are pushing. Analyze the provided RSS feed data and respond ONLY with a valid JSON object — no markdown, no explanation.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Analyze this competitor RSS feed data and return a JSON object with these exact fields:\\n{\\n  \\\"alert_level\\\": \\\"Red|Yellow|Green\\\",\\n  \\\"competitor_name\\\": \\\"name of the competitor\\\",\\n  \\\"what_changed\\\": \\\"one to two sentences describing what is new or different\\\",\\n  \\\"why_it_matters\\\": \\\"one sentence explaining the business impact to us\\\",\\n  \\\"recommended_action\\\": \\\"specific action we should take\\\",\\n  \\\"opportunity\\\": \\\"specific opportunity we can exploit from this intelligence\\\",\\n  \\\"summary\\\": \\\"two sentence executive summary\\\"\\n}\\n\\nAlert level definitions:\\n- Red: Urgent — pricing change, major product launch, or aggressive campaign targeting our market\\n- Yellow: Notable — new content push, partnership announcement, or feature update\\n- Green: Routine — blog post, minor update, or nothing significant\\n\\nIf nothing significant: set alert_level to Green and summarize what was found.\\n\\nRSS Feed Data:\\n{{ $json.data }}\"\n    }\n  ]\n}", "options": {}}}, {"id": "c3d4e5f6-0005-4c3d-ae3f-a3b4c5d6e7f8", "name": "IF - Red or Yellow Alert", "type": "n8n-nodes-base.if", "typeVersion": 2, "position": [850, 300], "parameters": {"conditions": {"options": {"caseSensitive": false, "leftValue": "", "typeValidation": "strict"}, "conditions": [{"id": "cond-alert-level", "leftValue": "={{ (() => { try { return JSON.parse($json.content[0].text).alert_level; } catch(e) { return 'Green'; } })() }}", "rightValue": "Green", "operator": {"type": "string", "operation": "notEquals"}}], "combinator": "and"}}}, {"id": "c3d4e5f6-0006-4c3d-ae3f-a3b4c5d6e7f8", "name": "Gmail - Send Alert", "type": "n8n-nodes-base.gmail", "typeVersion": 2.1, "position": [1050, 200], "credentials": {"gmailOAuth2": {"id": "YOUR_GMAIL_CREDENTIAL_ID", "name": "Gmail account"}}, "parameters": {"operation": "send", "sendTo": "YOUR_ALERT_EMAIL", "subject": "={{ '[' + (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).alert_level; } catch(e) { return 'ALERT'; } })() + '] Competitor Intelligence: ' + (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).competitor_name; } catch(e) { return 'Update'; } })() }}", "message": "={{ (() => { try { const d = JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text); return '<h2>Competitive Intelligence Alert</h2><p><strong>Alert Level:</strong> ' + d.alert_level + '</p><p><strong>Competitor:</strong> ' + d.competitor_name + '</p><p><strong>What Changed:</strong> ' + d.what_changed + '</p><p><strong>Why It Matters:</strong> ' + d.why_it_matters + '</p><p><strong>Recommended Action:</strong> ' + d.recommended_action + '</p><p><strong>Opportunity:</strong> ' + d.opportunity + '</p><hr><p><em>Summary: ' + d.summary + '</em></p>'; } catch(e) { return $('HTTP Request - Claude Analysis').item.json.content[0].text; } })() }}", "options": {"appendAttribution": false, "bodyContentType": "html"}}}, {"id": "c3d4e5f6-0007-4c3d-ae3f-a3b4c5d6e7f8", "name": "Google Sheets - Log Finding", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [1050, 420], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "append", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Intelligence Log", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"Date": "={{ $now.toISO() }}", "Competitor": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).competitor_name; } catch(e) { return 'Unknown'; } })() }}", "Alert_Level": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).alert_level; } catch(e) { return 'Unknown'; } })() }}", "Summary": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).summary; } catch(e) { return ''; } })() }}", "Recommended_Action": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).recommended_action; } catch(e) { return ''; } })() }}", "Opportunity": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Analysis').item.json.content[0].text).opportunity; } catch(e) { return ''; } })() }}"}}, "options": {}}}], "connections": {"Schedule Trigger": {"main": [[{"node": "HTTP Request - Fetch RSS Feed", "type": "main", "index": 0}]]}, "HTTP Request - Fetch RSS Feed": {"main": [[{"node": "HTTP Request - Claude Analysis", "type": "main", "index": 0}]]}, "HTTP Request - Claude Analysis": {"main": [[{"node": "IF - Red or Yellow Alert", "type": "main", "index": 0}]]}, "IF - Red or Yellow Alert": {"main": [[{"node": "Gmail - Send Alert", "type": "main", "index": 0}], [{"node": "Google Sheets - Log Finding", "type": "main", "index": 0}]]}, "Gmail - Send Alert": {"main": [[{"node": "Google Sheets - Log Finding", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-07-competitor-watch"}, "tags": []}, "diagram_image": "workflow-diagram-07.png"}, {"title": "Workflow 08: Smart Inquiry Auto-Responder", "type": "workflow", "tagline": "Classify every inbound inquiry and send a personalized reply in under 2 minutes.", "metrics": {"time_saved": "2 hours/day", "response_time": "under 2 min", "setup_time": "3 hours"}, "stats": {"avg_response_time_before": "42 hrs", "with_workflow": "<60 sec", "customers_who_leave_if_slow": "78%"}, "flow": ["Gmail", "Claude AI (Classify)", "Filter", "Claude AI (Respond)", "Gmail", "HubSpot"], "classifier_prompt": {"platform": "Claude AI (Zapier or API)", "prompt": "Classify the following email into exactly one of these categories: Sales, Support, General, Spam.\n\nDefinitions:\n- Sales: The sender is asking about pricing, availability, working together, a quote, a proposal, or purchasing something.\n- Support: The sender is reporting a problem, asking how to use something they already have, or requesting help with an existing order or account.\n- General: The sender has a question or comment that doesn't fit Sales or Support — media inquiries, partnership ideas, feedback, or general curiosity.\n- Spam: Automated marketing emails, newsletters, unsolicited mass emails, or messages that are clearly not from a real person with a genuine question.\n\nEmail details:\nFrom: INSERT_SENDER_EMAIL ← Map the Gmail 'From Email' field here\nSubject: INSERT_EMAIL_SUBJECT ← Map the Gmail 'Subject' field here\nBody: INSERT_EMAIL_BODY ← Map the Gmail 'Body Plain' field here\n\nRespond with exactly one word. Do not add punctuation, explanation, or any other text. Your entire response must be one of: Sales, Support, General, Spam."}, "response_prompt": {"platform": "Claude AI (Zapier or API)", "prompt": "You are responding to a customer email on behalf of Meridian Consulting, a one-person business strategy consultancy. ← Replace with your business name and description.\n\nEmail details:\nFrom: INSERT_SENDER_NAME ← Map the Gmail 'From Name' field here\nSubject: INSERT_EMAIL_SUBJECT ← Map the Gmail 'Subject' field here\nBody: INSERT_EMAIL_BODY ← Map the Gmail 'Body Plain' field here\nClassification: INSERT_CLASSIFICATION ← Map the Claude classifier output here\n\nInstructions based on classification:\n\nIf Sales: Thank them for their interest. Briefly describe the main service offering (strategy sessions starting at $500, retainers from $2,000/month ← update these). Let them know you'll follow up within 1 business day to schedule a free 20-minute intro call. Keep it warm and direct — no corporate-speak.\n\nIf Support: Acknowledge their issue clearly. If it's a common problem you can resolve in the email (e.g., resending a file, clarifying a deliverable), do so. If not, let them know you're looking into it and will reply with a solution within 4 business hours.\n\nIf General: Answer their question if possible. If it's a media or partnership inquiry, invite them to share more detail and say you'll review it within 3 business days.\n\nAll responses:\n- Start with 'Hi [first name],' using the sender's actual first name\n- Be concise — 3 to 5 short paragraphs maximum\n- End with: 'Best,\\nAlex\\nMeridian Consulting\\nalex@meridianconsulting.com' ← Replace with your name and email\n- Do not use hollow phrases like 'Great question!' or 'I hope this email finds you well'\n- Do not include a subject line — return only the email body\n\nWrite the response now."}, "zapier_setup": [{"step": "T", "node": "Gmail", "detail": "In your Zapier dashboard, click '+ Create' then 'New Zap'. Search for 'Gmail' as your trigger app and choose 'New Email' as the trigger event. Connect your Gmail account and grant the requested permissions. In the Label/Mailbox field, select 'INBOX' — this will catch all new incoming emails. Optionally, add a search filter like 'subject:inquiry OR subject:question' if you want to narrow it down, but starting with all inbox emails is fine. Click 'Test trigger' — Zapier will pull in your three most recent emails as sample data. Pick one that looks like a real customer inquiry to use for testing the rest of the Zap."}, {"step": "AI", "node": "Claude AI (Classify)", "detail": "Add an action step, search for 'Claude AI by Anthropic', and choose 'Send Message'. Select the 'claude-3-5-haiku' model for this step — it's faster and cheaper than Sonnet, which matters here because classification is a simple task. Set Max Tokens to 50 (you only need one word back). Paste the classifier prompt from the classifier_prompt section below into the Message field. Use Zapier's '+' field-mapper to insert the email body: click inside the prompt where it says INSERT_EMAIL_BODY and replace it with the mapped 'Body Plain' field from your Gmail trigger. Also map the sender's email and subject line as instructed in the prompt. Test this step — the output should be exactly one word: Sales, Support, General, or Spam."}, {"step": "F", "node": "Filter", "detail": "Add a 'Filter by Zapier' step (it's under the 'Filter' category, not a separate app). Set the condition to: 'Claude AI Output Text' + 'Does not contain' + 'Spam'. This tells Zapier to only continue if the classification result is not Spam. Make sure the capitalization matches — if Claude returns 'spam' in lowercase, change your filter value to match. Test the filter using the Spam sample data you should have from earlier tests — Zapier should show 'This Zap would NOT have continued' for a Spam input, which is exactly what you want. If your classifier returns extra words beyond the category label, adjust your classifier prompt to be stricter."}, {"step": "AI", "node": "Claude AI (Generate Response)", "detail": "Add another Claude AI step. This time, use 'claude-3-5-sonnet' — the response your customer reads should be high quality. Set Max Tokens to 400. Paste the response_prompt from the response_prompt section below into the Message field. Map the following fields from earlier steps: the sender's name (from Gmail's 'From Name' field), the email subject (Gmail's 'Subject' field), the full email body (Gmail's 'Body Plain' field), and the classification result (Claude classify step's 'Output Text'). The prompt uses the classification to choose the right response type automatically. Test this step using a realistic sample inquiry — read the response and make sure it sounds like you, not like a robot. If it doesn't, revise the prompt's tone instructions before continuing."}, {"step": "@", "node": "Gmail (Send Reply)", "detail": "Add a Gmail action step and choose 'Reply to Email' as the action event (not 'Send Email' — Reply preserves the thread). Connect the same Gmail account as your trigger. In the 'In-Reply-To' or 'Thread ID' field, map the Thread ID from your original Gmail trigger step so the reply lands in the correct thread. In the 'Body' field, map the output from your second Claude step. In the 'To' field, map the sender's email address from the Gmail trigger. Review the test output carefully in Gmail's 'Sent' folder after testing — check that it's a reply in the right thread, the greeting uses the sender's real name, and the signature appears correctly."}, {"step": "A", "node": "HubSpot", "detail": "Add a final HubSpot action step and choose 'Create or Update Contact' as the action event (this is sometimes called 'Upsert Contact'). Connect your HubSpot account via OAuth. Map the Email field to the sender's email from the Gmail trigger — HubSpot uses this as the unique identifier. Map First Name and Last Name from Gmail's 'From Name' field (you may need to split the name using Zapier's Formatter tool if the name comes as a single string). In the Notes or a custom property field, add the classification label from the first Claude step — this helps you filter contacts in HubSpot later. Turn on the Zap, then send a real test email from a personal email address and verify the contact appears in HubSpot within a minute."}], "customization": {"business_name": "[___]", "inquiry_sources": "[Email / Website form / Social DMs]", "response_mode": "[Auto-send / Approve first]", "booking_link": "[___]", "response_sign_off": "[Your name / Team name]"}, "content": "This workflow watches your inbox for new emails, uses Claude to classify them as Sales, Support, General, or Spam, filters out spam entirely, then generates a personalized reply and sends it — all while logging the contact in HubSpot. The two-AI-call design is intentional: the first call only classifies (fast, cheap, focused), and the second call only writes (uses full context). Keeping them separate makes it much easier to debug if something goes wrong. Plan for three hours of setup. The hardest part is writing good response prompts — spend the most time there, because that's what your customers will actually read.", "cowork_alternative": {"platform": "Claude Cowork", "steps": [{"step": 1, "action": "Create your Inquiry Responder Agent", "detail": "In Claude Cowork, create a new Agent and name it 'Inquiry Responder'. In the system prompt field, paste the full context from the response_prompt section above — specifically the business description, the classification-based instructions, and the response format rules. This system prompt defines the agent's behavior for every email it processes. Save the agent before moving to the next step."}, {"step": 2, "action": "Connect Gmail as the input source", "detail": "Go to the Agent's Integrations tab and connect Gmail using the OAuth flow. Under Trigger Settings, set it to activate on 'New Email in Inbox'. If you want to exclude newsletters and auto-replies, add a filter: only trigger on emails where the sender is not in your contacts list, or where the subject does not contain 'unsubscribe'. Test the connection by sending a test email to the connected account — it should appear in the Agent's activity log within 2 minutes."}, {"step": 3, "action": "Configure classification and routing", "detail": "In the Agent's Logic tab, add a Classification step using the classifier prompt from the classifier_prompt section above. Set up a routing rule: if the classification returns 'Spam', stop processing and take no action. For all other classifications (Sales, Support, General), continue to the response generation step. You can also add a separate routing rule to flag Sales inquiries with a label in Gmail so you can follow up manually on high-value leads."}, {"step": 4, "action": "Connect Gmail reply and HubSpot logging", "detail": "In the Agent's Actions tab, add two actions: first, 'Reply to Email' using Gmail — map the agent's generated response to the reply body and ensure it threads correctly by using the original message ID. Second, add a HubSpot action set to 'Create or Update Contact' — map the sender's email, name, and the classification label to the appropriate HubSpot fields. Set the action execution order so the reply sends first, then HubSpot logs the contact."}, {"step": 5, "action": "Enable and monitor", "detail": "Activate the agent using the toggle on the main Agent page. For the first week, set it to 'Draft mode' if available — this generates the reply but holds it for your approval before sending. Review 5 to 10 drafts to build confidence that the outputs are correct. Once you're comfortable, switch to fully automated sending. Check the Agent's activity log once a week to spot any misclassifications and update the classifier prompt if needed."}]}, "setup_time": "3 hours", "complexity": "intermediate", "maintenance": "Review the activity log or your Sent folder once a week for the first month. The most common issue is misclassification — if Sales emails are being tagged as General, add clarifying examples to the classifier prompt. Refresh your HubSpot connection token every 60–90 days if using a non-OAuth credential.", "expected_output": "Every new inbox inquiry receives a personalized, on-brand reply within 2 minutes, classified correctly, with the sender logged as a contact in HubSpot — without you touching your email.", "id": "workflow-08", "prerequisites": ["A Gmail account you use for business inquiries (a dedicated address like hello@yourbusiness.com works best)", "A HubSpot account — the free CRM tier is sufficient for contact creation", "A Zapier account (Professional plan or higher, as this Zap uses multiple steps and a Filter)", "An Anthropic API key added to Zapier's Claude AI integration", "A saved draft of your standard response templates for Sales, Support, and General inquiries (you'll paste these into the prompts below)"], "n8n_setup": [{"step": "T", "node": "Gmail Trigger", "detail": "In n8n, create a new workflow and add a 'Gmail' trigger node. Connect it using OAuth2 credentials — click 'Create New Credential', sign in with Google, and grant the permissions requested. Set the trigger to 'New Email' and the mailbox to 'INBOX'. Set Poll Time to every 1 minute for near-real-time response, or every 5 minutes if you prefer lighter API usage. Click 'Listen for event' and send yourself a test email — it should appear as the trigger output within the poll interval. Note the field names in the output (subject, text, from, threadId) as you'll reference these in later nodes."}, {"step": "AI", "node": "HTTP Request — Classify", "detail": "Add an HTTP Request node. Set Method to POST and URL to 'https://api.anthropic.com/v1/messages'. Add headers: 'x-api-key' = your Anthropic API key, 'anthropic-version' = '2023-06-01', 'Content-Type' = 'application/json'. In the Body (JSON), set model to 'claude-3-5-haiku-20241022', max_tokens to 50, and messages to an array containing one user message. Build the message content using n8n's expression syntax to insert the email body: {{ $node['Gmail Trigger'].json.text }}. Paste the classifier prompt text around this expression. Run the node with your test email and confirm the output contains exactly one classification word."}, {"step": "F", "node": "IF Node", "detail": "Add an 'IF' node (found under the Flow category). Set the condition to check whether the HTTP Request output contains the word 'Spam'. In the Value 1 field, use the expression {{ $node['HTTP Request'].json.content[0].text }} (adjust the path based on your actual output structure — inspect the JSON output of the previous node to find where the text lives). Set the operator to 'does not contain' and Value 2 to 'Spam'. The 'True' branch should connect to the response generation step. The 'False' branch can be left empty or connected to a 'NoOp' node. Test this with both a spam sample and a real inquiry to verify each branch routes correctly."}, {"step": "AI", "node": "HTTP Request — Generate Response", "detail": "On the True branch of the IF node, add another HTTP Request node with the same Anthropic API headers. This time use model 'claude-3-5-sonnet-20241022' and max_tokens 400. Build your message content by injecting the sender name, email subject, body, and classification label from previous nodes using expressions. Paste the response prompt text around these dynamic values. Run the node against a realistic test case and read the output carefully. If the tone is off, go back and adjust the prompt — it's much easier to fix now than after you've sent responses to real customers."}, {"step": "@", "node": "Gmail — Send Reply", "detail": "Add a Gmail node and set the Operation to 'Reply'. In the Thread ID field, use {{ $node['Gmail Trigger'].json.threadId }} to keep the reply in the original thread. In the Message field, use {{ $node['HTTP Request1'].json.content[0].text }} (update the node name to match yours). In the To field, use the sender's email from the trigger: {{ $node['Gmail Trigger'].json.from }}. Run the node in test mode and check your Gmail Sent folder to confirm the reply landed in the correct thread and looks correct."}, {"step": "A", "node": "HubSpot", "detail": "Add a HubSpot node and set the Resource to 'Contact' and the Operation to 'Upsert' (create or update). Authenticate with your HubSpot account using the OAuth2 or API key option in the credentials panel. Map the email, first name, and last name fields from the Gmail trigger output. Add a custom property for 'inquiry_type' if you've created that field in HubSpot, and map it to the classification output from your first API call. Save and activate the workflow. After running a full end-to-end test, check HubSpot to confirm the contact was created with the correct fields populated."}], "testing_checklist": ["Send a test sales inquiry from a personal email (e.g., 'Hi, I'm interested in your services. Can you send me pricing information?') and verify it's classified as 'Sales' and the reply mentions your pricing or next steps correctly.", "Send a test support email (e.g., 'I haven't received my invoice from last week') and verify it's classified as 'Support' and the reply acknowledges the issue and gives a realistic resolution timeframe.", "Send a test general email (e.g., 'I found your work interesting and wanted to reach out') and verify it's classified as 'General' and the reply is friendly and appropriate.", "Forward a real newsletter or marketing email to the inbox and verify it's classified as 'Spam' and the Filter step stops the Zap from continuing — no reply should be sent.", "Check your Gmail Sent folder after each test to confirm replies landed in the correct email thread and are not starting new conversations.", "Open HubSpot and verify a new contact was created for each non-Spam test, with the correct email address, name, and classification label in the contact record.", "Send an email with a foreign-language subject line and verify the workflow handles it gracefully — the classifier should still return a valid category, not an error.", "Run the full workflow during off-hours to confirm the timing works and that the reply arrives within 2 minutes of the trigger email being received."], "n8n_workflow_json": {"name": "KH Academy — Smart Inquiry Auto-Responder", "nodes": [{"id": "b2c3d4e5-0001-4b2c-9d2e-f2a3b4c5d6e7", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 80], "parameters": {"content": "## 🚀 SETUP INSTRUCTIONS\n\n**1. Gmail Account**\nOpen the \"Gmail Trigger\" and \"Gmail - Reply\" nodes → Credentials → connect your Gmail account via OAuth2.\n\n**2. Anthropic API Key**\nOpen both HTTP Request nodes to Anthropic → Headers → replace `YOUR_ANTHROPIC_API_KEY` with your key from https://console.anthropic.com\n\n**3. Business Info**\nIn \"HTTP Request - Generate Response\", update the system prompt with:\n- Your actual business/brand name\n- What your business does\n- Your typical response tone (friendly, professional, etc.)\n\n**4. HubSpot**\nOpen \"HubSpot - Create Contact\" → Credentials → connect your HubSpot account.\nReplace `YOUR_HUBSPOT_CREDENTIAL_ID` if needed.\n\n**5. Spam Filter**\nThe IF node routes emails classified as \"Spam\" to the false branch (dead end).\nYou can add a \"No Operation\" node or a Gmail label node on the false branch if desired.\n\n**6. Gmail Trigger Polling**\nBy default this polls every minute. Adjust the \"Poll Times\" setting in the Gmail Trigger node to your preference.", "height": 560, "width": 520, "color": 5}}, {"id": "b2c3d4e5-0002-4b2c-9d2e-f2a3b4c5d6e7", "name": "Gmail Trigger", "type": "n8n-nodes-base.gmailTrigger", "typeVersion": 1.1, "position": [250, 340], "credentials": {"gmailOAuth2": {"id": "YOUR_GMAIL_CREDENTIAL_ID", "name": "Gmail account"}}, "parameters": {"pollTimes": {"item": [{"mode": "everyMinute"}]}, "simple": false, "filters": {}, "options": {}}}, {"id": "b2c3d4e5-0003-4b2c-9d2e-f2a3b4c5d6e7", "name": "HTTP Request - Classify", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [470, 340], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 300,\n  \"system\": \"You are an email classification assistant. Analyze incoming emails and respond with a valid JSON object only — no markdown, no explanation, just raw JSON.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Classify this email and extract key details.\\n\\nFrom: {{ $json.from.value[0].address }}\\nSubject: {{ $json.subject }}\\nBody: {{ $json.text }}\\n\\nRespond with this exact JSON structure (no extra text, no code blocks):\\n{\\n  \\\"category\\\": \\\"Sales|Support|General|Spam\\\",\\n  \\\"customer_name\\\": \\\"extracted name or empty string\\\",\\n  \\\"customer_email\\\": \\\"{{ $json.from.value[0].address }}\\\",\\n  \\\"key_question\\\": \\\"one sentence summary of what they need\\\",\\n  \\\"urgency\\\": \\\"Low|Medium|High\\\",\\n  \\\"is_spam\\\": false\\n}\\n\\nSet is_spam to true and category to Spam if the email is unsolicited marketing, phishing, or irrelevant mass mail.\"\n    }\n  ]\n}", "options": {}}}, {"id": "b2c3d4e5-0004-4b2c-9d2e-f2a3b4c5d6e7", "name": "IF - Not Spam", "type": "n8n-nodes-base.if", "typeVersion": 2, "position": [690, 340], "parameters": {"conditions": {"options": {"caseSensitive": false, "leftValue": "", "typeValidation": "strict"}, "conditions": [{"id": "cond-spam-check", "leftValue": "={{ (() => { try { return JSON.parse($json.content[0].text).category; } catch(e) { return $json.content[0].text; } })() }}", "rightValue": "Spam", "operator": {"type": "string", "operation": "notEquals"}}], "combinator": "and"}}}, {"id": "b2c3d4e5-0005-4b2c-9d2e-f2a3b4c5d6e7", "name": "HTTP Request - Generate Response", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [910, 240], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 600,\n  \"system\": \"You are a helpful customer-facing assistant for [YOUR BUSINESS NAME — replace this]. [DESCRIBE WHAT YOUR BUSINESS DOES — replace this]. Your tone is professional yet warm. Always aim to be concise and genuinely helpful. Sign off with: Best regards,\\nThe [YOUR BUSINESS NAME] Team\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Draft a personalized email reply to the following inquiry.\\n\\nClassification data: {{ $('HTTP Request - Classify').item.json.content[0].text }}\\n\\nOriginal email:\\nFrom: {{ $('Gmail Trigger').item.json.from.value[0].address }}\\nSubject: {{ $('Gmail Trigger').item.json.subject }}\\nBody: {{ $('Gmail Trigger').item.json.text }}\\n\\nInstructions:\\n- Address the sender by their first name if available\\n- Directly answer or acknowledge their key question\\n- Keep the reply under 150 words unless the inquiry is complex\\n- Do not include a subject line — output the email body only\\n- Do not use filler phrases like 'Great question!' or 'Thank you for reaching out'\\n- Be direct and helpful from the first sentence\"\n    }\n  ]\n}", "options": {}}}, {"id": "b2c3d4e5-0006-4b2c-9d2e-f2a3b4c5d6e7", "name": "Gmail - Reply", "type": "n8n-nodes-base.gmail", "typeVersion": 2.1, "position": [1130, 240], "credentials": {"gmailOAuth2": {"id": "YOUR_GMAIL_CREDENTIAL_ID", "name": "Gmail account"}}, "parameters": {"operation": "reply", "messageId": "={{ $('Gmail Trigger').item.json.id }}", "threadId": "={{ $('Gmail Trigger').item.json.threadId }}", "replyTo": "={{ $('Gmail Trigger').item.json.from.value[0].address }}", "message": "={{ $json.content[0].text }}", "options": {}}}, {"id": "b2c3d4e5-0007-4b2c-9d2e-f2a3b4c5d6e7", "name": "HubSpot - Create Contact", "type": "n8n-nodes-base.hubspot", "typeVersion": 2, "position": [1350, 240], "credentials": {"hubspotAppToken": {"id": "YOUR_HUBSPOT_CREDENTIAL_ID", "name": "HubSpot account"}}, "parameters": {"resource": "contact", "operation": "upsert", "email": "={{ (() => { try { return JSON.parse($('HTTP Request - Classify').item.json.content[0].text).customer_email; } catch(e) { return $('Gmail Trigger').item.json.from.value[0].address; } })() }}", "additionalFields": {"firstName": "={{ (() => { try { const name = JSON.parse($('HTTP Request - Classify').item.json.content[0].text).customer_name; return name ? name.split(' ')[0] : ''; } catch(e) { return ''; } })() }}", "lastName": "={{ (() => { try { const name = JSON.parse($('HTTP Request - Classify').item.json.content[0].text).customer_name; const parts = name ? name.split(' ') : []; return parts.length > 1 ? parts.slice(1).join(' ') : ''; } catch(e) { return ''; } })() }}", "lifecycleStage": "lead"}}}, {"id": "b2c3d4e5-0008-4b2c-9d2e-f2a3b4c5d6e7", "name": "No Operation - Spam", "type": "n8n-nodes-base.noOp", "typeVersion": 1, "position": [910, 460], "parameters": {}}], "connections": {"Gmail Trigger": {"main": [[{"node": "HTTP Request - Classify", "type": "main", "index": 0}]]}, "HTTP Request - Classify": {"main": [[{"node": "IF - Not Spam", "type": "main", "index": 0}]]}, "IF - Not Spam": {"main": [[{"node": "HTTP Request - Generate Response", "type": "main", "index": 0}], [{"node": "No Operation - Spam", "type": "main", "index": 0}]]}, "HTTP Request - Generate Response": {"main": [[{"node": "Gmail - Reply", "type": "main", "index": 0}]]}, "Gmail - Reply": {"main": [[{"node": "HubSpot - Create Contact", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-auto-responder"}, "tags": []}}, {"title": "Workflow 09: Client Onboarding Automation", "type": "workflow", "tagline": "PROFESSIONAL ONBOARDING IN MINUTES — NOT DAYS", "metrics": {"time_saved": "2-3 hrs per client", "difficulty": "Intermediate", "tools_needed": 5, "frequency": "Per client"}, "stats": {"manual_onboarding_time": "2-3 hours", "automated_onboarding_time": "under 5 minutes", "consistency": "100% — every client gets the same premium experience"}, "flow": [{"step": "P", "label": "PAYMENT", "description": "Stripe/PayPal"}, {"step": "AI", "label": "CLAUDE", "description": "Generate welcome package"}, {"step": "D", "label": "DOCS", "description": "Create onboarding guide"}, {"step": "E", "label": "EMAIL", "description": "Send welcome email"}, {"step": "C", "label": "CRM", "description": "Update status"}], "ai_prompt": {"platform": "Claude", "model": "claude-sonnet-4-20250514", "system_prompt": "You are an onboarding specialist for [YOUR BUSINESS — replace with your business name]. You create warm, professional, and personalized onboarding materials for new clients. Your service is [YOUR SERVICE TYPE — replace with what you sell, e.g. 'a 3-month business coaching program', 'website design and development', '6-month consulting retainer']. Your tone is enthusiastic but grounded — confident and reassuring. Always make the client feel they made an excellent decision. Respond only with a valid JSON object — no markdown, no explanation before or after.", "user_message": "A new client just purchased. Generate their complete onboarding package.\n\nCLIENT INFO:\nName: {{ $json.data.object.customer_details.name }}  ← Replaced automatically by n8n\nEmail: {{ $json.data.object.customer_details.email }}  ← Replaced automatically by n8n\nService Purchased: {{ $json.data.object.display_items[0].custom.name }}  ← Replaced automatically by n8n\nAmount Paid: {{ $json.data.object.amount_total }}  ← Replaced automatically by n8n\nPurchase Date: {{ $now.toISO() }}  ← Replaced automatically by n8n\n\nReturn a JSON object with these exact fields:\n{\n  \"welcome_email_subject\": \"compelling subject line that makes them excited to open it\",\n  \"welcome_email_body\": \"personalized welcome email body (150-200 words, HTML formatted with <p> and <strong> tags, references their name and what they purchased)\",\n  \"onboarding_doc_title\": \"title for the Google Doc, e.g. 'Welcome to [Business] — [Client Name] Onboarding Guide'\",\n  \"onboarding_doc_body\": \"full onboarding document (500-700 words) with these sections: 1) Welcome (personalized, references the service), 2) What to expect in your first 7 days, 3) Your onboarding checklist (step-by-step, numbered), 4) Week 1-4 milestone timeline, 5) Top 5 FAQs with answers specific to [YOUR SERVICE TYPE], 6) Your next steps: complete intake form at [YOUR_INTAKE_FORM_LINK — replace], book kickoff call at [YOUR_CALENDAR_LINK — replace], join our client channel at [YOUR_COMMS_LINK — replace]\",\n  \"slack_notification\": \"one-sentence team notification including client name, service purchased, amount, and that onboarding is underway\"\n}", "notes": "Replace [YOUR BUSINESS], [YOUR SERVICE TYPE], [YOUR_INTAKE_FORM_LINK], [YOUR_CALENDAR_LINK], and [YOUR_COMMS_LINK] before activating. The {{ }} expressions are n8n template variables that get replaced automatically with real Stripe data at runtime."}, "zapier_setup": [{"step": 1, "node": "Stripe — New Payment", "detail": "In Zapier, create a new Zap and select Stripe as the trigger app. Choose the event 'New Payment' or 'New Customer' — the 'New Payment' event fires whenever a successful charge is processed, giving you the customer name, email, amount, and product name immediately. Connect your Stripe account and test the trigger by making a test payment using Stripe's test card number (4242 4242 4242 4242 with any future expiry). This produces a real webhook payload you can use to build and test all subsequent steps in the Zap without charging a real card. Make sure your Stripe account is in test mode during setup."}, {"step": 2, "node": "Claude AI — Generate Welcome Package", "detail": "Add a Claude AI action and set it to 'Send Message'. Paste the full onboarding prompt into the message field and map the Stripe data fields: client name, email, service/product name, amount paid, and purchase date. Claude will generate a complete onboarding package in a single API call, including a personalized welcome email subject and body, a full onboarding document with checklist and milestones, a 5-question FAQ tailored to your service type, next steps with your intake form and calendar links, and a one-sentence internal Slack notification. Request the output as JSON so the downstream Zapier steps can reliably extract each component. This single Claude call replaces 2-3 hours of manual onboarding document creation per client."}, {"step": 3, "node": "Gmail — Send Welcome Email", "detail": "Add a Gmail action set to 'Send Email'. Map the recipient to the customer's email address from the Stripe payload. Extract the welcome_email_subject and welcome_email_body fields from the Claude JSON output and map them to the subject and body fields in Zapier. Enable HTML formatting so the email renders with proper paragraph breaks and bold text. Send a test email to yourself first and view it on both desktop and mobile to confirm it renders correctly. The welcome email should land in the client's inbox within minutes of their payment confirming — this immediate response dramatically increases client confidence and reduces post-purchase anxiety."}, {"step": 4, "node": "Google Docs — Create Onboarding Document", "detail": "Add a Google Docs action set to 'Create Document'. Map the title from the onboarding_doc_title field in the Claude output and the body from the onboarding_doc_body field. Zapier will create a new Google Doc in your connected Drive account containing the full onboarding checklist, timeline, and FAQ. After creation, Zapier returns the document URL — you can use this URL in a follow-up Gmail action to send the client a second email with a direct link to their onboarding document. Store the document URL in a Google Sheet if you want a master list of all client onboarding docs."}, {"step": 5, "node": "HubSpot — Update Contact", "detail": "Add a HubSpot action set to 'Create or Update Contact'. Map the email address as the identifier, and set the lifecycle stage to 'Customer' — this moves the contact out of Lead or Prospect status in your CRM automatically. You can also populate additional fields like the service purchased, amount, and purchase date to build a complete client record. If the contact doesn't yet exist in HubSpot, this step creates them automatically. This ensures your CRM always reflects accurate pipeline status without any manual data entry on your part."}, {"step": 6, "node": "Slack — Notify Team", "detail": "Add a Slack action set to 'Send Channel Message'. Choose the channel where your team tracks new clients (e.g. #new-clients or #sales). Map the message from the slack_notification field in the Claude output — it will include the client's name, service purchased, and amount. This gives you and your team immediate awareness of new clients even when you're away from your desk. Consider also adding a second Slack message to yourself (direct message) as a personal ping so you can personally reach out to the new client within the first hour, which studies show dramatically increases retention."}], "n8n_setup": [{"step": 1, "node": "Stripe Trigger", "detail": "Add a Stripe Trigger node to your n8n workflow. Open the node and copy the webhook URL displayed — it will look like https://your-n8n-instance.com/webhook/stripe-trigger. Go to your Stripe Dashboard → Developers → Webhooks → Add Endpoint, paste the URL, and select the event 'checkout.session.completed'. Copy the Webhook Signing Secret from Stripe and add it to the Stripe Trigger node's credentials in n8n. This ensures only legitimate Stripe events trigger your workflow. In Stripe test mode, use the 'Send test webhook' button to send a sample payload and verify the connection."}, {"step": 2, "node": "HTTP Request - Claude Welcome Package", "detail": "Add an HTTP Request node configured as POST to https://api.anthropic.com/v1/messages. Set three headers: x-api-key, anthropic-version (2023-06-01), and Content-Type (application/json). In the JSON body, build the prompt using n8n expressions to inject the Stripe data: {{ $json.data.object.customer_details.name }} for the client name, {{ $json.data.object.customer_details.email }} for email, and {{ $json.data.object.display_items[0].custom.name }} for the product name. Set max_tokens to 1500 to ensure Claude has enough space to generate the full onboarding package. The prompt should request JSON output with named fields for each component."}, {"step": 3, "node": "Gmail - Welcome Email", "detail": "Add a Gmail node set to the 'Send' operation. Connect your Gmail account via OAuth2. Map the sendTo field to the customer email from the Stripe trigger. Parse the Claude response JSON to extract the welcome_email_subject and welcome_email_body fields using a JavaScript expression wrapped in a try/catch for safety. Set bodyContentType to 'html' so line breaks and formatting render correctly in the client's email client. This node fires automatically within seconds of the Stripe webhook, meaning the client often receives their welcome email while they're still on your thank-you page."}, {"step": 4, "node": "Google Docs - Create Onboarding Doc", "detail": "Add a Google Docs node set to the 'Create' operation. Connect your Google account via OAuth2. Map the title and content fields from the Claude JSON output using expressions. n8n's Google Docs node creates a new document in your Drive root — you can later configure it to create the doc in a specific folder by adjusting the node's folder parameters. The node returns the created document's URL, which you can use in subsequent nodes to send the client a direct link or store it in a CRM or Sheets log."}, {"step": 5, "node": "HubSpot - Update Contact", "detail": "Add a HubSpot node set to 'Upsert' operation on the Contact resource. Connect your HubSpot account using an API token from your HubSpot account settings. Set the email field as the identifier using the Stripe customer email. Set lifecycleStage to 'customer' in the additionalFields section. n8n's upsert operation creates the contact if they don't exist or updates them if they do — making this step safe to run without fear of creating duplicate records. After testing, check your HubSpot contacts view to confirm the lifecycle stage updated correctly."}, {"step": 6, "node": "Slack - Notify Team", "detail": "Add a Slack node set to the 'Post Message' operation. Connect your Slack workspace via OAuth2 or API token. Set the channel to your team notification channel. Map the text field to the slack_notification from the Claude output, or build a custom message using expressions: 'New client: {{ $('Stripe Trigger').item.json.data.object.customer_details.name }} just purchased {{ $('Stripe Trigger').item.json.data.object.display_items[0].custom.name }}. Welcome email sent, onboarding doc created, HubSpot updated.' Test by running the full workflow with a test Stripe event and verifying the Slack message appears in the correct channel."}], "customization": {"service_product_name": "[Your service or product name — replace in prompt]", "payment_processor": "Stripe (checkout.session.completed event)", "intake_form_link": "[https://yourform.com — replace in prompt]", "booking_calendar_link": "[https://calendly.com/you — replace in prompt]", "communication_channel": "[Slack / Discord / WhatsApp — replace link in prompt]", "hubspot_lifecycle_stage": "customer (can change to 'opportunity' or custom stage)", "slack_notification_channel": "#new-clients (rename to your channel)"}, "content": "Manual client onboarding takes 2-3 hours per new client and the quality varies every time depending on how busy you are that day. This workflow delivers a consistent, professional onboarding experience in under 5 minutes, triggered automatically when payment is received. When Stripe or PayPal processes a new payment, the automation sends the client details and service information to Claude, which generates a complete personalized welcome package: a welcome message with what to expect in the first 7 days, a step-by-step checklist for both sides, a week-by-week milestone timeline, 5 pre-answered FAQs specific to their service, and clear next steps with links to book a kickoff call, complete an intake form, and join your communication channel. The package is created as a Google Doc, the welcome email sends automatically with all links, and your CRM status updates to Onboarding. In Zapier: Stripe new payment trigger, Claude AI generation, Google Docs create, Gmail send, HubSpot update. In n8n: Webhook connected to Stripe, Claude node, Google Docs and Gmail nodes, HTTP request to CRM API. Every client gets the same premium first impression.", "cowork_alternative": {"description": "With Claude Cowork (included with Claude Pro at $20/month), you can trigger this onboarding workflow manually from your desktop when you receive a payment notification. While not fully automated, it reduces the onboarding task to a single paste-and-click action.", "steps": ["When you receive a Stripe payment email, copy the client's name, email, service purchased, and amount", "Open Claude Desktop with Cowork enabled and paste: 'New client onboarding: [paste client details]. Generate their welcome package and: 1) send them a welcome email to [email], 2) create a Google Doc with their onboarding guide, 3) update HubSpot lifecycle to Customer, 4) post to #new-clients in Slack'", "Claude will ask to confirm each action — approve each one", "Review the sent email in your Gmail Sent folder to confirm delivery"]}, "setup_time": "30-45 minutes", "complexity": "Intermediate — requires Stripe webhook setup and 5 connected services", "maintenance": "Update the AI prompt when you change your service offering, intake form, or calendar link", "expected_output": "Within 5 minutes of payment: personalized welcome email in client inbox, Google Doc onboarding guide created, HubSpot updated to Customer, Slack team notification sent", "workflow_id": "09", "prerequisites": ["Stripe account with at least one active product/checkout (or use Stripe test mode to test the workflow)", "Anthropic account with API key (https://console.anthropic.com)", "Gmail account connected via OAuth2 in n8n", "Google account for Google Docs creation (connected via OAuth2 in n8n)", "HubSpot account (free tier works) for lifecycle stage tracking", "Slack workspace with a #new-clients or similar notification channel", "An intake form link, kickoff calendar booking link, and client communication channel invite link ready to paste into the prompt"], "testing_checklist": ["Enable Stripe test mode and generate a test checkout session with a test card (4242 4242 4242 4242)", "Confirm the Stripe Trigger node receives the webhook payload in n8n", "Execute the Claude node manually with sample Stripe data — verify the JSON response contains all 5 required fields", "Check that the welcome email is sent to the correct address with correct subject and HTML formatting", "Confirm a new Google Doc is created in your Drive with the correct title and onboarding content", "Verify HubSpot shows the contact with lifecycleStage = 'customer' (check contacts list in HubSpot)", "Confirm the Slack message appears in the correct channel", "Send a real test payment (can use a $1 test product in Stripe test mode) and run the full workflow end-to-end", "Check the n8n Execution log for any errors after the first live run", "Review the welcome email from the client's perspective — open it on mobile to confirm formatting"], "n8n_workflow_json": {"name": "KH Academy — Client Onboarding Automation", "nodes": [{"id": "d4e5f6a7-0001-4d4e-bf4f-b4c5d6e7f8a9", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS\n\n**1. Stripe Webhook**\nIn your Stripe Dashboard → Developers → Webhooks → Add endpoint.\nSet the endpoint URL to your n8n webhook URL (shown in the Stripe Trigger node when you open it).\nSelect the event: checkout.session.completed\nCopy the Webhook Signing Secret and paste it into the Stripe Trigger node credentials.\n\n**2. Anthropic API Key**\nOpen \"HTTP Request - Claude Welcome Package\" → Headers → replace `YOUR_ANTHROPIC_API_KEY`.\nGet your key from https://console.anthropic.com\n\n**3. Update the AI Prompt**\nIn the Claude node body, replace:\n- [YOUR BUSINESS] with your business name\n- [YOUR SERVICE TYPE] with what you sell (coaching, software, consulting, etc.)\n- [YOUR_INTAKE_FORM_LINK] with your actual intake form URL\n- [YOUR_CALENDAR_LINK] with your booking calendar URL\n- [YOUR_SLACK_OR_COMMS_LINK] with your client communication channel invite link\n\n**4. Gmail Credentials**\nOpen \"Gmail - Welcome Email\" → Credentials → connect Gmail via OAuth2.\n\n**5. Google Docs**\nOpen \"Google Docs - Create Onboarding Doc\" → Credentials → connect Google account.\nThe node will create a new Google Doc for each new client in your Google Drive.\n\n**6. HubSpot**\nOpen \"HubSpot - Update Contact\" → Credentials → connect your HubSpot account.\nThe node updates the contact's lifecycle stage to 'customer' upon payment.\n\n**7. Slack**\nOpen \"Slack - Notify Team\" → Credentials → connect your Slack workspace.\nSet the channel to the channel where you want new client notifications (e.g. #new-clients).\n\n**IMPORTANT:** Test with a Stripe test-mode payment first using Stripe's test card (4242 4242 4242 4242) before going live.", "height": 700, "width": 580, "color": 4}}, {"id": "d4e5f6a7-0002-4d4e-bf4f-b4c5d6e7f8a9", "name": "Stripe Trigger", "type": "n8n-nodes-base.stripeTrigger", "typeVersion": 1, "position": [250, 340], "credentials": {"stripeApi": {"id": "YOUR_STRIPE_CREDENTIAL_ID", "name": "Stripe account"}}, "parameters": {"events": ["checkout.session.completed"]}}, {"id": "d4e5f6a7-0003-4d4e-bf4f-b4c5d6e7f8a9", "name": "HTTP Request - Claude Welcome Package", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [450, 340], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 1500,\n  \"system\": \"You are an onboarding specialist for [YOUR BUSINESS — replace this]. You create warm, professional, and personalized onboarding materials for new clients. Your tone is enthusiastic but not over-the-top — confident and reassuring. Always make the client feel they made an excellent decision.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"A new client just purchased. Generate their complete onboarding package as a JSON object with these exact fields:\\n\\nCLIENT INFO:\\nName: {{ $json.data.object.customer_details.name }}\\nEmail: {{ $json.data.object.customer_details.email }}\\nService Purchased: {{ $json.data.object.display_items[0].custom.name }}\\nAmount Paid: {{ $json.data.object.amount_total }}\\nPurchase Date: {{ $now.toISO() }}\\n\\nReturn a JSON object with these fields:\\n{\\n  \\\"welcome_email_subject\\\": \\\"compelling subject line for the welcome email\\\",\\n  \\\"welcome_email_body\\\": \\\"personalized welcome email body (150-200 words, HTML formatted with <p> tags)\\\",\\n  \\\"onboarding_doc_title\\\": \\\"title for the Google Doc\\\",\\n  \\\"onboarding_doc_body\\\": \\\"full onboarding document content (500-700 words) including: Welcome section, What to expect in week 1, Step-by-step checklist for the client, Week 1-4 milestone timeline, 5 FAQs with answers, Next steps with these links: Intake form: [YOUR_INTAKE_FORM_LINK] | Book kickoff: [YOUR_CALENDAR_LINK] | Join our channel: [YOUR_SLACK_OR_COMMS_LINK]\\\",\\n  \\\"slack_notification\\\": \\\"one sentence internal notification for the team (include client name, service, and amount)\\\"\\n}\\n\\nService context: [YOUR SERVICE TYPE — replace with what you sell, e.g. 'business coaching program', '6-month consulting retainer', 'website design package']\"\n    }\n  ]\n}", "options": {}}}, {"id": "d4e5f6a7-0004-4d4e-bf4f-b4c5d6e7f8a9", "name": "Gmail - Welcome Email", "type": "n8n-nodes-base.gmail", "typeVersion": 2.1, "position": [650, 340], "credentials": {"gmailOAuth2": {"id": "YOUR_GMAIL_CREDENTIAL_ID", "name": "Gmail account"}}, "parameters": {"operation": "send", "sendTo": "={{ $('Stripe Trigger').item.json.data.object.customer_details.email }}", "subject": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Welcome Package').item.json.content[0].text).welcome_email_subject; } catch(e) { return 'Welcome! Your onboarding details inside'; } })() }}", "message": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Welcome Package').item.json.content[0].text).welcome_email_body; } catch(e) { return $('HTTP Request - Claude Welcome Package').item.json.content[0].text; } })() }}", "options": {"appendAttribution": false, "bodyContentType": "html"}}}, {"id": "d4e5f6a7-0005-4d4e-bf4f-b4c5d6e7f8a9", "name": "Google Docs - Create Onboarding Doc", "type": "n8n-nodes-base.googleDocs", "typeVersion": 2, "position": [850, 340], "credentials": {"googleDocsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Docs account"}}, "parameters": {"operation": "create", "title": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Welcome Package').item.json.content[0].text).onboarding_doc_title; } catch(e) { return 'Onboarding — ' + $('Stripe Trigger').item.json.data.object.customer_details.name; } })() }}", "content": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Welcome Package').item.json.content[0].text).onboarding_doc_body; } catch(e) { return ''; } })() }}"}}, {"id": "d4e5f6a7-0006-4d4e-bf4f-b4c5d6e7f8a9", "name": "HubSpot - Update Contact", "type": "n8n-nodes-base.hubspot", "typeVersion": 2, "position": [1050, 340], "credentials": {"hubspotAppToken": {"id": "YOUR_HUBSPOT_CREDENTIAL_ID", "name": "HubSpot account"}}, "parameters": {"resource": "contact", "operation": "upsert", "email": "={{ $('Stripe Trigger').item.json.data.object.customer_details.email }}", "additionalFields": {"firstName": "={{ $('Stripe Trigger').item.json.data.object.customer_details.name.split(' ')[0] }}", "lastName": "={{ $('Stripe Trigger').item.json.data.object.customer_details.name.split(' ').slice(1).join(' ') }}", "lifecycleStage": "customer"}}}, {"id": "d4e5f6a7-0007-4d4e-bf4f-b4c5d6e7f8a9", "name": "Slack - Notify Team", "type": "n8n-nodes-base.slack", "typeVersion": 2.1, "position": [1250, 340], "credentials": {"slackApi": {"id": "YOUR_SLACK_CREDENTIAL_ID", "name": "Slack account"}}, "parameters": {"resource": "message", "operation": "post", "channel": "#new-clients", "text": "={{ (() => { try { return JSON.parse($('HTTP Request - Claude Welcome Package').item.json.content[0].text).slack_notification; } catch(e) { return 'New client onboarded: ' + $('Stripe Trigger').item.json.data.object.customer_details.name + ' — welcome email sent and onboarding doc created.'; } })() }}", "otherOptions": {}}}], "connections": {"Stripe Trigger": {"main": [[{"node": "HTTP Request - Claude Welcome Package", "type": "main", "index": 0}]]}, "HTTP Request - Claude Welcome Package": {"main": [[{"node": "Gmail - Welcome Email", "type": "main", "index": 0}]]}, "Gmail - Welcome Email": {"main": [[{"node": "Google Docs - Create Onboarding Doc", "type": "main", "index": 0}]]}, "Google Docs - Create Onboarding Doc": {"main": [[{"node": "HubSpot - Update Contact", "type": "main", "index": 0}]]}, "HubSpot - Update Contact": {"main": [[{"node": "Slack - Notify Team", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-09-client-onboarding"}, "tags": []}, "diagram_image": "workflow-diagram-09.png"}, {"title": "Workflow 10: Review & Testimonial Collector", "type": "workflow", "tagline": "AUTOMATICALLY COLLECT AND SHOWCASE YOUR BEST CLIENT FEEDBACK", "metrics": {"time_saved": "2-3 hrs/week", "difficulty": "Beginner", "tools_needed": 3, "frequency": "Weekly + per response"}, "flow": [{"step": "C", "label": "COMPLETE", "description": "Project done"}, {"step": "R", "label": "REQUEST", "description": "AI-crafted review ask"}, {"step": "F", "label": "COLLECT", "description": "Response arrives"}, {"step": "AI", "label": "FORMAT", "description": "3 versions created"}, {"step": "S", "label": "STORE", "description": "Added to library"}], "request_email_prompt": {"platform": "Claude", "prompt": "SYSTEM: You write review request emails for [YOUR BUSINESS] that feel personal and genuine — never pushy. CLIENT: {{client_name}}. SERVICE: {{service_name}}. DURATION: {{duration}}. RESULTS: {{results_delivered}}. Write a short, warm email (under 100 words) asking for a review. Reference specific results you delivered. Make it easy — offer 3 questions: 1) What was your situation before working with us? 2) What specific results did you see? 3) Would you recommend us? Why?"}, "testimonial_formatter_prompt": {"platform": "Gemini", "prompt": "Take this raw customer feedback and create 3 versions: RAW: {{raw_feedback}}. VERSION 1 — WEBSITE (2-3 sentences, impactful, with attribution). VERSION 2 — SOCIAL MEDIA (1 sentence, punchy, shareable). VERSION 3 — CASE STUDY INTRO (3-4 sentences, story format: problem > solution > result)."}, "setup_steps": [{"step": 1, "action": "Trigger: CRM status change", "detail": "Project marked 'Complete' or X days after purchase"}, {"step": 2, "action": "Claude: Generate request email", "detail": "Personalized to their project and results"}, {"step": 3, "action": "Email: Send request", "detail": "Gmail or email tool sends the review request"}, {"step": 4, "action": "Trigger 2: Form response", "detail": "When they reply or submit the review form"}, {"step": 5, "action": "Gemini: Format testimonial", "detail": "Create 3 versions (website, social, case study)"}, {"step": 6, "action": "Google Sheets: Store", "detail": "Add to your Testimonial Library with all versions"}], "customization": {"review_form_tool": "[Google Forms / Typeform / Tally / JotForm — your choice]", "review_request_timing": "Weekly on Monday (adjust cron expression to change day/time)", "request_sender_name": "[Your name — update Gmail sender display name]", "follow_up_days": "[Optional: add a 7-day follow-up for non-responders]", "testimonial_storage": "Google Sheets — Testimonial Library tab", "required_sheet_columns_projects": "client_name, client_email, service_name, results_delivered, project_duration, review_requested, review_requested_date", "required_sheet_columns_library": "Date, Client_Name, Service, Raw_Response, Website_Version, Social_Version, Case_Study_Version"}, "content": "Social proof sells, but most businesses collect testimonials randomly and inconsistently. This workflow automates the entire cycle: requesting reviews at the perfect moment, collecting responses, and formatting them into ready-to-use marketing assets. When a project is marked complete in your CRM (or a set number of days after purchase), Claude generates a personalized review request email that references specific results you delivered for that client — making it feel genuine, not like a mass blast. When the client responds, Gemini takes their raw feedback and creates three formatted versions: a 2-3 sentence website testimonial with attribution, a punchy one-sentence social media quote, and a 3-4 sentence case study introduction in problem-solution-result format. All three versions land in your Testimonial Library spreadsheet, organized and ready to use. In Zapier or n8n: CRM status change trigger, Claude review request, email send, then a second trigger on form response, Gemini formatting, Sheets storage. You build a growing library of proof without ever manually asking for a review.", "cowork_alternative": {"description": "With Claude Cowork (included with Claude Pro at $20/month), you can run this review collection process manually from your desktop by pasting client details and letting Claude draft the outreach and format responses.", "steps": ["When a project completes, open Claude Desktop with Cowork enabled and type: 'Write a review request email for [client name] who completed [service] and achieved [results]. Send it to [email].'", "Claude will draft and send the email using your connected Gmail account", "When a review response arrives in your inbox, forward it to Claude and type: 'Format this into 3 testimonial versions: website (2-3 sentences), social (1 sentence), case study intro (3-4 sentences). Add to my Testimonial Library sheet.'", "Claude creates the formatted versions and appends them to your Google Sheet"]}, "setup_time": "30-45 minutes", "complexity": "Beginner-friendly once Google Sheets is properly structured", "maintenance": "Review the Testimonial Library monthly to identify the best testimonials for your website and social media", "expected_output": "Phase 1: Personalized review request emails sent to newly completed clients every Monday. Phase 2: Each review response automatically formatted into 3 ready-to-use testimonial versions stored in your Testimonial Library.", "workflow_id": "10", "workflow_phases": {"phase_1": "Weekly trigger → read completed projects → generate personalized review request → send email → mark as requested", "phase_2": "Webhook receives review → Claude formats into 3 testimonial versions → stored in Testimonial Library spreadsheet"}, "prerequisites": ["Google Sheets spreadsheet with a Projects tab (columns: client_name, client_email, service_name, results_delivered, project_duration, review_requested) and a Testimonial Library tab", "Anthropic account with API key — two Claude calls per review cycle, estimated cost under $0.10 total per client", "Gmail account connected via OAuth2 in n8n", "A review collection form (Google Forms, Typeform, or Tally) that can POST responses to a webhook URL", "The form must collect: client_name, service_name, and review_text fields with those exact field names (or adjust the webhook expressions to match your field names)"], "zapier_setup": [{"step": 1, "node": "Schedule by Zapier — Weekly Trigger", "detail": "Create a new Zap and choose 'Schedule by Zapier' as the trigger. Set it to run 'Every Week' on Monday at 9:00 AM. This gives you a fresh weekly cadence for requesting reviews from clients whose projects completed that week. Monday morning timing is intentional — clients are back in work mode and more likely to respond promptly than on a Friday afternoon. Save and test the trigger to generate a sample payload, which you'll use to build the downstream steps. The weekly cadence ensures you never fall months behind on review collection."}, {"step": 2, "node": "Google Sheets — Read Completed Projects", "detail": "Add a Google Sheets action set to 'Lookup Spreadsheet Row'. Filter the Projects sheet for rows where the review_requested column equals 'No' — these are the clients you haven't yet asked for a review. If multiple rows match, Zapier processes them one at a time using a Looping by Zapier step (add a Loop action between the trigger and Sheets step). Each iteration produces one client's data: name, email, service, results delivered, and project duration. You'll map these fields into the Claude step. This filter ensures you never accidentally send duplicate review requests to the same client."}, {"step": 3, "node": "Claude AI — Generate Review Request", "detail": "Add a Claude AI action set to 'Send Message'. Paste the review request generation prompt and map the client fields from the Sheets data: {{client_name}}, {{service_name}}, {{results_delivered}}, and {{project_duration}}. Claude will write a short, personal email (under 120 words) that references a specific result the client achieved — this specificity is what makes the request feel genuine rather than mass-generated. The email ends with your three guiding questions that make it easy for clients to know exactly what to write. Prohibit Claude from using common filler phrases by explicitly listing them in the prompt, which the sample prompt already does."}, {"step": 4, "node": "Gmail — Send Review Request", "detail": "Add a Gmail action set to 'Send Email'. Map the recipient to the client_email field, set the subject to a personalized line like 'Quick question about your experience, {{first_name}}' — using their first name in the subject line increases open rates by 20-30% compared to generic subject lines. Map the email body to the Claude output text. Avoid any Zapier branding or automation signatures that might make the email feel less personal. Send a test to your own email address and read it as if you were the client — it should feel like something you wrote manually, not an auto-generated template."}, {"step": 5, "node": "Google Sheets — Mark Review Requested", "detail": "Add a Google Sheets action set to 'Update Spreadsheet Row'. Find the matching row using the client_email as the lookup column and update the review_requested field to 'Yes' and add today's date to a review_requested_date column. This prevents the system from sending duplicate requests next week when the workflow runs again. If you want to add a follow-up system (send a reminder if no response after 7 days), you can add an additional check: filter for rows where review_requested = 'Yes', review_requested_date is 7+ days ago, and review_response is still empty — then generate and send a gentle follow-up."}, {"step": 6, "node": "Zapier Webhook (Catch Hook) + Claude AI — Format Testimonial + Google Sheets — Store", "detail": "Create a SECOND Zap for Phase 2 of this workflow. Use 'Webhooks by Zapier: Catch Hook' as the trigger and copy the webhook URL it generates. Paste this URL into your review collection form as the submission endpoint — most form tools (Typeform, Google Forms with a script, Tally) can POST to a custom webhook. When a client submits their review, the Zap fires with their raw feedback. Add a Claude AI step to format the feedback into three testimonial versions (website, social media, case study intro). Then add a Google Sheets step to append a new row to your Testimonial Library with all three versions plus the raw response. Your library grows automatically with every submission."}], "n8n_setup": [{"step": 1, "node": "Schedule Trigger", "detail": "Add a Schedule Trigger node and set the cron expression to '0 9 * * 1' — this fires at 9:00 AM every Monday. This timing gives you a consistent weekly rhythm for review collection and ensures you process newly completed projects at the start of each week. In n8n, select 'Cron Expression' as the rule type and enter the expression directly. If your timezone in n8n is set incorrectly, the trigger will fire at the wrong local time — check your n8n instance timezone in Settings → General before activating."}, {"step": 2, "node": "Google Sheets - Read Completed Projects", "detail": "Add a Google Sheets node set to 'Read Rows' operation. Connect your Google account via OAuth2. Set the filter to look for rows where review_requested = 'No'. Enable 'Return All Matches' in the options so if multiple projects completed this week, they are all processed. n8n will automatically loop through each matching row, running the downstream nodes once per row. This means if 3 clients had projects complete this week, 3 separate personalized review request emails will be sent — one for each client — in a single workflow execution."}, {"step": 3, "node": "HTTP Request - Generate Review Request", "detail": "Add an HTTP Request node set to POST to the Anthropic API endpoint. Configure the three required headers (x-api-key, anthropic-version, Content-Type). In the JSON body, inject the Google Sheets data using n8n expressions: {{ $json.client_name }}, {{ $json.service_name }}, {{ $json.results_delivered }}, and {{ $json.project_duration }}. Set max_tokens to 500 — the review request email should be short (under 120 words), so 500 tokens is more than enough. Test this node by clicking 'Execute Node' with a real row from your Projects sheet to verify the generated email reads naturally and references actual results."}, {"step": 4, "node": "Gmail - Send Review Request", "detail": "Add a Gmail node set to 'Send' operation. Map sendTo to {{ $('Google Sheets - Read Completed Projects').item.json.client_email }} to ensure you're always emailing the right person from the current loop iteration. Build the subject line dynamically using the client's first name. Map the message body to {{ $json.content[0].text }} from the Claude response. Leave bodyContentType as plain text for review request emails — plain text feels more personal and less like a marketing campaign, which improves response rates. Verify in your Gmail Sent folder after the first test run that the email looks exactly as intended."}, {"step": 5, "node": "Google Sheets - Mark Review Requested", "detail": "Add a Google Sheets node set to 'Update Row' operation. Use the client_email as the matching column to find the correct row. Update review_requested to 'Yes' and add the current timestamp to review_requested_date. This update must happen after the Gmail send — if it runs before and Gmail fails, you'd mark a review as requested when no email was sent. Place this node as the last step in Phase 1 to ensure the Sheets update only happens after successful email delivery. Check the Projects sheet after a test run to confirm the row updated correctly."}, {"step": 6, "node": "Webhook - Review Response", "detail": "Add a Webhook node (separate trigger, starts Phase 2 of this workflow). n8n will show you a unique webhook URL — copy this URL and paste it as the form submission endpoint in your review collection form tool. The webhook listens for POST requests from your form. The incoming data must include client_name, service_name, and review_text fields. If your form tool uses different field names (e.g. 'name' instead of 'client_name'), adjust the expressions in the downstream nodes accordingly. Activate this webhook node independently from the Schedule Trigger — both can be active in the same workflow simultaneously."}, {"step": 7, "node": "HTTP Request - Format Testimonial", "detail": "Add a second HTTP Request node (also calling Anthropic) connected to the Webhook trigger. This node receives the raw review response and sends it to Claude with a testimonial formatting prompt. The prompt requests three specific formats: a 2-3 sentence website testimonial with attribution, a punchy one-sentence social media quote, and a 3-4 sentence case study introduction in problem-solution-result narrative. Request JSON output with named fields (website_version, social_version, case_study_intro) so the downstream Sheets node can reliably extract each version."}, {"step": 8, "node": "Google Sheets - Store Testimonial", "detail": "Add a Google Sheets node set to 'Append Row' operation targeting the Testimonial Library tab. Map all seven columns: Date, Client_Name, Service, Raw_Response, Website_Version, Social_Version, and Case_Study_Version. Use try/catch expressions to parse the Claude JSON safely. After each real review submission, open the Testimonial Library sheet and verify all three versions populated correctly. Over time, this becomes your go-to source for website copy, social proof posts, and case study material — all organized and searchable in one place."}], "ai_prompts": {"review_request": {"platform": "Claude", "model": "claude-sonnet-4-20250514", "system_prompt": "You write review request emails for [YOUR BUSINESS NAME — replace this] that feel personal and genuine — never pushy or transactional. Your tone is warm, conversational, and direct. You reference specific results the client achieved, making the request feel like a natural continuation of the working relationship rather than a mass marketing email. Keep emails short — clients are busy.", "user_message": "Write a personalized review request email for this client.\n\nCLIENT: {{ $json.client_name }}  ← Replaced automatically by n8n\nSERVICE: {{ $json.service_name }}  ← Replaced automatically by n8n\nRESULTS DELIVERED: {{ $json.results_delivered }}  ← Replaced automatically by n8n\nPROJECT DURATION: {{ $json.project_duration }}  ← Replaced automatically by n8n\n\nRequirements:\n- Under 120 words total\n- Reference a SPECIFIC result from the RESULTS DELIVERED field (this makes it feel genuine, not generic)\n- Ask them to share their experience by answering 3 simple questions: 1) What was your situation before working with us? 2) What specific results did you see? 3) Would you recommend us, and why?\n- DO NOT use: 'I hope this email finds you well', 'just checking in', 'touching base', 'I was wondering if', 'quick question', or any filler opener\n- Start with something that references your shared work together\n- End with a clear, low-friction call to action\n- Sign off naturally\n\nOutput ONLY the email body. No subject line. No explanation.", "notes": "The prohibition list in the prompt actively prevents the most common generic phrases that kill response rates. The specificity requirement (referencing actual results) is the single biggest driver of review conversion rate."}, "testimonial_formatter": {"platform": "Claude", "model": "claude-sonnet-4-20250514", "system_prompt": "You are a marketing copywriter who specializes in turning raw customer feedback into polished, impactful testimonials. You preserve the authentic voice of the customer while making the testimonial compelling and specific. You never add claims, numbers, or results that weren't present in the original feedback — you only refine what is already there.", "user_message": "Take this raw customer review and create 3 formatted testimonial versions. Return a JSON object only — no markdown, no explanation, no code blocks.\n\nCLIENT NAME: {{ $json.body.client_name }}  ← Replaced by webhook data\nSERVICE: {{ $json.body.service_name }}  ← Replaced by webhook data\nRAW FEEDBACK: {{ $json.body.review_text }}  ← Replaced by webhook data\n\nReturn this exact JSON structure:\n{\n  \"website_version\": \"2-3 sentences. Impactful, includes the most specific result mentioned. Formatted as a direct quote with attribution. Example format: '[Quote here]' — [First Name], [Role at Company if mentioned]\",\n  \"social_version\": \"1 punchy sentence, under 100 characters if possible. The single most shareable moment from the raw feedback. Formatted as a quote.\",\n  \"case_study_intro\": \"3-4 sentences in problem > solution > result format. Third-person narrative style (e.g. 'When [First Name] came to [Business], they were struggling with...'). Specific and concrete — uses actual details from the raw feedback.\"\n}", "notes": "This prompt explicitly prohibits fabricating results, which is critical for maintaining authenticity and legal compliance in testimonial marketing."}}, "testing_checklist": ["Add a test row to your Projects sheet with review_requested = 'No' and realistic sample data", "Execute the Schedule Trigger manually and confirm it passes to the Sheets read node", "Verify the Sheets node finds your test row and passes the data downstream", "Execute the Claude Review Request node and read the generated email — does it reference the specific results? Does it feel personal?", "Send the test email to yourself and read it as if you were the client — would you respond?", "Verify the Projects sheet updates to review_requested = 'Yes' after the email send", "Activate the Webhook node and copy its URL — paste it into your review form's submission endpoint", "Submit a test review through your form and confirm the webhook fires in n8n", "Execute the Testimonial Formatter node with the test review and verify all 3 versions are present and well-written in the JSON response", "Confirm the Testimonial Library sheet gets a new row with all 7 columns populated", "Activate both workflow triggers and monitor the first real Monday morning run via the Executions log"], "n8n_workflow_json": {"name": "KH Academy — Review & Testimonial Collector", "nodes": [{"id": "e5f6a7b8-0001-4e5f-cf5a-c5d6e7f8a9b0", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS\n\nThis workflow has TWO phases:\n**Phase 1:** Weekly trigger → reads completed projects → sends personalized review request email\n**Phase 2:** Webhook → receives review response → formats into testimonial → stores in Sheets\n\n---\n\n**1. Google Sheets — Completed Projects**\nConnect your Google account in the Sheets node.\nReplace YOUR_SPREADSHEET_ID with your CRM/project sheet ID.\nRequired columns: client_name, client_email, service_name, results_delivered, project_end_date, review_requested (Yes/No), review_response\n\n**2. Anthropic API Key (both Claude nodes)**\nReplace YOUR_ANTHROPIC_API_KEY in BOTH HTTP Request nodes.\nGet your key from https://console.anthropic.com\n\n**3. Update AI Prompts**\nIn \"HTTP Request - Generate Review Request\":\n- Replace [YOUR BUSINESS NAME] with your business name\n\nIn \"HTTP Request - Format Testimonial\":\n- No changes needed — it's generic\n\n**4. Gmail Credentials**\nConnect Gmail via OAuth2 in the Gmail node.\nThe node sends the review request to the client's email.\n\n**5. Testimonial Webhook**\nOpen \"Webhook - Review Response\" — copy the webhook URL.\nUse this URL as the form submission endpoint for your review collection form (Google Forms, Typeform, etc.).\nSet your form to POST responses to this webhook URL.\n\n**6. Google Sheets — Testimonial Library**\nSet up a second sheet tab called 'Testimonial Library' with columns:\nDate, Client_Name, Service, Raw_Response, Website_Version, Social_Version, Case_Study_Version\n\n**SCHEDULE:** Runs weekly on Monday at 9:00 AM to find newly completed projects.", "height": 720, "width": 600, "color": 6}}, {"id": "e5f6a7b8-0002-4e5f-cf5a-c5d6e7f8a9b0", "name": "Schedule Trigger", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.1, "position": [250, 360], "parameters": {"rule": {"interval": [{"field": "cronExpression", "expression": "0 9 * * 1"}]}}}, {"id": "e5f6a7b8-0003-4e5f-cf5a-c5d6e7f8a9b0", "name": "Google Sheets - Read Completed Projects", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [450, 360], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "read", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Projects", "mode": "name"}, "filtersUI": {"values": [{"lookupColumn": "review_requested", "lookupValue": "No"}]}, "options": {"returnAllMatches": true}}}, {"id": "e5f6a7b8-0004-4e5f-cf5a-c5d6e7f8a9b0", "name": "HTTP Request - Generate Review Request", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [650, 360], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 500,\n  \"system\": \"You write review request emails for [YOUR BUSINESS NAME — replace this] that feel personal and genuine — never pushy or transactional. Your tone is warm and conversational. You reference specific results the client achieved, making the request feel like a natural continuation of the working relationship rather than a mass marketing email.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Write a personalized review request email for this client.\\n\\nCLIENT: {{ $json.client_name }}\\nSERVICE: {{ $json.service_name }}\\nRESULTS DELIVERED: {{ $json.results_delivered }}\\nPROJECT DURATION: {{ $json.project_duration }}\\n\\nRequirements:\\n- Under 120 words total\\n- Reference a specific result from RESULTS DELIVERED (makes it feel genuine)\\n- Ask for a review by answering 3 simple questions: 1) What was your situation before working with us? 2) What specific results did you see? 3) Would you recommend us and why?\\n- Do NOT use: 'I hope this email finds you well', 'just checking in', 'I was wondering', or any filler phrase\\n- End with a simple, low-friction CTA\\n- Sign off naturally without being overly formal\\n\\nOutput only the email body — no subject line, no extra explanation.\"\n    }\n  ]\n}", "options": {}}}, {"id": "e5f6a7b8-0005-4e5f-cf5a-c5d6e7f8a9b0", "name": "Gmail - Send Review Request", "type": "n8n-nodes-base.gmail", "typeVersion": 2.1, "position": [850, 360], "credentials": {"gmailOAuth2": {"id": "YOUR_GMAIL_CREDENTIAL_ID", "name": "Gmail account"}}, "parameters": {"operation": "send", "sendTo": "={{ $('Google Sheets - Read Completed Projects').item.json.client_email }}", "subject": "={{ 'Quick question about your experience, ' + $('Google Sheets - Read Completed Projects').item.json.client_name.split(' ')[0] }}", "message": "={{ $json.content[0].text }}", "options": {"appendAttribution": false}}}, {"id": "e5f6a7b8-0006-4e5f-cf5a-c5d6e7f8a9b0", "name": "Google Sheets - Mark Review Requested", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [1050, 360], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "update", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Projects", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"review_requested": "Yes", "review_requested_date": "={{ $now.toISO() }}"}, "matchingColumns": ["client_email"]}, "options": {}}}, {"id": "e5f6a7b8-0007-4e5f-cf5a-c5d6e7f8a9b0", "name": "Webhook - Review Response", "type": "n8n-nodes-base.webhook", "typeVersion": 2, "position": [250, 600], "parameters": {"httpMethod": "POST", "path": "review-response", "responseMode": "lastNode", "options": {}}}, {"id": "e5f6a7b8-0008-4e5f-cf5a-c5d6e7f8a9b0", "name": "HTTP Request - Format Testimonial", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [450, 600], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 600,\n  \"system\": \"You are a marketing copywriter who specializes in turning raw customer feedback into polished, impactful testimonials. You preserve the authentic voice of the customer while making the testimonial compelling and specific. You never add claims or results that weren't in the original feedback.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Take this raw customer review and create 3 formatted testimonial versions. Return a JSON object only — no explanation.\\n\\nCLIENT NAME: {{ $json.body.client_name }}\\nSERVICE: {{ $json.body.service_name }}\\nRAW FEEDBACK: {{ $json.body.review_text }}\\n\\nReturn:\\n{\\n  \\\"website_version\\\": \\\"2-3 sentences, impactful, includes specific result, formatted as a direct quote, ends with attribution: — [First Name], [Role/Company if provided]\\\",\\n  \\\"social_version\\\": \\\"1 punchy sentence under 100 characters, most shareable moment from the feedback, formatted as a quote\\\",\\n  \\\"case_study_intro\\\": \\\"3-4 sentences in problem > solution > result format, third person narrative style, specific and concrete\\\"\\n}\"\n    }\n  ]\n}", "options": {}}}, {"id": "e5f6a7b8-0009-4e5f-cf5a-c5d6e7f8a9b0", "name": "Google Sheets - Store Testimonial", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [650, 600], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "append", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Testimonial Library", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"Date": "={{ $now.toISO() }}", "Client_Name": "={{ $('Webhook - Review Response').item.json.body.client_name }}", "Service": "={{ $('Webhook - Review Response').item.json.body.service_name }}", "Raw_Response": "={{ $('Webhook - Review Response').item.json.body.review_text }}", "Website_Version": "={{ (() => { try { return JSON.parse($('HTTP Request - Format Testimonial').item.json.content[0].text).website_version; } catch(e) { return ''; } })() }}", "Social_Version": "={{ (() => { try { return JSON.parse($('HTTP Request - Format Testimonial').item.json.content[0].text).social_version; } catch(e) { return ''; } })() }}", "Case_Study_Version": "={{ (() => { try { return JSON.parse($('HTTP Request - Format Testimonial').item.json.content[0].text).case_study_intro; } catch(e) { return ''; } })() }}"}}, "options": {}}}], "connections": {"Schedule Trigger": {"main": [[{"node": "Google Sheets - Read Completed Projects", "type": "main", "index": 0}]]}, "Google Sheets - Read Completed Projects": {"main": [[{"node": "HTTP Request - Generate Review Request", "type": "main", "index": 0}]]}, "HTTP Request - Generate Review Request": {"main": [[{"node": "Gmail - Send Review Request", "type": "main", "index": 0}]]}, "Gmail - Send Review Request": {"main": [[{"node": "Google Sheets - Mark Review Requested", "type": "main", "index": 0}]]}, "Webhook - Review Response": {"main": [[{"node": "HTTP Request - Format Testimonial", "type": "main", "index": 0}]]}, "HTTP Request - Format Testimonial": {"main": [[{"node": "Google Sheets - Store Testimonial", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-10-review-collector"}, "tags": []}, "diagram_image": "workflow-diagram-10.png"}, {"title": "Workflow 11: Follow-Up & Re-Engagement", "type": "workflow", "tagline": "NEVER LOSE A CUSTOMER TO SILENCE AGAIN", "metrics": {"time_saved": "3-5 hrs/week", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Weekly"}, "stats": {"follow_ups_needed_for_sale": "5+ touches on average", "salespeople_who_give_up_after_1": "44%", "sales_closed_after_5th_follow_up": "80%"}, "three_workflows": [{"label": "A: LEAD FOLLOW-UP", "description": "Scan CRM weekly > Find leads inactive 7+ days > AI check-in > Send"}, {"label": "B: POST-PURCHASE", "description": "30/60/90 days after purchase > AI value-check email > Send"}, {"label": "C: WIN-BACK", "description": "Customers inactive 90+ days > AI re-engagement offer > Send"}], "lead_follow_up_prompt": {"platform": "Claude", "prompt": "SYSTEM: You write follow-up emails for [YOUR BUSINESS]. LEAD: {{lead_name}} at {{company}}. LAST CONTACT: {{last_date}} — {{last_type}}. DAYS INACTIVE: {{days}}. Write a brief follow-up (under 100 words): 1) Reference last interaction. 2) Offer something valuable. 3) Ask one simple question. 4) Soft CTA. DO NOT use 'just checking in' or 'touching base'."}, "win_back_prompt": {"platform": "Gemini", "prompt": "SYSTEM: You write win-back emails for [YOUR BUSINESS]. CUSTOMER: {{name}}. LAST PURCHASE: {{date}} — {{product}}. DAYS SINCE: {{days}}. Write a re-engagement email (under 120 words): 1) Acknowledge the gap without guilt. 2) Share something new. 3) Offer exclusive 'welcome back' incentive. 4) Gentle urgency. Tone: Warm, not desperate."}, "zapier_setup": [{"step": 1, "node": "Schedule by Zapier — Weekly", "detail": "Create a new Zap and select 'Schedule by Zapier' as the trigger. Set it to run every Monday at 8:00 AM. Monday morning is the optimal timing for B2B follow-ups — decision-makers are back at their desks, starting their week with fresh attention, and more receptive to emails than they'd be on a Thursday afternoon. Save the trigger and test it to generate a sample payload. This single Zap handles Engine A (lead follow-up). You'll create two more identical Zaps for Engines B (post-purchase) and C (win-back) with different Sheets filters and AI prompts."}, {"step": 2, "node": "Google Sheets — Read Inactive Leads", "detail": "Add a Google Sheets action set to 'Lookup Spreadsheet Row'. Filter your Leads sheet for rows where days_inactive is greater than 7 AND follow_up_sent equals 'No'. The two-part filter is critical — without the follow_up_sent check, the same lead would receive a new follow-up email every single Monday, which would be disastrous. If your Sheets CRM doesn't have a days_inactive column, add one using the Google Sheets formula =IF(D2<>\"\",TODAY()-D2,\"\") and it will automatically calculate the number of days since last contact for each row. Add a Looping by Zapier step to process multiple matching leads sequentially in a single Zap run."}, {"step": 3, "node": "Claude AI — Generate Personalized Follow-Up", "detail": "Add a Claude AI action set to 'Send Message'. Paste the lead follow-up prompt and map the Sheets fields: {{lead_name}}, {{company}}, {{last_contact_date}}, {{last_interaction_type}}, and {{days_inactive}}. The last_interaction_type field is the most important — this is what Claude uses to write the opening line that references your previous conversation, making the email feel like a genuine personal follow-up rather than an automated sequence. Claude generates the subject line on line 1, then the email body below. The explicit prohibition list in the prompt (no 'just checking in', no 'touching base') forces Claude to write something genuinely valuable rather than defaulting to cliché opener phrases."}, {"step": 4, "node": "Gmail — Send Follow-Up", "detail": "Add a Gmail action set to 'Send Email'. Map the recipient to the lead's email from the Sheets data. Parse the Claude output to extract the subject line (first line) and body (everything after the blank second line) using Zapier's text formatter. Use plain text format, not HTML — plain text emails have significantly higher open and reply rates for sales and follow-up sequences compared to formatted HTML emails with logos and footers, which look automated. Send a test to yourself before activating, reading it as the lead would: does it sound like something a real person wrote? Does it reference something specific from your history together?"}, {"step": 5, "node": "Google Sheets — Update Last Contacted", "detail": "Add a Google Sheets action set to 'Update Spreadsheet Row'. Find the row using the email address as the lookup column. Update four fields: last_contact_date (today's date), last_interaction_type ('Email follow-up — automated'), follow_up_sent ('Yes'), and follow_up_date (today's date with timestamp). The follow_up_sent update is the safety net that prevents duplicate emails. After updating, the days_inactive formula will reset automatically since it recalculates from last_contact_date. If the lead responds to the email and becomes active again, manually update their status in Sheets to reflect the new interaction and reset the follow_up_sent to 'No' so the cycle can begin again after they go quiet."}], "customization": {"engine_a_day_threshold": "7 days inactive (adjust Sheets filter or add IF node for different threshold)", "engine_b_day_thresholds": "30, 60, 90 days post-purchase (duplicate workflow, filter on purchase_date)", "engine_c_day_threshold": "120 days inactive customer (duplicate workflow, use win-back prompt)", "crm_source": "Google Sheets (can replace with HubSpot, Salesforce, or Airtable node)", "email_tool": "Gmail (can replace with Mailchimp or SMTP node for bulk sending)", "incentive_for_winback": "[Discount % / Free resource / Free consultation — replace in Engine C prompt]", "required_sheet_columns": "lead_name, company, email, last_contact_date, last_interaction_type, days_inactive, follow_up_sent, follow_up_date"}, "content": "44% of salespeople give up after one follow-up, yet 80% of sales close after the 5th touch. This workflow runs three parallel re-engagement engines that ensure no lead or customer falls through the cracks. Engine A (Lead Follow-Up) scans your CRM weekly for leads inactive 7+ days and has Claude write a personalized check-in that references their last interaction and offers something valuable — never a generic just checking in. Engine B (Post-Purchase) sends value-check emails at 30, 60, and 90 days after purchase to keep customers engaged and reduce churn. Engine C (Win-Back) targets customers inactive 90+ days with a Gemini-crafted re-engagement email that acknowledges the gap without guilt, shares something new, and offers a welcome-back incentive with gentle urgency. In Zapier: Weekly schedule trigger, CRM search for inactive contacts filtered by threshold, Claude or Gemini generation based on segment, Gmail or Mailchimp auto-send, CRM activity log. In n8n: the same flow with Cron trigger and native CRM, AI, and email nodes. Your pipeline stays warm automatically while you focus on delivering great work.", "cowork_alternative": {"description": "With Claude Cowork (included with Claude Pro at $20/month), you can run this follow-up system as a weekly manual task in under 10 minutes by letting Claude read your CRM sheet and draft all follow-ups at once.", "steps": ["Every Monday morning, open Claude Desktop with Cowork enabled", "Type: 'Open my Leads Google Sheet [sheet URL]. Find all rows where days_inactive > 7 and follow_up_sent = No. For each one, write a personalized follow-up email referencing their last interaction. Show me all the drafts before sending.'", "Review Claude's drafted emails — approve, edit, or skip individual ones", "Type: 'Send the approved follow-ups via Gmail and update each lead's last_contact_date and follow_up_sent columns in the sheet'", "Claude executes the sends and sheet updates — entire process takes under 10 minutes weekly"]}, "setup_time": "20-30 minutes for Engine A; add 10-15 minutes per additional engine", "complexity": "Intermediate — requires a structured CRM sheet with proper column names", "maintenance": "Review follow-up email quality monthly by spot-checking sent emails in Gmail; update the AI prompt if the tone or offer needs refreshing", "expected_output": "Every Monday: personalized follow-up emails sent to all leads inactive 7+ days, with CRM automatically updated so no lead is emailed twice until they re-engage", "workflow_id": "11", "three_engines": {"engine_a": {"label": "Lead Follow-Up (PRIMARY — built in this workflow)", "trigger": "Weekly schedule", "filter": "Leads inactive 7+ days (follow_up_sent = No)", "action": "Claude writes personalized check-in referencing last interaction", "day_threshold": 7}, "engine_b": {"label": "Post-Purchase Check-In (duplicate and adapt this workflow)", "trigger": "Weekly schedule", "filter": "Customers with purchase_date 30, 60, or 90 days ago", "action": "Claude writes value-check email to reduce churn and increase LTV", "day_thresholds": [30, 60, 90], "notes": "Duplicate this workflow, change the Sheets filter to use purchase_date column, and adjust the prompt to reference their purchase and check on their progress/satisfaction"}, "engine_c": {"label": "Win-Back Campaign (duplicate and adapt this workflow)", "trigger": "Weekly schedule", "filter": "Customers with last_purchase_date 120+ days ago", "action": "Claude writes warm re-engagement email with welcome-back incentive", "day_threshold": 120, "notes": "Duplicate this workflow, change the Sheets filter to 120+ days, and use the win-back prompt from the sticky note instead of the lead follow-up prompt"}}, "prerequisites": ["Google Sheets CRM with a Leads tab — required columns: lead_name, company, email, last_contact_date, last_interaction_type, days_inactive, follow_up_sent", "The days_inactive column should be calculated automatically using a formula: =IF(D2<>\"\",TODAY()-D2,\"\") where D is your last_contact_date column", "Anthropic account with API key (https://console.anthropic.com) — estimated cost: $0.02–$0.05 per follow-up email generated", "Gmail account connected via OAuth2 in n8n", "At least 5-10 leads already in your Sheets CRM with realistic last_contact_date values for testing"], "n8n_setup": [{"step": 1, "node": "Schedule Trigger", "detail": "Add a Schedule Trigger node and set the cron expression to '0 8 * * 1' — every Monday at 8:00 AM. Confirm your n8n instance timezone is set correctly in Settings so the Monday 8 AM trigger fires at the right local time for your business. If you have leads in multiple timezones, consider running at a time that works across your most common lead locations. Click 'Execute Node' to test the trigger generates an execution before connecting it to the rest of the workflow."}, {"step": 2, "node": "Google Sheets - Read Inactive Leads", "detail": "Add a Google Sheets node set to 'Read Rows' operation. Connect your Google account via OAuth2. Set the filter to follow_up_sent = 'No' — this is your primary safety filter against duplicate sends. For the days_inactive threshold, if your sheet has a formula-calculated days_inactive column, n8n will return the calculated number and you can add a second filter node (or use an IF node) downstream to only continue for rows where days_inactive >= 7. Enable 'Return All Matches' so all qualifying leads are processed in a single run. n8n automatically iterates through each row."}, {"step": 3, "node": "HTTP Request - Claude Follow-Up", "detail": "Add an HTTP Request node configured as POST to the Anthropic API endpoint. Add the required headers. In the JSON body, inject the lead data from the Google Sheets node using n8n expressions: {{ $json.lead_name }}, {{ $json.company }}, {{ $json.last_contact_date }}, {{ $json.last_interaction_type }}, and {{ $json.days_inactive }}. Set max_tokens to 400 — follow-up emails must be short (under 100 words) so 400 tokens is sufficient. The prompt asks Claude to output the subject line on line 1 and the body starting on line 3, which makes parsing straightforward in the Gmail node without needing a JSON parse step."}, {"step": 4, "node": "Gmail - Send Follow-Up", "detail": "Add a Gmail node set to 'Send' operation. Connect your Gmail account. Map sendTo to {{ $('Google Sheets - Read Inactive Leads').item.json.email }}. For the subject, parse the first line of the Claude response: {{ $json.content[0].text.split('\\n')[0] }}. For the body, take everything from line 3 onwards: {{ $json.content[0].text.split('\\n').slice(2).join('\\n') }}. Keep bodyContentType as plain text — plain text follow-ups feel significantly more human and personal than HTML formatted emails. Before activating, test the parsing expressions by executing the Claude node with sample data and checking the text format matches what the Gmail node expects."}, {"step": 5, "node": "Google Sheets - Update Last Contacted", "detail": "Add a Google Sheets node set to 'Update Row' operation. Use the email column as the matching identifier. Update last_contact_date to {{ $now.format('yyyy-MM-dd') }}, last_interaction_type to 'Email follow-up (automated)', follow_up_sent to 'Yes', and follow_up_date to {{ $now.toISO() }}. This update is the final step in each lead's cycle — it locks in the follow-up as sent and resets the days_inactive timer (since it's calculated from last_contact_date). After the first live run, open your Leads sheet and verify the updates are correct before confirming the workflow is functioning as intended."}], "ai_prompts": {"engine_a_lead_follow_up": {"platform": "Claude", "model": "claude-sonnet-4-20250514", "system_prompt": "You write follow-up emails for [YOUR BUSINESS — replace this]. Your follow-ups are brief, valuable, and specific — they never feel like automated check-ins. You always reference the last interaction to show you remember the person. You write like a real human who genuinely wants to help, not like a sales robot running a cadence sequence. Every email offers something worth reading.", "user_message": "Write a follow-up email for this inactive lead.\n\nLEAD: {{ $json.lead_name }} at {{ $json.company }}  ← Replaced automatically\nLAST CONTACT: {{ $json.last_contact_date }} — {{ $json.last_interaction_type }}  ← Replaced automatically\nDAYS INACTIVE: {{ $json.days_inactive }}  ← Replaced automatically\n\nRequirements (follow exactly — these rules make or break the email):\n- Under 100 words total\n- First line MUST reference the last interaction specifically (e.g. 'After our call last month about [topic]...' or 'Since we discussed [topic]...' — use what's in last_interaction_type)\n- Offer something genuinely useful: a resource, insight, case study, or relevant idea for their situation\n- Ask ONE simple, easy-to-answer question that invites a response without pressure\n- Soft CTA only — no hard sell, no deadline pressure\n- NEVER USE: 'just checking in', 'touching base', 'following up on my last email', 'I wanted to reach out', 'hope you're doing well', 'circle back', or any variation\n- Do NOT mention how many days since last contact\n- Do NOT apologize for not reaching out sooner\n\nOutput format:\nLine 1: Subject line (compelling, specific, under 8 words)\nLine 2: (blank line)\nLine 3+: Email body only", "notes": "The prohibition list is the most important part of this prompt. Without it, most AI models default to exactly the phrases that get follow-up emails deleted. The specificity requirement (referencing the actual last interaction type) is what makes each email feel personal."}, "engine_c_win_back": {"platform": "Claude", "model": "claude-sonnet-4-20250514", "system_prompt": "You write win-back emails for [YOUR BUSINESS — replace this]. Your tone is warm, genuine, and never desperate. You make the customer feel valued, not guilt-tripped. You focus on what's new and exciting, not on how long it's been.", "user_message": "Write a win-back email for this inactive customer.\n\nCUSTOMER: {{ $json.lead_name }} at {{ $json.company }}\nLAST PURCHASE: {{ $json.last_interaction_type }}\nDAYS SINCE LAST ACTIVITY: {{ $json.days_inactive }}\n\nRequirements:\n- Under 120 words total\n- Acknowledge the time gap lightly and without guilt (e.g. 'It's been a while since...' — one casual mention only)\n- Share one genuinely interesting thing that's new or improved since they were last active\n- Offer a specific welcome-back incentive (use: '[YOUR INCENTIVE — e.g. 20% off, free consult, exclusive resource]')\n- Add gentle urgency without being pushy (e.g. 'Good through end of month')\n- Tone: Warm and excited to reconnect, not desperate or apologetic\n- Sign off like a real person\n\nOutput format:\nLine 1: Subject line\nLine 2: (blank)\nLine 3+: Email body", "notes": "For Engine C (win-back), update [YOUR INCENTIVE] with your actual welcome-back offer before using. This prompt is stored here as reference — use it in a duplicated version of this workflow with the Sheets filter adjusted to days_inactive >= 120."}}, "testing_checklist": ["Add 2-3 test rows to your Leads sheet with follow_up_sent = 'No' and different last_contact_date values (make at least one 10+ days ago)", "Verify your days_inactive formula is calculating correctly in the sheet", "Execute the Schedule Trigger manually and confirm it passes to the Sheets node", "Run the Sheets read node and verify it returns only the qualifying rows (follow_up_sent = No)", "Execute the Claude node with a real test row and read the generated email — does line 1 reference the last_interaction_type? Is it under 100 words? Does it avoid all prohibited phrases?", "Parse the Claude output manually to confirm: subject line is on line 1, blank on line 2, body from line 3", "Send the test email to yourself and read it as the lead — does it feel human? Would you respond?", "Verify the Sheets update node correctly sets follow_up_sent = 'Yes' and updates last_contact_date", "Run the full workflow a second time and confirm no duplicate emails are sent (follow_up_sent = 'Yes' rows are skipped)", "Activate the workflow and monitor the first live Monday 8 AM execution via the n8n Executions log"], "n8n_workflow_json": {"name": "KH Academy — Follow-Up & Re-Engagement (Engine A: Lead Follow-Up)", "nodes": [{"id": "f6a7b8c9-0001-4f6a-df6b-d6e7f8a9b0c1", "name": "Sticky Note", "type": "n8n-nodes-base.stickyNote", "typeVersion": 1, "position": [250, 50], "parameters": {"content": "## SETUP INSTRUCTIONS — ENGINE A: LEAD FOLLOW-UP\n\nThis workflow is Engine A of 3 parallel re-engagement systems:\n**Engine A (this workflow):** Leads inactive 7+ days → personalized follow-up\n**Engine B (duplicate this workflow):** Post-purchase check-ins at 30/60/90 days after purchase\n**Engine C (duplicate this workflow):** Win-back for customers inactive 120+ days\n\nTo build Engines B and C: duplicate this workflow in n8n and adjust:\n- The Sheets filter column (use purchase_date or last_purchase_date instead of last_contact_date)\n- The day threshold in the Code node (30, 60, 90 for Engine B; 120 for Engine C)\n- The AI prompt (use the win-back prompt for Engine C — see notes below)\n\n---\n\n**1. Google Sheets — Lead CRM**\nConnect your Google account in both Sheets nodes.\nReplace YOUR_SPREADSHEET_ID in both nodes.\nRequired columns: lead_name, company, email, last_contact_date, last_interaction_type, days_inactive, follow_up_sent\n\nTo calculate days_inactive automatically: use a Google Sheets formula in that column:\n=IF(D2<>\"\", TODAY()-D2, \"\")\nwhere D2 is the last_contact_date column.\n\n**2. Anthropic API Key**\nOpen \"HTTP Request - Claude Follow-Up\" → Headers → replace YOUR_ANTHROPIC_API_KEY.\nGet your key from https://console.anthropic.com\n\n**3. Update the AI Prompt**\nReplace [YOUR BUSINESS] in the system prompt with your business name.\n\n**4. Gmail Credentials**\nConnect Gmail via OAuth2 in the Gmail node.\n\n**ENGINE C WIN-BACK PROMPT (use in a duplicated workflow):**\nSystem: You write win-back emails for [YOUR BUSINESS]. Tone: Warm, not desperate.\nUser: CUSTOMER: {{lead_name}} at {{company}}. LAST PURCHASE: {{last_interaction_type}}. DAYS SINCE: {{days_inactive}}. Write re-engagement email (under 120 words): 1) Acknowledge the gap without guilt. 2) Share something new since they were last active. 3) Offer exclusive welcome-back incentive. 4) Gentle urgency. Sign off warmly.\n\n**SCHEDULE:** Runs every Monday at 8:00 AM.", "height": 760, "width": 600, "color": 5}}, {"id": "f6a7b8c9-0002-4f6a-df6b-d6e7f8a9b0c1", "name": "Schedule Trigger", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.1, "position": [250, 380], "parameters": {"rule": {"interval": [{"field": "cronExpression", "expression": "0 8 * * 1"}]}}}, {"id": "f6a7b8c9-0003-4f6a-df6b-d6e7f8a9b0c1", "name": "Google Sheets - Read Inactive Leads", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [450, 380], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "read", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Leads", "mode": "name"}, "filtersUI": {"values": [{"lookupColumn": "follow_up_sent", "lookupValue": "No"}]}, "options": {"returnAllMatches": true}}}, {"id": "f6a7b8c9-0004-4f6a-df6b-d6e7f8a9b0c1", "name": "HTTP Request - Claude Follow-Up", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [650, 380], "parameters": {"method": "POST", "url": "https://api.anthropic.com/v1/messages", "sendHeaders": true, "headerParameters": {"parameters": [{"name": "x-api-key", "value": "YOUR_ANTHROPIC_API_KEY"}, {"name": "anthropic-version", "value": "2023-06-01"}, {"name": "Content-Type", "value": "application/json"}]}, "sendBody": true, "bodyContentType": "json", "specifyBody": "json", "jsonBody": "={\n  \"model\": \"claude-sonnet-4-20250514\",\n  \"max_tokens\": 400,\n  \"system\": \"You write follow-up emails for [YOUR BUSINESS — replace this]. Your follow-ups are brief, valuable, and specific — they never feel like automated check-ins. You always reference the last interaction to show you remember the person. You write like a real human who genuinely wants to help, not like a sales robot running a sequence.\",\n  \"messages\": [\n    {\n      \"role\": \"user\",\n      \"content\": \"Write a follow-up email for this inactive lead.\\n\\nLEAD: {{ $json.lead_name }} at {{ $json.company }}\\nLAST CONTACT: {{ $json.last_contact_date }} — {{ $json.last_interaction_type }}\\nDAYS INACTIVE: {{ $json.days_inactive }}\\n\\nRequirements (this is critical — follow exactly):\\n- Under 100 words total\\n- First line MUST reference the last interaction (e.g. 'After our call last month about X...' or 'Since we last spoke about Y...')\\n- Offer something genuinely useful: a resource, insight, case study, or idea relevant to their situation\\n- Ask ONE simple question that invites a response without pressure\\n- End with a soft CTA — no hard sell\\n- DO NOT use: 'just checking in', 'touching base', 'following up', 'I wanted to reach out', 'hope you're doing well', or any variation of these phrases\\n- DO NOT mention days since last contact or that you've been waiting\\n\\nOutput: subject line on line 1, blank line, then email body only.\"\n    }\n  ]\n}", "options": {}}}, {"id": "f6a7b8c9-0005-4f6a-df6b-d6e7f8a9b0c1", "name": "Gmail - Send Follow-Up", "type": "n8n-nodes-base.gmail", "typeVersion": 2.1, "position": [850, 380], "credentials": {"gmailOAuth2": {"id": "YOUR_GMAIL_CREDENTIAL_ID", "name": "Gmail account"}}, "parameters": {"operation": "send", "sendTo": "={{ $('Google Sheets - Read Inactive Leads').item.json.email }}", "subject": "={{ $json.content[0].text.split('\\n')[0] }}", "message": "={{ $json.content[0].text.split('\\n').slice(2).join('\\n') }}", "options": {"appendAttribution": false}}}, {"id": "f6a7b8c9-0006-4f6a-df6b-d6e7f8a9b0c1", "name": "Google Sheets - Update Last Contacted", "type": "n8n-nodes-base.googleSheets", "typeVersion": 4.4, "position": [1050, 380], "credentials": {"googleSheetsOAuth2Api": {"id": "YOUR_GOOGLE_CREDENTIAL_ID", "name": "Google Sheets account"}}, "parameters": {"operation": "update", "documentId": {"__rl": true, "value": "YOUR_SPREADSHEET_ID", "mode": "id"}, "sheetName": {"__rl": true, "value": "Leads", "mode": "name"}, "columns": {"mappingMode": "defineBelow", "value": {"last_contact_date": "={{ $now.format('yyyy-MM-dd') }}", "last_interaction_type": "Email follow-up (automated)", "follow_up_sent": "Yes", "follow_up_date": "={{ $now.toISO() }}"}, "matchingColumns": ["email"]}, "options": {}}}], "connections": {"Schedule Trigger": {"main": [[{"node": "Google Sheets - Read Inactive Leads", "type": "main", "index": 0}]]}, "Google Sheets - Read Inactive Leads": {"main": [[{"node": "HTTP Request - Claude Follow-Up", "type": "main", "index": 0}]]}, "HTTP Request - Claude Follow-Up": {"main": [[{"node": "Gmail - Send Follow-Up", "type": "main", "index": 0}]]}, "Gmail - Send Follow-Up": {"main": [[{"node": "Google Sheets - Update Last Contacted", "type": "main", "index": 0}]]}}, "active": false, "settings": {"executionOrder": "v1"}, "meta": {"templateCredsSetupCompleted": false, "instanceId": "n8n-workflow-11-follow-up"}, "tags": []}, "diagram_image": "workflow-diagram-11.png"}, {"title": "Chapter 12: Automation Dashboard", "type": "templates", "content": "Once you have multiple workflows running, you need a single view to track what is working, what is breaking, and where to optimize. This dashboard template gives you that view in a Google Sheet you update weekly. Each row tracks one workflow: name, platform (Zapier or n8n), status, runs per week, and estimated time saved. The weekly summary prompt feeds your dashboard data to Gemini, which generates a report covering total time saved, your most active workflow, any errors needing attention, optimization suggestions, and an ROI estimate calculated as time saved multiplied by your hourly rate. The monthly optimization checklist walks through each active workflow: is AI output quality still accurate, are there recurring errors in the logs, are API costs within budget, does the prompt need updating for changed business info? The cost tracker tallies your Anthropic API, Google AI Studio, Zapier, and n8n spend against the hours saved — so you always know your automation ROI in real dollars. This is how you run automations like a business operation, not a set-and-forget experiment.", "dashboard_template": {"columns": ["Workflow", "Platform", "Status", "Runs/Wk", "Time Saved"], "example_rows": [["Social Post Gen", "Zapier", "Active", "7", "5 hrs"], ["Email Sequences", "n8n", "Active", "12", "4 hrs"], ["Content Repurpose", "Zapier", "Active", "3", "8 hrs"], ["Lead Magnet Follow", "Zapier", "Active", "15", "3 hrs"], ["Competitor Watch", "n8n", "Active", "7", "3 hrs"], ["Inquiry Responder", "Zapier", "Active", "28", "7 hrs"], ["Client Onboarding", "n8n", "Active", "4", "8 hrs"], ["Review Collector", "Zapier", "Active", "3", "2 hrs"], ["Customer Follow-Up", "n8n", "Active", "8", "4 hrs"]]}, "weekly_summary_prompt": {"platform": "Gemini", "prompt": "Here is my automation dashboard data for this week: {{dashboard_data}}. Generate a weekly report: 1) TOTAL TIME SAVED. 2) MOST ACTIVE workflow. 3) ANY ERRORS needing attention. 4) OPTIMIZATION SUGGESTIONS. 5) ROI ESTIMATE: Time saved x $[YOUR_HOURLY_RATE] = value generated."}, "monthly_optimization_checklist": {"for_each_active_workflow": ["Review AI output quality — still accurate?", "Check error logs — any recurring failures?", "Review API costs — within budget?", "Test with edge cases — handling unusual inputs?", "Update prompts — business info changed?"], "scaling_questions": ["Which workflow saves the most time? Can I expand it?", "Which has the most errors? Fix or replace?", "What manual task am I still doing? New workflow needed?", "Am I under API budget? Add more automations", "Am I over API budget? Switch models or reduce frequency"]}, "cost_tracker": {"anthropic_api": "$[___] / month ([___] runs)", "google_ai_studio": "$[___] / month ([___] runs)", "zapier_plan": "$[___] / month", "n8n_plan": "$[___] / month", "total": "$[___] / month", "time_saved": "[___] hours / month", "value_at_hourly_rate": "$[___] / month"}}, {"title": "Chapter 13: Troubleshooting & Optimization", "type": "educational", "content": "Automations break. AI outputs drift. API keys expire. This chapter is your field manual for diagnosing and fixing the seven most common automation issues — from generic AI output (fix: add your Business Profile to every prompt) to rate limit errors (fix: add 30-60 second delays between steps in your Zapier Zap or n8n workflow). Beyond troubleshooting, five optimization strategies help you cut costs and improve quality: use cheaper models like claude-haiku or gemini-flash for simple classification tasks while reserving expensive models for complex generation, batch multiple items into single API calls, cache repeated responses, pre-filter data so AI only processes what matters, and write more specific prompts that produce better output with fewer retries. The emergency checklist gives you step-by-step protocols for three crisis scenarios: automation sending wrong output (pause, check last 5 outputs, fix prompt, test, resume), automation stopped completely (check API key, billing, platform status, re-authenticate), and output quality declining (grade last 10 outputs, add context and examples, upgrade model if needed).", "common_issues": [{"problem": "AI output too generic", "fix": "Add your Business Profile to every prompt"}, {"problem": "Automation stopped", "fix": "Check API key + billing on provider dashboard"}, {"problem": "Wrong tone in emails", "fix": "Add 3 example emails in YOUR voice to the prompt"}, {"problem": "Too many errors", "fix": "Add a 'clean data' step before AI processes"}, {"problem": "API rate limits hit", "fix": "Add 30-60 second delays between steps"}, {"problem": "AI hallucinating facts", "fix": "Always feed real data, never ask AI to guess"}, {"problem": "Task limit reached", "fix": "Consolidate workflows or upgrade plan"}], "optimization_strategies": [{"number": 1, "name": "Model Selection", "description": "Use cheaper models (claude-haiku, gemini-flash) for simple tasks; expensive for complex."}, {"number": 2, "name": "Batching", "description": "Process multiple items in one AI call instead of one at a time."}, {"number": 3, "name": "Caching", "description": "Store repeated AI responses to avoid redundant API calls."}, {"number": 4, "name": "Pre-Filtering", "description": "Add conditional logic to only send relevant data to AI."}, {"number": 5, "name": "Prompt Engineering", "description": "More specific prompts = better output = fewer retries = lower cost."}], "emergency_checklist": {"sending_wrong_output": ["PAUSE immediately", "Check last 5 outputs", "Fix prompt", "Test > Resume"], "stopped_working": ["Check API key/billing", "Check platform status", "Re-auth connections", "Fix > Resume"], "results_are_meh": ["Grade last 10 outputs", "Add more context", "Add example outputs", "Upgrade model"]}}, {"title": "Chapter 14: What's Next", "type": "educational", "content": "You have completed the full AI journey: from typing single prompts (Starter Kit) to building AI specialists (Skills Builder) to deploying complete business systems (Small Business) to putting it all on autopilot (Automation Mastery). Each level built on the previous one, and together they form an integrated AI operation that handles marketing, sales, customer service, operations, and reporting with minimal daily input from you. The Ultimate AI Bundle packages all four products at $147 (saving $15 versus buying separately) and includes all future updates as we add new workflows and refine existing ones. Whether you went through the products one at a time or jumped straight to automation, you now have the skills and systems to run a business where AI does the heavy lifting and you make the strategic decisions.", "complete_journey": [{"step": "01", "product": "AI Starter Kit", "price": "$19", "description": "Learned to talk to AI", "status": "DONE"}, {"step": "02", "product": "AI Skills Builder", "price": "$29", "description": "Built AI specialists", "status": "DONE"}, {"step": "03", "product": "AI for Small Business", "price": "$47", "description": "Deployed business systems", "status": "DONE"}, {"step": "04", "product": "AI Automation Mastery", "price": "$67", "description": "Put it all on autopilot", "status": "DONE"}]}, {"title": "Installable AI Tools — 4 Claude Skills", "type": "skills", "content": "Ready-to-install AI tools built specifically for solopreneurs. Each tool is a pre-configured AI specialist that you install once and use forever. Copy the code below, follow the install steps, and you'll have a working AI assistant in under 5 minutes.", "install_overview": {"claude": {"title": "How to Install Claude Skills", "steps": ["Open Claude (claude.ai) and sign in", "Type /skill-creator in any conversation", "Paste the SKILL.md content when prompted", "Name your skill and save — it's now available in all your conversations"]}, "gemini": {"title": "How to Install Gemini Gems", "steps": ["Open Gemini (gemini.google.com) and sign in", "Click \"Gem manager\" in the left sidebar", "Click \"New Gem\" and give it a name", "Paste the system prompt into the instructions field and save"]}}, "skills": [{"name": "Daily Business Dashboard", "description": "Solopreneurs who want a morning briefing on their business without manually checking 10 apps", "platform": "Claude Skill", "system_prompt": "You are Daily Business Dashboard — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners start every morning with total clarity — knowing exactly what matters today, what's slipping, and what to focus on first.\nHow you work:\nThe user provides their data each morning — this could be yesterday's revenue, pending tasks, client follow-ups, pipeline updates, or any combination. You compile it into a clean, scannable briefing. If the user has a consistent set of metrics they track, ask them to share a template or list on day one so you can use it every session without re-asking.\nWhat you produce every morning:\n- Today's Headline: One sentence — what is the single most important thing for today?\n- Key Metrics: Revenue to date this week/month, deals in pipeline, any numbers the user tracks regularly. Flag anything off-trend with a note.\n- Top 3 Priorities: The three tasks that will make today a success. Revenue-generating first.\n- Follow-Ups Due: Client emails, proposals, check-ins that need action today. Pulled from what the user provides.\n- Quick Wins: 1-2 small things that take under 15 minutes and will clear mental load\n- Watch List: One thing that's at risk or needs attention today — not urgent enough to be a priority, but important enough not to ignore\nRules you always follow:\nThis briefing should take under 2 minutes to read. No padding. No lengthy analysis — save that for Weekly Performance Analyst. If the user's data suggests they're behind on something important, say it directly at the top.\nFormatting rules:\nAll sections clearly labeled. Metrics as a compact table or quick list. Total output: scannable in under 2 minutes. Today's Headline bold at the top."}, {"name": "Lead Nurture Engine", "description": "Solopreneurs who get leads but lose them because follow-up is inconsistent", "platform": "Claude Skill", "system_prompt": "You are Lead Nurture Engine — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners follow up with leads consistently and personally — turning cold contacts into warm relationships without requiring a CRM or a sales team.\nHow you work:\nThe user tells you about a lead: who they are, how they came in, where the conversation left off, and what the goal is (book a call, close a deal, get a reply). You draft the next touchpoint and suggest a follow-up schedule. You can also help users build full nurture sequences for multiple leads at once.\nWhat you produce:\nFor a single lead:\n- Next touchpoint draft (email or DM): Personalized, specific, not salesy. Reference the last interaction. Include a clear but low-pressure next step.\n- Suggested timing: When to send this and when to follow up again if there's no response\n- 2-3 message sequence: The next touchpoints mapped out with suggested timing between each\nFor pipeline reviews:\n- List of leads with a suggested action and message draft for each\n- Flag leads gone cold — suggest a re-engagement message or a decision to close them out\nRules you always follow:\nEvery message should feel like it came from a real person who remembers the lead — not a blast email. One ask per message. Never use 'just checking in' or 'circling back.' Ask for lead context before drafting if the user hasn't provided it. Suggest realistic gaps between touchpoints.\nFormatting rules:\nFor sequences, label each message (Message 1, Message 2, etc.) with suggested send timing. Keep messages under 100 words each. Include a brief rationale for the approach used."}, {"name": "Content Calendar Generator", "description": "Solopreneurs who never know what to post and waste hours deciding", "platform": "Claude Skill", "system_prompt": "You are Content Calendar Generator — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners plan and batch their content so they always know what to post, never repeat themselves, and stay consistent without burning out.\nHow you work:\nThe user tells you their platform(s), posting frequency, and business/content focus. If they haven't defined their content pillars, ask — or suggest defaults based on their business type and let them approve. Then build the calendar. You support both planning (what to create) and execution (the actual post drafts).\nWhat you produce:\nWeekly calendar: 5-7 slots with specific post topics, formats, recommended platforms, and suggested posting times. Balanced across content pillars.\nMonthly calendar: 4-week overview with themes per week and specific topics per day. Include a mix of content types: educational, entertaining, personal/behind-the-scenes, promotional, and engagement-focused.\nActual post drafts: When the user is ready to batch-create, produce the full posts (hooks, body, CTA, hashtags) for each calendar slot.\nContent pillar balance (default unless user specifies otherwise):\n- 40% educational / how-to / tips\n- 25% personal / behind-the-scenes / story\n- 20% promotional / offer / CTA\n- 15% engagement / question / conversation\nRules you always follow:\nNo two posts in the same week should use the same hook format. Promotional content gets no more than 1-2 slots per week — more than that and the audience tunes out. Always include variety in post format (text, carousel idea, image suggestion, short video idea). Flag any seasonal opportunities or relevant dates in the calendar period.\nFormatting rules:\nCalendar as a table (Day | Topic | Format | Pillar | Platform). Actual posts in numbered, labeled blocks below or in a separate section. Include a note on the overall content theme for the week or month."}, {"name": "Weekly Performance Analyst", "description": "Solopreneurs who fly blind without knowing what's working", "platform": "Claude Skill", "system_prompt": "You are Weekly Performance Analyst — a specialized AI assistant for solopreneurs.\nYour job is to help solo business owners review their week objectively — understand what worked, what didn't, and walk away with three clear actions to make next week better.\nHow you work:\nThe user shares weekly metrics and data — numbers (revenue, leads, content reach), qualitative notes, or both. You analyze it, compare against their goals if provided, and produce a structured performance review. Ask for goals on the first session if they haven't been set.\nWhat you produce every week:\n- Weekly Snapshot: Key numbers at a glance. Revenue, leads, top content performance, and any other metrics the user tracks. Flag anything significantly above or below expectation.\n- What's Working: Specific wins with a hypothesis for why — not 'content did well' but 'the LinkedIn post outperformed because it used a personal story.'\n- What Needs Attention: Honest assessment of what underperformed or slipped. No sugarcoating — but no catastrophizing either.\n- Progress vs. Goals: Simple comparison against weekly or monthly targets\n- 3 Actions for Next Week: Specific, testable, and prioritized. Each action should connect directly to something in the analysis above. Not generic advice.\nRules you always follow:\nInsight over data dumps — every number needs context. If the user only shares partial data, work with it but flag what's missing. Never end on a negative — the three actions should feel motivating, not punishing.\nFormatting rules:\nWeekly Snapshot as a compact table. Sections clearly labeled. Three Actions in bold, numbered, one sentence each. End with a one-line 'Analyst's Note' — an honest overall read of the week in plain language."}]}, {"title": "Get the Complete Toolkit", "type": "cta", "content": "You built the automations. Your AI writes, responds, follows up, onboards, monitors competitors, collects reviews, and re-engages customers — all without you touching a keyboard. The Ultimate AI Bundle at $147 gives you every product in the KH Academy lineup (Starter Kit, Skills Builder, Small Business Systems, and Automation Mastery) plus all future updates and new workflow additions. That is $15 less than buying each product separately, and it means every new workflow or system we release lands in your account automatically. If you started with just this guide, the bundle fills in the foundation layers. If you already own everything, you are set — keep optimizing, keep reviewing your dashboard, and keep climbing.", "items": [{"offer": "Ultimate AI Bundle", "price": "$147", "description": "All 4 products | Separately: $162 | Save $15. AI Starter Kit + AI Skills Builder + AI for Small Business + AI Automation Mastery.", "url": "https://www.kh-academy.com"}], "contact": "info@kh-academy.com", "purchase_url": "https://kh-academy-storefront.vercel.app/#pricing", "storefront_url": "https://kh-academy-storefront.vercel.app"}]};

